window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-009.json"] = [{"name":"长嘴斑海雀","english_name":"Long-billed Murrelet","scientific_name":"Brachyramphus perdix","overview":"长嘴斑海雀（英文名：Long-billed Murrelet，学名：Brachyramphus perdix），是鸻形目海雀科斑海雀属的鸟类。小型海鸟，们体型圆胖，常见于北太平洋沿岸海域，有时也会接近陆地。繁殖期成鸟全身巧克力棕色，腹部带有褐色与白色的鳞状斑纹。冬季成鸟上身灰色，下身白色，眼周有细白环，侧面和背部点缀着不规则的白色斑点。在北太平洋地区，尤其是库页岛、鄂霍次克海、堪察加半岛到日本北海道一带繁殖。非繁殖期广泛分布于日本沿海中部，偶尔长距离漂泊至美国大陆。","appearance":"长嘴斑海雀长约25厘米，拥有黑色细长的喙和尖锐的翅膀。非繁殖期外观为白腹黑冠、颈、翼和背；繁殖期羽毛主要为棕色，边缘较浅形成鳞片状外观，腹部中央白色。与其他同类相比，长嘴斑海雀喙较长，体型略大，体重增加约20%，并且具有白色的眼圈。在冬季，它缺乏像大理石斑海雀那样的白色颈圈。","call":"关于其鸣叫和声音行为的资料目前尚未可知，是否与大理石斑海雀的叫声有差异还有待研究。","habits":"长嘴斑海雀主要栖息于海洋，繁殖期才会返回岸边岛屿或陆地。它们能直接从海面起飞，上岸时直立站立，如同企鹅，这是趋同进化的一种表现。擅长游泳和潜水，能潜入水下10米以上。食物主要包括鱼类、甲壳类和其他海生无脊椎动物。它们在海洋和海岸附近活动。","breeding":"繁殖习性知之甚少，据报告在俄罗斯发现大约四个树巢和一个地面巢，最近一次是在1961年。树巢位于落叶松树上，高度从2.5到7米不等，通常在混合针叶林和落叶林中。繁殖季节与大理石斑海雀相似，可能是一夫一妻制，表现出高繁殖地和配偶忠诚度。单个配对在成熟森林中低密度分布。巢建于苔藓、树枝、针叶和干落叶的平台上，巢杯至少长5.5厘米、宽3.5厘米、深2.5厘米。产一枚淡橄榄绿至黄绿色的蛋，表面覆盖不规则的棕色、黑色和紫色斑点，大小约为63.6至66.2毫米×39至39.3毫米，重量48至53.7克。","identification":"与大理石斑海雀相似，但长嘴斑海雀体型更大，喙更长，冬季缺乏白色颈圈，且有白色眼圈。在繁殖羽下，长嘴斑海雀喉部呈淡色，而大理石斑海雀没有这一特征，且长嘴斑海雀的鳞状斑纹因缺少锈色和淡色标记而显得较弱。","protection":"IUCN：NT（近危）","distribution":"繁殖于欧亚大陆的北太平洋沿岸，包括堪察加半岛、鄂霍次克海、库页岛和日本北海道北部，巢穴可达内陆30公里。冬季迁徙至日本沿海中部，偶见于美国大陆。","other":"长嘴斑海雀面临的主要威胁是老生长林的砍伐，尤其是在库页岛和堪察加半岛。石油工业在鄂霍次克海和白令海架的发展构成额外威胁。"},{"name":"小嘴斑海雀","english_name":"Kittlitz's Murrelet","scientific_name":"Brachyramphus brevirostris","overview":"小嘴斑海雀（英文名：Kittlitz's Murrelet，学名：Brachyramphus brevirostris），是鸻形目海雀科斑海雀属的鸟类。体型较小的海雀科鸟类，以德国博物学家Heinrich von Kittlitz的名字命名。主要分布在北美洲和欧亚大陆的北极至亚北极地区，尤其在阿拉斯加和东西伯利亚沿海地带。这种海鸟因其独特的繁殖习性——在山地顶部的裸露地面筑巢而闻名，而非像多数海鸟那样群居繁殖。繁殖季节时，其灰色或棕色的羽毛有助于伪装，而在冬季则换上黑白相间的羽毛。","appearance":"小嘴斑海雀体长约25厘米，具有一副圆润的身躯，头部相对较大，喙短而呈褐色，眼睛深色且较大。繁殖季时，上体呈暗灰至棕褐色，带有不规则的淡黄色或红金色边缘，下体淡黄色或略带灰白色，胸部有暗灰色条纹或U形羽缘，形成条纹效果。非繁殖季时，上体和上胸侧为石板灰色，形成几乎完整的暗灰色胸带；头部灰色部分位于眼上方，形成窄的暗灰色新月形；背部和臀部的羽毛边缘较窄，白色；脸部、喉咙和下体洁净白色。翅膀暗灰褐色，翼覆羽狭窄边缘白色；腋羽和下翼覆羽深褐灰色；肩羽白色。尾巴暗褐灰色，中央尾羽尖端白色，外侧尾羽白色，带有小黑点。幼鸟外观与非繁殖季成鸟相似，但喉部和胸部有隐约的条纹，尾部有白色或淡黄色次端斑点和深褐色终端带。","call":"种类多样，包括主叫“Groan Call”，特征音似“aaahrr”，频率1.7-1.9 kHz，短促；“Long-groan Call”，嘶哑、粗糙，可重复数次；“Quack Call”，短促，像压缩的Groan Call；“Chew Call”，仅一次记录，频率高，音调上升；“Duet Call”和“Wavering Duet Call”，涉及一对或多只鸟的交互叫声。叫声多在海上繁殖区被听见，用于伴侣沟通和雏鸟喂食时。叫声功能包括伴侣联系和可能的求偶行为。叫声的详细社会语境仍待进一步研究。","habits":"小嘴斑海雀主要栖息在靠近冰川的海岸和高山地区，它们在冰川流出水域觅食，以幼鱼、磷虾和其他小型浮游动物为食。繁殖季节，它们在山地顶部的裸露地面筑巢，非繁殖季节则广泛分布于海湾、峡湾和开阔海域，甚至在冰层裂缝附近的海域过冬。它们的飞行快速且直接，善于潜水捕食。","breeding":"繁殖期通常在夏季，每窝产一枚蛋，孵化期约30天。雏鸟孵化后，父母会持续喂养直至雏鸟体重达到能够飞行的程度，大约需25天左右。雏鸟在离巢前12小时失去绒毛，之后可能直接飞向大海或通过河流到达海洋，之后不再接受亲鸟照料。","identification":"与云石斑海雀和长嘴斑海雀相比，小嘴斑海雀的喙更小，繁殖季时羽毛颜色更偏灰、红或黄褐色，而非深棕色，且具有更多变色。非繁殖季时，脸部白色延伸至眼上方，颈部有完整的白色颈环，胸带几乎完整，这些特征有助于与其它斑海雀属物种区分。","protection":"IUCN：NT（近危）","distribution":"繁殖区域分布于欧亚大陆和北美的北极至亚北极地区，包括Wrangel岛（东北西伯利亚）、楚科奇、东北勘察加半岛、Okhotsk海（俄罗斯东部）、白令海、阿留申群岛、阿拉斯加海湾，直至阿拉斯加东南部，巢穴可达内陆75公里。非繁殖区域则扩展至繁殖范围内的海湾和峡湾。","other":"小嘴斑海雀曾被认为处于极度濒危状态，但在2014年，IUCN将其状态下调为近危，这得益于近年来观察到的种群下降速度似乎有所放缓，某些群体出现了稳定或轻微恢复的趋势。然而，全球变暖导致的栖息地丧失、油轮泄露和船只干扰仍是威胁其生存的因素。"},{"name":"桑氏海雀","english_name":"Guadalupe Murrelet","scientific_name":"Synthliboramphus hypoleucus","overview":"桑氏海雀（英文名：Guadalupe Murrelet，学名：Synthliboramphus hypoleucus），是鸻形目海雀科扁嘴海雀属的鸟类。小型黑白色潜水海鸟，主要在太平洋加利福尼亚潮流系统活动。在加利福尼亚和墨西哥的海岛繁殖，受到外来掠食者的威胁。","appearance":"桑氏海雀是一种小型海鸟，身长23-25厘米，平均重量130-185克，翼展约40厘米。拥有短而细的黑色鸟喙，背部黑色带有淡灰色调，包括头部顶部、颈部、背部、翅膀和尾巴；面部有明显的白色新月形斑纹，环绕眼睛并与喉咙的白色相连；腹部主要为雪白，两胁颜色从纯白到灰白相间不等；脚和蹼为蓝灰色，带有黑色网状和爪子。雌鸟通常比雄鸟大，尤其在喙长、翼展和体重上（平均重15克），但在喙深和跗跖长度上没有差异。冬季，由于羽毛磨损，上部羽毛可能显得更浅的灰黑色。幼鸟与成鸟相似，但两侧有散落的暗色条纹。","call":"桑氏海雀的叫声特征与斯氏海雀没有已知的区别。","habits":"桑氏海雀生活在远离陆地的岩石和岛屿附近的海域，主要占据比大多数海鸟更温暖的水域，除了克氏海雀和斯氏海雀。繁殖季节在陡峭的海岸悬崖、斜坡和峡谷上筑巢。冬季主要在远离陆地的海域度过，尽管这一时期的分布情况因与斯氏海雀难以区分而不太清楚。","breeding":"桑氏海雀的繁殖习性相比斯氏海雀较为未知，12月中旬至晚些时候出现在近海，繁殖可能持续到7月。夜间在繁殖地活动，产卵时间在不同年份间存在异步性和变异性，但总体季节与斯氏海雀相似或稍晚。在San Benito Islands，最早记录到2月底的雏鸟和5月初的蛋。通常在岩隙、洞穴、地洞或灌木丛中筑巢，巢常位于面向大海的沙质斜坡上。每窝产两枚蛋，关于孵化和育雏的进一步信息有限。","identification":"与斯氏海雀非常相似，但面部的白色部分更为广泛，使得眼睛在白色区域中突出，而不是融入黑色的帽状羽毛。下翼明亮的白色，与斯氏海雀相同，但不同于克氏海雀的暗色下翼。","protection":"IUCN：EN（濒危）","distribution":"繁殖区主要在北太平洋沿岸的Guadalupe岛和San Benito群岛（位于墨西哥Baja California西部）。非繁殖季节分布至美国加利福尼亚州北部沿海。","other":"桑氏海雀与斯氏海雀曾被归为同一物种，直到2012年有足够的证据表明它们是不同的物种，基于面部图案、喙形、叫声和遗传学的差异。"},{"name":"斯氏海雀","english_name":"Scripps's Murrelet","scientific_name":"Synthliboramphus scrippsi","overview":"斯氏海雀（英文名：Scripps's Murrelet，学名：Synthliboramphus scrippsi），是鸻形目海雀科扁嘴海雀属的鸟类。小型黑白色海鸟，在加利福尼亚海峡群岛和墨西哥巴哈加州中部的岛屿上繁殖，分布于北太平洋沿岸，从南加州到巴哈加州中部的岛屿。其特征为背部黑色，腹部白色，拥有细长的喙。曾与桑氏海雀一同被视为Xantus's Murrelet的一部分，但现已被认为是独立物种。","appearance":"斯氏海雀是一种体型较小的海鸟，背部为纯黑色，腹部为白色，头部小巧，喙细长尖锐。全长约23-25厘米，翼展约40厘米，成年平均体重148-167克。背部颜色在新鲜羽毛时带有蓝灰色调，磨损后变为灰黑色。下体雪白，包括喉咙和尾下覆羽。翼下覆羽通常纯白，有时混有少量灰色羽毛。两翼折叠下方的侧腹部分大多为白色或灰白相间，下体其余部分为纯白色。喙比克氏海雀的喙更短更厚。","habits":"斯氏海雀栖息在离岸岛屿，繁殖后向北分散，最远可达美国华盛顿州沿海。它们通常在海上觅食，与大型海洋掠食性鱼类如金枪鱼相伴，以小鱼如鳀鱼、沙丁鱼和Sebastes岩鱼的幼鱼为食。它们是翼驱动潜水者，能在水下追逐猎物。它们在夜间返回巢穴，通常在岩石裂缝、洞穴或浓密灌木下筑巢。","breeding":"斯氏海雀在干燥的岛屿上形成松散的繁殖群落，雌雄共同孵化两个蛋约一个月。幼鸟出生两天内便离开巢穴，向海移动，父母会在海中呼唤它们。幼鸟高度早熟，出生后不久就能独立跟随父母前往远离陆地的海域。","identification":"斯氏海雀与克氏海雀极为相似，但可以通过翼下覆羽的白色而非灰色来区分。此外，斯氏海雀的颈部两侧可能有黑色羽毛形成的不完整项圈，而克氏海雀的项圈更长更窄。桑氏海雀的面部周围有白色，是另一个重要的辨识特征。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于北太平洋沿岸，包括南加州的海峡群岛和墨西哥巴哈加州西北部和北部的岛屿。非繁殖期时，分布至北至美国华盛顿州沿海的太平洋中部北部海域。"},{"name":"克氏海雀","english_name":"Craveri's Murrelet","scientific_name":"Synthliboramphus craveri","overview":"克氏海雀（英文名：Craveri's Murrelet，学名：Synthliboramphus craveri），是鸻形目海雀科扁嘴海雀属的鸟类。小型海鸟，分布于墨西哥太平洋沿岸和加利福尼亚湾的岛屿，偶尔在美国加州中部出现。具有黑色的上部和白色的下部，雌雄羽毛颜色相似，前趾间有蹼膜，后趾缺失。面临引入的捕食者、油污、渔船网具和旅游开发的威胁。","appearance":"克氏海雀体长约21厘米，体重介于128至149克之间，拥有短而细的黑色喙，上体为褐色黑，头部顶部延伸至下颌底部呈黑色；喉咙和脸部下方白色；下体白色，胸部侧面有一窄黑楔，两侧及背部延伸处为暗色；脚和趾为蓝灰色，爪子黑色。幼鸟与成鸟类似，但喙略短，上体更深色，胸腹有细黑条纹或斑点。","call":"克氏海雀发出高亢的颤音哨声，有时声音响亮且强度高，最远可达18米之外。","habits":"克氏海雀栖息于海洋，仅在繁殖季节靠近岛屿或陆地。它们偏好温暖水域，主要分布于加利福尼亚湾和太平洋沿岸，冬季迁徙至南加州至墨西哥西部。它们通常单独或成对觅食，以小型鱼类为主食，也会捕食虾和乌贼。","breeding":"克氏海雀在陡峭的海岛悬崖和海岸斜坡上筑巢，形成小群（数十对）。巢穴位于岩石缝隙或洞穴中，入口狭窄，或在地下洞穴、浓密灌木下和巨石旁。繁殖期从2月持续至4月初，产卵期集中在2月下半月至3月初，每次产2枚卵，孵化期约31至33天，由双亲共同承担。幼鸟孵化后25克重，羽毛呈深棕色至黑色，腹部白色，出生1至2天后即被带至海上喂食小鱼。","identification":"克氏海雀与斯氏海雀非常相似，主要通过灰色而非白色的下翼区分。克氏海雀的黑色头罩向下延伸更多，胸部侧面的黑色斑块更长，下翼覆羽为暗灰而非白色。","protection":"IUCN：VU（易危）","distribution":"克氏海雀主要繁殖于墨西哥的加利福尼亚湾岛屿（北至圣乔治岛）和巴哈半岛太平洋沿岸的岛屿（塞德罗斯、阿松森至圣罗克岛，可能还包括圣马丁和圣贝尼托岛）。冬季分布于加利福尼亚湾及南至墨西哥纳亚里特的海域。","other":"克氏海雀的种群受到人类活动的严重威胁，包括引入的捕食者（如鼠类）、油污、商业渔业和旅游业的发展。"},{"name":"扁嘴海雀","english_name":"Ancient Murrelet","scientific_name":"Synthliboramphus antiquus","overview":"扁嘴海雀（英文名：Ancient Murrelet，学名：Synthliboramphus antiquus），是鸻形目海雀科扁嘴海雀属的鸟类。因其背部的灰色如同老人披肩而得名\"古代\"。繁殖季节头部、喉咙和后颈呈黑色，背部灰色，腹部白色，喙短且钝，带有黄色。分布于北太平洋沿岸，从中国黄海岛屿至俄罗斯远东、阿留申群岛，直至加拿大的Haida Gwaii群岛，其中约半数种群在此繁殖。","appearance":"扁嘴海雀是一种小型海鸟，头部、喉咙和后颈为黑色，背部灰色，腹部白色。繁殖期成鸟有白色眉纹，使外观显得老态龙钟。喙短而粗，颜色从浅灰色至淡黄色不等，尖端可能带黑色。脚和蹼淡蓝色，有时偏粉红，趾和跗跖下部黑色，爪黑色，虹膜深棕色。由于腿位于身体后方，它们通常不会像海鹦那样直立站立，而是向前躺在腹部。飞行时，翅膀快速拍打，躯体和翅膀之间倾斜明显。","habits":"扁嘴海雀栖息于北太平洋沿岸的海岛和海岸，冬季则迁徙至较暖的海域。它们主要在离岸水域觅食，偶尔也会出现在靠近陆地的水域。扁嘴海雀通过潜入水下捕食小鱼和大型浮游动物，尤其是磷虾类甲壳动物。它们在海上度过大部分时间，仅在繁殖季节返回陆地。","breeding":"扁嘴海雀在近海岛屿上的松软土壤中挖掘洞穴繁殖，或在树根下的空腔、草丛中的浅坑，偶尔在岩石裂缝中。每窝产两枚同等大小的卵，孵化成功率高。幼鸟不喂养在洞穴中，出生1-3天后即离开前往大海。每对繁殖的扁嘴海雀大约能有1.5只幼鸟离开巢穴，这相对较高的繁殖输出与相对较低的成年鸟年度存活率（约77%）相关联。","identification":"繁殖期扁嘴海雀的黑色头和喉咙与苍白的喙是显著特征。它们的灰色上体与黑色头部的对比在小型海鸟中独一无二。与海雀相比，后者虽然体型较小且呈灰色，但缺乏深黑色的头和喉咙；注意形状差异，海雀整体较为粗壮。云石斑海雀在繁殖期主要呈褐色，但在非繁殖期变为黑白相间，两种海鸟在近岸水域同时出现。云石斑海雀喙细长且暗色，白色领圈更为宽广，肩部羽毛白色。当远离观察者起飞时，云石斑海雀的臀部两侧显白色（扁嘴海雀臀部灰色），肩部羽毛浅色明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆和北美温带海洋西北部至太平洋东北部海岸：零星分布于堪察加半岛、鄂霍茨克海、库页岛、千岛群岛和科曼多尔群岛（俄罗斯东部）、日本海、日本、阿留申群岛、美国阿拉斯加湾至加拿大不列颠哥伦比亚省西部。非繁殖期向日本海和太平洋西南部海岸线迁移，远至美国加利福尼亚南部，易发生长途迷鸟事件，出现在加拿大南部和美国北部内陆。"},{"name":"冠海雀","english_name":"Japanese Murrelet","scientific_name":"Synthliboramphus wumizusume","overview":"冠海雀（英文名：Japanese Murrelet，学名：Synthliboramphus wumizusume），是鸻形目海雀科扁嘴海雀属的鸟类。小型海鸟，身长24至26厘米，体重约164至183克。其最显著的外部特征是黑色头部上的长而窄的黑色羽毛组成的冠状物，以及白色的喉部和体侧条纹。分布于日本东部和南部沿海岛屿，偶尔在韩国南部海域可见，可能在俄罗斯远东地区繁殖。","appearance":"冠海雀体型丰满，体长24至26厘米，翼展约43厘米，体重介于139至213克之间。喙短而厚，呈淡蓝灰色，顶部较暗；眼睛深棕色接近黑色；头部黑色，顶部长有黑色细长羽毛构成的冠状物，两侧有白色条纹至颈背处相遇；背部黑灰相间，腹部白色，两胁灰黑色；腿脚黄色。非繁殖季节，冠状物和头纹消失，头部颜色更浅，与扁嘴海雀相似，但仍有白色头侧标记。幼鸟外观类似冬季成鸟，但头部和背部颜色偏棕色。","call":"发出尖锐的‘chi-chi-chi’叫声，与鵐科鸟的飞行叫声相似。此外，还会有‘byubyubuy’夜间的叫声和类似‘peeep-p-p-p’的叫声。","habits":"冠海雀主要栖息于西北太平洋的寒带和温带亚热带水域，繁殖于日本沿海的岩石岛屿和海岸。非繁殖季节，它们主要生活在海上，靠近大陆架边缘，有时也会在近岸觅食，特别是在上升流或汇合流使食物集中在表面的地方。冬季，它们大多在温带亚热带水域度过。","breeding":"繁殖期从2月中旬至3月初开始，产卵期一般为3月中旬至6月底或7月初，雏鸟通常在4月末至5月末离巢。巢建于岩石缝隙、洞穴下或巨石下，也可能在土壤中挖掘短洞穴，甚至在树根或草丛下。每窝产卵2枚，孵化期约为32至33天，由双亲轮流孵卵。雏鸟出生后不久便随父母离开巢穴。","identification":"与扁嘴海雀相比，冠海雀拥有更为明显的黑色冠状羽毛，头部两侧的白色标记更突出，下喉部没有黑色，且喙略大。非繁殖期两者差异减小，但冠海雀头部颜色更浅，黑色帽状部分较小，通常仍保留至少一些白色头侧标记。","protection":"IUCN：VU（易危）。在中国国家重点保护野生动物名录中列为Ⅱ级保护（2021.02.05）。","distribution":"繁殖区主要位于日本西部和南部沿海岛屿，包括本州岛、九州岛和伊豆群岛的部分岛屿，以及韩国半岛南部，可能在俄罗斯远东地区有少量分布。非繁殖区则扩展至北海道北部和日本东南部。","other":"历史上，冠海雀数量因人类捕猎、栖息地破坏和外来掠食者的引入而显著减少。目前总数量估计在2,500至10,000只之间，是全球最稀有的海雀种类之一。"},{"name":"海雀","english_name":"Cassin's Auklet","scientific_name":"Ptychoramphus aleuticus","overview":"海雀（英文名：Cassin's Auklet，学名：Ptychoramphus aleuticus），是鸻形目海雀科卡氏海雀属的鸟类。雌雄羽色相似，前趾间有蹼膜，后趾缺如。广泛分布于北太平洋沿岸，从俄罗斯/日本的库页岛至阿拉斯加阿留申群岛，南至墨西哥下加利福尼亚半岛。在繁殖季节，主要集中在加拿大不列颠哥伦比亚省沿岸。","appearance":"海雀是一种小型、结实的海鸟，全长约25厘米，体重200克左右。其上身呈暗灰色，带有蓝色调，下身逐渐变淡至腹部的白色。脚和腿为蓝色，成年个体具有白色的虹膜，眼周有小块白色新月形羽毛。幼鸟类似成鸟，但虹膜为褐色。次年个体与成鸟相似，虹膜通常较暗，到第三年变为白色。","habits":"海雀在非繁殖季节大部分时间在海上度过，南方种群可能向北迁移，北方种群则向南移动，主要栖息在大陆架和斜坡附近的水域，以小型甲壳类、鱿鱼和幼鱼为食。它们常聚集在食物丰富的海域，利用短小的翅膀潜水捕食。","breeding":"海雀在秋季至冬季在下加利福尼亚繁殖，而在夏季于阿拉斯加繁殖。它们在浅洞穴中筑巢，有时也在岩石裂缝或树下。海雀是唯一已知在单个繁殖季节内连续孵化两窝的海鸟，至少在其南部范围内。每窝产卵一枚，孵化期约40天，由双亲共同喂养。","identification":"海雀在外观上较为独特，但在其分布区域内可能与其它小型灰色海鸟混淆。它与白腹海雀的区别在于后者上体更深色，喉部至胸部的白色连贯，且具有橙色的喙。此外，海雀与角嘴海雀相比体型较小，喙颜色不同，且头部比例更小。","protection":"IUCN：NT（近危）","distribution":"北美太平洋东部北部沿海，从库页岛至阿拉斯加阿留申群岛，南至墨西哥下加利福尼亚半岛。主要繁殖区域在加拿大不列颠哥伦比亚省沿岸的三角岛。","other":"海雀是被《1918年候鸟条约法案》保护的物种。"},{"name":"白腹海雀","english_name":"Parakeet Auklet","scientific_name":"Aethia psittacula","overview":"白腹海雀（英文名：Parakeet Auklet，学名：Aethia psittacula），是鸻形目海雀科小海雀属的鸟类。中等体型的海雀，以其亮橙色的喙和独特的笑脸外观著称。背部呈深灰黑色，腹部洁白，繁殖季节时眼后有一条长白‘胡须’。白腹海雀广泛分布于北太平洋海域，包括阿拉斯加湾北部、白令海大部分区域、阿留申群岛以南的北太平洋、以及西伯利亚的鄂霍茨克海。","appearance":"白腹海雀拥有中等身材，喙短而厚实，向上弯曲，赋予其独特表情。背部深灰黑色，腹部纯白，繁殖季节眼后有明显的白色‘胡须’状羽毛。雌雄同形同色，冬季时白色的延伸至喉咙，与夏季区别在于白色部分的分布。白腹海雀与小海雀色彩模式相似，但体型为其两倍，且小海雀非繁殖期脸颊白色，繁殖期上半身有白色斑点。","call":"白腹海雀在繁殖季节极为鸣叫活跃，发出一系列节奏感强的嘶哑叫声，与卡辛氏海雀的叫声类似，还有颤音尖叫，功能不明，可能与巢穴防御和伴侣关系维护有关。","habits":"白腹海雀偏好高岩壁裂缝、陡峭草坡或可挖掘的碎石堆作为繁殖地点，偶尔使用前代海雀遗弃的巢穴。夏季在远离陆地的海上觅食，以小型浮游甲壳类动物为食，如磷虾、桡足类和端足类。研究显示，它们也会在某些区域捕食水母。白腹海雀在繁殖季结束后向南迁徙。","breeding":"繁殖始于4月至5月，通常与其它海雀共栖于同一岛屿群落。在悬崖裂缝中筑巢，路径曲折难以触及。每对仅产一枚蛋，孵化约需一个月，雏鸟在35天左右由双亲喂养四次后独立，夜间独自离巢飞往大海。","identification":"白腹海雀与小海雀在外形上有明显区别，后者体型较小，非繁殖期脸颊白色，繁殖期上半身有白色斑点。与其它海雀相比，白腹海雀的白色腹部是最显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北太平洋沿岸，从俄罗斯楚科奇半岛东部、堪察加半岛东北部、鄂霍茨克海、萨哈林岛、千岛群岛和指挥官群岛，到白令海岛屿、阿留申群岛和阿拉斯加湾。非繁殖季节分布于北太平洋远海，到达日本北部海域和加拿大西南部的不列颠哥伦比亚省西部。","other":"白腹海雀面临海洋污染和摄入微塑料的风险，但总体数量稳定，未受威胁。"},{"name":"小海雀","english_name":"Least Auklet","scientific_name":"Aethia pusilla","overview":"小海雀（英文名：Least Auklet，学名：Aethia pusilla），是鸻形目海雀科小海雀属的鸟类。是最小的海雀种类之一，体型略大于麻雀。是北美洲数量最多的海鸟之一，全球数量估计超过2000万只，主要在阿留申群岛和白令海岛屿密集繁殖。小海雀以浮游动物为食，筑巢于岩缝中，每年仅产一枚卵，日进食量接近体重的90%，反映了其飞行和觅食的高能量需求。","appearance":"小海雀总长度约12-14厘米，翼展33-36厘米，成年平均体重约85克。繁殖期成鸟为灰色和白色相间，面部有白色婚羽，喙短钝呈暗红色，顶部有一小块淡色斑点，从喙基部向上突出一个小角质瘤。成鸟繁殖期下体颜色变化明显，从纯白到斑点过渡直至几乎全黑，除了喉部白色斑块，中间色型最为常见，且颜色与年龄和社会地位相关。背部深灰色，肩部有不同程度的白色斑点。冬季，上体大多黑色，面部装饰减少，面部白色羽饰缺失，喙黑色，角质瘤消失。亚成鸟（约12个月大）夏季类似繁殖期成鸟，但装饰较暗淡，羽毛颜色更深，飞羽极度磨损。物种在羽毛和外部测量上性别相似，除了雄鸟的喙稍深一些。雏鸟与基本羽色成鸟相似，但眼睛灰色。","call":"在繁殖群中频繁发出一致的尖叫和吱吱声。","habits":"小海雀栖息于岩石海岸附近的大型繁殖群落，夏季在近岸活动，冬季则在远离海岸的海域形成较小的群落。它们潜入水中捕食浮游动物，主要为桡足类，特别是在夏季偏好Calanoid类型的桡足类。小海雀是追击潜水者，利用翅膀在水下推进，如同在水中飞翔。它们是贪婪的捕食者，每天消耗相当于体重86%的食物。","breeding":"高度群居，成千上万只鸟儿在岩石裂缝中筑巢。繁殖群落可能与其他种类的海雀混居，共同面对掠食者的威胁，但也面临着被较大种类如凤头海雀抢占巢位的风险。每窝产一枚卵，孵化期一个月，孵化出的雏鸟半早熟，全身覆盖黑色绒毛。双亲共同承担孵化、抚育和喂食的责任。与许多海雀不同，小海雀雏鸟通过下颌囊被喂食桡足类和其他浮游动物，无需额外的亲鸟照顾即可独立潜水捕食。","identification":"小海雀与须海雀难以区分，尤其是海上无法观察面部装饰的情况下，但小海雀更小，翅膀更圆，飞行更快更强壮，通常下体有大量白色，肩部有淡色斑点。与白腹海雀外表相似，但体型不到后者的一半。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于欧亚大陆东北部至北美西北部的沿海地区，分布零星，从俄罗斯远东的楚科奇东部、勘察加东北部、鄂霍次克海、千岛群岛和科曼多尔群岛，至白令海和阿留申群岛。非繁殖季节，广泛分布于北太平洋远洋水域，北至日本海和加拿大西南部的不列颠哥伦比亚西部。","other":"小海雀面临油污和外来物种的威胁，北极狐狸的引入导致该物种在多个阿留申群岛上的灭绝，而老鼠在许多岛屿上也是问题。"},{"name":"须海雀","english_name":"Whiskered Auklet","scientific_name":"Aethia pygmaea","overview":"须海雀（英文名：Whiskered Auklet，学名：Aethia pygmaea），是鸻形目海雀科小海雀属的鸟类。且不那么群居。仅在偏远的火山岛屿上繁殖，冬季则留在周边海域。繁殖期成鸟具有鲜亮的橙色喙，脸部细长的白色胡须状羽毛，以及向前垂下的黑色羽毛簇。须海雀在夜间活动，偏好在岩缝中筑巢。","appearance":"须海雀体型小，总长度约17-19厘米，体重平均约120克。其特征为深灰色的背部和胸部，腹部白色，与之形成鲜明对比。最显著的是三组白色的面部羽毛，赋予了其独特的\"胡须\"外观。喙部呈红色，尖端白色，与最小海雀的黑色带淡红色喙部有所不同。须海雀比凤头海雀和白腹海雀小5-7厘米，比海雀小3-4厘米，但比小海雀大3-4厘米。","call":"关于须海雀的鸣叫特征信息不足。","habits":"须海雀栖息在北太平洋的岛屿附近，偏好在潮汐流聚集猎物的近岸区域觅食。它们主要以浮游甲壳类动物为食，尤其是夏季的Neocalanus plumchrus，而在秋季和冬季则转向磷虾。须海雀全年留守在繁殖岛屿附近，这一习性在海雀家族中较为少见。","breeding":"须海雀可能是一夫一妻制，每次产一枚蛋，通常在岩隙中筑巢。雌雄双方共同承担孵化和抚育雏鸟的责任。它们倾向于在其他岩隙筑巢物种附近建立巢穴。","identification":"须海雀与白眉海雀相比，体型更小，喙部更细长，且具有独特的面部羽毛。与卡辛海雀的区别在于后者缺乏面部羽毛。须海雀的喙部颜色也不同于最小海雀。","protection":"IUCN：LC（无危）。尽管须海雀数量和趋势了解不多，但狐狸和鼠类在其繁殖岛屿上的引入被认为减少了其数量。","distribution":"繁殖于北太平洋的阿留申群岛和千岛群岛，包括俄罗斯东部的科曼多尔群岛和库页岛附近的海域。冬季则留在周边海域。","other":"须海雀的羽毛在繁殖季节具有柑橘般的气味，这一特性也见于白眉海雀。"},{"name":"凤头海雀","english_name":"Crested Auklet","scientific_name":"Aethia cristatella","appearance":"凤头海雀的身长介于18-27厘米，翼展34-50厘米，体重约195-330克。其特征性的红色橙色尖端喙、黄色眼虹膜和从眼睛延伸至耳朵的白色耳羽非常醒目。全身羽毛呈深灰色，腿脚灰黑色，爪子黑色。两性相似，但雌鸟的喙稍小且更直，冠羽也略小。繁殖季节中，其额头上的黑色弯曲羽冠尤为显眼，由数根至二十几根细长的前弯羽毛构成。冬季，喙变小，呈暗黄色，缺少装饰性羽板，冠羽和耳羽减少。","call":"凤头海雀具有多样化的叫声，包括复杂的鸣唱和单音节的叫声。在繁殖季节，它们会发出响亮的喇叭声，这是一种与特定视觉展示相关的复杂但刻板的声音序列。","habits":"凤头海雀主要在深水区觅食，但也靠近海岸。它们通常在大群体中活动，以磷虾、桡足类、翼足类、端足类和鱼苗为主食。它们从水面潜水捕捉食物，表现出类似水下飞行的行为。","breeding":"繁殖季节从5月中旬持续到8月中旬。它们在北太平洋沿岸的岩石裂缝中筑巢，形成密集的群体，巢间距仅0.3米。配偶选择相互，但雌鸟拥有最终决定权。凤头海雀在繁殖季节前和成对后高度社交，但一旦成对，它们在一年内保持一夫一妻制。","identification":"凤头海雀与较小的须海雀最为相似，但凤头海雀的额头羽冠更为蓬松，缺乏白色耳羽，夏季喙色橙色而非红色，因此在陆地上不会混淆。在海上和冬季，其特有的装饰性羽毛通常不可见，但凤头海雀总是全黑灰的羽毛，飞得相对较快，翅膀较长且尖。","protection":"IUCN：LC（无危）","distribution":"繁殖区分布在欧亚大陆和北美，从楚科奇东部、堪察加东北部、鄂霍茨克海、库页岛、千岛群岛和科曼多尔群岛（俄罗斯远东地区）、白令海和阿留申群岛。非繁殖区则遍布北太平洋，向南可达日本北海道和本州北部，以及美国阿拉斯加州海域。","other":"凤头海雀的繁殖地面临来自海鸥、北极狐和乌鸦的捕食威胁，以及油污和光源碰撞的风险。在阿拉斯加，存在一定的狩猎压力。"},{"name":"角嘴海雀","english_name":"Rhinoceros Auklet","scientific_name":"Cerorhinca monocerata","overview":"角嘴海雀（英文名：Rhinoceros Auklet，学名：Cerorhinca monocerata），是鸻形目海雀科角嘴海雀属的鸟类。本属唯一鸟类。以独特的喙部‘独角’而闻名，这一构造在繁殖季出现，具有荧光特性，可能用于繁殖信号传递。角嘴海雀分布于北太平洋区域，从美国加州的海峡群岛至阿拉斯加的阿留申群岛，以及亚洲的日本、韩国和萨哈林岛。繁殖时，偏好在沿海岛屿和悬崖上筑巢。","appearance":"角嘴海雀是一种中等体型的海鸟，拥有厚实的橙棕色喙，繁殖季节时，喙基部上方会突出一个类似独角的结构。成鸟的上体呈深灰色，下体颜色较浅，腹部偏白。面部有两束白色的羽毛，分别位于眼睛上方和喙根部。雄鸟的面部羽毛比雌鸟略长。非繁殖期的成鸟和幼鸟喙色较暗，缺乏‘独角’，白色面部羽毛减少或消失。幼鸟的喙较小且颜色更暗。","call":"角嘴海雀的鸣叫声未详述。","habits":"角嘴海雀栖息于北太平洋沿岸海域，通常在近岸水域觅食，偶尔出现在河口和泻湖。它们以小鱼为主食，也捕食磷虾和鱿鱼，能潜水至57米深，持续时间可达148秒。在繁殖季节，它们形成密集的群体，在夜间活动以避免天敌的捕食。","breeding":"繁殖发生在早夏，大约5月至6月间。角嘴海雀在土中挖掘洞穴或利用天然洞穴筑巢，巢深1至5米。雌雄共同孵化单枚卵约30至35天。孵化出的雏鸟由父母每晚喂食满载鱼类的食物，持续35至45天。成鸟在繁殖季结束后单独迁徙，但在非繁殖季同步进行觅食活动。","identification":"角嘴海雀的‘独角’是其显著特征，用于区分于其他海鸟，尤其是与之相近的海雀种类。繁殖季节的雄鸟和雌鸟都具有这一特征，但非繁殖季节的个体外观较为普通，可通过喙的大小和颜色辨别。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要分布在北太平洋温带海域，包括俄罗斯东南部的萨哈林库页岛、日本北海道和本州北部、美国阿拉斯加南部至加利福尼亚州南部。非繁殖期分布至日本南部、朝鲜半岛（西太平洋北部）和墨西哥下加利福尼亚州北部（东太平洋北部）。在中国，有记录显示它们出现在辽宁等地。","other":"角嘴海雀依赖物理特征选择终身伴侣，其‘独角’具有荧光特性，可能在繁殖中扮演角色。"},{"name":"北极海鹦","english_name":"Atlantic Puffin","scientific_name":"Fratercula arctica","overview":"北极海鹦（英文名：Atlantic Puffin，学名：Fratercula arctica），是鸻形目海雀科海鹦属的鸟类。身长26-29厘米，体重介于310-550克之间，以它那厚实的身材和多彩的喙著称。在繁殖季节时，喙部呈现出醒目的黑、橙、黄色，与橙色的腿和脚形成鲜明对比。北极海鹦聚集在远离陆地的岛屿上繁殖，产单枚卵于地面挖的洞穴或岩石缝隙中。尽管在陆地上和飞行时显得笨拙，但在捕食时，却是一位敏捷的潜水高手，主要以小型集群鱼类为食。北极海鹦寿命可达30岁以上，首次繁殖年龄在3至6岁之间。在非繁殖季节，会迁徙到远海，很少靠近陆地。","appearance":"北极海鹦拥有中等体型，体长约26-29厘米，翼展47-63厘米，体重在310-550克之间。雄鸟和雌鸟羽色相似，头部、颈部和上体为黑色，大部分脸部为灰白至灰白色，脸颊有窄黑带，眼下方有灰暗条纹。胸部、腹部和尾下覆羽为白色，下翼面为深色。喙大而三角形，繁殖季节时为红橙色，基部有淡黄色，边缘有至少一条沟槽平行于喙基形状。非繁殖季节时，喙失去彩色角质片，变得较小，形状不那么三角，颜色较暗。腿和脚为橙色至橙黄色，趾间有锐利的黑色爪。","call":"在繁殖季节，北极海鹦在地面和空中发出柔和的嗡嗡声和咕噜声。在非繁殖季节，它们在海上几乎无声。","habits":"北极海鹦主要栖息在北半球的亚北极地区，繁殖于温带海洋岛屿的悬崖和岩岸上。它们在非繁殖季节迁徙至开阔的北冰洋和北大西洋海域。北极海鹦是出色的潜水者，以小鱼、甲壳类和软体动物为食，通过潜水捕获猎物。它们在繁殖季节返回陆地，在草坡或岩石裂缝中挖掘巢穴。","breeding":"北极海鹦在繁殖季节返回特定的岛屿，挖掘巢穴进行繁殖。它们每年产一枚卵，由双方轮流孵化约40天。孵化后，雏鸟由父母共同喂养，以小鱼为主要食物。大约6周后，雏鸟会夜间离巢前往大海。","identification":"北极海鹦与太平洋的角海鹦在外观上有明显差异，角海鹦的喙图案和面部装饰不同。此外，与刀嘴海雀相比，北极海鹦的下翼为深色，头部形状不同，翅膀更加圆润。","protection":"IUCN：VU（易危）","distribution":"北极海鹦主要繁殖于俄罗斯、冰岛、爱尔兰、英国、挪威、格陵兰、纽芬兰和拉布拉多、新斯科舍省以及法罗群岛，南至美国缅因州和法国。在非繁殖季节，它们迁徙至北冰洋和北大西洋的开阔海域。","other":"北极海鹦是纽芬兰和拉布拉多省的省鸟。历史上，它们曾因蛋、羽毛和肉而遭受大量捕杀。目前，北极海鹦受到严格保护，以恢复种群数量。"},{"name":"角海鹦","english_name":"Horned Puffin","scientific_name":"Fratercula corniculata","overview":"角海鹦（英文名：Horned Puffin，学名：Fratercula corniculata），是鸻形目海雀科海鹦属的鸟类。重约581-648克，体长约32厘米，翼展18-20厘米。以其独特的‘角’状皮肤突起和厚实的黄色与红色相间的喙著称，分布于北太平洋亚北极水域，繁殖于加拿大、阿拉斯加的岩石岛屿或悬崖，冬季则迁徙至开阔海域。","appearance":"角海鹦拥有厚实的身体，黑色背部与白色腹部形成鲜明对比。繁殖期的成鸟有黑色‘角’状皮肤延伸自眼上方，脸部呈白色，喙部黄色基部和红色尖端，足部橙色。非繁殖期成鸟的脸部转为灰暗，喙部变为灰色与红色相间。幼鸟有较小的灰色喙，脸颊灰暗。成年角海鹦的喙在繁殖季时显著增大，带有艳丽色彩，非繁殖季则缩小，颜色暗淡。","call":"角海鹦发出低沉、音量较小的声音，通常被描述为咕咕声、吼声或哼哼声，加速时声音转为‘A-gaa-kah-kha-kha’。","habits":"角海鹦栖息于海洋，繁殖期间返回海岸岛屿或悬崖。它们偏好岩缝或岩石堆下的避风港作为巢穴，而非挖掘土穴。角海鹦擅长潜水捕鱼，以鱼类为主食，也食用小型无脊椎动物，如鱿鱼。它们成群活动，尤其在繁殖地附近与其他海鸟混群。","breeding":"角海鹦达到性成熟需5-7年。繁殖季节在5月至9月间，成对的角海鹦是单配制。雌雄共同选择岩缝作为巢址，雌鸟产下一枚卵，双亲轮流孵卵约41天，之后再共同养育幼鸟约40天。幼鸟独自离巢，夜间出走。","identification":"角海鹦与同属的其他种类如北极海鹦和簇羽海鹦的区别在于，后者巢穴挖掘于软土中，而角海鹦在岩缝中筑巢。与簇羽海鹦相比，角海鹦有白色胸部，而簇羽海鹦的胸部为深色。","protection":"IUCN：LC（无危）","distribution":"繁殖于西伯利亚东北部至阿拉斯加北部、西部、南部至不列颠哥伦比亚省的亚北极地区。非繁殖期广泛分布于北太平洋开放海域。","other":"角海鹦在繁殖后经历换羽过程，这通常发生在秋季和冬季。"},{"name":"簇羽海鹦","english_name":"Tufted Puffin","scientific_name":"Fratercula cirrhata","overview":"簇羽海鹦（英文名：Tufted Puffin，学名：Fratercula cirrhata），是鸻形目海雀科海鹦属的鸟类。亦称: “花魁鸟”，中等体型的海鸟，体长约为36-40厘米，翼展64-66厘米，体重介于520-1000克之间。其最显著的特征是金黄色的头凤羽，黑色的身体，白色的面部，以及色彩鲜艳的橙色喙和脚。分布于北太平洋沿岸，从阿拉斯加至加州，再到日本海域。","appearance":"簇羽海鹦拥有短粗的身材，大而圆的头部，金黄色的头凤羽在繁殖季节尤为明显。背部淡灰色，翅膀黑色，喙和脚呈现醒目的橙色。非繁殖季节，面部转为灰褐色，头凤羽消失，喙缩小且失去部分颜色。成年雄鸟略大于雌鸟。雏鸟相似于非繁殖期的成鸟，但有灰褐色胸部和白色腹部，喙为浅棕色。","habits":"簇羽海鹦偏好群居，常栖息于沿海岛屿和悬崖峭壁，选择靠近生产力高的水域。它们是高社交性的鸟类，形成大群，主要以各种鱼类和海洋无脊椎动物为食，如鲱鱼和沙丁鱼。在繁殖季节，它们会在陆地上挖洞筑巢，而在非繁殖季节则分散于北太平洋海域。","breeding":"繁殖于夏季，巢通常为简单的土穴，由喙和脚挖掘而成，或利用岩石间的裂缝。每窝仅产一枚蛋，由双亲共同孵化约45天。雏鸟在40-55天后离巢。","identification":"与角嘴海雀相比，簇羽海鹦体型更大，喙更厚实，腹部颜色更深。与角海鹦相比，簇羽海鹦体型更大，胸前无白色，且头部有金色头凤羽。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北太平洋沿岸，从西伯利亚东北部的楚科奇半岛，鄂霍茨克海，萨哈林岛，勘察加半岛，千岛群岛和命令岛（俄罗斯东部），北海道东北部（日本北部），白令海岛屿，阿留申群岛，阿拉斯加西部和南部至加利福尼亚中部。非繁殖期，它们广泛分布于北太平洋海域，南至日本和美国加利福尼亚州。"},{"name":"西藏毛腿沙鸡","english_name":"Tibetan Sandgrouse","scientific_name":"Syrrhaptes tibetanus","overview":"西藏毛腿沙鸡（英文名：Tibetan Sandgrouse，学名：Syrrhaptes tibetanus），是沙鸡目沙鸡科毛腿沙鸡属的鸟类。俗名: 沙鸡，大型沙鸡科鸟类，分布于塔吉克斯坦至西藏至中国中西部，栖息于海拔3500~5100米的荒漠、草原、半荒漠及高山草甸草原。其特征为细长针状尾，橙黄色面部，灰褐色胸部细条纹，白色腹部，黑色下翼。雄鸟翅膀无斑点，雌鸟上体及翼部有条纹。","appearance":"体长约30~41厘米，头部及颈部较小，体态紧凑结实。拥有长而尖的翅膀和尾羽。脸部橙黄，胸颈及头顶有精细条纹，腹部白色，下翼黑色。雄鸟翅膀无斑点，雌鸟翼部及上体有条纹，上腹亦有条纹，尾羽较短。幼鸟尾羽无针状，条纹更窄，脸部橙色较少。","call":"发出类似起重机或天鹅的叫声，具有音乐感。受惊时发出\"uvva, uvva, av-va\"或\"uak, uak\"的声音，雄鸟逃离地面危险时发出鼻音\"a....\"，飞行中重复此声。雌鸟在相似情况下发出嘶哑的\"ka-ka-ka-ka-ka-ka-ra\"声。雌鸟对幼鸟发出安静的\"seep seep\"声，被观察者在场时发出\"ku-ka-re-ku\"声。还有\"guk-guk\"、\"caga-caga\"和\"yak-yak-kaga\"的叫声，绒毛雏鸟发出类似新生小狗的\"peep\"叫声。","habits":"栖息于海拔较高的荒漠、草原及半荒漠地区，夏季多群居，冬季可达数百只的大群。飞行速度快，但飞行高度较低。主要以豆科植物的花、叶、嫩芽、种子及其它植物种子为食，偶尔食用鞘翅目的小型昆虫。","breeding":"繁殖季节从中4月至7月末，高峰期为5~6月。通常筑巢于石头或土堆间，有时以干草和羽毛作衬垫。每窝产卵3枚，偶尔2枚，卵呈陶土色，有深棕色或紫色斑点。孵化期20~24天，由双亲共同孵化。绒毛雏鸟颜色独特，雌鸟会进行断翅表演以吸引潜在捕食者的注意力。","identification":"与毛腿沙鸡相比，西藏毛腿沙鸡具有白色腹部和黑色下翼，雄鸟翅膀无斑点而雌鸟有。小脚无后趾，前三趾融合。","protection":"IUCN：LC（无危）","distribution":"分布于帕米尔山脉（从塔吉克斯坦东部）至西藏高原及中国中西部（青海、甘肃西部、四川西部）。在印度北部（喜马拉雅）、尼泊尔（上穆斯塘）也有记录。","other":"在前苏联地区数量显著下降，1970年代中期仅剩300只分布在五个亚种群。19世纪时较为常见和广泛分布，但由于狩猎和牲畜放牧增加，近年来数量可能进一步减少。"},{"name":"毛腿沙鸡","english_name":"Pallas's Sandgrouse","scientific_name":"Syrrhaptes paradoxus","overview":"毛腿沙鸡（英文名：Pallas's Sandgrouse，学名：Syrrhaptes paradoxus），是沙鸡目沙鸡科毛腿沙鸡属的鸟类。别名: 沙鸡、突厥雀、寇雉、鸠。栖息于干燥的平原和草原，分布于中亚的广阔区域，从哈萨克斯坦西部至中国东北部、中东部。毛腿沙鸡整体沙褐色，雄鸟具橙灰脸部和粉色翅膀、背部，雌鸟则更偏褐色，颈部和枕部有深色斑纹。","appearance":"毛腿沙鸡体长27-41厘米，体重雄鸟约250-300克，雌鸟约200-260克，翼展60-78厘米。它们拥有长而尖锐的尾羽，外侧初级飞羽特别长且尖细，尤其是雄鸟。前趾被覆羽毛，后趾缺失。腹部有一块鲜明的黑色斑块，与淡色下体形成强烈对比。雄鸟有模糊的胸带，雌鸟则有较窄的黑色喉下线。幼鸟与雌鸟相似，但没有延长的尾羽和飞羽，颈部和胸部有棕色斑点。","call":"飞行中最常见的叫声是一连串重复的、突然的、鼻音浓厚的‘chup’或‘pup’，以及快速连续的‘pududup’声，如同一群滨鸟的持续鼻音鸣叫。还有旋律般的‘ten-ten’、低沉的‘cu-ruu...cu-ruu…cu-ou-ruu’、气泡似的‘ker-ki’和‘puh-puh-purr’等多种叫声。","habits":"毛腿沙鸡栖息于有低矮稀疏植被的草原和半沙漠地带，包括草本植物或灌木丛，如艾蒿和戈壁植物。它们偏好黏土质地而非沙质或石质土壤，避免流沙和无水的广袤地带。毛腿沙鸡可在海拔高达3250米的地方发现。它们以多种植物的种子和嫩芽为食，包括豆科、藜科、十字花科和禾本科植物，有时也会食用农田中的谷物。","breeding":"繁殖季节从4月中旬持续到6月。它们在地面筑巢，有时藏匿于灌木或草丛中，巢间距仅4-6米。每窝通常产三枚蛋，孵化期约为23-26天。雏鸟出生时覆盖着带有黑色斑点的浅黄色绒毛。","identification":"毛腿沙鸡与相关物种西藏沙鸡的区别在于其黑色腹部和淡色下翼。雄性毛腿沙鸡的灰头、橙脸和灰胸带使其易于识别，而雌鸟则因缺乏胸带且上体条纹更多而与雄鸟有所区别。","protection":"IUCN：LC（无危）","distribution":"毛腿沙鸡主要分布于中亚，北纬40°至50°之间，自哈萨克斯坦（乌拉尔山南端）和乌兹别克斯坦北部向东延伸至西伯利亚南部和蒙古，直至中国北部（甘肃）、西北及中国西部（新疆；昆仑山和柴达木盆地，在青海）。在中国南方的广西南宁地区亦有冬季记录。","other":"毛腿沙鸡有时会从常规分布区迁移到欧洲，最远可达英国和爱尔兰，原因尚不完全清楚，可能与食物供应、雪覆盖或干旱有关。"},{"name":"白腹沙鸡","english_name":"Pin-tailed Sandgrouse","scientific_name":"Pterocles alchata","overview":"白腹沙鸡（英文名：Pin-tailed Sandgrouse，学名：Pterocles alchata），是沙鸡目沙鸡科沙鸡属的鸟类。中型沙鸡科鸟类，分布于欧亚西南部和非洲北部。其特征是腹部和下翼呈白色，胸带呈黄褐色，周围有黑色边框，头部和上半身则为橄榄绿色调。雄鸟在繁殖季节喉部有一块黑色斑点，雌鸟则有白色的喉咙和额外的黑色颈线。","appearance":"体长31至39厘米，体重雄鸟约250至408克，雌鸟约207至370克。翅膀跨度54至65厘米，尾部中央羽毛长而突出，下翼和腹部白色，胸部有宽阔的栗色带，边缘黑色。喙灰蓝角质色，眼环蓝色。雌鸟较暗淡，颈部有额外的黑线，背部金色、蓝灰色和黑色条纹相间。与黑腹沙鸡共栖时，可通过体型较小、尾巴更长且尖锐、腹部白色等特征区分。","call":"发出相对响亮的'catar-catar'声，在飞行中也可听到鼻音的'ga-ga-ga'和更为低沉的'gang gang'声。","habits":"栖息于干旱平原，从半沙漠到干涸的河流和湖泊床，偏好黏土或沙质而非岩石或石质基底。避免密集灌木丛和高海拔地区，通常在1000米以下高度。每天早晨访问水源，通常成大群。在西班牙，选择合理的休耕土地和茬地，与小鸨一起利用茬地，依赖后者较高的警觉技能。","breeding":"单配偶制，但长期配偶忠诚度未确定。繁殖期为4月至8月，主要在5月至6月。筑巢于地面的轻微凹陷处，直径113至125毫米，深70毫米，通常不铺垫，偶尔装饰以小石子、羽毛或粪便。每窝产卵2至4枚，平均2.75枚，孵化期19至25天，双亲轮流孵化，雄鸟提供水分给雏鸟。","identification":"与黑腹沙鸡区分明显，体型较小，尾巴更长且尖锐，腹部白色。雌雄差异在于雌鸟颜色更暗淡，有额外的黑色颈线。","protection":"IUCN：LC（无危）。欧洲种群处于濒危状态，特别是在农业变化导致的西班牙数量锐减。法国La Crau是唯一现存地点，约有165至175对。葡萄牙和以色列数量显著下降。","distribution":"繁殖区域在欧亚西南部和北非，冬季迁徙至巴基斯坦、东北伊朗、叙利亚、阿拉伯半岛北部等地。","other":"在东南土耳其的范围可能正在扩大，但欧洲部分地区的数量因农业生产变化而减少。"},{"name":"南非沙鸡","english_name":"Namaqua Sandgrouse","scientific_name":"Pterocles namaqua","overview":"南非沙鸡（英文名：Namaqua Sandgrouse，学名：Pterocles namaqua），是沙鸡目沙鸡科沙鸡属的鸟类，又称沙漠鸽。其最显著的外部特征是拥有长而尖锐的尾巴和翅膀，以及独特的黑白胸带。广泛分布于南部非洲的沙漠、半沙漠及干旱草原地带。","appearance":"体型略小，长度约28厘米，重量介于150至190克之间。雄鸟胸部有黑白相间的带状羽毛，腹部棕色渐变至尾部，头部呈淡黄褐色，无明显斑纹。雌鸟羽毛上布满黑色、棕色和白色斑点。喙灰色，眼圈黄色。幼鸟外观与成年鸟相似，但色彩更为隐蔽。","call":"发出远传的颤抖而悦耳的‘Kelkiw-wyn’叫声。","habits":"栖息于沙漠边缘、半沙漠及干旱草原，偏好平坦或起伏的地带，覆盖着稀疏的草丛和分散的灌木及多肉植物。以草籽为主食，偶尔摄入昆虫碎片和软体动物。清晨或黄昏时分可见其饮水。迁徙模式多样，南部种群迁往北开普、博茨瓦纳和纳米比亚。","breeding":"繁殖期延长，受降雨影响，南非洲多数月份均可繁殖，高峰期在较凉爽的8月至11月。筑巢于裸露土壤或石缝中，有时形成小型松散的群落。通常产三枚蛋，孵化期约21天，雄鸟夜间孵卵，孵化率约为68%，每对亲鸟平均抚养1.3只雏鸟。","identification":"与二斑沙鸡和杂色沙鸡同域分布，可通过羽毛颜色和图案加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于西南安哥拉、纳米比亚东部至西南津巴布韦，向南穿过博茨瓦纳和西及中央南非（西林波波省和自由州南至西开普省南部）。","other":"历史上曾在奥兰治自由邦和莱索托存在，现已消失；近年来在德兰士瓦的分布变得不稳定且不可预测。"},{"name":"栗腹沙鸡","english_name":"Chestnut-bellied Sandgrouse","scientific_name":"Pterocles exustus","overview":"栗腹沙鸡（英文名：Chestnut-bellied Sandgrouse，学名：Pterocles exustus），是沙鸡目沙鸡科沙鸡属的鸟类。体型丰满，鸽子般，拥有尖锐的尾巴。雄鸟呈沙棕色，胸部有一细黑带，腹部栗色；雌鸟背部具黑色条纹，颈部斑驳。广泛分布于亚洲和非洲，甚至被引入夏威夷西北部岛屿。","appearance":"体型介于31至33厘米，雄鸟体重约170至290克，雌鸟约140至240克，翼展48至51厘米。中央尾羽延长，下翼暗色，腹部黑色，头部无斑点。雄鸟具有狭窄的胸带，栗褐色腹部逐渐变深至后部；喙为蓝灰色，端部较暗；眼圈淡绿色。雌鸟上部斑驳更多，显示三色腹部图案。幼鸟尾部较短，上体条纹更密，下体颜色对比减弱。各亚种主要在上体色彩上有差异。","call":"飞行时发出节奏感强烈的三音节叫声：“whit!-kt-arrr”，第一个音节为急促的过滑哨音，后两个音节更低沉，似鹅叫声，粗犷。群飞时，鸟儿同时鸣叫，形成持续的鼻音鸭鸣般的争吵声。","habits":"常栖息于半沙漠地带，有散生荆棘灌木或树木的地方，如巴基斯坦和印度西北部的金合欢、刺槐和胡椒树。活动于平原或丘陵地形，海拔可达1500米。夏季干旱时，会向有水源的地方迁移。以种子为主食，偏好豆科植物，如印红树和苦豆树，也吃农田残留谷物。清晨和傍晚较凉爽时段觅食，日出后2至3小时饮水，极热天气下部分个体日落前再次饮水。","breeding":"繁殖期受当地降雨影响而变化，南印度为1月至4月，北印度为3月至5月（记录到7月初的雏鸟），阿拉伯、苏丹、埃塞俄比亚和索马里为4月至6月，肯尼亚为2月至11月，北坦桑尼亚为5月至11月，马里和塞内加尔为3月至7月。筑巢简单，地面浅坑，少或无衬垫。通常产3枚卵；孵化期22至23天，雄鸟夜间孵卵；雏鸟有金色绒毛，饰有黑白标记。","identification":"雄鸟与雌鸟的羽毛颜色有明显差异，尤其是腹部的色彩；亚种之间在上体色彩上有区别，如尼罗河谷的花栗腹沙鸡（P. e. floweri）上体颜色较暗且灰，与指名亚种为栗腹沙鸡（P. e. exustus）的差异明显。","protection":"IUCN：LC（无危）","distribution":"分布于北部和中部非洲、西部至南部亚洲，包括非洲西部至印度，以及欧亚大陆的部分地区。","other":"在某些地区，如塞内加尔北部、马里东北部、乍得中部、苏丹北部、埃塞俄比亚低地、索马里和巴基斯坦，栗腹沙鸡数量非常丰富，有时数千只聚集在水源处。"},{"name":"斑沙鸡","english_name":"Spotted Sandgrouse","scientific_name":"Pterocles senegallus","overview":"斑沙鸡（英文名：Spotted Sandgrouse，学名：Pterocles senegallus），是沙鸡目沙鸡科沙鸡属的鸟类。广泛分布于北非和东非的干旱地带以及中东至亚洲部分地区，最远可达印度西北部。是群居的日行性鸟类，以小而硬的种子为主食，每天早晨聚集到水坑饮水。","appearance":"斑沙鸡长约33厘米。雄鸟具有红棕色颈背，周围环绕着浅灰色带，延伸至喙和颈部形成领状。下巴、颈部和喉部橙色，胸部灰色。上半身呈粉灰褐色，翅膀深色，翼下有明显的两色对比。雌鸟喉部也呈橙色，但整体羽毛较雄鸟暗淡，体色为灰棕色，布满小而暗的斑点。幼鸟尾羽短，喉部白色，上半身有条纹和斑点。","call":"飞行时发出响亮的双音节叫声“whik!-kaaw”，第一个音节过滑，第二个音节下滑，常连续重复2-3次。在群体中，鸟儿同时呼叫，产生持续的、鼻音的、紧张的吠声。","habits":"斑沙鸡栖息于沙漠和半干旱乡村，偏好稀疏植被的半沙漠和沙漠环境，需附近有饮用水源。它们通常避开浓密的灌木丛、树木和耕地，占据石质和沙质地带。白天群居，晚上则飞往远离植被的岩石沙漠。","breeding":"繁殖期为3月至7月。巢穴是在地面上的凹痕或自然洼地中，通常选择石头附近的松软岩石。每窝通常产3枚蛋，孵化期29-31天，雄鸟夜间孵卵。刚孵化的雏鸟淡灰色棕色，几乎无斑点。一般一次最多抚养2只幼鸟。","identification":"与花头沙鸡相比，斑沙鸡具有尾丝和不同的面部图案，且缺乏胸带。雄鸟的银灰色眉毛、橙色脸颊和喉咙是其显著特征。雌鸟具有较淡的雄鸟模式版本，以及斑点颈背和胸部。","protection":"IUCN：LC（无危）。斑沙鸡在大部分分布范围内广泛且常见，但摩洛哥分布零散，阿拉伯半岛罕见。","distribution":"分布于北非至印度西北部，包括摩洛哥、阿尔及利亚、突尼斯、利比亚、苏丹、埃及、厄立特里亚、索马里、埃塞俄比亚、吉布提、马里、毛里塔尼亚、乍得和尼日尔。中东地区包括阿曼、沙特阿拉伯、以色列、约旦、叙利亚、伊朗、伊拉克和阿富汗。","other":"斑沙鸡能够在高温环境中通过增加隔热能力以及口咽颤动和张嘴呼吸来调节体温。"},{"name":"黑腹沙鸡","english_name":"Black-bellied Sandgrouse","scientific_name":"Pterocles orientalis","overview":"黑腹沙鸡（英文名：Black-bellied Sandgrouse，学名：Pterocles orientalis），是沙鸡目沙鸡科沙鸡属的鸟类。中型沙鸡科鸟类，具有独特的黑色腹部和楔形短尾。雄鸟头部和颈部呈灰色，喉咙橙色，雌鸟全身密布斑点，两性均具有明显的白色翼下覆羽与黑色翼尖，形成鲜明对比。常见于沙漠和半沙漠地带的低植被区，特别是在早晨访问水源时。分布于欧亚西南部和北非。","appearance":"黑腹沙鸡体型饱满，长度33-39厘米，体重300-615克，翼展70-73厘米。雄鸟头部和颈部灰，喉咙橙色，雌鸟上体褐色，具细密斑点。两性均具黑色腹部，白色翼下覆羽，翼尖黑色，胸带宽且以黑色条纹镶边。喙色从灰色到角质黑色，眼环白色。雌鸟较暗淡，斑纹更多。幼鸟似成鸟，但颜色更淡。亚种arenarius色彩较淡。","call":"其叫声独特，飞行时发出远传的液体般的颤音，逐渐放慢至结尾，如同\"chorrrrerereh\"。其他叫声包括低沉的滑音\"wheeuw\"和双音节的泡泡声\"pup-wuw\"。","habits":"栖息于半干旱平原，包括草原至半沙漠植被，如牧场灌木丛和干燥谷物种植区的休耕地。偏好较凉爽和湿润的环境，不同于共域的其他Pterocles物种。在巴基斯坦和印度的冬季栖息地为半沙漠的沙质平原，有时为盐碱化荒地和灌溉沙漠耕作周围的休耕地。","breeding":"繁殖期为3月至8月，随纬度变化。巢筑于地面凹坑或自然凹陷，一般不铺垫。通常产3枚蛋，平均孵化期21-24天，由雄鸟在黄昏至次日清晨承担孵化。雏鸟具有赭色绒毛，带有黑白标记，约一个月后能飞行，此时体型约为成鸟的3/4，完全成熟需约两个月。一般无第二窝现象。","identification":"与同属其他物种的区别在于其黑色腹部和翼下白色的覆羽，以及飞行时的黑色翼尖，易于识别。雌雄差异主要体现在色彩上，雄鸟喉部橙色，雌鸟上体更暗且斑点更多。","protection":"IUCN：LC（无危）。在中国，《中国濒危动物红皮书•鸟类》中列为未定种。数量相当稀少。","distribution":"繁殖区域包括伊比利亚半岛、西北非、土耳其、伊朗、塞浦路斯、以色列和加那利群岛。东部亚种arenarius见于哈萨克斯坦、中国西部和巴基斯坦北部。部分迁徙，亚洲中部鸟类迁往巴基斯坦和印度北部越冬。","other":"在文学作品中，如Chagatai语言的Baburnama中，Mughal皇帝Babur称其为qīl-qūyirūgh \"马尾\"，描述其为Transoxiana的bāghrī qarā。"},{"name":"黄喉沙鸡","english_name":"Yellow-throated Sandgrouse","scientific_name":"Pterocles gutturalis","appearance":"黄喉沙鸡长约30厘米，雄鸟体重约340-345克，雌鸟约285-400克。具有短而楔形的尾巴，雄鸟的头部图案明显，眉纹、脸颊、下巴和喉咙呈淡黄色，眼纹和半颈圈黑色；下体深色，包括栗色腹部和黑色翅膀下部；眼环灰色，喙蓝灰色。雌鸟的脸纹棕色，黄色喉咙无黑边，下体有条纹。幼鸟与成年雌鸟相似，但上体斑点较小，条纹较窄。黄喉沙鸡亚种羽色更鲜艳，上翼覆羽边缘更加肉桂色。","call":"飞行时发出独特的嘶哑鼻音节奏叫声，如'ki-kwoak...kok-korr-rorr'，有时缩短为'kwoak...kok-korrrr'，叫声频率比同类慢，因此群体不会持续发出紧张的叽叽喳喳声。","habits":"偏好短草覆盖的开阔平原，常靠近河流或沼泽地带，也可见于耕作土地和休耕地。在肯尼亚，避开干旱地区，栖息于800-2000米高海拔地区。主要以种子为食，包括豆科、禾本科和其他植物的种子，也吃谷物。饮水时间集中在早晨7:00-10:00。","breeding":"主要在旱季筑巢，时间为4月至9月，但具体时间因分布广泛而异。巢为地面凹坑或自然洞穴，有时位于蹄印中，常被草丛或麦茬部分遮掩。通常产卵3枚，有时2枚；孵化期约25天；绒毛雏鸟身上有赤褐色、黑色和白色大胆的花纹；幼鸟在体型约为成鸟一半时就能飞行。","identification":"与非洲其他沙鸡相比，黄喉沙鸡体型较大，雄鸟具黑边黄色喉咙，雌鸟下体有条纹。黄喉沙鸡亚种羽色更鲜艳，上翼覆羽边缘更肉桂色。","protection":"IUCN：LC（无危）","distribution":"分布在安哥拉、博茨瓦纳、厄立特里亚、埃塞俄比亚、肯尼亚、纳米比亚、南非、坦桑尼亚、赞比亚和津巴布韦。在东非至中南非洲的广阔范围内频繁出现，有时形成大群。在南非红皮书中的状态不确定。","other":"黄喉沙鸡在南非的Transvaal地区据说数量有所下降，可能并非每年都有记录。已有人工繁殖成功的报道。"},{"name":"花头沙鸡","english_name":"Crowned Sandgrouse","scientific_name":"Pterocles coronatus","overview":"花头沙鸡（英文名：Crowned Sandgrouse，学名：Pterocles coronatus），是沙鸡目沙鸡科沙鸡属的鸟类。体型中等，比斑沙鸡小，主要分布于北非和中东的沙漠地带，偏好石质而非沙质的沙漠环境。","appearance":"花头沙鸡身长27-30厘米，翼展52-63厘米。雄鸟具有独特的黑色额头和下巴，而雌鸟和幼鸟则缺乏这一特征。雌雄鸟均有橙色喉咙，头部和颈背呈灰色。飞行时，可以看到翅膀下部鲜明的双色调图案。雌鸟全身布满密集的条纹或斑点，雄鸟的上部羽毛略显褐色，密布暗灰色斑点。幼鸟与成年雌鸟相似，但条纹更粗，羽色偏红褐色。","call":"发出柔和的‘kla kla kla’声或断续但传播远的‘cha-chagarra’声，遇警报时会重复2-3次软弱的双音节‘hu hu’声，以及下降的‘wheek’声。","habits":"栖息于沙漠和半沙漠地带，包括最热最干燥的区域，偏好石质而非沙质的基底。它们在早晨约8:30至10:30喝水，夏季则提前到约7:00至9:00。以种子为主食，也会食用草本植物的嫩枝。通常与斑沙鸡和黑腹沙鸡一同出现在水源。","breeding":"繁殖季节主要在4月至7月，一夫一妻制。筑巢于石头间或沙地上，通常不铺垫巢材，但可能围绕巢边放置一圈小石子。每窝产卵2-3枚，蛋壳颜色为奶油色至淡黄色，带有淡棕色和淡紫色斑点。孵化期未知，但已知雄鸟会在夜间孵卵，雏鸟出生后由雄鸟早晚喂水。","identification":"与斑沙鸡相比，花头沙鸡的尾巴较短，雌鸟腹部没有深色羽毛。雄性花头沙鸡的头部有醒目的红色或紫红色斑块和黑色面具，而雌鸟则有黄色的脸颊和喉咙，羽毛上有密集的条纹或斑点。","protection":"IUCN：LC（无危）","distribution":"分布于北非至巴基斯坦，具体包括非洲西部至巴基斯坦，以及阿拉伯半岛的部分国家。"},{"name":"黑脸沙鸡","english_name":"Black-faced Sandgrouse","scientific_name":"Pterocles decoratus","overview":"黑脸沙鸡（英文名：Black-faced Sandgrouse，学名：Pterocles decoratus），是沙鸡目沙鸡科沙鸡属的鸟类。小型沙鸡科鸟类，以雄鸟的独特黑色面纹和喉部标记著称。雌雄外观有所差异，雌鸟较为朴素。广泛分布于非洲东部干燥的灌木丛和半沙漠地带。","appearance":"成年黑脸沙鸡长约28厘米，体重约140至210克。雄鸟具有明显的黑色面部标记延伸至喉咙，对比鲜明的腹部，黑色肚皮和宽阔的白色胸部带纹。雌鸟颜色较为单一，腹部具条纹。雄鸟上胸为棕色，边缘有细窄的黑色带纹；雌鸟胸部有条纹。眼环黄色，雄鸟的喙为鲜艳的黄色，雌鸟则为灰色。幼鸟与成年雌鸟相似，但背部条纹更深。","call":"飞行中的叫声为类似鸽子的、节奏感强的三音节短语，\"what-wa-wha\"。还有高音调的、略带滑音的纯哨声\"wheeeuw\"，在起飞和飞行中发出。群居时，鸟儿同时鸣叫，形成持续的叽叽喳喳声。其他叫声包括三音节的\"chuker-chuker-chuker\"和低沉的\"quick-quick-quick…\"","habits":"栖息于干燥的灌木丛和半沙漠地带，偶尔出现在密集的荆棘丛中的小开阔地带，如路缘。在肯尼亚，最高记录到海拔1600米。主要以种子为食，尤其偏爱豆科植物（如Indigofera和Trianthema）和博拉金科植物（Heliotropium）。早晨前半段时间饮水。","breeding":"在坦桑尼亚，繁殖期从5月至11/12月，可能在6月至8月旱季达到高峰。巢穴是在沙质或石质地面上的浅坑，通常产3枚蛋，有时产2枚。孵化期和离巢期未知。刚孵化的小鸟呈沙色或金色，混杂着灰色和斑驳的黑色。有迹象表明幼鸟会参与繁殖和双窝繁殖，但目前缺乏确凿证据。","identification":"雌性黑脸沙鸡与一些其他沙鸡种类相似，但结合其小巧体型和胸部的白色标记可以区分。雄鸟的黑色面部标记和对比鲜明的腹部是显著特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲东部，包括埃塞俄比亚、肯尼亚、索马里、坦桑尼亚和乌干达。在埃塞俄比亚常见，在索马里南部普遍且广泛分布，在肯尼亚局部地区常见。","other":"有三个亚种，具体繁殖模式受降雨影响，与半干旱热带环境下的雨季相关联，因此繁殖季节的确切时间和范围难以预测。"},{"name":"马岛沙鸡","english_name":"Madagascar Sandgrouse","scientific_name":"Pterocles personatus","overview":"马岛沙鸡（英文名：Madagascar Sandgrouse，学名：Pterocles personatus），是沙鸡目沙鸡科沙鸡属的鸟类。体型丰满，短腿，头部棕色，雄鸟面部环绕黑色区域，胸部呈粉红褐色，背部有淡棕色斑点，翅膀和腹部下部有深棕色条纹。雌鸟外观较暗淡，呈保护色，背部有深色斑点和条纹。在马达加斯加西部和南部广泛分布，常见于干燥开阔地带。","appearance":"雄性马岛沙鸡拥有棕色头部，黑色面部区域，粉红至棕红色胸部，淡棕色背部带有黑色斑点，翅膀和腹部下部有深棕色细条纹。雌鸟呈暗淡的棕色，背部有深色斑点和条纹，胸部粉红褐色，侧面有深色条纹，腹部更暗，呈棕红色。成年个体长约35厘米。幼鸟类似雌鸟，但色泽更暗淡，翅膀有非常浅的棕黄色条纹，上体和三级飞羽呈温暖的棕黄色和深棕色，胸部有深棕色斑点。","call":"发出快速、粗糙的‘catch-catcha-catcha’或‘ag-ag-ag-ag-ag-ag-ag’声，既在地面也在飞行中发出。叫声通常开始上升，变得更为有力，然后下降，每组音符持续约2秒，以2-3音符/秒的速率发出；许多鸟同时鸣叫。","habits":"栖息于低地至海拔1200米的草原和开阔的林地平原，偏好平坦、植被稀疏的地面，有时伴有岩石，包括干旱植物草原和稍退化的开阔刺林。主要在清晨饮水（07:00-08:30小时），但白天其他时间也会出现在水源（包括河流、池塘和湖泊），通常成群出现，2-6只或更罕见的20-40只，报告在喜爱的地点有300-400只的总数，特别是在旱季。饮食可能以种子为主，但也报道有昆虫。","breeding":"繁殖季节可能贯穿晚旱季和早雨季（8月至11月），再次在早旱季（4月至6月）。巢穴位于砾石、沙质或硬地上的凹坑中，通常添加一些植物纤维，通常在水平或略微倾斜的地面上，偶尔在相对密集植被中的灌木脚下或大型Tamarindus indica树下。巢穴通常是单独的，但不排除松散的群体。每窝产3枚绿褐色到褐色的蛋，上面细密地标有棕色和灰色。两性共同孵化。","identification":"与花头沙鸡和黑脸沙鸡相似，具有短的中央尾羽和雄鸟的黑色面罩，但下体有明显的分界：胸部呈纯红色或酒红色，腹部呈淡黄色，有黑色条纹。雌鸟上体黑色呈强烈而狭窄的条纹。","protection":"IUCN：LC（无危）","distribution":"在非洲的马达加斯加西部和南部广泛分布。"},{"name":"里氏沙鸡","english_name":"Lichtenstein's Sandgrouse","scientific_name":"Pterocles lichtensteinii","overview":"里氏沙鸡（英文名：Lichtenstein's Sandgrouse，学名：Pterocles lichtensteinii），是沙鸡目沙鸡科沙鸡属的鸟类。又名: 横斑沙鸡，们拥有美丽的黑色条纹装饰全身，雄鸟具有黑白相间的额纹和宽阔的沙黑横条胸带。栖息于非洲西北部至巴基斯坦的干旱荒漠地带，偏好岩石山地和金合欢灌木丛生的环境。","appearance":"里氏沙鸡体长约25厘米，体重雄鸟约175-250克，雌鸟约190-230克，翼展48-52厘米。雄鸟和雌鸟都具有密集的条纹，雄鸟的胸部带有条带，额头有黑白图案，雌鸟的颜色略暗淡，喉部有黄色斑点。幼鸟外观类似雌鸟，但更密集的条纹覆盖全身，到第一个冬季时接近成年个体的外观。","call":"在黄昏和清晨时分，会发出重复的、液状的‘wheet-wheet-wheet’或‘quitoo’叫声，音调比地理范围内其他沙鸡更低沉。访问水源时，会发出尖锐的‘squilp’声，受惊时则发出干涩的‘krre-krre-krre-krre’叫声。","habits":"栖息于干旱的半沙漠灌丛区，活动范围广泛，包括岩石山地、金合欢灌木丛等。它们主要是夜行性，酷热的午间会在阴凉处休息，黄昏后和黎明前会前往水源饮水。食物主要包括种子、金合欢属植物和其他灌木植物。","breeding":"繁殖季节从2月持续到9月，主要集中在5月至7月。巢穴通常是在地面的浅坑中，位于散落的树木或岩石之间，有时靠近住宅或与其他鸟群相邻。每窝产卵2-3枚，由雄鸟负责夜间孵化和照顾幼鸟。","identification":"与同属的其他沙鸡相比，里氏沙鸡的颈项和上胸部也具有细纹，雌鸟的喉部也有细纹。不同亚种在总体色调和下体条纹宽度上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西北部至巴基斯坦，具体包括肯尼亚、中东至阿富汗，非洲的阿尔及利亚、乍得、埃及等地，亚洲的伊朗、伊拉克、约旦等国家。","other":"里氏沙鸡在非常干燥的年份可能不会筑巢繁殖。"},{"name":"彩沙鸡","english_name":"Painted Sandgrouse","scientific_name":"Pterocles indicus","overview":"彩沙鸡（英文名：Painted Sandgrouse，学名：Pterocles indicus），是沙鸡目沙鸡科沙鸡属的鸟类。外观似鸽子与雉鸡的结合体。雄鸟呈温暖的沙棕色，饰以鲜明的棕、黑、白条纹；雌鸟全身密布复杂条纹。该物种主要分布于印度和巴基斯坦的内陆平原、高原等开阔地带。","appearance":"彩沙鸡体长约28厘米，体重约170至227克。雄鸟头部具黑白花纹，胸带内有一条栗色横杠；雌鸟胸部和颈部重叠密集条纹。喙橙褐色，眼周黄色环状。幼鸟外观类似雌鸟，但条纹更为密集。","call":"彩沙鸡在飞行时发出一连串急促的2至4个断续粗糙音节，重点落在最后一个音上，声音类似“dji-dji-chik！”或“wi-chik！”，间隔重复。","habits":"彩沙鸡栖息于稀疏灌木覆盖的裸露山脚和平原，偏好岩石地面和火烧迹地，避开沿海地带。黄昏后群集饮水，主要以种子、嫩枝和特定季节的白蚁为食。","breeding":"繁殖期可能集中在4月至6月，但全年除7月和9月外均有零星记录。筑巢于石缝或土堆中，通常由3枚蛋组成，孵化期估计为21至23天。绒羽雏鸟被描述为均匀的土棕色。","identification":"雄鸟翼覆羽上的特征设计，雌鸟背部标记更直而非新月形，腹部颜色更深，有助于与其他近似种类如四斑沙鸡和二斑沙鸡区分。","protection":"IUCN：LC（无危）；在印度部分地区较为常见，而在巴基斯坦则较罕见且分布局限，但在某些区域仍频繁出现。","distribution":"分布于印度东北部至北部哈里亚纳邦，从古吉拉特邦向东至西孟加拉邦和奥里萨邦，向南直至泰米尔纳德邦。在巴基斯坦开伯尔普赫图赫瓦省也有分布。","other":"彩沙鸡为留鸟，可能局部游荡，常在雨季结束时集中于某些区域。"},{"name":"四斑沙鸡","english_name":"Four-banded Sandgrouse","scientific_name":"Pterocles quadricinctus","overview":"四斑沙鸡（英文名：Four-banded Sandgrouse，学名：Pterocles quadricinctus），是沙鸡目沙鸡科沙鸡属的鸟类。中等体型以其独特的黑白环带标记著称。雄鸟头部顶冠和胸部具有醒目的黑白条纹，而雌鸟则较为朴素，缺乏这些特征性的环带。","appearance":"四斑沙鸡体长约25厘米，拥有圆形尾巴和精细的黑白前额图案，仅见于雄鸟个体。雄鸟的胸带复杂，包含栗色、奶油白色和黑色条纹；雌鸟虽有条纹，但更接近雄鸟的外观，而非其他近缘物种中的显著差异。喙和眼环黄色，幼鸟外观类似成年雌鸟。","call":"其鸣声为高音颤音，开始时伴有2到3个干涩的断奏音“pididit..twirrrrrree”或简化为“twirrrree”，主要频率范围在3至5千赫兹，通常在飞行中发出。","habits":"四斑沙鸡栖息于开阔或部分林木覆盖的干燥草原和灌木丛，也会出现在耕作区，偏好粘土或石质土壤，避开沙漠地带。它们是季节性迁徙的，西非的种群在雨季向北移动，如在乍得主要活动于6月至10月。夜间觅食，傍晚饮水，饮水时间从日落前约20分钟持续到日落后约50分钟，有时会在日出前再次饮水。","breeding":"繁殖期通常在旱季，从11月至次年6月，主要集中在3月。筑巢于地面，常位于苏丹的粉红色干枯Bauhinia树的叶子之间，或裸露的石质土壤、灌木下或灌木丛中。已知的巢穴中，有的含有3枚卵，有的含2枚卵。","identification":"雄性四斑沙鸡通过其复杂的胸带和翼覆羽的独特模式与非常相似的彩沙鸡相区分；雌鸟则通过缺乏强烈白色腹部标记与黑脸沙鸡雌鸟相区别。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔和冈比亚至厄立特里亚、埃塞俄比亚和肯尼亚西部，横跨非洲中部至乌干达，常见于西非地区。"},{"name":"二斑沙鸡","english_name":"Double-banded Sandgrouse","scientific_name":"Pterocles bicinctus","overview":"二斑沙鸡（英文名：Double-banded Sandgrouse，学名：Pterocles bicinctus），是沙鸡目沙鸡科沙鸡属的小型鸽类。其最显著的外部特征是雄鸟额头上的黑白相间条纹和黄色眼环。分布于非洲南部，偏好近岩石地带的烧过草地。","appearance":"雄鸟重约215-250克，雌鸟约210-280克，体长约25厘米。雄鸟具有一条明显的黑白胸带，背部羽毛宽白尖。雌鸟呈黑、棕、白斑驳状。幼鸟与雌鸟相似，但色彩较淡，羽毛边缘常带有淡色。","call":"叫声独特，似“oh NO, he’s gone and done it AGAIN!”，由一系列嘶哑、泡泡声组成。","habits":"偏好从半沙漠到密林的各种生境，尤其喜欢轻木灌丛草原和岩石地面。白天不活跃，黄昏时聚集在水坑边饮水、社交，夜晚觅食。以种子为主食。","breeding":"冬季干季繁殖，筑巢于地面，巢穴简单，通常藏于草丛或灌木下。每窝产卵2-3枚，平均2.6枚。雌雄轮流孵卵，孵化期23-24天。雏鸟出生即具绒毛，头部和背部有棕色斑点。","identification":"与四斑沙鸡和彩沙鸡相似，但雄鸟仅有一条黑白胸带，无栗色胸部，背羽宽白尖。","protection":"IUCN：LC（无危）","distribution":"分布于南部非洲，包括安哥拉、博茨瓦纳、马拉维、莫桑比克、纳米比亚、南非、赞比亚和津巴布韦。","other":"在博卡拉洛国家公园，主要出现在干燥季节，夏季湿季则离开。"},{"name":"杂色沙鸡","english_name":"Burchell's Sandgrouse","scientific_name":"Pterocles burchelli","overview":"杂色沙鸡（英文名：Burchell's Sandgrouse，学名：Pterocles burchelli），是沙鸡目沙鸡科沙鸡属的鸟类。以英国自然学家William John Burchell命名。这种鸟体型丰满，类似鸽子大小，头部较小，腿相对较长。主要分布在非洲南部的干旱和半干旱地带，包括安哥拉南部、纳米比亚、博茨瓦纳、津巴布韦和南非。","appearance":"成年杂色沙鸡体长约25厘米，体重在160至200克之间。全身呈现红褐色，带有白色斑点，翅膀下方为深赤褐色。雄鸟面部为灰色，眼周有黄色裸皮，雌鸟面部则为黄褐色。两性在外观上相似，但雌鸟的腹部颜色更淡，且脸颊、下巴和喉咙的颜色为黄褐色而非灰色。幼鸟外观与成鸟相似，但雄鸟的喉咙和眉纹为灰褐色。北方个体的颜色略浅。","call":"飞行时发出较为高亢、圆润的双音节‘chow-wheep’叫声，第二声上扬。此外，还发出单独的‘chow’音和起飞时尖锐的重复‘quip’声。相比同属其他物种，叫声较少。","habits":"栖息于开阔的、半干旱的短草平原和开放的金合欢灌木丛，偏好红色的卡拉哈里沙漠沙地。它们通常在清晨饮水，大约在日出后2至4小时。以种子为食，特别是卡拉哈里的Lophiocarpus burchelli（藜科）种子。","breeding":"繁殖期在4月至10月间的旱季，通常在地面上筑浅巢，位于短草或矮灌木丛中，周围遮蔽不多。每窝产卵3枚，罕见情况下产2枚。孵化和离巢时间未知，雏鸟在体型达到成鸟一半大小时即可飞行。","identification":"与其他沙鸡属物种相比，杂色沙鸡具有明显的白色斑点，深赤褐色的下翼，以及黄色的眼环。在性别辨识上，雄鸟的面部为灰色，雌鸟为黄褐色。","protection":"IUCN：LC（无危）","distribution":"分布于东南安哥拉、纳米比亚和博茨瓦纳，向东延伸至西南赞比亚、津巴布韦和南非北部，向南至北开普省和西奥兰治自由州。","other":"杂色沙鸡依赖水源，能适应极端高温，成鸟能携带水分回巢喂养幼鸟，雄鸟能携带平均22毫升水，雌鸟平均9毫升。"},{"name":"原鸽","english_name":"Rock Dove","scientific_name":"Columba livia","overview":"原鸽（英文名：Rock Dove，学名：Columba livia），是鸽形目鸠鸽科鸽属的鸟类。又名: 野鸽子、野鸽、脖鸽，直译:岩鸽鸽，原鸽的野生种群分布于欧洲西部至亚洲中部的悬崖和洞穴中，而驯化后的种群遍布全球的城市、农田和谷仓。野生原鸽与野化个体的羽色相对单一，多为淡灰色，带有明显的黑色翼带和颈部的紫色与绿色虹彩。野化和驯养个体羽色丰富多变，从黑色、白色到橙棕色都有。","appearance":"大型鸠鸽，总长度在30至36厘米之间，平均体重雄鸟为369克，雌鸟为340克。嘴暗灰色，翼下覆羽白色，尾部有蓝黑色亚端带，外侧尾羽近三分之二处白色，臀部灰或白色。翼通常带有两道深色横纹。基本颜色多为蓝灰色，最深在头部和臀部，最浅在翼覆羽；部分个体为蓝黑色或锈红色，少数几乎全白或斑驳。颈和上胸有紫色和绿色虹彩，每根羽毛双叉。虹膜颜色从金橙色到红橙色不等；眼周皮肤蓝灰色；喙黑色，蜡膜白色；腿红色或紫红色。雌鸟略显灰暗，颈部虹彩较少。幼鸟更为暗淡，眼睛和脚钝色；雄鸟颈两侧有虹彩，雌鸟则无。","call":"叫声柔和，略带波动的咕咕声。展示叫声被描述为‘whoo，hoo-witoo-hoo’，也有变化包括警报声、巢穴叫声和幼鸟噪音。","habits":"原鸽栖息于悬崖和岩石地带，巢建于岩隙中，通常形成数百只的大群体。它们偏爱开阔和半开阔环境，能在地面上觅食。原鸽的食物主要是植物性食物，包括各种植物的果实和种子。城市中的驯化和野化种群利用人类构筑物如高楼、桥墩和废弃建筑物作为巢穴。","breeding":"繁殖期全年均可，春季和夏季为高峰期。巢为简单的平台状，由稻草和小树枝搭建，位于遮蔽的崖壁或建筑物边缘。每窝产卵两枚，白色，孵化期约17至19天，由父母双方共同孵化。雏鸟出生后头几天由父母通过反刍喂食‘鸽乳’，直至约30天后离巢。","identification":"原鸽与家鸽（包括信鸽）的区别在于分布区域和羽色差异。除西北、内蒙古地区，原鸽极为罕见，个体间羽色差异小；而家鸽经人工繁育，品种多样，羽色变化大。","protection":"IUCN：LC（无危）","distribution":"原鸽的自然分布范围包括欧洲西部至亚洲中部，北非至印度。全球分布主要因人为引入，现在几乎遍及所有大陆，特别是在城市环境中。","other":"原鸽是最早被人类驯化的鸟类之一，是家鸽的祖先。"},{"name":"岩鸽","english_name":"Hill Pigeon","scientific_name":"Columba rupestris","overview":"岩鸽（英文名：Hill Pigeon，学名：Columba rupestris），是鸽形目鸠鸽科鸽属的鸟类。俗名: 野鸽子、横纹尾石鸽、山石鸽，特征为腹部及背色较浅，尾上有宽阔的偏白色次端带，与原鸽及家鸽有显著区别。分布广泛，自黑龙江至新疆、青海、四川、西藏、云南，栖息于山区多岩石和峭壁的地方。","appearance":"岩鸽体长31-35厘米，外观与原鸽相似，但头部颜色更浅，尾羽上具有独特的宽阔白色次端带，颈部虹彩较淡，胸部下方常带有酒红色调。幼鸟呈棕色，缺乏颈部虹彩，翅膀、颈部和胸部的许多羽毛边缘呈黄褐色。雌鸟虹彩不如雄鸟鲜艳。","call":"鸣声与原鸽类似，但发出迅速重复的、略显犹豫的咕噜声，音调较高，还有一系列快速、深沉的短音用于宣示领土。","habits":"岩鸽栖息于开阔崎岖的地带，围绕悬崖和峡谷生活，形成群体，夏季海拔高度可达2000-6100米，冬季会降至1500米左右。主要以杂食为主，食谱包括杂草种子、谷物、作物嫩芽、叶子和一些蜗牛。它们在小群中觅食，偶尔成百上千，常在靠近人类居住区的农田中觅食。","breeding":"繁殖季节通常在2月至9月，主要集中在4月至7月。岩鸽在悬崖、峡谷和岩石突出处构建由树枝和植物材料组成的巢平台。每窝产两枚白色卵，雌雄轮流孵化，孵化期约为18天，幼鸟出生后以父母口中的‘鸽乳’为食。","identification":"岩鸽与原鸽和家鸽的区别在于腹部和背色较浅，尾上有宽阔的偏白色次端带，与原鸽的灰暗尾部形成鲜明对比。家鸽因人工选育，羽色差异较大。","protection":"IUCN：LC（无危）","distribution":"岩鸽分布于欧亚中部和东部，包括中国、巴基斯坦、印度、尼泊尔、哈萨克斯坦、朝鲜半岛、蒙古、俄罗斯、塔吉克斯坦、阿富汗和土库曼斯坦。在中国，分布于东起黑龙江，西至新疆、青海、四川、西藏、云南等地。"},{"name":"雪鸽","english_name":"Snow Pigeon","scientific_name":"Columba leuconota","overview":"雪鸽（英文名：Snow Pigeon，学名：Columba leuconota），是鸽形目鸠鸽科鸽属的鸟类。分布于喜马拉雅山脉沿线至阿富汗以及中国西部地区，包括甘肃、青海、四川、云南和西藏。这种高海拔地区的居民常在岩石峭壁和雪线附近的陡峭峡谷中筑巢，形成群落。","appearance":"雪鸽长约31至34厘米，重约255至307克。头部呈深石板灰色，颈部、腹部、下背部和上臀部为白色，肩羽和较小的翼覆羽为淡灰褐色，翼部其余部分为浅石板灰色，翅膀上有三道黑色条纹，有时可见第四道条纹。初级飞羽和尖端黑色，下臀部、尾上覆羽和尾巴黑色，尾部有宽阔的白色新月形带。虹膜黄色或黄绿色，喙黑色，腿红色或粉红色。雌雄相似，幼鸟较暗淡，羽毛带有棕色，眼睛和腿颜色较深。","call":"声音知之甚少，最常见的是短促的‘kuk’或‘ki-kup’音符组成的系列，类似松鼠叫声。也有报道说它们会发出低沉、空洞且具有腹语效果的歌曲。","habits":"雪鸽主要栖息在海拔3000至5000米的高山悬岩地带，冬季会迁移到较低海拔的温暖地带，最低可达1500米，甚至低至750米。夏季成对或小群体活动，冬季则成群，最多可达150个个体，聚集在多岩石的山坡、草地斜坡、碎石区和融雪边缘。","breeding":"繁殖期通常在5月至7月，常在难以接近的悬崖缝隙或岩石平台上建造简陋的巢穴。每窝产卵2枚，孵化期为17至19天。","identification":"雪鸽与其它鸽子的区别在于其独特的头部颜色、白色的颈环和下体，以及翅膀上的宽大棕色条纹。与其他鸽子相比，它在高海拔地区活动。","protection":"IUCN：LC（无危）","distribution":"雪鸽主要分布在欧亚大陆中南部和东南部，包括阿富汗、中国西部省份如甘肃、青海、四川、云南和西藏。在中国大陆，它们出现在海拔2000至4000米的高山悬岩地带。","other":"雪鸽的食物主要包括草籽、野生豆科植物种子和浆果等植物性食物，也会食用青稞、油菜籽、豌豆等农作物。"},{"name":"斑鸽","english_name":"Speckled Pigeon","scientific_name":"Columba guinea","overview":"斑鸽（英文名：Speckled Pigeon，学名：Columba guinea），是鸽形目鸠鸽科鸽属的鸟类。广泛分布于非洲撒哈拉以南地区。常见于开阔地带，包括稀树草原、开放林地和花园，从海平面到海拔3000米均有其踪迹，唯独森林地带少见。斑鸽的显著特征是肩部有白色斑点，眼睛周围有大片红色裸露皮肤。","appearance":"斑鸽体长32至35厘米，体重219至390克。头部、胸部和腹部呈蓝灰色，臀部接近银色；披肩和翅膀覆羽为深红紫色；外侧翅膀覆羽蓝灰色，多数翅膀覆羽尖端带有白色三角斑点，形成密集斑点的闭合翅膀效果；初级飞羽和次级飞羽为深板岩色；尾巴黑色，中央有一条淡灰色带，最外侧尾羽边缘浅色；颈环由两叉状羽毛构成，基部栗色，尖端银绿色或银粉色。虹膜白黄色、黄色或金色，环绕橙色或紫色外环；脚和腿粉红色、鲑鱼色或红色；喙黑色，鼻孔白色。雌雄相似，幼鸟较暗淡，翼斑不明显，颈羽不具两叉状，脚和眼周皮肤灰白色。","call":"斑鸽有两种主要鸣声。展示叫声为重复的四音节喉音‘ru-rhrrr … rroOOooh-hu’。广告叫声为一系列快速连续的喉音，开始声音短促而低沉，逐渐变响亮和延长，突然终止，‘hu-hu-hu-hu-huu-huu-huu-huu-huu-huu’。","habits":"斑鸽适应多种开放环境，包括稀树草原、开放林地和花园，从海平面至海拔3000米。西部种群常与猴面包树和Borassus棕榈相关联；东部和南部种群尤其与岩石地形、悬崖和峡谷相连，进入农田和草地觅食。埃塞俄比亚种群在草地和林区丰富。部分斑鸽成为城市鸟类，在建筑物上密集栖息和筑巢。","breeding":"斑鸽全年繁殖，干季高峰在塞内加尔冈比亚。巢可简单为地面刮痕，或几根树枝，或由约5毫米厚、3至29厘米长的树枝构成的杂乱平台；位于悬崖、树木或建筑物上；在人烟稠密地区，常在高大树木、棕榈或其他树上筑巢。通常产卵2枚（1至3枚），南非研究中，2巢含1枚卵，266巢含2枚卵，1巢含3枚卵；孵化期因地理而异，开普省（南非）为14至16天，埃塞俄比亚为17至18天；雏鸟期20至25天；部分幼鸟20天大即可飞行。","identification":"与Rameron鸽相似，但主要不在森林中出现，翼斑更大，面部裸露皮肤红色而非黄色。","protection":"IUCN：LC（无危）","distribution":"非洲：广泛分布于撒哈拉以南地区，包括西部、东部和南部非洲，从海平面至海拔3000米的高度，避开茂密森林。","other":"斑鸽的食物主要是种子，通常在开阔田野中觅食，也会聚集在收获后的田地中食用玉米、小麦、高粱和其他栽培谷物；偶尔取食蜗牛。"},{"name":"白领鸽","english_name":"White-collared Pigeon","scientific_name":"Columba albitorques","overview":"白领鸽（英文名：White-collared Pigeon，学名：Columba albitorques），是鸽形目鸠鸽科鸽属的鸟类。以它后颈上醒目的纯白色‘白领’而得名。为非洲埃塞俄比亚和厄立特里亚高原所特有，常见于城镇中心及岩石峭壁周边的乡村地带。","appearance":"白领鸽体型长约32厘米，全身呈蓝灰色调，羽色和谐统一。其显著特征为后颈处有一圈明亮的白色环状羽毛，与头部的石板灰色形成鲜明对比。飞行时，可见翼部由白色初级飞羽覆羽构成的白色斑块，次级飞羽覆羽带有黑色棋盘状斑纹，尾羽黑色，中央有一条模糊的灰色带。虹膜红色或紫红色，喙黑或深灰色，脚红色或粉红色。雌雄外观相似，幼鸟的冠羽边缘较淡，‘白领’缺乏光泽。","call":"通常不太鸣叫，偶尔会发出低沉的咕咕声，其展示叫声被描述为‘hu...ho-ho’，仅在近距离时可听见。广告叫声则是一系列低沉柔和的咕咕音，起始为单音节，逐渐变为双音节。","habits":"白领鸽栖息于海拔1800米以上的林地、草地或农田，常靠近悬崖、沟壑、岩石露头或村庄，甚至已进入城市，如埃塞俄比亚首都亚的斯亚贝巴。它们主要生活在海拔2400米以上，觅食高度可达4400米。日间，它们会从低海拔的栖息地飞往高海拔觅食地，归巢时速可达120公里。饮食上，它们主要食用各种种子、谷物及新播种的小麦。","breeding":"全年均可繁殖，巢筑于悬崖洞穴、岩洞或建筑物中的隐蔽台地，每次产两枚乳白色的蛋。在圈养条件下，孵化期约为16天，雏鸟离巢时间在27至31天之间。","identification":"与家鸽（Rock Pigeon）相比，白领鸽可通过后颈的白色标记加以区分。","protection":"IUCN：LC（无危）。尽管分布范围有限，但在其范围内数量丰富，特别是在亚的斯亚贝巴常见。适应城市生活及占据高海拔生境的能力表明该物种相对安全。","distribution":"白领鸽分布于非洲的厄立特里亚山区和埃塞俄比亚，主要栖息于两地的高原地带。"},{"name":"欧鸽","english_name":"Stock Dove","scientific_name":"Columba oenas","overview":"欧鸽（英文名：Stock Dove，学名：Columba oenas），是鸽形目鸠鸽科鸽属的鸟类。广泛分布于欧洲、北至芬兰、斯堪的纳维亚半岛，南至非洲，东至小亚细亚、伊朗，以及中国的部分地区如新疆。这种中等体型的鸽子整体呈灰蓝色，胸部带有粉红色调，翅膀上有一条不明显的黑色横纹。在繁殖季节，偏好在空旷地带、农田、林缘地带和开阔的森林中筑巢，通常在老树洞、岩石缝隙、兔穴或建筑物中安家。","appearance":"欧鸽长约32至34厘米，体重雄鸟约303至365克，雌鸟约286至290克。全身呈现蓝灰色，翅膀的主羽和次羽有黑色尖端，飞行时十分显眼；翅膀折叠时有两条短黑条纹，第三条较短且淡，但在雄鸟中有时相当明显；胸部呈淡紫色；颈部两侧有绿色和淡紫色的虹彩斑块，某些个体的斑块会延伸到颈后；尾巴灰色，末端有黑色带，最外侧的尾羽边缘白色；眼睛深棕色；眼圈蓝灰色；喙基部粉色，尖端黄色，蜡膜白色；腿红色。雌鸟颜色较暗淡，腿和喙颜色更深。幼鸟更暗，胸部的淡紫色被锈褐色取代，腿色深。Yarkandensis亚种平均颜色更浅，翅膀稍长。","call":"欧鸽不是很爱鸣叫。在展示时，发出一系列快速的8至10个微弱、短促、单音节的咕咕声：\"coo..coo..coo..coo..coo\"。广告叫声是一系列拉长的双音节咕咕声，\"oooh-uh...oooh-uh...ooh-uh...\"，通常开始时声音微弱且速度略慢，然后突然结束。","habits":"欧鸽主要栖息在较为开放的乡村地带，常见于耕作区，延伸至开阔的森林，偏好森林与开阔地带交界处，那里有许多老树提供繁殖洞穴。欧洲种群居住在温带地区的中高纬度，同时也出现在北极和地中海区域，偶尔进入草原地带。主要生活在低地，海拔可达500米，有时甚至1000米以上；在摩洛哥的种群可以在海拔1000至2300米的松树林、橡树林和雪松林中找到。北部种群几乎都是候鸟，而南部种群逐渐减少迁徙，主要在伊比利亚半岛和法国南部以及整个北地中海盆地过冬。","breeding":"繁殖期主要在4月至10月。欧鸽倾向于在老树洞、岩缝、兔窝或建筑中筑巢。如果可用，会利用老黑啄木鸟留下的洞穴，尤其是活的山毛榉树洞，可能是因为光滑的树皮提供了对松貂的某种保护。它们也会轻易地接受巢箱，一些巢可能位于茂密植被丛中甚至灌木下。巢通常是一个树枝平台，有时直接在裸露的木头上产卵。通常产2枚白色蛋，有时仅1枚，也有发现3至6枚蛋的巢，但这被认为是两只雌鸟的贡献；孵化期16至18天；幼鸟在16至30天后离巢。","identification":"欧鸽与岩鸽和家鸽在大小和羽毛上有相似之处，但野岩鸽有白色臀部和两个明显的暗色翼条，而欧鸽的臀部是灰色，翼条不完整。家鸽高度变异，灰色标本缺乏白色臀部时可能与欧鸽非常相似。","protection":"IUCN：LC（无危）","distribution":"欧鸽的分布遍布欧洲西部和西南部，北至芬兰、斯堪的纳维亚半岛，南至非洲，东至小亚细亚、伊朗，以及中国的新疆等地。","other":"欧鸽的名字源于古英语“stocc”，意味着\"树桩、木桩、树干、木头\"，因此\"欧鸽\"意味着\"住在空心树中的鸽子\"。"},{"name":"中亚鸽","english_name":"Yellow-eyed Pigeon","scientific_name":"Columba eversmanni","overview":"中亚鸽（英文名：Yellow-eyed Pigeon，学名：Columba eversmanni），是鸽形目鸠鸽科鸽属的鸟类。中型鸽类，特征为亮黄色的眼环，体色以蓝灰色为主，头部和胸部带有淡紫色光泽。分布于中亚地区，包括哈萨克斯坦南部、乌兹别克斯坦、土库曼斯坦等地，以及阿富汗、伊朗东北部和中国西北部。近年来数量显著减少，主要原因是过度猎杀。","appearance":"中亚鸽体型中等，长度约30厘米，体重介于183至234克。全身呈现蓝灰色调，冠部和胸部有紫粉色光泽，翅膀下方和背部下半部为白色或浅灰色，尾部上方的覆羽为深灰色。虹膜黄色或黄棕色，眼周皮肤呈淡黄色或乳白色，喙基部褐色或深绿色，尖端黄色至黄绿色或绿色，腿肉色偏黄。雌鸟较雄鸟暗淡，腿部和喙部带有灰暗色调。幼鸟比成鸟更暗淡，头部和胸部呈锈色赤褐色。","call":"中亚鸽通常较为安静，但在繁殖季节会发出轻微的“oo-oo-oo”声，声音低沉而哀婉。","habits":"偏好干旱开阔地带和山间谷地，常靠近水源。在中亚地区繁殖，冬季部分群体南迁至南亚西部地区。栖息地包括农业区、果园和有零星树木的开阔乡村，尤其偏爱桑树生长的地区。","breeding":"繁殖期为4月至8月，筑巢于悬崖裂缝、枯老的杨树、榆树、梧桐树洞中，或是在果园和废弃建筑中。每窝产两枚白色卵，由双亲共同孵化。","identification":"与原鸽相比，翼条和尾部的条纹不明显；与岩鸽区别在于尾部上侧的亚端带为白色，而非黑色。中亚鸽的黄色眼环是显著辨识特征。","protection":"IUCN：VU（易危）","distribution":"繁殖于中亚，包括伊朗至中国西北部；冬季迁徙至印度西北部、巴基斯坦和伊朗。","other":"历史上曾大量存在的中亚鸽，因过度猎杀导致数量急剧下降。目前全球估计数量在15,000至30,000只之间，已被列为《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》，并在中国被列入国家二级保护动物。"},{"name":"索马里岩鸽","english_name":"Somali Pigeon","scientific_name":"Columba oliviae","overview":"索马里岩鸽（英文名：Somali Pigeon，学名：Columba oliviae），是鸽形目鸠鸽科鸽属的鸟类。特征为中等体型，羽毛呈淡灰色，头部带有薰衣草色的帽子，黄色的眼睛，颈后有青铜绿色光泽的项圈。主要分布于索马里东北部沿海地带，偏好干旱悬崖和丘陵环境。","appearance":"体长约28厘米，整体颜色为薰衣草灰色，背部和翅膀略带棕色，下背和臀部蓝灰色较深，初级飞羽尖端黑色，尾部黑色并有一条灰色中央带。头部前额、顶冠和颈后为薰衣草粉色，颈后方有一片铜棕色并带有绿色光泽的斑块。虹膜黄色，眼周皮肤红色或紫红色，喙黑色，蜡膜白色，腿脚粉红色。部分个体的翅膀上可能有黑色斑点，这是翼条斑的退化遗迹。性别相似，幼鸟特征未知。","call":"叫声描述为‘wuk-wuk-wuk-ooooh’，音符类似其他相关物种，但最后一音拉长。","habits":"栖息于岩石和砂岩山丘及悬崖，偏好植被稀少、几乎无水源的干旱区域，海拔可达750米（曾记录至1425米）。在炎热的五月至九月期间，会离开Guban的悬崖。主要在地面觅食，以种子、谷物和浆果为食。","breeding":"繁殖季节中，巢穴由干草制成，位于洞穴顶部的凹陷处，已知每巢含一枚蛋。","identification":"与更暗且斑点密集的斑鸽相比，索马里岩鸽较为明亮且斑点较少。与同域的其他珠颈鸽不同，缺乏后颈上的黑带。","protection":"IUCN：LC（无危）。需紧急研究，虽局部常见，但因其极小的分布范围，可能受到威胁。","distribution":"分布于索马里东北部沿海，特别是在干燥的海岸线附近的悬崖和丘陵。","other":"人类关系：索马里岩鸽的形象出现在国际不承认的东非共和国索马里兰官方货币一先令硬币的正面。"},{"name":"斑尾林鸽","english_name":"Common Wood Pigeon","scientific_name":"Columba palumbus","overview":"斑尾林鸽（英文名：Common Wood Pigeon，学名：Columba palumbus），是鸽形目鸠鸽科鸽属的大型鸟类，广泛分布于西部和西南部欧亚大陆，包括欧洲、北非和亚洲西部直至锡金山区。体长41-45厘米，重284-690克，通体呈蓝灰色，颈部有独特的白色斑块，翅膀上有明显的白色带纹，尾羽灰黑相间。常见于山地阔叶林、混交林和针叶林，也偶尔出现在森林平原地带。","appearance":"斑尾林鸽体型较大，长约41-45厘米，体重介于284-690克之间。全身色彩偏蓝灰色，翅膀较为暗淡，初级飞羽黑色边缘泛白；胸部呈现淡紫色至粉红色，腹部颜色较浅；两侧翼缘的羽毛形成一道白色条纹；颈侧有紫粉色与绿色光泽的羽毛环绕白色斑块；尾羽灰色，末端宽大的黑色带状。眼睛颜色从绿白色至浅金色不等；脚部呈红紫色。雌鸟的白色颈斑较小，胸部粉红色较淡。幼鸟色泽更淡，缺乏成鸟的白色和光泽。","call":"斑尾林鸽的叫声为一系列低沉、沙哑的咕噜声，常被描述为“hrrruu-hoo-who-who”。","habits":"斑尾林鸽栖息于多种环境，包括森林边缘、农田、公园和城镇花园。它们在冬季会形成大群，尤其偏好农作物区域觅食。繁殖季节，北方和东方的种群会迁徙，而西方和南方的种群则多为留鸟。在地中海国家有大量北方种群越冬。它们的饮食以植物为主，包括谷物、果实、种子和蔬菜，偶尔也食用昆虫。","breeding":"繁殖期一般从4月至7月，斑尾林鸽成对繁殖，巢建于僻静的森林树杈上，接近树干的分枝处，结构松散。每窝产卵2枚，孵化期约为17天，雏鸟在20至35天后离巢。","identification":"斑尾林鸽通过其较大的体型、独特的白色颈斑和翅膀上的白色条纹与其它鸽类区别开来。","protection":"IUCN：LC（无危）","distribution":"斑尾林鸽广泛分布于欧洲、北非和亚洲西部，包括但不限于英国、法国、西班牙、瑞典、芬兰、乌克兰等地。在中国，主要分布在西部和西南部地区。","other":"斑尾林鸽在某些地区被视为农业害鸟，因其大群损害作物，尤其是在油菜种植区。"},{"name":"长趾鸽","english_name":"Trocaz Pigeon","scientific_name":"Columba trocaz","appearance":"长趾鸽体长约38至40厘米，体重约500克。与近缘种斑尾林鸽相比，其色泽更深，呈暗石板色，颈部两侧的银灰色斑块在颈后相遇，喉咙和上颈为灰色，胸部较暗淡的粉红趋向橙色，白色翼斑缺失，虹膜为淡黄色，眼周皮肤红色，腿珊瑚红色。两性相似。幼鸟色彩更暗淡，缺乏金属光泽。","call":"发出一系列低沉、沙哑的咕咕声，声音微弱且音调低，具有节奏感，常表现为‘rhuu-urh-rhu-rhooh... rhuu-urh-rhu-rhooh...’的六音符组合，中间音节拉长。","habits":"长趾鸽栖息于马德拉岛的云雾缭绕的高山森林区，主要由月桂树和浓密的树状石楠构成。它们通常定居，但在秋季会从悬崖向低地迁移觅食。以果实为主食，也食用叶子和谷物，冬季和秋季主要吃果实，春季和夏季则更多依赖树叶。","breeding":"全年繁殖，高峰期在2月至6月。巢置于悬崖裂缝、洞穴或月桂树林中，偶尔在树状石楠中，巢由松散的树枝堆砌而成。每窝产一枚白色蛋，孵化期19至20天，幼鸟在28天左右离巢。","identification":"与Bolle's鸽相比，长趾鸽的颈部缺少白色斑块，胸部颜色更偏向粉红，且分布于马德拉岛而非加那利群岛。","protection":"IUCN：LC（无危）","distribution":"仅限于马德拉群岛的主岛，曾经在邻近的Porto Santo岛也有分布。","other":"过去数量曾大幅下降，现在在欧洲法律保护下数量趋于稳定。物种生存直接依赖于栖息地保护和严格控制猎杀，以及可能对黑鼠的管理。"},{"name":"波氏鸽","english_name":"Bolle's Pigeon","scientific_name":"Columba bollii","overview":"波氏鸽（英文名：Bolle's Pigeon，学名：Columba bollii），是鸽形目鸠鸽科鸽属的鸟类。大型暗灰色鸽子，体型略大于普通鸽子，长度约为36至38厘米。主要栖息在加那利群岛的山地月桂森林中，以德国自然学家卡尔·波勒的名字命名，他是第一个将其与桂冠鸽区分开来的科学家。波氏鸽是加那利群岛特有种，适应了当地独特的月桂森林环境。","appearance":"波氏鸽拥有深灰色的羽毛，胸部带有粉红色调。它的背部、臀部和翅膀呈棕色灰色，成年雄鸟的肩部有金属蓝色光泽。初级和次级飞羽为黑褐色，胸腹部蓝暗灰色，雄鸟染有紫色。雌鸟较不显眼，缺乏金属光泽和鲜艳色彩，颜色更偏灰暗。红嘴，眼睛橙黄色，虹膜边缘薄而肉色。幼鸟总体较暗淡，上体更多赤褐色，缺乏虹彩，翼覆羽有淡色边缘，下体更红棕色，喙黑色，腿脚棕红色。","call":"波氏鸽发出低沉而嘶哑的咕咕声，其声音独特，与桂冠鸽明显不同。","habits":"波氏鸽主要栖息在加那利群岛的山地月桂森林中，特别是在山谷地带，也可见于Myrica faya和Erica arborea的灌木丛，偶尔出现在较为开阔的地区，如农田和混交松林。它们在炎热的白天会躲进月桂树的深荫处。夏季，波氏鸽会飞往较低海拔地区寻找成熟的谷物和果实。","breeding":"繁殖季节从1月至9月，可能在2月至5月达到高峰。波氏鸽在一棵树上筑巢，通常选择最丰富的本地树木，如Erica arborea、Laurus azorica、Ilex canariensis和Myrica faya，高度在地面以上1.75至15米之间。巢由树枝构成，一般产一枚白色蛋。孵化期约18至19天，雏鸟在大约30至35天后离巢，但在离巢后一段时间内仍依赖父母。","identification":"波氏鸽与桂冠鸽的区别在于其暗灰色而非棕色的羽毛，以及灰色尾巴上的暗色带纹。波氏鸽的头部较大，颈部两侧有蓝绿色或绿色光泽，而桂冠鸽的颈部斑点更为明显。","protection":"IUCN：LC（无危）","distribution":"波氏鸽分布在加那利群岛的El Hierro、La Palma、La Gomera和Tenerife岛屿上，过去也在Gran Canaria岛上存在过，位于北非西北方向的Macaronesia中部。","other":"历史上，波氏鸽因森林砍伐和狩猎而数量锐减，但近年来随着森林砍伐速度放缓，其种群似乎有所恢复。"},{"name":"桂冠鸽","english_name":"Laurel Pigeon","scientific_name":"Columba junoniae","overview":"桂冠鸽（英文名：Laurel Pigeon，学名：Columba junoniae），是鸽形目鸠鸽科鸽属的鸟类。别称白尾桂冠鸽。最显著的外部特征是暗灰色头部，绿色至紫色的颈背，深酒红色的腹部，以及尾部带有明显的白色尖端。主要分布于加那利群岛的特定岛屿，如拉帕尔马岛、戈梅拉岛、特内里费岛和埃尔赫罗岛。该物种是岛上特有的珍稀品种。","appearance":"桂冠鸽长约37-38厘米，头部、面部和喉咙呈深灰色，带有一些绿色或淡紫色的光泽；头顶、颈背和颈部大部分覆盖着绿色光泽的羽毛，逐渐变为红紫色，上背部也是类似颜色；下胸部和下体呈葡萄酒红色；下背部和臀部为深蓝灰色，向上延伸至尾羽覆羽和中央尾羽，颜色变浅；外侧尾羽为深蓝灰色，横跨一条几乎看不见的白色尾端带，该带在尾部下方显得更加明显。眼睛橙色，眼睑红色；喙基部酒红色，尖端粉红或粉白；腿为红色。雌鸟颈部和胸部的红紫色略显苍白。幼鸟较为暗淡和棕色，翅膀覆羽边缘锈褐色。","call":"发出一系列低沉的咕咕声，有时会重复两次：“hoo-hoOOOOoooh-hoo-hoOOOOooh”。","habits":"栖息于加那利群岛的山地，通常在深谷、陡峭山坡和大悬崖的月桂森林中，海拔高度可达1600米。偏好成熟的月桂森林，但也出现在森林下限的灌木地带，以及上限的混合松树林中。偶尔会从高地森林迁移到低地农业区觅食。以果实、芽、一些谷物和花朵为主食，尤其偏爱奥科蒂亚臭椿和印度桂皮的果实。","breeding":"繁殖期记录在3月和5月至9月之间，可能全年都有繁殖行为。筑巢于岩石露台、树干下或石头旁的森林中，一窝产一枚乳白色的蛋，偶尔两枚。","identification":"与共存的波氏鸽相比，桂冠鸽的尾部有更明显的白色尖端，且叫声完全不同。此外，颈部有明显的绿色光泽斑块，下体为深酒红色，而波氏鸽的下体颜色较浅。","protection":"IUCN：NT（近危）","distribution":"分布于加那利群岛的四个岛屿：拉帕尔马岛、戈梅拉岛、特内里费岛和最近发现的埃尔赫罗岛。曾经在大加那利岛存在，现已灭绝。","other":"曾因过度狩猎和栖息地破坏而数量锐减，目前受非法狩猎的影响依然严重。过去五百年中，月桂森林遭受严重破坏，尤其是拉帕尔马岛。"},{"name":"鳞斑灰鸽","english_name":"Afep Pigeon","scientific_name":"Columba unicincta","overview":"鳞斑灰鸽（英文名：Afep Pigeon，学名：Columba unicincta），是鸽形目鸠鸽科鸽属的鸟类。此鸽体型较大，羽毛呈淡灰色，眼周有红色裸皮，胸部带有红褐色调，尾部有一明显的灰色带纹，飞行时尤为显眼。主要栖息于赤道非洲的雨林和林缘地带，分布于几内亚至加纳，尼日利亚东部至安哥拉，刚果民主共和国和乌干达。","appearance":"体长约35至36厘米，体重介于356至490克之间。头部和颈背为银灰色，上体和翅膀为石板灰色。背部和臀部的羽毛边缘呈银灰色，翼羽和次级飞羽的边缘较窄。尾部深石板色，中央有一宽大的灰白色横带，但在中央两根尾羽上不明显。喉咙和腹部为白色，胸部为葡萄酒粉红色。眼睛橙色或红色，眼圈暗红色，腿灰色，喙灰色，尖端淡灰色或白色。雌鸟胸部粉色较暗，常混有灰色。幼鸟的羽毛顶端有明显的浅黄色和栗色，以及暗色亚端带。","call":"鸣叫声为一系列低沉、拉长的咕咕声，通常由一个更响亮、回声效果的音符引出，之后是约7到14个平调的低沉咕咕声，如'grroorh..cooooh..cooooh..coooh..'。","habits":"栖息于森林，通常在树冠层，但也会沿森林边缘觅食。占据山地和河岸森林，以及有高大树木的峡谷。也会在远离水源的马尔基西亚灌丛中出现。在西北安哥拉，可见于咖啡林中。主要生活在低地，但在喀麦隆和乌干达可达海拔1600米。","breeding":"有限数据显示，繁殖季节可能在旱季的1月至9月。巢由树枝构成，位于高树上。产单枚白色蛋。关于繁殖的更多信息尚不可得。","identification":"与其他森林鸽的区别在于整体的淡色和显著的尾部带纹。","protection":"IUCN：LC（无危）","distribution":"分布于西非的几内亚至加纳，以及东南尼日利亚至安哥拉，刚果民主共和国和乌干达。"},{"name":"黄眼鸽","english_name":"African Olive Pigeon","scientific_name":"Columba arquatrix","overview":"黄眼鸽（英文名：African Olive Pigeon，学名：Columba arquatrix），是鸽形目鸠鸽科鸽属的鸟类。大型鸽子，广泛分布于东非和南部非洲，从埃塞俄比亚至南非，以及西部安哥拉、沙特阿拉伯西南部和北也门。常出现在海拔1400米以上的凉爽湿润森林中，有时低至700米。该鸽种在当地常见，但由于其特定的栖息地需求，分布区存在显著缺口。","appearance":"成年雄性黄眼鸽体型较大，长度约37至42厘米，体重介于300至450克之间。背部与翅膀呈酒红色，肩部点缀着大量白色斑点；下体同样为酒红色，伴有白色斑点；头部灰色，眼周环绕黄色斑块，喙亦为黄色。雌鸟相似但色彩略暗淡。幼鸟的酒红色和灰色被深棕色取代，裸露部位呈淡黄绿色，翼羽边缘带有浅色条纹。飞行迅速，翅膀拍打有力，展现典型的鸽子飞行特征。","call":"其鸣叫特征为低沉的咕咕声，通常由一长串滚动的起始音符接续四声颤音，例如：“rrrooooh.....c-c-c-croooh..c-c-c-croooh..c-c-c-croooh..c-c-c-croooh”。飞行中的叫声为鼻音“crreh”。","habits":"黄眼鸽偏好生活在海拔1400米以上的凉爽湿润森林冠层，但也适应山地灌木丛、次生林和开阔地带。它们会在农业区域觅食，只要不受到人类干扰。以橄榄状浆果为主食，同时摄取其他果实、种子、昆虫及其幼虫。食物主要从大树冠层获取，偶尔也会在地面觅食。","breeding":"繁殖活动全年皆有可能发生，尤其是在某些地区。成对占据0.8至3公顷的领地。巢由树枝搭建，内部铺有几片绿叶，位于地面1至14米高的灌木丛中。一般产一枚蛋，偶尔产两枚；孵化期约为20天；幼鸟离巢时间大约为19天。","identification":"与其它鸽种相比，黄眼鸽最显著的识别特征在于其明亮的黄色眼环、喙和腿，以及背部和翅膀上的酒红色羽毛与白色斑点的组合。雌雄之间颜色差异细微，雌鸟色彩略显暗淡。","protection":"IUCN：LC（无危）","distribution":"非洲橄榄鸽分布于东非至南非、西部安哥拉，以及沙特阿拉伯西南部和北也门。","other":"历史上，黄眼鸽曾在部分地区数量众多，如19世纪中叶的南非，数千只鸽群常见于纳塔尔海岸。然而，由于狩猎和栖息地破坏，该物种的数量已大幅减少，如今在某些区域变得稀少。近几十年，在南非的保护措施下，黄眼鸽的数量有所回升。"},{"name":"喀麦隆鸽","english_name":"Cameroon Olive Pigeon","scientific_name":"Columba sjostedti","overview":"喀麦隆鸽（英文名：Cameroon Olive Pigeon，学名：Columba sjostedti），是鸽形目鸠鸽科鸽属的鸟类。以其独特的白色斑点和蓝灰色头部著称，拥有鲜红与黄色的喙。该物种仅在喀麦隆山脉森林中发现，主要在海拔1000至2500米的密集云雾森林中活动。","appearance":"体长33至37厘米，全身呈均匀的蓝灰色，胸部和背部有丰富的白色斑点，腹部斑点较大。喙基部红色，其余部分黄色，虹膜淡黄色，腿部深紫色。雌雄外观相似，幼鸟胸部和腹部有更密集的软白色斑点，颈部较灰。","call":"声音记录较少，叫声被描述为低沉的咆哮后跟一系列低沉、模糊的咕咕声及展示飞行中的类似羊叫声。","habits":"喀麦隆鸽居住在海拔1000至2500米的浓密云雾森林中，有时会飞越树冠寻找食物。以含水果肉和硬种子的果实为食，具体细节未知。","breeding":"已知在五月筑巢，巢由交错的树枝构成，位于森林空地的树上约8米高处，巢中有一枚白色的蛋。","identification":"与黄眼鸽相比，喀麦隆鸽头部颜色一致，胸部白点丰富，腹部斑点大，喙色独特。与白枕鸽区别在于后者头部有白色斑块，胸部颜色较浅。","protection":"IUCN：LC（无危）","distribution":"非洲喀麦隆山脉，包括Bioko岛。在喀麦隆山脉，从1000米到2500米的森林和树蕨地带都有分布。","other":"喀麦隆鸽在Gashaka-Gumti国家公园和Obudu高原相对常见，尽管其栖息地受到一定程度的破坏，但种群仍保持稳定。"},{"name":"圣多美绿鸽","english_name":"Sao Tome Olive Pigeon","scientific_name":"Columba thomensis","overview":"圣多美绿鸽（英文名：Sao Tome Olive Pigeon，学名：Columba thomensis），是鸽形目鸠鸽科鸽属的鸟类。体型较大，显著特征为暗灰色头部、酒红色身体点缀以细小白斑，以及鲜黄色的喙和腿。雌鸟相较于雄鸟色彩较淡。这种鸽子数量稀少，常单独或成对出现在圣多美岛的原始和次生森林树冠层，尤其在海拔1300米以上更为常见。","appearance":"体长37至40厘米，雄鸟体重约520至530克，雌鸟约350克。头部深灰，颈部羽毛呈矛状，基部黑色，顶端蓝灰色带珍珠光泽，颈部泛紫色，背部和臀部呈黑色，上尾覆羽深棕色。下体为丰富的酒红色，腹部和两胁有微弱的白色斑点。眼睛橄榄褐色，喙黄角色，腿黄色。雌鸟相似但色彩更暗淡，胸和翼覆羽仅隐约显现酒红色，多为深棕色，有斑点。幼鸟全身深棕色，缺乏白色斑点，羽毛边缘呈栗色。","call":"发出低沉模糊的咕咕声，重复间隔较长，由一个滚动、结巴的起始音符接续通常三个同样结巴的音符组成，声音结构类似黄眼鸽，但存在明显差异。","habits":"生活在从海平面至2024米的原生和次生雨林中，但在圣多美岛东部，仅在海拔1300米以上发现。已知取食Scheffleria mannii的浆果。据推测，该物种为留鸟。","breeding":"关于繁殖的信息目前尚不可得。","identification":"与较小的圣多美鸽相比，后者胸部灰色，颈背具金属绿色光泽，且不具备Maroon Pigeon的黄色脚和喙。","protection":"IUCN：EN（濒危）","distribution":"主要分布在圣多美岛的山区，以前也在主岛南部的小岛I das Rôlas存在，但因森林严重破坏而灭绝。"},{"name":"科摩罗林鸽","english_name":"Comoro Olive Pigeon","scientific_name":"Columba pollenii","overview":"科摩罗林鸽（英文名：Comoro Olive Pigeon，学名：Columba pollenii），是鸽形目鸠鸽科鸽属的鸟类。此鸽体型较大，拥有暗色羽毛，头部可见黑白相间的斑纹，常见于科摩罗群岛的湿润森林树冠层，亦见于次生林与种植园中，多栖息于较高海拔处。","appearance":"体长约35至40厘米，头部、颈部、胸部及上背部呈暗紫红色，混杂灰色，颈后具长条状羽毛，中心呈紫色，边缘白色，形成独特的黑白条纹效果。上翼、尾羽上方覆羽为暗灰褐色，翅膀主羽与尾羽为棕色黑色，腹部及翼下覆羽为蓝灰色，偶见微小白色斑点。下背及臀部颜色较淡，眼环、眶周皮肤、喙与腿均为黄色。雌鸟色泽较暗淡，头胸部的紫红色减弱或消失，下方更偏棕色。幼鸟类似雌鸟，但轮廓羽毛边缘呈棕红色，喙、腿与眼环较深色。","call":"其典型叫声为低沉的咕噜声，随后接续数个低沉的呼呼声：“crrroooh...whuuu.whuuu.whuuu”。叫声独特，与同类中的其他物种明显不同。","habits":"常栖息于热带湿润山地森林，尤其在科摩罗群岛的高海拔地区。在马约特岛上，其分布可低至海平面。以树上的果实为食，偶尔也会从地面觅食。飞行时不显眼。","breeding":"巢筑于5至24米高的树上，每次产卵1至2枚。繁殖期至少在8月至11月之间，可能全年都有繁殖行为。","identification":"与马达加斯加斑鸠相比，科摩罗林鸽栖息于树冠，体型更大，具有黄色裸露部分，飞行时尾部无淡色角，叫声也显著不同。","protection":"IUCN：NT（近危）","distribution":"分布于科摩罗群岛的所有四个岛屿，包括大科摩罗岛、莫埃利岛、昂儒昂岛以及马约特岛。","other":"尽管在某些地区被视为常见的鸟类，但由于栖息地丧失与狩猎压力，总体数量稀少，总人口估计不足10,000只，目前面临威胁。"},{"name":"点斑林鸽","english_name":"Speckled Wood Pigeon","scientific_name":"Columba hodgsonii","overview":"点斑林鸽（英文名：Speckled Wood Pigeon，学名：Columba hodgsonii），是鸽形目鸠鸽科鸽属的鸟类。显著特征在于颈部的虹彩光泽和腹部的斑点，广泛分布于喜马拉雅山脉至缅甸一带的高海拔森林中。","appearance":"体长约38-40厘米，头部呈淡灰色，胸部和颈部侧面有粉银色斑点。每根羽毛银底带暗色条纹及银粉色尖端，颈背羽毛呈长矛状，基部黑色或紫黑色，尖端银色，形成斑驳外观。背部深酒红色，翼上覆羽暗红紫色渐变为蓝灰色，尾羽和主翼羽黑色，翼下覆羽有小白点，腹部暗红紫色带粉白条纹，下体、尾下覆羽及翼下灰蓝，虹膜白色或灰白色，喙蓝紫色基部，末端黑色，腿黄色至绿褐色，爪鲜黄。雌鸟银色区域替换为浅灰或褐灰色，紫色部分为暗灰色，虹膜灰或褐色。幼鸟缺乏长矛状颈羽，较雌鸟更淡且偏棕色，斑点不明显，许多羽毛边缘呈赤褐色。","call":"叫声低沉，类似'whock-whrooo-whrooo'，最后一个音节拉长且滚动。","habits":"栖息于1800-4000米海拔的常绿和半常绿山林，如橡树林、杜鹃花丛及周边植被。有时可见于开阔的树下空地，如岩石上休息。冬季在泰国北部观察到的个体可能来自更北的迁徙。主要食果，也吃草本植物、种子和谷物，大部分饮食由橡子、Prinsepia utilis的果实组成，成对或小群体（6-10只）觅食。","breeding":"繁殖季节主要在5-6月，可能延伸至夏季更高海拔地区（1800-3300米）。巢为交错树枝平台，建于3-8米高的橡树或其他树上，产一枚白色卵。","identification":"与其他鸽类相比，点斑林鸽的颈部和腹部的斑点是其显著识别特征。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉自克什米尔至中国西部（甘肃南部，四川西部和云南），缅甸，至少在冬季访问泰国西北部和老挝西北部。"},{"name":"白枕鸽","english_name":"White-naped Pigeon","scientific_name":"Columba albinucha","overview":"白枕鸽（英文名：White-naped Pigeon，学名：Columba albinucha），是鸽形目鸠鸽科鸽属的鸟类。以独特的白枕斑纹而著称，分布于喀麦隆山脉和非洲东部的阿尔伯特裂谷山区森林中，包括刚果民主共和国东部、乌干达西部、卢旺达和布隆迪。","appearance":"成年白枕鸽长约34厘米，体重约280至290克。雄鸟的后颈和枕部白色，雌鸟相应部位为灰色。喙基部黑色，尖端红黄色，腿呈紫红色。飞行时，尾羽边缘呈淡色。幼鸟头部灰暗，上体深褐色，翼覆羽锈色边缘，胸羽暗棕色带浅红褐色边缘，腹部灰色带红褐色边缘，尾部灰色，末端淡色。","call":"关于其鸣叫特征的记录有限，但已知的叫声与同属的黄眼鸽相似。","habits":"白枕鸽通常成对出现在低地和亚山地森林的树冠层，生活在孤立的人口群落中。它们的栖息地主要位于喀麦隆和阿尔伯特裂谷地区。","breeding":"有关白枕鸽繁殖生态的具体信息记录不足。","identification":"白枕鸽与黄眼鸽相比更小，最显著的区别在于其较大的白色颈背斑纹。雄鸟头部后部和颈部白色，雌鸟相应部位为灰色。","protection":"IUCN：LC（无危）。白枕鸽在分布区内普遍被认为数量稀少，其分布范围狭窄使物种极易受到栖息地丧失的影响。","distribution":"分布于西喀麦隆（如Rumpi山、Bakossi山脉、Santchou、Manenguba山）、刚果民主共和国东部、乌干达西部，围绕Rwenzori山脉，以及南苏丹的Bangangai国家保护区。","other":"白枕鸽的分布范围可能自地质近期以来有所收缩，尤其是在较凉爽、湿润的时期。"},{"name":"灰林鸽","english_name":"Ashy Wood Pigeon","scientific_name":"Columba pulchricollis","overview":"灰林鸽（英文名：Ashy Wood Pigeon，学名：Columba pulchricollis），是鸽形目鸠鸽科鸽属的鸟类。尤其是带有奶油黄羽尖的黑色羽毛构成的棋盘式颈环。分布于喜马拉雅山脉至中国南部及台湾，主要栖息于栎树为主的常绿阔叶林中。","appearance":"体长31–36厘米，体重约330克。头部呈蓝灰色渐变为白色喉部，颈部有宽广的黑羽带，末端带光泽的奶黄色或米色尖端，其余部分为蓝灰色，带绿色光泽。紫色的上颈、肩背和上胸，下胸为较浅的灰色，腹部更淡或微黄。尾下覆羽为奶白色，主翼羽和尾羽为灰黑色。虹膜白色、灰色或淡黄色，眼周皮肤灰色，喙端绿色基部紫，腿脚紫红至珊瑚红，爪为角质棕色。雌鸟略显暗淡，幼鸟更暗，胸前有锈色边缘，颈环标记不明显。","call":"广告叫声为连续低沉的呼噜声，\"whooh....whooh....whooh...\"，每一声音略带滑音，中间达到最大音量，音符长度约0.3–0.4秒，间隔约1.5秒。台湾分离种群的叫声类似。","habits":"通常单个、成对或成小群活动，性格羞怯，受惊时迅速飞离。主要栖息于温带森林，尤其偏好橡树、栗树和杜鹃花混合的落叶和常绿森林，海拔1200–3200米，在孟加拉国全年可低至100–150米。以果实为主食，也吃种子、谷物、橡子、姜科浆果和小型蜗牛。在树上觅食，偶尔成群10–30只。","breeding":"已知繁殖期为5月至8月。巢由树枝搭建，较为粗糙，位于树较低处，内部可能衬有羽毛。典型情况下产一枚白色蛋，但在锡金发现双蛋的情况；孵化期为21–23天；幼鸟在孵化后约4周离巢。","identification":"与点斑林鸽的区别在于上部颜色，灰林鸽为深灰色，而点斑林鸽为栗褐色并带有斑点。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至中国南部，包括尼泊尔、印度东北部、不丹、中国西藏南部、云南、台湾，以及泰国北部、缅甸北部至中部。","other":"台湾种群数量估计在10,000至100,000对繁殖对之间。"},{"name":"灰头林鸽","english_name":"Nilgiri Wood Pigeon","scientific_name":"Columba elphinstonii","overview":"灰头林鸽（英文名：Nilgiri Wood Pigeon，学名：Columba elphinstonii），是鸽形目鸠鸽科鸽属的大型鸽类。其头部呈现蓝灰色，与较暗的颈部和胸部融合，腹部和尾下覆羽带有棕色混杂。分布于印度西南部的湿生森林，主要栖息于海拔1000米以上的山区。","appearance":"体长36至42厘米，体重约379克。头部为蓝灰色，逐渐过渡到较深的颈部和胸部颜色；腹部和尾下覆羽掺杂棕色；后颈由黑色羽毛构成，尖端带有白色，形成宽阔的斑点状半环颈饰；后颈下方的绿色金属光泽逐渐变为紫色或棕紫色；背部、肩羽、内翼覆羽、臀部和上尾覆羽呈板岩色或棕紫色，大多数羽毛边缘带有棕紫色；其余上体部分和尾巴为黑色；虹膜灰褐色或明亮的卡其色；蜡膜和喙基部为紫红色，喙远端为象牙白；腿为紫红色，爪为象牙色。雌鸟比雄鸟略暗淡，上体的紫色减少，头部的蓝灰色掺杂棕色。幼鸟比成鸟更暗淡，颈饰发育不全，翼覆羽边缘为锈红棕色。","call":"发出低沉拉长的低音咕噜声，结合多音节的咕噜音符：“whoooh....whu-hu-hu-hoo....whoooh...whu-hu-hu”。","habits":"栖息于湿润的常绿森林，从山脚到海拔2000米的区域。以果实为主食，偶尔下到地面觅食落果和蜗牛。在繁殖季节，即3月至5月期间，有记录显示它们会进食土壤，可能与钙质需求有关。","breeding":"繁殖季节通常从3月持续到7月，主要集中在4月至6月。筑巢采用典型的鸽子平台式，由细枝构成，每次产一枚白色蛋。","identification":"通过其较大的体型、深色外观和后颈上独特的棋盘图案来识别。与之最易混淆的是山皇鸠，但后者具有较浅色的翼下覆羽。","protection":"IUCN：VU（易危）。由于其森林栖息地的广泛破坏，种群数量小且正在下降。","distribution":"主要分布在印度西部山脉（Western Ghats）和尼尔吉里山（Nilgiri Hills），包括从马哈拉施特拉邦北部到喀拉拉邦南部和泰米尔纳德邦西部的区域。偶尔在较低海拔的西部山脉内部出现。","other":"与紫头林鸽和灰林鸽亲缘关系密切。"},{"name":"紫头林鸽","english_name":"Sri Lanka Wood Pigeon","scientific_name":"Columba torringtoniae","overview":"紫头林鸽（英文名：Sri Lanka Wood Pigeon，学名：Columba torringtoniae），是鸽形目鸠鸽科鸽属的鸟类。大型灰鸽，以颈部明显的黑白色条纹而著称，腹部呈现淡紫色调。主要栖息于斯里兰卡山区和丘陵地带的密林中，常以小群或成对出现。","appearance":"体长33至36厘米，头部呈紫灰色，后颈有金属光泽。喉部白色，颈侧有黑白相间的条纹，类似灰头林鸽。背部蓝灰色，胸前有一大片紫色或绿色的金属光泽，逐渐变为灰紫色。下腹紫灰色，尾下覆羽灰色。翅膀、肩部及背部蓝灰色，初级飞羽和尾巴颜色稍浅。虹膜淡红或粉红色，眼周皮肤暗粉色，腿脚粉红，趾和足底更红。雌鸟头部和胸部灰色较淡，胸部下方和后颈下部有铜色光泽。幼鸟色彩较暗，带有棕色，成鸟特有的紫灰色被暗灰色替代，边缘带红褐色，翅膀覆羽边缘锈色，展示的颈羽黑色，尖端绿灰色带金属光泽。","call":"叫声较为沉寂，发出低沉的单音‘wooh...wooh...’，间隔出现，有时发出颤抖的‘whu-hu-hoo’声，与灰头林鸽相似。","habits":"生活在常绿和湿润落叶林中，通常海拔高于1000米，但偶尔会降至300米。为了觅食而迁移。主要以树上的果实和浆果为食。","breeding":"繁殖季节从2月持续到11月，但大部分筑巢活动发生在10月。巢由树枝构成，位于树上或灌木丛中，每次产一枚卵。","identification":"颈部的黑白色条纹和纯色、无斑点的深灰色背部使其在斯里兰卡的所有鸽子中独树一帜。","protection":"IUCN：VU（易危）","distribution":"主要分布在斯里兰卡的内陆山地地区。"},{"name":"紫林鸽","english_name":"Pale-capped Pigeon","scientific_name":"Columba punicea","overview":"紫林鸽（英文名：Pale-capped Pigeon，学名：Columba punicea），是鸽形目鸠鸽科鸽属的鸟类。分布于印度东北部至东南亚的大型鸽类。主要栖息在次生林区边缘或隐匿于树叶稠密处，以浆果、无花果为主食，兼食植物种子及谷物。","appearance":"成年紫林鸽体长36至41厘米，体重370至510克。头部前额、头顶和颈背呈银灰色，额头在侧面观察时明显倾斜；喉部和颈部为棕色，带铜色光泽，逐渐变为下体较暗的紫棕色；颈侧和背部有紫色和青铜绿色的虹彩光泽；肩部、背部、上臀部和大部分翼覆羽呈深紫色栗色，新羽毛边缘带紫色虹彩；下臀部灰黑色，所有羽毛带有绿紫虹彩；尾羽和次级飞羽内侧深褐色；主飞羽和次级飞羽外侧黑色；尾羽黑色；眼睛奶油黄色、黄褐色、橙黄色或橙红色；眼周皮肤灰紫色或紫罗兰色；喙基部和蜡膜为紫罗兰色，其余部分象牙色或淡角质色；腿为鲜红紫罗兰色或紫红色，爪为淡黄色或白色。雌鸟体型较小，颜色较暗淡；头部灰色区域更深，带有棕色、紫色或淡紫色光泽。幼鸟颜色更暗淡，偏棕色，翼覆羽和肩羽边缘为赤褐色。","call":"群居时发出微弱的接触叫声，被描述为‘rhuhuhuhu’，具体声音细节几乎未知。","habits":"栖息于山地林区或次生林区边缘，单独活动或小群体出现。食性以果实为主，包括无花果、Litsea nitida、L. monopetala、Syzygium cumini、Strychnos nux-vomica、Bambusa arundinacea、Phyllanthus属植物和Trema orientalis的果实。亦在稻田、小米、野豌豆和玉米田中寻找种子。常在单个个体或小群体中被观察到，有时会聚集30至40只的群体在结果树或竹林中觅食。","breeding":"繁殖季节通常在5月至8月，高峰期在7月。巢由细枝构成，位于离地面较低处，一般不超过6米，常见于高大的灌木丛或竹子中。每窝产一枚白色蛋，极少数情况下产两枚。","identification":"与同类物种相比，紫林鸽的显著特征在于其独特的银灰色头部，尤其是雄鸟的头部。雌鸟头部颜色较暗，光泽较少，有助于在野外辨识。","protection":"IUCN：VU（易危）。在中国国家重点保护野生动物名录中列为二级保护动物（2021.02.05）。","distribution":"分布于东洋界，包括印度东北部至东南亚，具体包括东印度、西孟加拉、阿萨姆山谷、阿萨姆南部山区、缅甸局部地区、泰国、老挝、柬埔寨和越南。曾经在东南亚西藏和海南岛有记录，但在1997年至2004年的森林鸟类调查中未能找到。","other":"紫林鸽的全球数量估计少于10,000只成熟个体，由于栖息地丧失和狩猎威胁，相信其数量正在减少。"},{"name":"银鸽","english_name":"Silvery Pigeon","scientific_name":"Columba argentina","overview":"银鸽（英文名：Silvery Pigeon，学名：Columba argentina），是鸽形目鸠鸽科鸽属的鸟类。这种鸽子以淡银灰色的羽毛著称，带有黑色翼尖和尾端，主要分布在印度尼西亚和马来西亚的某些岛屿，如苏门答腊西部岛屿。曾在19世纪末至20世纪初被认为灭绝，但在2008年于孟塔威群岛附近的马斯托库特岛被重新发现。","appearance":"银鸽体长34-38厘米，羽毛大部分为非常浅的蓝灰色，黑色的一级和二级飞羽显著；尾部基部为灰白色，远端黑色；颈部后方有轻微的绿色光泽；虹膜红棕色至橙黄色；眼周皮肤深红色；喙基部棕色或紫罗兰色，尖端淡绿色或黄绿色；腿灰色带红色斑点。雌鸟在新鲜羽毛状态下比雄鸟略暗且银色较淡；幼鸟胸部和羽毛边缘为沙色。","call":"鸣叫声深沉、响亮、上升的咕咕声，但了解有限，很少听到。","habits":"栖息于低地和丘陵森林，主要在苏门答腊和婆罗洲附近的小岛上的红树林、林地和椰林。可能因食物供应变化而迁移到其他岛屿。已知的食物信息有限。","breeding":"繁殖季节未知，通常在一棵树或灌木上筑巢，每次产一枚质地略带粉状的白色蛋。1899年在Burong岛与白冠果鸠大量繁殖。","identification":"与斑皇鸠区别明显：银鸽全身呈淡银灰色，黑色的飞羽和尾端羽毛长度相等，眼周有深红或紫色肉垂，喙基部颜色更深，脚部蓝灰色带红斑。雌鸟较雄鸟稍大且颜色更深。","protection":"IUCN：CR（极危）","distribution":"现今仅限于苏门答腊西部岛屿：Simeulue、Nias、Bojo（Batu Is）、Masokut和Simaimu（Siberut南部）。曾出现在苏门答腊东部（Riau和Lingga群岛）、婆罗洲西部（Karimata、Anambas和Natuna岛屿）。","other":"历史上在1931年至2008年间没有确认的目击记录。2008年在Siberut南部的Masokut岛和Simaimu岛之间拍摄到的照片证实了其存在。"},{"name":"安达曼林鸽","english_name":"Andaman Wood Pigeon","scientific_name":"Columba palumboides","overview":"安达曼林鸽（英文名：Andaman Wood Pigeon，学名：Columba palumboides），是鸽形目鸠鸽科鸽属的鸟类。体型较大的，头部和颈部呈银灰色，上体暗灰带绿光泽，下体淡灰色，具独特外观特征。分布于印度的安达曼和尼科巴群岛，数量稀少，栖息于密林中，偏好厚实森林环境。","appearance":"安达曼林鸽体长36至41厘米，体重510至520克。头部和颈部银灰色，逐渐过渡至上背的较深灰色，带有绿色光泽；其余上体黑色，上背有绿色光泽，背部和臀部的羽毛边缘呈现虹彩紫色和绿色；两胁和下尾覆羽深灰色；虹膜具有深橙色或红色外环和黄色或橙色内环；眼周皮肤紫红色；腿红色或粉红色，爪白色；喙基部紫红色，尖端绿色或淡黄色。雌鸟头部和颈部颜色较暗，银色较少。幼鸟整体呈褐色，缺乏成鸟的虹彩光泽。","call":"鸣声记录不足。广告叫声为连续的单一柔和咕哝声，“whooo”，音节略带滑音，最大音量在中间，音长约为0.3秒，间隔数秒。","habits":"栖息于密林，常见于湿润常绿森林的密集区域，通常以成对或小群体出现。会根据树木结果情况在岛屿间迁移，飞行高度高，跨过海峡。","breeding":"关于繁殖信息目前尚无资料。","identification":"与绿皇鸽相似，但安达曼林鸽具有淡灰色腹面，眼周红褐色皮肤，以及不同的喙色。","protection":"IUCN：NT（近危）","distribution":"分布于安达曼和尼科巴群岛，主要见于较大岛屿。"},{"name":"黑林鸽","english_name":"Black Wood Pigeon","scientific_name":"Columba janthina","overview":"黑林鸽（英文名：Black Wood Pigeon，学名：Columba janthina），是鸽形目鸠鸽科鸽属的鸟类。俗名: 黑果鸽、鸦鸽，是东亚最大的鸽属鸟类，重约550克，全长43厘米。分布于日本南部诸岛至琉球、硫黄、小笠原群岛，以及中国大陆山东部分地区。偏好栖息于亚热带常绿林间的小岛上，依赖成熟森林。","appearance":"黑林鸽体型大，全身深紫黑色，颈侧金属绿色光泽显著，头部、肩部及臀部呈紫色，翅膀和尾上覆羽带有青铜、紫、绿光泽，初级飞羽和尾羽无光泽。虹膜棕色，喙绿蓝，腿红色。两性相似，幼鸟较暗淡，颈侧光泽有限。亚种stejnegeri较小，尾短；亚种nitens头呈紫褐色。","call":"发出深沉的呼叫声和缓慢的呻吟式鸣唱，类似岩鸽的日常叫声。还有不同的咔哒声，随后是牛般的下降哞叫声。飞行时会发出响亮的‘krrrrrr’声。","habits":"栖息于亚热带和暖温带的常绿阔叶林，偏好成熟的森林环境。以茶树种子为主食，也吃其他种子、芽和果实。在小岛上独居或形成小群。可能在部分范围内迁徙。","breeding":"繁殖季节从2月持续到9月，偶尔在晚秋和冬季也有记录。在树洞或岩石中筑巢，一窝仅产一枚蛋。有关繁殖的详细信息不足。","identification":"与同属其他鸽类相比，黑林鸽体型最大，颜色最深，具有独特的金属光泽。亚种nitens头部颜色与主种有差异。","protection":"IUCN：LC（无危）。在伊豆群岛仍相对常见，但自1950年代以来数量大幅减少。亚种nitens在日本被认为是Critically Endangered（极危）。","distribution":"分布于日本南部、琉球群岛、硫黄群岛、小笠原群岛、台湾附近岛屿，以及韩国南部海岸的岛屿。在中国大陆，记录于山东地区。","other":"对成熟森林的严重依赖使得黑林鸽面临栖息地丧失的威胁，尤其是伐木和狩猎压力。亚种nitens的遗传多样性极低，其保护状况令人担忧。"},{"name":"小笠原杂色林鸽","english_name":"Bonin Wood Pigeon","scientific_name":"Columba versicolor","overview":"小笠原杂色林鸽（英文名：Bonin Wood Pigeon，学名：Columba versicolor），是鸽形目鸠鸽科鸽属的鸟类。已灭绝的鸽子，原生于日本南部小笠原群岛的Nakodo-jima和Chichi-jima岛。该物种以约45厘米的平均体长著称，由于森林破坏、猎杀以及外来物种如鼠和猫的捕食，于19世纪末期消失。","appearance":"这是一种中等体型的鸽子，身长平均为45厘米。其上体主要呈现灰黑色，带有金属光泽，仅翅膀和尾巴例外。头部冠羽带绿紫色光泽，肩羽至臀部反射出紫、紫水晶和蓝绿色调。肩羽和背部其余部分泛金绿色光泽，夹杂着青铜色调；翅膀覆羽深绿带蓝。尾上覆羽宽幅金色绿边。胸部至腹部边缘饰以深绿和紫色彩辉，尤其胸部色彩最为浓郁。虹膜呈蓝色或深蓝色；喙绿色偏黄，尖端淡色；腿脚暗红色。","habits":"小笠原杂色林鸽栖息于森林环境，具体生活习性和活动范围的详细信息已无法考证。","breeding":"通常在树上或森林中配对。它们每次产两枚蛋，孵化期大约需17至19天，孵化后成为幼鸽，与现存的木鸽繁殖模式相似。","identification":"其独特的颜色组合和体型大小使其与其它鸽子种类易于区分。","protection":"IUCN：EX （已灭绝）","distribution":"曾分布于小笠原群岛（日本东南部），包括Nakodo-jima和Chichi-jima岛屿。"},{"name":"琉球银斑黑鸽","english_name":"Ryukyu Wood Pigeon","scientific_name":"Columba jouyi","appearance":"由于历史记录有限，关于银斑黑林鸽的具体外形特征描述较为匮乏。它被归类于Columba属，与其他鸽子具有相似的基本形态，但具体的羽毛颜色、图案和大小等细节未能详尽记录。","call":"关于银斑黑林鸽的鸣叫特征，历史文献中并未留下详细记录。","habits":"银斑黑林鸽偏好广阔的未受干扰的亚热带森林环境，这对其生存至关重要。它们曾广泛分布于冲绳群岛的多个岛屿上，包括Iheyajima、Izenajima、Okinawa主岛及其邻近的Yagachijima小岛。","breeding":"关于银斑黑林鸽的繁殖习性的具体信息，历史资料中缺乏详细记载。","identification":"银斑黑林鸽与同属的其他鸽子种类在外观上有一定的相似性，但由于其灭绝状态，现代辨识标准无法确立。","protection":"IUCN：EX（已灭绝）","distribution":"银斑黑林鸽原生于日本南部的冲绳岛和大东群岛，以及琉球群岛的其他岛屿。它们曾在Okinawa主岛及其周边岛屿如Iheyajima、Izenajima、Yagachijima，以及西部的Kerama Retto的Zamamijima，还有东南部Daitō群岛的Kita Daitōjima和Minami Daitōjima上被发现。","other":"银斑黑林鸽的科学命名是为了纪念标本收集者Pierre Louis Jouy，而它的灭绝主要归咎于栖息地破坏和过度狩猎。"},{"name":"白喉林鸽","english_name":"Metallic Pigeon","scientific_name":"Columba vitiensis","overview":"白喉林鸽（英文名：Metallic Pigeon，学名：Columba vitiensis），是鸽形目鸠鸽科鸽属的鸟类。中型鸽子，体长约37厘米，显著特征是三角形的喉部斑块颜色随地理位置变化，一般呈白色到浅灰色，但在小巽他群岛则较深。广泛分布于远东、澳新界和太平洋岛屿，从菲律宾至萨摩亚（波利尼西亚中部）。","appearance":"体型较大，重量在345至511克之间，背部、翅膀和尾巴呈暗灰色，带有不同程度的绿紫色金属光泽。下巴、喉咙和脸颊为纯白色，前额、头顶、颈部和下体为深栗色，带紫粉色光泽，至石板棕色带紫色或绿色光泽。虹膜橙色或红色，脚和腿为紫红色，眼周皮肤为紫褐色，喙为紫红色或红色，尖端淡黄色。雌雄相似，雌鸟通常比雄鸟略显暗淡。幼鸟与成鸟相似但色泽更暗淡，下体部分金属光泽较少。不同亚种间金属光泽程度不同。","call":"发出低沉的轰鸣声和较高音调的‘COOroo...COOroo...’的叫声，叫声在不同亚种间有轻微差异。","habits":"栖息于多种森林类型，从低地至云雾森林，最高可达海拔2750米。适应力强，能在受干扰的生境中生存，如年轻的次生林、农林、空地和村庄花园。飞行有力而直接，以果实、花蕾和种子为主食，偶尔吃毛虫和蜗牛。单个、成对或以小群（最多30只）出现，会与其他鸽子种类形成混群。","breeding":"繁殖季节信息有限，但在瓦努阿图，繁殖期为9月至2月，偶尔7月至8月。巢为简单的树枝平台，通常建于树上3至8米高处，有时也会在地面茂密植被中筑巢。通常产一枚纯白色蛋，但在东部边缘区域有时会产两枚蛋。孵化期17至19天，幼鸟21天离巢时已能强力飞行。","identification":"与同属其他物种的区别在于其独特的喉部斑块颜色和金属光泽，不同亚种间的差异主要体现在金属光泽的程度。","protection":"IUCN：LC（无危）。尽管在整个分布范围内相对稀少或罕见，但现存亚种未显示严重下降趋势。Lord Howe I的godmanae亚种曾因人类猎杀而灭绝。","distribution":"分布于热带森林，从东部印尼、菲律宾、新几内亚、所罗门群岛、斐济、新喀里多尼亚、萨摩亚及周边西南太平洋岛屿。","other":"在斐济较为常见和显眼，而在西萨摩亚局部地区较为少见。"},{"name":"白头鸽","english_name":"White-headed Pigeon","scientific_name":"Columba leucomela","overview":"白头鸽（英文名：White-headed Pigeon，学名：Columba leucomela），是鸽形目鸠鸽科鸽属的大型森林鸽类。其最显著的特征是白色的头部、颈部、胸部和腹部，成年个体翅膀和尾巴呈黑灰色，具金属绿色或紫色光泽。红眼环和红色脚爪，喙淡至暗红色，尖端黄白色。分布于澳大利亚东海岸，从昆士兰州库克镇至新南威尔士州伊登，偶尔见于维多利亚州东南部。","appearance":"体长约38-42厘米，重约420克。头部、颈部、胸部和腹部白色，有时带微黄色调，两胁、腹侧和下尾覆羽变为石板灰色。背部石板黑色，肩羽、臀部、上尾和二级飞羽覆羽带有金属绿或紫光泽。喙色从淡到暗红，尖端黄白色；腿和脚粉红色至红色。雌鸟类似雄鸟，但白色部分斑驳或模糊浅灰色。幼鸟似雌鸟，但头顶更灰，下体更均匀深灰色，与白色下巴、喉部和颈侧形成对比；喙暗红棕色，尖端白色；腿和脚红灰色。","call":"广告叫声为间隔重复的双音节。首音为强调的短啸声，第二音为较弱且渐弱的啸声：‘WhoOoh..huuuu’。距离远时，第二音几乎听不见。在低头展示时，会发出单一低沉的‘咕’声。","habits":"栖息于雨林、廊道森林，偶尔出现在开阔地带与散生森林。常见于森林边缘和次生林。适应农业区，尤其是茂盛的樟树（Cinnamomum camphora）区域。迁徙行为随果实供应而变化，可能数月消失后再次返回。冬季时，某些地区会移至更开阔地带，以食用引进的樟树。","breeding":"繁殖季节延长，至少连续两窝在同一巢中抚养。巢由细枝和藤蔓构成，置于浓密树叶或藤蔓丛中，高度2.5-20米。产一枚白色蛋；孵化期19-20天；孵化时，雏鸟覆盖锈色绒毛，体重约17克；雏鸟20天内达到幼鸟羽毛；离巢约21-22天。","identification":"与同属物种相比，白头鸽的独特之处在于其白色的头部和身体，以及金属光泽的背部。幼鸟和雌鸟的特征较为模糊，可通过头部和下体颜色差异加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从约克角半岛东南部至昆士兰州东北部，至维多利亚州东南部。在沿海地区和相邻高地最为常见。","other":"自1940年代以来，数量似乎有所增加，特别是在1860年至1900年间雨林大量被清除之后。适应次生林和森林边缘，喜食引进的樟树。"},{"name":"黄腿鸽","english_name":"Yellow-legged Pigeon","scientific_name":"Columba pallidiceps","overview":"黄腿鸽（英文名：Yellow-legged Pigeon，学名：Columba pallidiceps），是鸽形目鸠鸽科鸽属的鸟类。背部和翅膀为深蓝色，头部银色亮丽，喙尖粉黄色，腿脚鲜黄至橙黄色。通常在黄昏和黎明时分，小群飞翔于森林树冠之上。","appearance":"体长约36-38厘米，体重可达459克。头部全银灰色，雄鸟尤为明显。上身黑色，下身蓝黑色，羽毛边缘带明亮的粉色、紫色和绿色光泽。眼睛黄色或橙色，喙紫红色，尖端黄色，腿脚黄色至黄橙色。雌鸟头部较暗淡，幼鸟头部呈棕色，羽尖银色，翅膀和下体光泽减少。","call":"虽然大多时候安静，偶尔会发出典型的鸽子低沉‘hooOO hooOO’声。","habits":"偏好海拔400米以上的原始森林和成熟的次生林，最高可达1300米。常于地面觅食，以果实和种子为食。","breeding":"繁殖信息有限。在马基拉岛发现过筑于地面的巢，其中含有一只接近离巢的大雏鸟。另有一次观察到雄鸟正在孵蛋。","identification":"与白喉林鸽相似，但白喉林鸽有暗色帽状羽毛和粉色腿，而黄腿鸽头部完全银色，腿脚鲜明黄色。","protection":"IUCN：VU（易危）","distribution":"分布于新爱尔兰、新不列颠岛（俾斯麦群岛东部）、布干维尔岛至马基拉岛（所罗门群岛北部至东南部）。"},{"name":"德氏鸽","english_name":"Eastern Bronze-naped Pigeon","scientific_name":"Columba delegorguei","overview":"德氏鸽（英文名：Eastern Bronze-naped Pigeon，学名：Columba delegorguei），是鸽形目鸠鸽科鸽属的鸟类。分布在非洲东部和东南部，包括安哥拉、肯尼亚、马拉维、莫桑比克、南非、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。德氏鸽以收藏家Adulphe Delegorgue的名字命名。","appearance":"德氏鸽是一种中等体型、短尾的黑色鸽子，全长约33厘米。雄鸟具有独特的白色颈带，而雌鸟较为朴素，但通常在颈部背面显现出一些红褐色。头部前额和面部呈暗灰色，冠部略具虹彩光泽；颈后和颈侧的虹彩颜色可为粉红、绿色、紫罗兰色或紫水晶色，依光线而异。雄鸟的上背部至翼覆羽为深红色至紫棕色，其余上体部分为石板色，尾羽外缘有宽约4毫米的灰色尖端；胸部为暗紫罗兰色，常带有细小的灰色波状纹；下胸部为棕色，波状纹比上胸更明显；腹部为红棕色；两胁和尾下覆羽为暗灰色；虹膜为深棕色、白色、灰色或黄色；眼周皮肤为粉色或灰粉色；喙为灰色，前端较浅；腿为粉色或红色。雌鸟缺乏白色颈环，冠部和颈后为铜褐色，上体为黑褐色；下体缺少雄鸟的紫色色调，为灰色并带有细小的淡褐色波状纹。幼年雄鸟与成年相似，但冠部和颈后为灰色，颈虹彩减弱，上体为深灰褐色，翼覆羽和下体羽毛边缘为赤褐色。","call":"德氏鸽的鸣唱是一系列低沉的咕咕声，开始时有一两个低沉的呼噜声，随后是一个或两个响亮的双音节呼噜声，最后是一连串大约八个音调稍降的呼噜声，音量逐渐减弱。","habits":"德氏鸽主要栖息于低地常绿林和相邻的河岸林地，也局部出现在海拔较高的山地常绿森林中。它是一种树冠层的鸟类，大部分时间在森林树冠中度过。它在肯尼亚的一项研究中，于3月和4月每天都在统计中出现，但在5月之后消失，暗示存在局部季节性迁徙，但具体细节尚不清楚。其食性主要是果实，但也食用Trema orientalis的浆果、一些种子、昆虫幼虫和蝉的若虫；食用的果实包括野无花果、Podocarpus latifolius、Macaranga capensis和Phialodiscus zambesianus的果实。","breeding":"繁殖期在乌干达为3月至6月和12月，在马拉维为11月，在津巴布韦为1月，在南非为11月至4月。巢穴建在树上，离地面7至10米高，由树枝搭建的平台组成。每次产卵2枚白色蛋，两性共同孵卵并喂养幼鸟。","identification":"雌性德氏鸽与非洲鸽相似，但很少出现在林下层，且面部较暗。雄性德氏鸽的白色颈环是显著的辨识特征。","protection":"IUCN：LC（无危）。在东非局部常见；在苏丹的山脉中常见。在津巴布韦的东部高地，它似乎正在扩散。在莫桑比克，最大的区域性种群位于北部的Mount Nabu，那里它广泛分布在森林树冠中，海拔980至1420米。在南非，它可能因栖息地破坏而受到威胁，尤其是在Mount Thyolo，那里的森林砍伐导致了它的灭绝，尽管它在那里可能仅是一个稀有的季节性访客。","distribution":"德氏鸽主要分布在非洲东部和东南部，包括安哥拉、肯尼亚、马拉维、莫桑比克、南非、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。"},{"name":"铜颈鸽","english_name":"Western Bronze-naped Pigeon","scientific_name":"Columba iriditorques","overview":"铜颈鸽（英文名：Western Bronze-naped Pigeon，学名：Columba iriditorques），是鸽形目鸠鸽科鸽属的鸟类。分布于非洲热带雨林区域，自几内亚和塞拉利昂直至乌干达、刚果民主共和国和安哥拉。","appearance":"成年铜颈鸽体长约25厘米，雄鸟体重约130克，雌鸟略轻，约122克。头部呈蓝灰色，喉部颜色较浅，冠和颈后有粉红或绿色的虹彩光泽；后颈和上背有铜青铜色的虹彩，上体部分为板岩色，带有金色绿、绿或紫蓝色的边缘；中央尾羽板岩色，末端暗灰色不明显；外侧尾羽内侧深栗色，外侧板岩色，末端有宽的淡黄色带；尾部下侧栗色，末端淡黄色；胸腹部深紫粉色，翅膀和尾上覆羽黑色和灰白色，略带虹彩；虹膜粉色、粉红色、灰色、黄绿色或蓝色；眼周皮肤红色；喙灰色，尖端白色，蜡膜红色或深紫色；腿粉色或浅红色。雌鸟脸部泛棕色，冠和颈后青铜棕色，后颈虹彩粉或绿色；胸腹部分红色，有细灰或灰红色的斑纹；腹部和尾下覆羽鲜亮的栗色。","call":"铜颈鸽的鸣唱是一系列复杂节奏的短语，开始时有几声抑制的低吼，接着是四声更响亮和强调的低吼，最后以一到两声低沉的渐弱低吼结束：“uwhuu..uwhuu..OOOh..OOOh..OOOh...OOOh...uh..uh”。有时省略前导音符。在乌干达西南部的极端东部，鸣叫似乎有一系列更长的渐弱音符，缺乏强调和渐弱音符的明显差异，因此听起来更接近德氏鸽。","habits":"铜颈鸽居住在低地森林中，从海平面至海拔1500米；亦见于河岸常绿森林、老二次生林、森林坡地、画廊森林和远离水源的密丛。通常在树冠层活动，但也会出现在低植被和森林地面。通常是单独活动，但也可见成对或3-4只的小群体。","breeding":"繁殖期在利比里亚为3月、4月、7月和9月；在扎伊尔为12月至3月；在赞比亚为10月。在赞比亚发现的一个巢是一个位于密集灌木丛中离地1-2米的脆弱平台，里面有一个浅奶油色的蛋。","identification":"与非洲鸽相似，但很少出现在林下层，且有暗色脸庞。雄鸟可能与蓝头森鸠混淆，但背部颜色更深，通常在森林较高处被发现。","protection":"IUCN：LC（无危）","distribution":"分布于几内亚和塞拉利昂至乌干达、刚果民主共和国和安哥拉，占据整个刚果盆地，从喀麦隆南部和刚果西部东至乌干达西南部，南至赞比亚西北部。","other":"有时被认为是与Columba delegorgue)和圣多美鸽同种，三个物种有时被归入亚属Turturoena。"},{"name":"圣多美鸽","english_name":"Island Bronze-naped Pigeon","scientific_name":"Columba malherbii","overview":"圣多美鸽（英文名：Island Bronze-naped Pigeon，学名：Columba malherbii），是鸽形目鸠鸽科鸽属的鸟类。仅见于几内亚湾的圣多美岛、普林西比岛和安诺本岛，常栖息于雨林、次生林和种植园，常见于低海拔地区。","appearance":"小型至中型的深色鸽子，总长约28厘米。头部、前冠、颈背及肩部呈石板灰色，具粉绿或绿色光泽；翅膀、背部和尾羽上部黑色带绿辉；胸部、腹部灰白色，腹部下方和尾羽下侧呈红褐色，脚红色。雄鸟腹面灰白，雌鸟腹面暗灰，下胸和上腹具细小红褐色斑点。","call":"广告鸣叫由两个嘶哑的呼噜声开始，随后是一系列15到20个逐渐缩短并消退的颤音，\"rhuuuw...rhuuw...rhu-tu-tu-tu-tutututu\"，音调和结构与Streptopelia鸽类相似。","habits":"栖息于森林树冠层，包括次生林和种植园，偏好人类改造的生境如遮荫林和非林地。在圣多美岛，它在农业地边界的灌木丛中取食Cestrum laevigatum的果实。","breeding":"繁殖季节从11月至次年1月在普林西比岛，2月起在圣多美岛。巢筑于次生林、Erythrina或可可树种植园中的树木，离地面5至12米处，每窝产一至两枚脏白色的蛋。","identification":"与西部和东部青铜颈鸽相似，但在其分布范围内不会同时出现。在圣多美岛，可能与圣多美橄榄鸽和圣多美非洲鸽混淆，前者体型更大，下胸和翅膀有白斑，后者更偏陆栖，体型圆润，虹膜和眼周皮肤红色。","protection":"IUCN：NT（近危）","distribution":"该物种仅限于几内亚湾的圣多美岛、普林西比岛和安诺本岛。在安诺本岛上至多分布至海拔500米的雨林。","other":"面临的主要威胁是狩猎，尤其在圣多美岛，其肉被视为美食，商业猎人捕获量占总量的近60%，尽管目前捕猎量在可持续水平内，但狩猎压力可能正在增加。"},{"name":"非洲鸽","english_name":"Lemon Dove","scientific_name":"Columba larvata","overview":"非洲鸽（英文名：Lemon Dove，学名：Columba larvata），是鸽形目鸠鸽科鸽属的鸟类。","appearance":"非洲鸽体型中等，长度在24至30厘米之间，体重介于81.7至150克。雄鸟上部暗棕色，颈侧有绿光，胸部呈肉桂色，头部有显著的白色标记。脚、眼睛和眼周皮肤红色，喙黑色。雌鸟和年轻雄鸟相似，但毛色较浅的棕色，面部标记为暗灰色。西部非洲亚种的雄鸟则羽毛为深灰色。","call":"发出单调的低沉\"呼-呼-呼-\"声系列，音量有时略升，通常14次持续20秒，两性可能在繁殖季节高点时合唱。还发出缓慢的低音\"奥-奥-奥-\"和快速的高音\"呼呼呼呼\"。","habits":"主要栖息于低地和山地常绿森林，包括部分退化区域。也出现在种植园、大型林木花园和灌木丛中。依赖森林内的流水进行繁殖活动。活动范围从低海拔到2100米以上的高度。偏好地面觅食，主要以Calodendron capense果实为主食，同时吃竹子、Podocarpus、Kiggelaria africana的种子，以及小地下兰花的块茎。偶尔捕食白蚁和蜗牛。","breeding":"繁殖时间随区域而异，可能全年均可繁殖。一夫一妻制，领地面积2至6公顷。巢由枝条和根须构成，位于树叉或藤蔓中，常处于深荫处。每次产1至3枚乳白色或奶油色的蛋，雌鸟独自孵卵约14至18天。雏鸟覆盖着稀疏的金黄色绒羽，约20至21天后离巢，但会继续与成鸟生活约2个月。","identification":"与Delegorgue's和Bronze-naped鸽相比，非洲鸽栖息于林下层，脸部颜色较浅。西部非洲亚种雄鸟羽毛为深灰色，与其它亚种有明显区别。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲次撒哈拉地区的山地森林，包括东非的低海拔到3000米的高海拔区域，西至几内亚湾群岛。","other":"某些亚种如São Tomé柠檬鸽在分类上存在争议，有时被视为独立物种。"},{"name":"白顶鸽","english_name":"White-crowned Pigeon","scientific_name":"Patagioenas leucocephala","overview":"白顶鸽（英文名：White-crowned Pigeon，学名：Patagioenas leucocephala），是鸽形目鸠鸽科新大陆鸽属的鸟类。体型较大，羽毛深灰，头部显眼的白色帽状羽毛为其标志。分布于北美地区和中美洲，常见于佛罗里达南部至西印度群岛和中美东部。近危物种。","appearance":"白顶鸽长约29至35厘米，翼展48至59厘米，体重介于150至301克之间。成鸟羽毛呈均匀的暗灰色至近黑色，头部具有鲜明的白色冠羽，颈部后方有绿色闪光的鳞片状羽毛，仅在良好光照下可见。虹膜白色，喙红且尖端淡色。幼鸟较成鸟色泽浅，缺乏白冠及虹膜的明亮色泽，仅在头顶有少量淡色羽毛。","call":"其叫声为响亮而低沉的‘coo-cura-coo’或‘coo-croo’声。","habits":"主要栖息于沿海低地，尤其偏爱红树林环境。在美国，仅限于佛罗里达州最南端。它们倾向于群居，常以双或小群体形式活动，尤其在飞行时更为明显。以多种硬木树的果实为主食。","breeding":"在巴哈马群岛、古巴、牙买加和安提瓜岛等地繁殖。它们通常在潮汐淹没的红树林岛屿上建立巢穴，冬季会迁往加勒比海岛屿。在佛罗里达，白顶鸽历史上仅在偏远的潮汐红树林岛上筑巢。","identification":"白顶鸽与原鸽相似，但通过其独特的白冠和粉红色喙可轻易区分。幼鸟与鳞背鸽（Columba squamosa）类似，但后者头部、颈部和胸部有紫色调，且缺乏白顶鸽幼鸟的灰白色额头。","protection":"IUCN：NT（近危）","distribution":"繁殖于巴哈马群岛、古巴、牙买加、安提瓜岛、多米尼加共和国、海地、波多黎各、维尔京群岛、开曼群岛、安圭拉和其他加勒比岛屿。在中美洲沿加勒比海岸线繁殖。在美国，仅限于佛罗里达州南部的佛罗里达群岛、埃弗格莱兹和佛罗里达州南部陆地的最南端。","other":"该物种受到栖息地丧失和狩猎的威胁，特别是在繁殖地的砍伐和非法猎杀。"},{"name":"鳞枕鸽","english_name":"Scaly-naped Pigeon","scientific_name":"Patagioenas squamosa","overview":"鳞枕鸽（英文名：Scaly-naped Pigeon，学名：Patagioenas squamosa），是鸽形目鸠鸽科新大陆鸽属的鸟类。体型较大，羽毛呈暗灰石板色，颈部环绕着独特的紫褐色鳞状斑纹，头部、上颈及胸部带有暗淡的紫色调。广泛分布于加勒比海地区，包括大安的列斯群岛（除牙买加）和小安的列斯群岛，以及库拉索岛、博奈尔岛和委内瑞拉东北部附近的Los Testigos群岛。","appearance":"雄性鳞枕鸽体长约32.5至41厘米，雌鸟略小，体长34至39厘米，体重在250至360克之间。全身羽毛呈现深灰色调，翼羽和尾羽颜色更深，腹部颜色较浅。头部、上颈及胸部带有淡淡的紫灰色，颈后部形成一片紫棕色的盾牌状斑块。颈后部的羽毛带有金属光泽，颜色从紫色渐变为绿色或紫色，边缘呈深棕色，形成鳞片般的视觉效果。虹膜周围有一圈黄色环带，边缘为鲜红色；眼周皮肤为红色；喙基部红色，尖端白色或黄白色；腿部为红色。雌鸟外观与雄鸟相似，但色泽较暗淡。幼鸟羽毛边缘带有淡黄色，成年个体的紫色和酒红色区域在幼鸟身上为红棕色，灰色区域被棕灰色替代。","call":"鳞枕鸽的鸣唱为一系列低沉的咕咕声，通常开始于一个悠长单调的音符，随后是重复的三音符：“whooo...pu-whu-whuh...pu-whu-whuh..pu-whu-whuh...”，有时声音粗糙或简化为：“whooo...pu-whu...pu-whu...pu-whu...”。叫声为低沉的‘rhurrrrrrr’。","habits":"鳞枕鸽栖息于湿润的高地，尤其偏爱雨林环境，但在巴巴多斯等地也能下至干燥的低地。在海地，它们占据高地，而白顶鸽则出现在低地。在城市环境中也有观察到它们的存在，例如巴巴多斯的布里奇敦。它们主要以各种水果、浆果、花蕾、多汁叶片和小型蜗牛为食，种子与果实一同消化。在波多黎各，它们的食物包括多种棕榈树的浆果、野生豆科植物、野生无花果、道德树（Cordia）和美洲金桔（Genipa americana）。","breeding":"繁殖活动一般在水果丰富的季节开始，具体时间因岛屿而异，但在海地和古巴主要集中在3月至6月。筑巢通常在树上，偶尔在灌木、棕榈树、凤梨科植物中，或岩石峭壁上的洞穴和裂缝中，高度可达5米。在荷兰安的列斯群岛，它们可能在红树林和Avicennia中筑巢。有时报告称它们在无人居住的岛屿上直接在地面繁殖。每次产卵1至2枚白色蛋，更多繁殖细节未知。","identification":"鳞枕鸽与铅灰鸽的区别在于其更暗的石板灰色身体，后者明显较淡；与白顶鸽的区别在于后者头部为白色。此外，鳞枕鸽的颈部具有独特的鳞片状斑纹。","protection":"IUCN：LC（无危）","distribution":"鳞枕鸽分布于大安的列斯群岛（除牙买加）和小安的列斯群岛，以及库拉索岛、博奈尔岛和委内瑞拉东北部附近的Los Testigos群岛。","other":"尽管在一些岛屿上数量下降，尤其是在受狩猎压力影响的地区，但全球范围内鳞枕鸽并不面临威胁。"},{"name":"鳞斑鸽","english_name":"Scaled Pigeon","scientific_name":"Patagioenas speciosa","overview":"鳞斑鸽（英文名：Scaled Pigeon，学名：Patagioenas speciosa），是鸽形目鸠鸽科新大陆鸽属的鸟类。这大型热带鸽，以其独特的鳞状羽毛而闻名。雄鸟个体呈红褐色，雌鸟则为灰褐色，两者均具有鲜红色的喙尖和丰富的暗色鳞状花纹。分布于中美洲至南美洲的热带低地森林中。","appearance":"雄性鳞斑鸽体长28-34厘米，体重约262克；雌鸟略小，体长28-32厘米，体重225-350克。头部颜色从紫到红棕色，颈部羽毛黑色带白色末端斑点，边缘有紫色光泽；背部、肩部和翅膀覆羽呈红紫色；上胸和颈后部金棕色，带白色末端斑点和铜金色边缘；下胸和腹部白色，羽毛边缘带有紫棕色；翅膀初级飞羽黑色，最外侧边缘白色；尾部黑色；眼环红色，虹膜浅棕色，外圈蓝色或深紫色；喙鲜红色，尖端白色或淡黄色；腿色从淡紫色到紫红色。雌鸟相似，但背部、臀部、肩羽和小翼羽的紫栗色被较暗的棕色取代，头部侧面不如雄鸟紫棕色，鳞状标记光泽较差。幼鸟比成年个体暗淡，几乎无鳞状纹和斑点；雌鸟幼鸟与雄鸟幼鸟类似，但总体颜色更偏向灰色。","call":"其鸣声是一系列节奏感强烈的低沉单调咕噜声，通常以双音开始，随后是重复的三音符：“pu-whooo...puh-whu-whooh...puh-whu-whooh..puh-whu-whooh...”，有时简化为：“rwhooo...pu-whooh...pu-whooh...pu-whooh...”。叫声是一种低沉的咕噜声，很少被听到。","habits":"鳞斑鸽栖息于热带湿润常绿和半落叶林，森林边缘和有高大树木的开阔地带。在中美洲，它们常见于森林边缘和林间空地；在委内瑞拉，它们出现在雨林边缘、开阔森林和草原地带；在哥伦比亚，也见于河岸森林。在哥斯达黎加，海拔高度可达1200米；在巴拿马西部和哥伦比亚圣玛尔塔山脉，海拔高度可达1524米；在圭亚那，海拔高度可达1070米。它们主要以高树上的小型果实和附生植物为食，偏好梅拉斯托姆（Hirtella）果。它们是树冠层的物种，可能形成多达100只的大群，但在哥斯达黎加的瓦莱德尔将军地区，通常以单个或成对出现。","breeding":"巢由细枝和花序构成，略凹的平台，放置在离地面45-60厘米高的灌木丛中。尽管倾向于在树冠活动，但巢通常位于较低的位置。在特立尼达发现的一个巢位于铁角蕨（Pteridium aquilinum）中，距离地面60厘米。在特立尼达，每窝产2枚卵，但在大陆上产1枚卵。","identification":"雄性鳞斑鸽与雌鸟的主要区别在于颜色和大小，雄鸟红褐色，雌鸟灰褐色，雄鸟略大。与同属的其他物种相比，鳞斑鸽的特征是其独特的鳞状羽毛和红色喙尖。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥南部经中美洲至巴西南部，包括特立尼达岛。","other":"鳞斑鸽在中美洲至南美洲的部分地区由于森林砍伐而数量正在减少。"},{"name":"红头鸽","english_name":"Picazuro Pigeon","scientific_name":"Patagioenas picazuro","overview":"红头鸽（英文名：Picazuro Pigeon，学名：Patagioenas picazuro），是鸽形目鸠鸽科新大陆鸽属的鸟类。大型鸽子，原生于南美洲，常见于多种生境，包括城市到草原和轻型林地。其显著特征为紫色至灰色的鳞状体羽和颈侧的银色斑块。该物种分布广泛，已知在阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭均有记录。","appearance":"体长约34厘米，重约402克。头部、颈背和上胸部呈粉紫色，逐渐变淡至腹部。两胁、尾上覆羽、尾下覆羽和翼下覆羽为深蓝灰色。背部、颈侧和上背覆羽具虹彩黑色边缘，形成鳞片状外观，单个羽毛有绿银色亚端带。下背、内侧次级飞羽和内侧翼覆羽为暗棕色，羽缘较浅。闭合翼可见白色线纹，因外侧大覆羽和中覆羽的蓝灰色羽毛带有白色边缘，展翅时显现为白色带。尾羽为深蓝灰色，末端有不明显的黑色带。虹膜颜色从橙色到红色不等，眼周皮肤红色，混有粉末状白色。蜡膜白色，喙基部深红色，尖端黄色。腿为深红色。雌鸟比雄鸟更灰暗，头顶呈灰色，雄鸟的下胸部和下体的紫色被淡黄褐色替代。幼鸟类似雌鸟但更暗淡，颈部背面的斑点不明显。边际亚种体型较小，上体颜色更淡，尤其是臀部和尾上覆羽；翼覆羽有更宽的白色边缘；下体有玫瑰色调。","call":"鸣唱为一连串单调的咕咕声，通常以单一音符开始，随后是重复的三音符：\"rwhoooh...puh-whu-whooo...puh-whu-whooo..puh-whu-whooo...\"。叫声为重复的双音节\"rrrrr-whuh\"，首音节非常含糊。","habits":"栖息于林地、树丛和河岸森林；亦见于巴西东北部的干燥灌木植被区，以及阿根廷的耕作区。容易入侵砍伐区域，已开始利用城市区域。常在地面活动。食物包括种子、花蕾、浆果和嫩叶，偶尔吃昆虫。既在地面觅食也在树上。","breeding":"在巴西南部记录于10月和12月繁殖；在阿根廷全年均可繁殖。在树或灌木上筑典型的鸽巢。通常每窝仅产一枚（白色）蛋，但也有报道产两枚。无更多信息。","identification":"与珠颈斑鸠相似，但具有独特的颈背白色条纹和深色翼纹。边际亚种与普通亚种的区别在于体型较小，上体颜色更淡，翼覆羽的白色边缘更宽。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲东南部，包括阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭。在巴西和阿根廷的部分地区，随着持续的森林砍伐，其分布范围正在扩大。","other":"据报道，在巴西部分地区作为农作物害鸟而受到毒杀，但其受迫害的全面程度尚未确定。"},{"name":"裸眶鸽","english_name":"Bare-eyed Pigeon","scientific_name":"Patagioenas corensis","overview":"裸眶鸽（英文名：Bare-eyed Pigeon，学名：Patagioenas corensis），是鸽形目鸠鸽科新大陆鸽属的鸟类。具有独特的外观，最显著的特征是围绕橙棕色眼睛的大片裸露皮肤，呈现出蓝灰色调。这种鸽子主要分布在南美的哥伦比亚和委内瑞拉的加勒比海岸，以及附近的阿鲁巴岛、库拉索岛、博内尔岛、玛格丽塔岛和布兰基利亚岛。","appearance":"雄性裸眶鸽长度约为32至37厘米，雌鸟略小，为30至34.5厘米，体重约274克。头部、颈部和胸部呈淡紫色，头部顶部带有蓝灰色调。下巴、腹部区域和尾下覆羽为白色。颈背的羽毛边缘带有粉红青铜色的黑色条带，后跟淡棕色边缘，形成鳞状效果。闭合的翅膀边缘有一大片白色斑块，由白色边缘的外翼覆羽和次级飞羽内部构成。下背部、臀部和上尾覆羽为浅蓝灰色；初级飞羽和外侧次级飞羽为黑色，边缘狭窄的白色。虹膜橙色到橙棕色；眼周突出的裸露皮肤为红棕色，内环为蓝色；喙粉色；腿红色。两性相似，幼鸟颜色较淡，较为暗淡，后颈有苍白的亚端横纹。","call":"其鸣唱是一系列节奏性的咕咕声，通常以嘶哑单调的单音开始，随后是重复的相对高音的三音符，最后一个音符明显拖长，听起来像是'rwhoh...woh-hu-whOAh...woh-hu-whOAh..woh-hu-whOAh...'。","habits":"裸眶鸽主要栖息在干旱低地，但有时会在哥伦比亚和委内瑞拉升高至400米的高度。它们生活在刺灌丛、仙人掌（尤其是管风琴类型）和金合欢树的环境中；同时也在红树林和耕作区中找到它们的身影。在库拉索岛和博内尔岛上，它们与鳞枕鸽共存，但后者倾向于占据高地。","breeding":"繁殖似乎由雨水触发；在库拉索岛和博内尔岛上的记录显示，一月、三月和四月有发现带蛋或幼鸟的巢穴。巢是一个脆弱透明的枝条平台，非常薄以至于可以从下面看到蛋，位于树或灌木中；在荷兰安的列斯群岛，红树林、金合欢树或密集的刺灌丛是典型的筑巢地点。每次产一枚白色蛋。幼鸟在5个月大时即可繁殖。","identification":"在干燥地区的范围内，它是唯一具有白色翼斑的鸽子，这有助于与同类物种区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在哥伦比亚和委内瑞拉的加勒比海岸以及附近岛屿，包括阿鲁巴岛、库拉索岛、博内尔岛、玛格丽塔岛和布兰基利亚岛。"},{"name":"斑翅鸽","english_name":"Spot-winged Pigeon","scientific_name":"Patagioenas maculosa","overview":"斑翅鸽（英文名：Spot-winged Pigeon，学名：Patagioenas maculosa），是鸽形目鸠鸽科新大陆鸽属的鸟类。广泛分布于南美洲的大型灰褐色鸽子。其最显著的特征是翅膀上独特的淡色斑点，以及灰色的眼睛。斑翅鸽在安第斯山脉的鸟类中具有明显的白色翼带，飞行时尤为显眼。该物种在东部低地与红头鸽有所区别，后者具有琥珀色的眼睛、粉色的胸部和白色的翼带。","appearance":"成年斑翅鸽体长32-34厘米，体重约308-347克。头部、颈部、臀部和整个下体呈蓝灰色，带有紫色调，尤其在雄鸟中更为明显。背部和翅膀覆羽为灰棕色，每根羽毛边缘有乳白色三角斑点，形成斑点效果。最外侧的大次级飞羽为蓝灰色，外缘为白色。初级飞羽和次级飞羽黑色，有狭窄的白色边缘。下翼面为浅灰色。背部、臀部和上尾覆羽为蓝灰色，部分羽毛顶端较淡。尾巴为深灰色，末端有不显眼的黑色带纹。虹膜颜色可变，从灰色到白色。喙为黑色至暗灰色，基部为白色。腿红色。雌雄相似，但雌鸟的头部和颈部通常较暗淡。幼鸟全身较暗，头部和胸部为暗灰色。","call":"鸣声为粗犷的连续吼叫声，通常开始时音调较低，随后重复三音节的“rrrrrow grr-g’RRRR grr-g’RRRR grr-g’RRRR”。此外，还会发出短暂的“corw”声和在地面展示时的低沉声音。","habits":"斑翅鸽常见于半开放的生境，从城市公园到安第斯山脉的灌木斜坡都有它们的身影。它们栖息于海拔2000至4200米的安第斯山脉斜坡，从秘鲁中部到玻利维亚西部和阿根廷西北部，以及智利北部的阿里卡和帕里纳科塔。在低地，它们可达海拔至少1000米，特别是在阿根廷的卡塔马卡和拉里奥哈。它们常在小群或成对出现，有时会形成大群，经常与红头鸽相伴。主要以种子为食，包括稻谷和向日葵，偶尔食用果实和绿叶。被视为向日葵作物的害虫。","breeding":"繁殖季节在巴西记录于10月、11月、2月和5月，但在阿根廷可能全年繁殖。雄鸟会在缓慢的翼拍下进行展示飞行。巢筑于树上，结构脆弱，直径约13-15厘米，位于刺丛或豆科树木中，离地1.5-3米。每次产1-2枚白色卵，大小约为39-42毫米×28-29毫米。雏鸟有长而淡棕色的毛状绒羽，喙非常大。","identification":"与红头鸽相比，斑翅鸽具有更粗糙的叫声和不同的饮食偏好。在外观上，斑翅鸽有明显的白色翼带，而红头鸽没有。此外，斑翅鸽的栖息高度通常高于红头鸽。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中部至东南部巴西和阿根廷中南部，包括玻利维亚东南部、巴拉圭、乌拉圭和阿根廷的圣克鲁斯。在智利，发现于阿塔卡马地区和塔拉帕卡地区，包括Putre、Azapa、Belen等地，记录于除五月和八月外的所有月份。","other":"斑翅鸽可能因安第斯山脉内种植园树木的增加而数量有所增长。在阿根廷，它正在扩大其分布范围，尤其是在攻击向日葵作物方面，被视为农民的害虫。"},{"name":"北斑尾鸽","english_name":"Band-tailed Pigeon","scientific_name":"Patagioenas fasciata","overview":"北斑尾鸽（英文名：Band-tailed Pigeon，学名：Patagioenas fasciata），是鸽形目鸠鸽科新大陆鸽属的鸟类。体型较大，广泛分布在从北美到南美的成熟森林地带，自不列颠哥伦比亚省至阿根廷西北部。其特征为蓝色灰上部，紫色灰下部，颈背有独特的白色新月标记，足黄色。分布于美国西部山地、墨西哥至南美洲，包括太平洋海岸和内陆山区。","appearance":"体长33至40厘米，平均体重342至364克，头部呈紫灰色，颈背具白色新月形斑纹，由绿色青铜色羽毛环绕，上部暗边形成鳞片状图案。上体灰至棕灰色，下体淡紫色至灰白色，尾基部暗灰，尖端淡灰至灰棕色，翼覆羽稍淡，具白色边缘。喙黄色，黑尖（哥斯达黎加以南全黄），足黄色。雌雄相似，但雌鸟颜色较暗，白色新月较窄，颈后虹彩较少。","call":"发出一系列低频两音节咕咕声，可在密林中传播至300米。","habits":"栖息于成熟森林，尤其是针叶林区，以种子和果实为食，迁徙时翅膀拍打声音响亮。夏季常访问富含矿物质的水源。","breeding":"繁殖季节长，可能全年皆可，一般一窝产一蛋，有时完成三轮繁殖周期。巢为简单的树枝层叠，双亲共同孵化及喂养雏鸟，雏鸟食用双亲胃中的乳状物质。","identification":"与岩鸽相比，尾部较短，体态更紧凑，羽色更均匀，通常可见白色臀斑，尾尖有暗带而非基部，喙全黑，脚粉色。红喙鸽虽体型相似，但全身较暗，无颈后白带，尾部深色，翼覆羽无白色边缘，喙全黄无黑尖。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西南部四州至墨西哥中部，以及从阿拉斯加南部至巴哈加州北部的太平洋海岸区域。冬季迁徙至墨西哥，加州中部和南部。","other":"历史上曾被大量猎杀，目前在美国六个州和墨西哥南部持续狩猎。自1966年以来，北美种群数量年均下降2.8%。"},{"name":"智利鸽","english_name":"Chilean Pigeon","scientific_name":"Patagioenas araucana","overview":"智利鸽（英文名：Chilean Pigeon，学名：Patagioenas araucana），是鸽形目鸠鸽科新大陆鸽属的鸟类。大型森林鸽。其分布区域主要集中在智利和阿根廷西部的温带雨林地带，常见于农田旁的树林及干燥灌木丛中。整体外观暗沉，具独特的白色颈圈、亮红脚色和宽广的灰色尾尖。与广泛分布于人类聚居区的岩鸽相比，智利鸽更少出现在人群中。","appearance":"成年智利鸽体型庞大，体长约35至37厘米，体重介于220至340克之间。雄鸟主体呈深紫红色，颈背部分有绿色金属光泽，上颈有一窄白环。尾羽灰黑相间，末端泛淡灰。雌鸟颜色稍暗淡，偏棕色。幼鸟全身均匀的灰褐色，翅膀、臀部及尾羽蓝灰色。","call":"发出一系列深沉的‘hoos’音节，如‘hooo-HOOOO hooo-HOOOO hooo-HOOOO...’，声音浑厚而略带沙哑。","habits":"主要栖息于南部的温带森林，偏好Araucaria和Nothofagus树种为主的森林环境。在北方较干燥的森林地带也能找到它们的身影。以果实为主食，偶尔在开阔地带觅食种子。","breeding":"繁殖季节从12月持续至次年3月，有时延续至5月。通常成群繁殖，可达数百对，筑巢于森林深处，尤其是竹林密集处。巢由松散的枝条搭建，单产一枚蛋。","identification":"与同属的北斑尾鸽相似，但后者分布范围不重叠，且色彩更偏向紫色。两者在形态上的区别在于智利鸽的颈圈和尾部特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，主要集中在智利和阿根廷西部，从Coquimbo地区南至Aysén地区。","other":"智利鸽的觅食习性和迁徙模式尚未得到充分研究，但在冬季会形成较大群体，出现在低海拔的开阔地带。"},{"name":"环尾鸽","english_name":"Ring-tailed Pigeon","scientific_name":"Patagioenas caribaea","overview":"环尾鸽（英文名：Ring-tailed Pigeon，学名：Patagioenas caribaea），是鸽形目鸠鸽科新大陆鸽属的鸟类。主要分布于牙买加的约翰克劳山脉、东部蓝山和Cockpit Country，偏好湿润的高地森林及石灰岩森林环境。","appearance":"成年雄性环尾鸽长度介于38至48.5厘米，雌鸟则在38至43厘米之间，体重可达250克。头部、颈部及下体呈暗红到粉红色，颈后有金属绿或青铜色斑块，上体其余部分为褐色。尾羽基部灰色，靠近身体处颜色加深，中央有一条石板色带。雌鸟翅膀带有橄榄绿或棕色调，下体更偏红色，颈后金属光泽较弱。幼鸟全身以灰色为主，腹部转为浅黄至肉桂色。","call":"环尾鸽的广告叫声由一系列4至5个咕咕声组成，每音节持续约1秒，音节间停顿约0.75秒，通常为双音节，音高和音量在后半部分升高，如“cooOOh...cooOOh...cooOOh...”。","habits":"栖息于牙买加湿润的高地森林，海拔高度可达2000米。秋季和冬季会从高地降至150至300米的低海拔地区。以新鲜水果为食，常在树梢或倒挂姿态下觅食，食物种类包括本地及外来植物的果实。","breeding":"春季和夏季繁殖，巢为厚实的枝条平台，内部铺有叶子、树皮和小枝，筑于大树顶部，隐蔽于攀缘植物之中。","identification":"环尾鸽的独特之处在于其带有石板色带的尾羽，与同域的其他鸽子如平鸽明显不同，后者具有红色肩部和白色翼纹。","protection":"IUCN：VU（易危）。由于过度猎杀和栖息地丧失，尤其是近150年来，数量急剧减少。目前面临的主要威胁是Cockpit Country的铝土矿开采，对西部中心牙买加的重要种群构成威胁。","distribution":"仅分布于北美牙买加，特别是在John Crow Mts、Blue Mts东部和Cockpit Country。","other":"历史上曾被列为极危物种，现因各种威胁仍处于易危状态。"},{"name":"淡腹鸽","english_name":"Pale-vented Pigeon","scientific_name":"Patagioenas cayennensis","overview":"淡腹鸽（英文名：Pale-vented Pigeon，学名：Patagioenas cayennensis），是鸽形目鸠鸽科新大陆鸽属的鸟类。广泛分布于中美洲至南美洲的热带区域。其灰头与粉红体色形成鲜明对比，白肚与灰尾融合自然，黑喙独特。常见于沼泽草原、河畔及开阔地带，甚至城镇，如墨西哥的Villahermosa。","appearance":"淡腹鸽体型较大，整体呈淡紫色，上翼覆羽带锈色，头部灰色，喉部白色，下腹及尾下覆羽特征性地呈现白色。初级飞羽黑色，尾羽灰色，末端有一略浅色的横带。虹膜橙红至红橙色，眼周裸皮暗至蓝灰色，喙黑色，跗跖和趾红色。","call":"其鸣叫特征为一系列重复的三音符咕咕声，先是一串长长的引子，随后重复的短语通常为三音节的“who’koo-koo”，与四音节的红嘴鸽“oo’koo-koo-koo”有所不同。","habits":"栖息于湿润低地森林边缘，偏好较为开阔的生境，如森林边缘、森林斑块在开阔地带及河岸环境。以浆果为主要食物，常单独或成小群觅食，尤其在结果树附近。","breeding":"繁殖季节在林中小树或灌木上筑巢，通常产一枚白色卵。繁殖行为包括半圆形滑翔回巢的展示。","identification":"与短嘴鸽、赤鸽、铅灰鸽及红嘴鸽在颜色和生境偏好上有显著差异，后者更倾向于完整森林。","protection":"IUCN：LC（无危）","distribution":"从墨西哥南部延伸至阿根廷北部，包括中美洲和南美洲大部分地区。在地理分布上，分为繁殖区与非繁殖区，主要栖息于热带森林边缘。","other":"淡腹鸽与同属其他物种在地理分布上重叠，但通过颜色、生境偏好和叫声可明确区分。"},{"name":"红嘴鸽","english_name":"Red-billed Pigeon","scientific_name":"Patagioenas flavirostris","overview":"红嘴鸽（英文名：Red-billed Pigeon，学名：Patagioenas flavirostris），是鸽形目鸠鸽科新大陆鸽属的鸟类。体型较大、羽色暗淡的鸽子，们拥有蓝灰色的身体和翅膀，颈肩部呈酒红色，最显著的特征是带有黄色尖端的红色喙。红嘴鸽分布于墨西哥至哥斯达黎加的低地和山脚地带，偶尔进入美国南部德克萨斯州的里奥格兰德河谷。","appearance":"成年红嘴鸽体长约30至37厘米，体重约250克。全身主要为暗灰或蓝灰色，颈部和肩部呈暗褐色，腹部和下体为浅灰色。头部、颈部和胸部颜色为紫红色或暗红紫色。尾巴颜色较深，呈暗石板灰色至灰黑色。虹膜橙色到红色，眼睑红色；喙基部红色，末端黄色；腿和脚为暗红色。雌雄外观相似，但雌鸟较为暗淡，头部、冠部、胸部和小覆羽带棕色调。幼鸟像雌鸟，但仅在颈背有淡淡的紫色，前部更淡，上翼覆羽和次级飞羽边缘带有淡棕色，形成鳞状外观。","call":"红嘴鸽的叫声独特，为一系列长而高音的‘coooo’声后跟三个‘cuk-c'-c'-coo’音符，声音上升。","habits":"红嘴鸽常见于墨西哥和中美洲沿海和低地的干燥森林中，尤其是在里奥格兰德河区域。它们在夏季期间偶尔出现在美国南部德克萨斯州，冬季时则较为罕见。红嘴鸽栖息于各种生境，包括开放森林、零星农田和红树林。","breeding":"红嘴鸽的繁殖习性研究较少，一般单卵繁殖，筑巢于树上。在南部分布区，它们栖息于半干旱低地，海拔可达2130米。在德克萨斯州的繁殖个体主要观察到在沿里奥格兰德河的林地，由光皮柏、墨西哥梣、得克萨斯糖胶树、得克萨斯乌木和黑柳组成。","identification":"红嘴鸽与原鸽大小相近或略小，但原鸽尾巴相对较短，体型更壮实，羽毛图案不均匀，通常有白色臀部斑块和尾尖深色带。与北斑尾鸽相比，红嘴鸽整体颜色更深，有白色颈带，尾部宽大浅灰色，翼覆羽有白色边缘，喙黄色带黑色尖端，脚黄色。与短嘴鸽相比，红嘴鸽体型较小，羽毛颜色更深，尾巴较短，喙色较暗。与淡腹鸽相比，红嘴鸽头蓝色，腹部和下体覆羽白色。","protection":"IUCN：LC（无危）","distribution":"红嘴鸽广泛分布于中美洲，从墨西哥南部至哥斯达黎加，包括美国南部德克萨斯州的里奥格兰德河谷。在繁殖季节，它们主要出现在沿海和低地的干燥森林。","other":"红嘴鸽的生物学特征与带尾鸽相似，有时在墨西哥东北部和中部与其共存，但红嘴鸽生活在较低海拔，而带尾鸽通常栖息在较干燥的山地森林。"},{"name":"秘鲁鸽","english_name":"Maranon Pigeon","scientific_name":"Patagioenas oenops","overview":"秘鲁鸽（英文名：Maranon Pigeon，学名：Patagioenas oenops），是鸽形目鸠鸽科新大陆鸽属的鸟类。大型、锈色的鸽子，主要分布在南美洲的秘鲁西北部马腊翁河流域。在极端南部厄瓜多尔可能也有分布，但证据不足。其最显著的外部特征是全身大多呈红褐色，腹部、肩部和臀部为灰色，喙基红色，眼环红色，眼黄色至橙色。","appearance":"雄性秘鲁鸽约34厘米长，雌鸟略小，介于31至34厘米之间，体重约276克。头部、颈部和胸部为暗淡的红紫色，背部和翅膀上覆羽为蓝灰色至深灰色，带有紫栗色调。下体呈浅灰色，尾巴深灰色。眼睛黑色，周围有橙色和蓝色环，裸露的蓝灰色皮肤环绕眼周。雌鸟和幼鸟颜色较暗淡，偏棕色。","call":"其鸣叫为一系列有节奏的咕咕声，通常以单音开始，随后是重复的三音节：'rwhoOoh...pUh-hu-whoOOo...pUh-hu-whoOOo...'。","habits":"秘鲁鸽栖息于河流附近的林地和沙漠地带，偏好沿水道的森林，如大型柳树（Salix humbertiana）和胡椒树（Schinus molle）为主的河岸森林，也倾向于干燥森林，由Ceiba、仙人掌和多种豆科植物，包括金合欢（Acacia）所主导。它们季节性地在不同的海拔高度间移动，从850米的Balsas到Malca的2400米。","breeding":"关于秘鲁鸽的繁殖生态知之甚少，仅有一份记录显示在4月采集到了一只幼鸟。","identification":"与较为常见的淡腹鸽相比，秘鲁鸽具有红色的喙基，缺乏苍白的尾带，且下体颜色与腹部一致，不更浅。","protection":"IUCN：NT（近危）。栖息地的丧失和退化正导致其范围和小种群数量下降。","distribution":"秘鲁鸽的分布范围限于南美洲的极端东南部厄瓜多尔和秘鲁北部，具体从马腊翁河上游谷地向南延伸至La Libertad省。","other":"物种被归类为新大陆鸽属，与红喙鸽（P. flavirostrus）和纯色鸽关系密切，可能构成超物种复合体。"},{"name":"纯色鸽","english_name":"Plain Pigeon","scientific_name":"Patagioenas inornata","overview":"纯色鸽（英文名：Plain Pigeon，学名：Patagioenas inornata），是鸽形目鸠鸽科新大陆鸽属的大型鸟类。其主要特征是淡蓝灰色外观，头部、颈背、胸部及部分折叠翅膀呈现酒红色调，翼端有一条醒目的白色边线。分布于古巴、多米尼加、海地、牙买加和波多黎各等大安的列斯群岛。","appearance":"雄性纯色鸽长约41厘米，雌鸟略小，约39厘米，体重在250至365克之间。头部、颈部和大部分下体呈酒红色，头部颜色稍深，前额较灰。背部、肩羽、外侧小翼羽为灰褐色，边缘白色。臀部、尾上覆羽、两胁及尾下覆羽为蓝灰色。尾羽暗灰色。虹膜有浅蓝色环包围着深蓝色环，随后是橙色环。眼周皮肤灰色，喙和蜡膜黑色，腿脚红色。雌鸟颜色较浅且暗淡。幼鸟全身灰褐色，腹部更浅，翅膀覆羽和胸羽有窄的淡色边缘。","call":"其鸣唱为一系列咕咕声，通常以单音开始，随后是重复的双音节：“whoOo...pUh-whoOOo...pUh-whoOOo...pUh-whoOOo...”。","habits":"纯色鸽栖息于多种生境，偏好低地森林、红树林和沼泽地带。在古巴，它主要出现在低地森林、红树林和沼泽区，同时也可见于特立尼达山脉和纳贾萨山脉。在多米尼加和海地，它们居住在高地松林和阔叶林，也出现在干燥沿海沙漠和红树林。在牙买加，它们占据高山雨林，但每日会飞往低地觅食。在波多黎各，它们曾经是低地森林的常客，现在主要生活在次生植被区域，包括本土和外来植物群落，以及农田和牧场。","breeding":"繁殖记录在古巴为4月、5月和7月，在多米尼加和海地为4月至7月，而波多黎各似乎全年都可繁殖，高峰期为12月至6月。巢筑于树上，如红树林、松树或硬木树，高度6至21米。巢穴大多位于成熟的竹林中，少数在其他各种树木中。每窝产一枚蛋（在波多黎各）或两枚（在其他地方）。孵化期13至15天，雏鸟离巢期21至23天。","identification":"与类似物种如环尾鸽相比，纯色鸽的肩部呈红棕色，尾部无环带，且体型更大。白顶鸽和鳞枕鸽颜色更深。与白翅哀鸽相似，但后者翅膀上的白色标记更亮，体型较小。","protection":"IUCN：NT（近危）。全球数量估计在1,500至6,100只之间。在海地数量尚可，但在古巴、波多黎各和牙买加面临严重威胁。非法狩猎和栖息地破坏是主要的威胁。","distribution":"分布在古巴、多米尼加共和国（海地）、牙买加和波多黎各。在古巴，主要分布在低地森林、红树林和沼泽地带。在多米尼加共和国和海地，常见于高地松林和阔叶林，也出现在干燥沿海沙漠和红树林。在牙买加，占据高山雨林，但每日会飞往低地觅食。在波多黎各，主要生活在次生植被区域，包括本土和外来植物群落，以及农田和牧场。","other":"在1970年代，亚种P. i. wetmorei曾濒临灭绝，通过保护计划，现数量恢复到几千只。"},{"name":"铅灰鸽","english_name":"Plumbeous Pigeon","scientific_name":"Patagioenas plumbea","overview":"铅灰鸽（英文名：Plumbeous Pigeon，学名：Patagioenas plumbea），是鸽形目鸠鸽科新大陆鸽属的鸟类。主要栖息于南美的热带和亚热带森林内部，分布自哥伦比亚至巴西东南部。其外观整体呈紫灰色，翼部略深且带棕色，与其它鸽子相比，尾巴较长，外表较为朴素。","appearance":"铅灰鸽体长约34厘米，体重介于172至231克之间。头部、颈部和下体通常为深灰色，有时带有粉红或紫色调；喉部颜色较浅，常为淡奶油色；背部、肩部、臀部、翅膀和尾巴为深灰褐色至暗橄榄色。虹膜红色，眼周皮肤呈紫红色；喙黑色，脚红色。雌雄相似，但雌鸟的紫色调不如雄鸟明显，颈斑更显眼。幼鸟色泽较暗淡，紫色调显著减少，翼覆羽和胸部羽毛边缘锈色。","call":"其鸣唱为重复的2至5声咕咕声的节奏性短语，与赤鸽的声音类似但有区别。叫声为一种拉长、轻微滑音的‘rrrrrow’。","habits":"生活在热带和亚热带雨林及云雾林中，有时也会出现在次生林。在奥里诺科河以北，海拔范围在1200至1900米之间，而河以南则在200至300米。在巴西东南部，会进行季节性的海拔迁移。主要在森林树冠层觅食，以果实和种子为食，尤其在某些时期大量食用槲寄生。","breeding":"关于繁殖生态的信息尚未研究清楚。","identification":"与赤鸽最为相似，但铅灰鸽的羽毛颜色偏灰而非红色，眼睛颜色较浅。不同的亚种在上体的紫色或深棕色紫色调上有差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布在南美洲，从哥伦比亚到巴西东南部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拿马、巴拉圭、秘鲁、苏里南和委内瑞拉。","other":"存在五种明显的声学群体，暗示可能涉及不止一个物种。"},{"name":"赤鸽","english_name":"Ruddy Pigeon","scientific_name":"Patagioenas subvinacea","overview":"赤鸽（英文名：Ruddy Pigeon，学名：Patagioenas subvinacea），是鸽形目鸠鸽科新大陆鸽属的鸟类。广泛分布于中美洲至南美洲亚马逊雨林区域。其整体呈酒红至紫红色，背部更偏棕红色。该物种属于新大陆鸽属，与旧世界鸽子在分类上已分离。雌雄外观相似，雄鸟略大。","appearance":"赤鸽长约28厘米，重约170克，全身无明显斑纹，主要呈现酒紫色，背部色调更偏红棕色。尾羽与初级飞羽深褐色，喙黑色，腿脚紫红色。雌鸟颜色稍暗淡，头部、颈部和胸部灰色带些微的肉桂色或红棕色鳞状花纹。幼鸟头部、颈部和胸部灰褐色，头和上体有肉桂色或红棕色的边缘。","call":"赤鸽发出响亮且音调较高的咕咕声，ko'COO coo，各叫声间有显著停顿，与其近亲类似。叫声在地理上有变异性，部分群体会发出四音节的歌曲，而其他则为三音节。","habits":"栖息于中高海拔森林的树冠层，偏好云雾森林环境，分布高度从近海平面到1500米，偶尔可达更高。以水果为食，特别喜爱槲寄生果实，常在树顶觅食，也会在路旁寻找砾石。","breeding":"繁殖期记录在哥伦比亚为4月至6月及8月，筑巢于离地面5米高的小树上，以粗枝搭建平台巢，每窝产一枚白色蛋，关于繁殖的更多信息尚缺。","identification":"与短嘴鸽极为相似，但可通过叫声区分，赤鸽的叫声更快且复杂程度较低。在中美洲，短嘴鸽在低海拔地区取代了赤鸽。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加至南美洲亚马逊雨林区域，包括哥伦比亚、委内瑞拉、巴西的马托格罗索和马拉尼昂等地。","other":"虽然广泛分布，但由于预计的森林砍伐，被列为易危物种。在多个保护区中出现，包括一些大型和孤立的保护区。"},{"name":"短嘴鸽","english_name":"Short-billed Pigeon","scientific_name":"Patagioenas nigrirostris","overview":"短嘴鸽（英文名：Short-billed Pigeon，学名：Patagioenas nigrirostris），是鸽形目鸠鸽科新大陆鸽属的鸟类。体型较大的鸽类，主要栖息于中美洲至南美洲西北部的热带低地雨林中。其羽毛呈深褐色，头部、胸部及腹部带有粉红色调，最显著的特点是其较短的黑色喙。常在树冠层活动，难于直接观察，但其远距离传播的‘呼库库库’歌声往往能帮助定位其位置。","appearance":"短嘴鸽的雄鸟个体长度约27至31厘米，雌鸟则稍小，约为26至29厘米，体重介于128至236克之间。上身颜色为橄榄棕色或深紫棕色，比赤鸽赤鸽更暗。头部、颈部和胸部的羽毛边缘呈锈红色，全身羽毛较为暗淡，尤其是幼鸟，其上体羽毛边缘带锈色，头部、颈部和胸部的羽毛边缘更宽大，呈现出锈红色。","call":"其叫声为重复的四音节节奏，‘呼…扑呼…呼呼’，其中第二个音节通常带有下滑音，首二音节间停顿最长。整个四音节的长度大约为1.5秒。","habits":"短嘴鸽主要栖息在湿润的低地森林中，偶尔会下降到地面觅食，如在哥斯达黎加，它们会接近地面食用大量存在的毒葛果。它们主要在树冠层至中间层觅食，以果实和浆果为主食，也会在地面上寻找砂石和小型无脊椎动物。","breeding":"繁殖季节在哥斯达黎加为三月和八月，在巴拿马西北部为六月，在哥伦比亚北部为一月。它们会建造由枝条和干枯花序组成的巢台，位于5至30米高的树上或浓密藤蔓缠绕的次生林中，每次产一枚白色蛋。","identification":"与赤鸽相似，但喙较大且粗壮，背部颜色更深，雌鸟可能难以区分，但通常较为暗淡，幼鸟全身更暗，上体羽毛边缘带有锈色。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东南部至哥伦比亚西北部，主要栖息在低地森林树冠层和半开放的林地。","other":"在中美洲低地森林中常见，但在哥伦比亚的分布较为边缘化。"},{"name":"乌鸽","english_name":"Dusky Pigeon","scientific_name":"Patagioenas goodsoni","overview":"乌鸽（英文名：Dusky Pigeon，学名：Patagioenas goodsoni），是鸽形目鸠鸽科新大陆鸽属的鸟类。主要分布在南美的哥伦比亚西部和厄瓜多尔西北部，外观灰褐色，头部和胸部呈灰色，颈背带有紫色光泽。","appearance":"乌鸽约24厘米长，整体颜色较为暗淡，以灰褐色为主，头部、喉咙和胸部呈灰或紫灰色，颈部灰色并带有紫色光泽。肩部、背部和臀部橄榄棕色或深紫棕色，翅膀和尾巴为青铜灰色，有时带紫色光泽。眼睛颜色多样，可为多种红色调。","call":"其鸣声为重复的三音节高音咕咕声，前两音节较长且较高，后一音节短促，类似“whoah..pup..pup”。还发出一种拉长的类似低吼的叫声。","habits":"乌鸽栖息于雨林地带，通常在低地，但也可见于高达1,500米的山地。关于其迁徙、飞行特点、活动范围和觅食方式的具体信息尚未公布。","breeding":"已知在哥伦比亚，乌鸽的繁殖季节可能在1月至5月以及8月，但关于其繁殖行为的详细信息尚待研究。","identification":"与赤鸽相比，乌鸽头部和胸部的颜色更偏向灰色，翼下的红褐色更为明亮且范围更广。可以通过鸣叫声来最容易地区分两者。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部（从中部阿特拉托河至塞拉尼亚德博杜山脉南部）到厄瓜多尔西北部（南至帕伦克河）。","other":"乌鸽在其分布区内局部常见，但由于其生境信息较少，对其生物学特性了解甚少，需要进一步的研究。"},{"name":"马岛斑鸠","english_name":"Malagasy Turtle Dove","scientific_name":"Nesoenas picturatus","overview":"马岛斑鸠（英文名：Malagasy Turtle Dove，学名：Nesoenas picturatus），是鸽形目鸠鸽科粉红鸽属的鸟类。大型鸠鸽科鸟类，体型壮实，尾羽末端具显著白色斑点。常见于马达加斯加、毛里求斯、印度洋领土、科摩罗群岛、留尼汪、塞舌尔等地，亦可能被引入查戈斯群岛。头部蓝灰色，背部带有紫色或绿紫色光泽，尾部灰蓝色，翼下覆羽暗棕色，翼羽边缘呈红棕色，腹部灰白至淡黄色。雌鸟色彩较淡，幼鸟全身灰褐，上体羽毛边缘呈栗色或红棕色。","appearance":"体长约28厘米，体重146至188克。头部蓝灰色，颈部两侧与背侧有略带虹彩的紫粉色或绿紫色羽毛，基部黑色，羽毛略分叉。颈部与胸部呈深粉紫，逐渐过渡到翅膀与肩部的更深的红紫色。腹部颜色从灰色到淡黄色。翅膀大覆羽暗棕色，有紫红色晕染。次级飞羽与初级飞羽暗棕色，每根羽毛边缘有狭窄的红棕色边缘。臀部和尾上覆羽深蓝灰色，有时混有棕色。中央尾羽暗灰棕色，外侧尾羽灰黑，有宽阔的白色终端带。雌鸟较暗淡，翼覆羽上的紫红色覆盖面积较小，尾羽终端带颜色更深的灰色。幼鸟通体灰褐，胸部和上体羽毛边缘有栗色或红棕色边框。","call":"广告叫声为一系列空洞上升的“hoooo”音符，每个音符之间有短暂停顿，如“cu...cooooOOh.....cu.. cooooOOh.....”。飞行叫声由短促的鼻音组成，如“neh-neh-nyeh-neh”。","habits":"栖息于各种森林类型和退化生境中的木本植被区，包括退化林地、农田和人类居住地附近的树林。在马达加斯加，从海平面至2000米海拔均有分布。以种子为主食，也吃落地果实和部分无脊椎动物；在塞舌尔，食用蓖麻和蓖麻树的种子；在椰子烘干机上也可见其啄食椰肉。主要在地上觅食，偏好无密覆盖的林地，也会出现在小径旁和林间空地。","breeding":"繁殖期在马达加斯加为7月至次年2月，在科摩罗群岛为10月至11月。巢为平盘状，由交错的枝条构成，位于离地面1.5至5米高的树杈或灌木丛中；在塞舌尔，常在卡苏里纳树上筑巢；在阿尔达布拉，有时在红树林中筑巢。每次产2枚白色蛋。","identification":"粉红色和赤褐色的羽毛色泽不同于其分布范围内任何其他鸽类。与近缘种粉红鸽相比，马岛斑鸠的色彩更为丰富，体型更大。","protection":"IUCN：LC（无危）","distribution":"主要分布在马达加斯加区域，包括毛里求斯、印度洋领土、科摩罗群岛、留尼汪、塞舌尔等。可能被引入查戈斯群岛（西印度洋）。","other":"一些岛屿近缘种或亚种面临威胁，甚至已经灭绝，如罗德里格斯蓝鸠已灭绝，而纯种亚种rostrata在塞舌尔正因外来种的基因入侵而受到威胁。"},{"name":"罗岛蓝鸠","english_name":"Rodrigues Pigeon","scientific_name":"Nesoenas rodericanus","appearance":"罗德里格斯蓝鸠的体型类似于白胸森鸠，整体呈灰蓝色，颜色均匀，给人一种温和的印象。它们的体态丰满，与常见的鸽子大小相仿，具有鸽类典型的圆润身形。","habits":"罗德里格斯蓝鸠偏好在岛上活动，它们在陆地上觅食，尤其喜爱瓜类种子。它们在远离鼠患的离岸小岛上筑巢，以避免天敌的侵扰。","breeding":"关于罗德里格斯蓝鸠的繁殖细节记录有限，但已知它们在海岛上筑巢，这可能是一种适应策略，以避开陆地上的威胁。","identification":"罗德里格斯蓝鸠与马岛斑鸠属的其他成员相比，最显著的区别在于其灰蓝色的羽毛，以及在历史文献中的描述，尤其是在罗德里格斯岛的独特生存记录。","protection":"IUCN：EX（已灭绝）","distribution":"罗德里格斯蓝鸠仅分布于印度洋的马斯克林群岛中的罗德里格斯岛，这里是它们曾经的唯一家园。"},{"name":"粉红鸽","english_name":"Pink Pigeon","scientific_name":"Nesoenas mayeri","overview":"粉红鸽（英文名：Pink Pigeon，学名：Nesoenas mayeri），是鸽形目鸠鸽科粉红鸽属的鸟类。亦称: 鸽子，属于鸠鸽科。拥有独特的粉红色头部和下体，棕色翅膀，以及红褐色尾巴。这种鸽子仅分布于印度洋的毛里求斯岛，曾一度濒临灭绝，但在保护措施下数量有所回升。曾是马斯克林群岛唯一未灭绝的鸽子种类。","appearance":"成年粉红鸽体长约40厘米，体重可达315克（雄鸟）和291克（雌鸟）。面部、额头至颈部呈白色渐变为柔和的浅粉色，上背为棕粉色，腹部为奶油色，翅膀深棕色，外侧初级飞羽边缘红褐色。背部灰粉色，臀部淡灰色，逐渐过渡到尾上覆羽的栗色，尾巴亮栗色，最外侧尾羽带粉灰色和栗色痕迹。虹膜白色至淡黄色，眼周皮肤粉红，喙呈粉红色，尖端白色，鼻孔上方深红色，腿脚粉红色。雌鸟较暗淡，臀部混有棕色。幼鸟更暗，羽毛末端呈浅黄色，喙和腿脚紫灰色，臀部杏色，虹膜深棕色。","call":"粉红鸽的典型叫声是一系列低沉、哀伤的呼叫声，飞行时翅膀会发出特有的金属般的喇叭声。","habits":"栖息于毛里求斯岛上的湿润森林、种植园和次生环境，通常在海拔300米以上。它们广泛散布在其范围内，白天活动，常飞行6-8公里寻找食物。以大约50种植物为食，但主要依赖几种，如Nuxia verticillata、Aphloia theiformis和Erythrospermum monticolum，这些植物广泛分布，可能全年提供大部分食物。它们也吃昆虫和其他小型无脊椎动物。","breeding":"繁殖季节通常开始于12月，高峰期在1月至6月，旱季减少，8月至11月几乎无繁殖。巢置于地面4-15米高处，由细枝构成，内衬更细的枝条。每窝通常产2枚蛋，有时仅1枚。孵化期13-15天，雏鸟离巢时间18-22天。最初三天雏鸟以亲鸟分泌的鸽乳为食，之后加入叶子，第5或第6天后添加种子、嫩叶、花和果实。","identification":"粉红鸽与Madagascar Turtle-Dove相似，但体型更大，通过粉红色头部和红褐色尾巴易于区分。","protection":"IUCN：VU（易危）","distribution":"分布于毛里求斯岛，包括黑河国家公园内的五个亚群和Île aux Aigrettes小岛。曾经在留尼汪岛有分布，但已灭绝。","other":"由于毛里求斯原始森林的破坏，其自然栖息地严重缩减。自1994年以来，野外个体数量超过300只。"},{"name":"欧斑鸠","english_name":"European Turtle Dove","scientific_name":"Streptopelia turtur","overview":"欧斑鸠（英文名：European Turtle Dove，学名：Streptopelia turtur），是鸽形目鸠鸽科斑鸠属的鸟类。以其独特的颈部条纹和白尾尖著称。广泛分布于欧洲、非洲和亚洲部分地区，包括中国的西北部省份如新疆、青海和甘肃。该物种在农区绿洲附近较为常见。","appearance":"成年欧斑鸠体长26至28厘米，翼展47至53厘米，体重介于100至156克之间。头部、颈部、两胁和臀部呈蓝灰色，翅膀为肉桂色并带有黑色斑点。胸部呈酒红色，腹部和尾下覆羽白色。喙黑色，腿和眼圈红色。幼鸟颜色较暗淡，腿棕色，颈部黑白色斑块不明显。","call":"其叫声为连续的低沉咕噜声，重复‘turrr, turrr’，音调一致，有时中间夹杂短暂音节。","habits":"欧斑鸠栖息于开放林地而非密林，常在地面觅食。偏好干燥、避风的环境，避免高海拔和多云多雨地区。主要以种子和果实为食，偶尔食用浆果、真菌、昆虫和小型无脊椎动物。","breeding":"繁殖季节始于5月，筑巢于树、灌木或篱笆中，使用小树枝搭建。每窝产两枚白色卵，孵化期13至14天，孵化同步。幼鸟约20天后离巢。","identification":"与欧斑鸠相比，灰斑鸠体型更大、色彩更浅。与山斑鸠相似，但后者翼羽暗中心更为广泛，胸羽粉红色更深。","protection":"IUCN：VU（易危）","distribution":"繁殖于欧洲、中东和北非，冬季迁徙至撒哈拉以南非洲。在中国大陆，主要见于西北省份。","other":"面临农业土地转变、食物供应减少、猎杀以及寄生虫威胁。"},{"name":"粉胸斑鸠","english_name":"Dusky Turtle Dove","scientific_name":"Streptopelia lugens","overview":"粉胸斑鸠（英文名：Dusky Turtle Dove，学名：Streptopelia lugens），是鸽形目鸠鸽科斑鸠属的鸟类。体长约28厘米，头部呈蓝灰色，胸部粉红色，颈部带有黑色斑块。分布于非洲中部和东部的高海拔森林地带，包括苏丹南部、埃塞俄比亚、肯尼亚、坦桑尼亚等地，同时在沙特阿拉伯和也门也有分布。","appearance":"成年粉胸斑鸠外观以灰蓝色为主，颈部和下体暗蓝灰色，略带薰衣草色光泽；喉部淡黄白色，下胸部呈粉色；颈部侧面有黑色斑点；背部、肩部、部分翼覆羽、臀部中央和尾上覆羽为深棕色灰色，多数羽毛边缘呈浅灰色或赤褐色；内侧二级飞羽和大覆羽的外缘有橙黄褐色或淡栗色边缘；外侧二级飞羽、初级飞羽覆羽和初级飞羽为黑色，边缘狭窄而苍白；中央尾羽深棕色灰色，外侧尾羽黑色，尖端淡灰色。虹膜颜色从棕色橙色到金色不等；眼周皮肤颜色从蓝灰色到紫红色；喙基部黑色、暗灰色或紫黑色，尖端较浅；腿为棕色红色、紫红色或深紫色。雌鸟略显暗淡和苍白，一些个体虹膜黄色。幼鸟整体更淡、更棕色，大多数羽毛为深色哑光，边缘淡赤褐色，内侧初级飞羽和内侧二级飞羽边缘宽赤褐色。","call":"粉胸斑鸠的叫声是一系列低沉的咕噜声，音符并不完全相同，例如“grrrow...grrruh...grrruh....rrrroh...”，比的叫声更缺乏旋律。","habits":"粉胸斑鸠主要栖息于1800至3200米的山地森林，常见于杜松、桉树、雪松、Hagenia和竹林地带，也出现在花园、松树林、农田和较低的灌木地带。在雨季，它可能下降到较低的海拔，低至200米。它们主要在地面上觅食，以杂草种子、谷物、向日葵、Salvadora浆果、小根茎、昆虫和软体动物为食。非繁殖季节可能形成高达100只的群体。","breeding":"繁殖主要发生在干季，在埃塞俄比亚记录全年除7月至8月外均有繁殖活动，在东非地区月份有所变化。巢由交错的树枝构成的松散平台，有时衬有细小的根须，置于离地2至7米的高度。产2枚白色蛋，孵化期约20天，由双亲共同承担；幼鸟成长迅速，10天左右体型较大且羽毛丰满。","identification":"粉胸斑鸠与红眼斑鸠相似，但体型较小，整体颜色更深，头部没有明显对比的淡色。其独特的黑颈斑点和橙黄褐色的翼部边缘是辨识的关键。","protection":"IUCN：LC（无危）。在埃塞俄比亚高原和其他东非范围内频繁至常见，甚至丰度较高；在马拉维较为罕见。目前未知威胁。","distribution":"粉胸斑鸠主要分布在非洲中部和东部，包括南苏丹和埃塞俄比亚至马拉维的山脉；沙特阿拉伯和也门。在埃塞俄比亚、肯尼亚、坦桑尼亚等国均有分布。"},{"name":"喀麦隆斑鸠","english_name":"Adamawa Turtle Dove","scientific_name":"Streptopelia hypopyrrha","overview":"喀麦隆斑鸠（英文名：Adamawa Turtle Dove，学名：Streptopelia hypopyrrha），是鸽形目鸠鸽科斑鸠属的鸟类。其特征为深色斑鸠，翅膀边缘呈典型的红褐色鳞状图案，颈部两侧有黑色斑块。脸部银灰色，腹部及两侧呈粉紫罗兰色。雌鸟和幼鸟较雄鸟淡色。在喀麦隆北部、尼日利亚东北部及乍得西南极地区域较为常见，同时也零星记录于塞内加尔、冈比亚、几内亚比绍、几内亚、马里和多哥。","appearance":"喀麦隆斑鸠长约30至31厘米，体重介于147至187克。额头、脸部和喉咙呈银灰色；头顶、颈背、颈部及胸部蓝灰色；颈部两侧有黑色斑块；下胸和腹部暗粉色带紫色调；两胁、臀部两侧、下尾羽覆羽和翼下表面深蓝灰色；背部、肩羽、上尾羽覆羽暗灰褐色，边缘模糊的红棕色；内侧飞羽和次级飞羽内侧黑褐色，边缘淡色；外侧飞羽覆羽有灰和淡色边缘；初级飞羽和外侧次级飞羽外缘深灰褐色，边缘狭窄而浅色；虹膜内环粉色或橙色，外环深色；眼周皮肤深红色；喙黑色；腿呈紫黑色。雌鸟比雄鸟更淡色和暗淡。幼鸟比成年雄鸟更淡，全身一般为灰褐，飞羽边缘红褐色。","call":"喀麦隆斑鸠的叫声为三音节的缓慢吟唱，‘cloor-cloor-clor’或‘TURRR turr-TURRR’，前两个音节比第三个音节长，三个音节在同一音高，总时长约为2.2至2.4秒，偶尔会增加第四个音节。在求偶展示时发出尖锐的咔嚓声，其咕噜声似乎比欧斑鸠更深沉。","habits":"喀麦隆斑鸠栖息于密林边缘、树木覆盖的峡谷、河谷森林，以及郊区和乡村地区，包括公园和花园，也出现在种植园和农田中，海拔可达1200米。它通常定居，但在某些地区如喀麦隆，会在五月后离开繁殖区分散，二月后首次繁殖的小鸟也会离开。它以小草籽为食，多在地面觅食，繁殖季节时单独行动，非繁殖季节时会形成多达60只的群落，有时与棕斑鸠、白喉斑鸠和斑鸽一同觅食。","breeding":"喀麦隆斑鸠的繁殖期在尼日利亚东北部和喀麦隆北部为8月至3月，可能在雨季初期结束。它们是单配偶制。雄鸟的求偶展示包括有力拍翅上升，达到最高点时一或两次拍打翅膀，随后是长时间缓慢的滑翔下降。双亲共同筑巢，巢为直径约15厘米的薄平台状，离地面2至5米，偏好在桉树、芒果树和Monterey macrocarpa树上筑巢，通常位于水源附近800米内。它们至少双窝繁殖，每次产1至2枚白色蛋，尺寸约为27.5毫米×22毫米。","identification":"喀麦隆斑鸠与欧斑鸠在外观上有明显区别：欧斑鸠在颈部两侧的羽毛有白色边缘，胸部颜色为粉红色而非灰色，腹部颜色更浅。此外，喀麦隆斑鸠比欧斑鸠体型略小。","protection":"IUCN：LC（无危）","distribution":"喀麦隆斑鸠分布于喀麦隆北部、尼日利亚东北部和乍得西南极地区域，以及西部的塞内加尔、冈比亚、几内亚比绍、几内亚、马里和多哥。在尼日利亚主要分布在乔斯高原，喀麦隆则分布稀疏，仅在Bénoué国家公园等地有记录。","other":"喀麦隆斑鸠在过去二十年中分布范围显著扩大。"},{"name":"山斑鸠","english_name":"Oriental Turtle Dove","scientific_name":"Streptopelia orientalis","overview":"山斑鸠（英文名：Oriental Turtle Dove，学名：Streptopelia orientalis），是鸽形目鸠鸽科斑鸠属的鸟类。其特征为颈部带有明显的黑白色条纹，肩羽和翅上覆羽呈赤色鳞状花纹。分布于亚洲中部至东部，包括印度和东南亚。在北自黑龙江、新疆，南至西藏南部、海南的广大区域内可见。","appearance":"山斑鸠体长约33-35厘米，体重介于165-274克之间。头部蓝灰色渐变为褐色，颈后部赤色，脸部粉红。喉部淡黄，颈部和胸部灰粉色，颈侧有黑色斑块，每根羽毛尖端银色。腹部粉黄色，尾下覆羽淡灰色。背部羽毛暗灰色，边缘赤褐色。翼上覆羽、肩羽和次级飞羽中心较暗，边缘橙色或淡栗色。其他部位羽毛边缘蓝灰色，或有黑色中心，边缘粉棕色，末端灰白色。初级飞羽黑色，边缘浅色；臀部和下翼暗蓝灰色；尾羽上覆羽暗灰色，末端较浅；中央尾羽深灰或暗褐色；外侧尾羽黑色，末端灰白色，最外侧尾羽网状部分淡灰色。虹膜颜色从浅红到橙红或金色；眼周皮肤深紫色或暗粉色；喙大多黑色，基部暗红或紫色，尖端角质色；腿色从深粉到紫红色。雌鸟通常在颈和胸处颜色较淡，替换为鲑鱼色。幼鸟类似成鸟，但总体更暗，背部、翅膀和胸部羽毛明显赤色边缘。不同亚种间存在差异。","call":"叫声为两声嘶哑、两声清晰的声调：\"呼-呼 呜-呜\"。","habits":"山斑鸠占据从寒带到热带的广泛生境，包括日本的森林边缘和山地亚高山地带，以及稀疏林地、灌木丛和农田旁的树林。在喜马拉雅山脉，它们在松树、桦树、白杨、柳树、橡树、落叶林和竹林中繁殖。活动范围广泛，高度可达海拔2400米至4000米。在开阔的农耕区、村庄、寺庙周围或小沟渠附近活动，主要在地面取食。","breeding":"繁殖季节在温带区域为5月至8月，在印度南部为11月至2月。巢建在小树、灌木或竹丛中，距地面2-4米。在日本北部，早期巢建在针叶树中，后期建在落叶树中。在喜马拉雅山脉，巢建在云杉、杜松或雪松中。通常产2枚白色蛋，偶尔1枚；孵化期15-16天；离巢期15-17天。","identification":"山斑鸠与欧斑鸠的区别在于山斑鸠颈侧有明显的黑白色条纹块状斑，而欧斑鸠颈侧为黑白点斑珠花状图案。与灰斑鸠相比，山斑鸠体型更大，花纹更浓重。","protection":"IUCN：LC（无危）","distribution":"分布于欧亚大陆，从亚洲中部向东至印度和东南亚。在西伯利亚中部和中亚地区繁殖，冬季大部分种群迁徙。在中国，分布于北自黑龙江、新疆，南至西藏南部、海南的广大区域。","other":"已知山斑鸠在某些地区因过度猎杀而数量减少，尤其是在人类居住地附近。"},{"name":"爪哇斑鸠","english_name":"Sunda Collared Dove","scientific_name":"Streptopelia bitorquata","appearance":"爪哇斑鸠体长约30至33厘米，体重约146至174克。前额淡灰色渐变为蓝灰色，颈侧有宽黑半环，边缘白色；颈部和背部暗酒红色，常带锈色；胸部淡紫色，比颈部颜色浅；两侧灰；腹部和尾下覆羽灰白至白色；背部、翼内覆羽、次级飞羽内侧和尾上覆羽暗褐色；其余翼覆羽深蓝灰色；初级飞羽、初级飞羽覆羽和次级飞羽外侧黑色；臀部深蓝灰色，略带褐色；中央尾羽褐色，外侧尾羽淡灰，基部三分之一暗灰；最外侧尾羽外翈全淡灰；尾下覆羽灰白，基部三分之一黑色；虹膜黄色、橙色或橙红色；眼周皮肤红色；喙黑色或深灰色，口裂红色；腿紫红或粉红。性别相似。幼鸟颜色较淡，酒红色较暗，颈标模糊，仅限于颈侧。","call":"发出深沉喉音的‘咕噜’声，连续5至9次，有时更多，间隔0.5至1秒。展示飞行时还会发出高音颤音。","habits":"主要栖息于红树林，但也普遍出现在开阔的林地；同时频繁出现在农田和城市区域。通常生活在低地，极少出现在海拔600米以上，但有记录显示至少可达800米。通常定居，很少迁移。主要以种子为食，大部分食物来自地面。经常单独或成对出现。","breeding":"繁殖记录见于4月至5月在小巽他群岛。巢由细小树枝构成的脆弱平台。产两枚白色蛋；孵化期17至18天；幼鸟离巢16至19天。","identification":"与灰斑鸠相比，外尾颜色对比不那么明显，尾下覆羽对比更明显，项圈颜色更深，有白色上缘，下体颜色更深，嘴较长，叫声明显不同。","protection":"IUCN：LC（无危）。在小巽他群岛和爪哇、巴厘岛上一般较为稀少，苏门答腊的记录可能源于圈养个体，当地任何种群似乎都无法长久生存。","distribution":"分布于爪哇岛、巴厘岛和龙目岛至帝汶岛（小巽他群岛）。","other":"直到最近，人们认为与菲律宾斑鸠同种，但在外尾、尾下覆羽颜色对比、项圈颜色、下体颜色、嘴长以及明显不同的叫声方面存在差异。"},{"name":"灰斑鸠","english_name":"Eurasian Collared Dove","scientific_name":"Streptopelia decaocto","overview":"灰斑鸠（英文名：Eurasian Collared Dove，学名：Streptopelia decaocto），是鸽形目鸠鸽科斑鸠属的鸟类。俗称: 灰鸽子，中等体型的斑鸠，长约32厘米。其最显著特征为后颈处的黑白色半领圈。原生于欧洲部分地区、中亚、中国和缅甸的暖温带地区，是留鸟。灰斑鸠性格温顺，已从原分布区成功扩展至北美、加勒比海岛屿及中美洲部分区域。","appearance":"灰斑鸠呈中等体型，长约32厘米，翼展47-55厘米，体重125-240克。整体羽色灰褐至粉灰，上体稍深于下体，翼下有蓝灰色斑。尾羽灰褐色，下部暗灰且末端白色，外侧尾羽上部白色尖端。后颈有黑色半领圈，边缘白色。喙黑色，眼虹膜红色，眼周裸皮白或黄色，腿脚红紫色。幼鸟领圈发育不良，虹膜棕色。","call":"叫声为典型的‘咕咕－咕’，第二声较重，重复多次。偶尔发出约两秒的刺耳鸣叫。","habits":"栖息于平原至低山丘陵的树林、农田、果园、灌丛、城镇和村庄附近。群居，常见于食物丰富的谷仓周边，以植物果实、种子、草籽、农作物谷粒和昆虫为食。飞行直接，快速拍打翅膀，不常用滑翔。","breeding":"繁殖期4月至8月，每年繁殖2窝。巢筑于小树或灌丛中，每窝产2枚乳白色卵，卵形卵圆，雌鸟为主孵卵，孵化期15至17天。雏鸟晚成性，由双亲共同抚养，约15至17天后可离巢。","identification":"与珠颈斑鸠区别明显，后者颈斑为黑白色珠花点斑。幼鸟珠颈斑鸠无领环，虹膜黄色。与火斑鸠雌鸟区别在于，后者虹膜褐色，领环全黑，脚黑色。灰斑鸠虹膜红褐色，领环黑白相间，脚粉红色。","protection":"IUCN：LC（无危）","distribution":"分布于欧洲西部至印度，中国东部和朝鲜半岛，以及北美、加勒比海岛屿和中美洲部分区域。","other":"灰斑鸠和粉头斑鸠可能是家养环鸽的野生祖先，能够与环鸽杂交繁殖。"},{"name":"粉头斑鸠","english_name":"African Collared Dove","scientific_name":"Streptopelia roseogrisea","overview":"粉头斑鸠（英文名：African Collared Dove，学名：Streptopelia roseogrisea），是鸽形目鸠鸽科斑鸠属的鸟类。小型鸽类，广泛分布在非洲的萨赫勒地区、非洲之角北部以及阿拉伯半岛西南部。偏爱干燥地带，常围绕水源而居，体长约26厘米，上体呈淡灰褐色，翼缘略带蓝灰色，飞羽接近黑色。头部、颈部和胸部为粉色渐变为白色，下巴和腹部尤为明显。该物种性别差异不大。","appearance":"成年粉头斑鸠的上体为淡灰褐色，最外侧的二级覆羽和初级覆羽呈蓝灰色，初级飞羽黑色；中央尾羽灰褐色；头部、颈部及胸部为柔和的粉灰色，逐渐过渡至下巴和腹部的白色；具有黑色半领圈，边缘镶白；翼下覆羽白色；最外侧尾羽上方灰褐色，尖端白色，下方黑色，尖端亦为白色；虹膜红色；眼周皮肤浅灰色；喙黑色；腿紫红色。幼鸟颜色更淡，轮廓羽毛边缘较浅，腿色灰暗；虹膜颜色随成长由黄色转橙再变红。两性外观相似。","call":"鸣唱特征为重复的两音节短语，首个音节短促有力，第二个音节为延长的咕咕声，起始为滚动颤音：'cuh...rrrrrrr-oooh'。叫声类似咩笑，向下渐弱，'ceh-heh-heh-heh-he'。","habits":"栖息于干旱区的耐旱灌木丛，或开阔沙漠地带，常出现在年生草丛中；亦见于沙质河床和农田，但距离水源不超过25公里。能够长时间无水生存，果实可能提供水分需求。避开河流边和森林地带，一般位于海拔1000米以下。","breeding":"繁殖记录全年可见，具体时间因地区而异。巢建于树或灌木上，平均高度2.5米，可能远离最近水源20公里。巢材简单，为开放杯状。在塞内加尔甘比亚的研究显示，多数巢筑于Balanites aegyptiaca，也利用Acacia raddiana、Grewia bicolor、Commiphora africana和其他7种树种。通常产卵2枚，有时1枚；孵化期14-15天；幼鸟离巢期15天。","identification":"与灰斑鸠相比，粉头斑鸠体型较小（26厘米对32厘米），尾巴较短，上体主要为淡沙棕色，头部和下体为淡粉灰，腹部和尾下覆羽白色。灰斑鸠头部和下体为淡黄褐色，背部更灰，上体为淡黄棕色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东北部、中部、西部以及阿拉伯半岛西南部。","other":"粉头斑鸠被认为是家养巴巴里鸽的野生祖先之一，尽管有人认为灰斑鸠也可能参与其中。"},{"name":"白翅斑鸠","english_name":"White-winged Collared Dove","scientific_name":"Streptopelia reichenowi","overview":"白翅斑鸠（英文名：White-winged Collared Dove，学名：Streptopelia reichenowi），是鸽形目鸠鸽科斑鸠属的鸟类。分布于非洲埃塞俄比亚东南部和索马里西南部。以独特的白色翼斑和眼环而闻名，常在河流附近的灌木丛和树林中活动。","appearance":"白翅斑鸠体长约25厘米，体重98至135克。头部呈深蓝灰色，逐渐过渡到脸部、胸部和两胁的淡色调；部分头部羽毛尖端带有棕色；喉咙、腹部和尾下覆羽为奶油白色；背部棕色，一条宽阔的黑色半领圈将灰色头部与棕色肩部区隔开；外侧翅膀覆羽呈浅蓝灰色，多数羽毛边缘宽大且为白色，形成明显的白色翼斑；初级飞羽和初级覆羽黑色；中央尾羽棕色，其他尾羽棕色带灰色边缘和白色尖端；尾羽基部三分之一为黑色，下面灰白色；眼睛黄色或银橙色；喙黑色；腿粉色。雌鸟灰色区域泛有棕色。幼鸟颜色较淡，更偏棕色，大多数羽毛边缘为浅黄色或赭色。","call":"白翅斑鸠的叫声为双音节的鸣叫，重复迅速（约每秒2个音节），第二个音节最长且明显滚动，发出类似‘cu-rrrruh..cu-rrrruh..cu-rrrruh...’的声音。系列中的第一个音通常不完整，接近结尾时，音节可能突然结束，变得不够清晰，或者鸟可能会切换到一系列更快的滚动音。","habits":"白翅斑鸠在埃塞俄比亚东南部栖息于距离河流2公里内的阔叶树上。在索马里，仅出现在河岸林地的杜姆棕榈和扇棕榈（Hyphaene，Borassus aethiopicum）中，避开邻近的金合欢灌木丛。它们是留鸟，已知的饮食包括红色浆果，但更多信息尚不可得。","breeding":"在埃塞俄比亚，繁殖期为1月至2月。巢由交错的叶柄和树枝构成的松散平台，位于Parkinsonia树高2.5米处。一窝通常产2枚白色蛋。更多繁殖信息未知。","identification":"白翅斑鸠与环颈斑鸠整体相似，但通过其白色的环眼、灰色胸部和白色翼斑可轻易区分。","protection":"IUCN：LC（无危）。尽管分布范围受限，但目前在该范围内仍常见至丰富。长期内战对该物种的影响未知，需进一步研究。","distribution":"分布于非洲的埃塞俄比亚东南部和索马里西南部，主要在河流附近和河岸林地中。","other":"白翅斑鸠的自然生境包括亚热带或热带湿润低地森林、亚热带或热带干燥灌木丛、种植园和城市地区。目前因栖息地丧失而受到威胁。"},{"name":"灰头斑鸠","english_name":"Mourning Collared Dove","scientific_name":"Streptopelia decipiens","overview":"灰头斑鸠（英文名：Mourning Collared Dove，学名：Streptopelia decipiens），是鸽形目鸠鸽科斑鸠属的鸟类。分布广泛，常见于接近水源处。具有独特的黄色眼睛，周围环绕着红色裸露皮肤，以及玫瑰色颈项和灰色头部。","appearance":"灰头斑鸠长约28厘米，体重介于140至230克之间，性别相似。头部顶部和颈背呈灰褐色，下巴和喉咙白色到灰白色，上颈、后颈和颈侧为淡紫色；脸部灰褐色，后颈与背部由黑色半环带区隔，边缘白色；背部、翼上覆羽、肩羽、三级飞羽和内侧翼覆羽呈棕色，臀部两侧带灰色，胸部酒红色渐变为腹部的灰玫瑰色或灰色；胁腹和尾下覆羽灰色，尾下覆羽末端白色；中间尾羽棕色，最外侧尾羽灰棕色带宽白色尖端，基部三分之二黑色，其余部分白色带灰色调；初级飞羽最外三枚棕色带细白边，其余基部灰色远端棕色；虹膜红色或橙红色，内环黄色；眼周皮肤红色；喙黑色；腿葡萄酒红色。幼鸟的冠和颈背为棕色，胸部浅棕色，翅膀末端锈色，虹膜淡棕色。","call":"灰头斑鸠的鸣唱是一系列有独特模式的咕咕声：以短而模糊的呼噜声开始，随后是滚动的颤音，之后是重复的双音节呼噜声，偶尔以一些额外的滚动音符结束。在西非，叫声更鼻音，颤音的节奏明显较慢。","habits":"灰头斑鸠栖息于干燥草原中的刺槐和常绿河岸树林及灌木丛，距离水源10公里以内；也出现在村庄和种植区，有大量本地和外来树木的地方。在东非部分地区，海拔可达1400米，甚至在埃塞俄比亚高达2000米。已知会成百地在塞内加尔甘比亚的Aeschynomene elaphroxylon树上过夜。在雨季期间，会从河流附近迁徙。日常活动包括在栖息、饮水和觅食地点间的移动。","breeding":"繁殖记录全年可见于塞内加尔甘比亚；在其他地方，季节性变化。巢为直径约15厘米的树枝和叶柄平台，内部铺有细根须，通常隐藏于Acacia nilotica、Balanites aegyptiaca和A. raddiana等树种中，平均高度3.1米离地面；有时在异国树种中筑巢，最高可达5.3米离地面。通常产2枚蛋，有时仅1枚；孵化期13至14天；幼鸟离巢时间15至18天。","identification":"灰头斑鸠与其他类似的环颈鸽相比，其黄色眼睛周围环绕着红色裸露皮肤是明显的区别特征。","protection":"IUCN：LC（无危）","distribution":"非洲南部撒哈拉沙漠以南广泛分布，从苏丹向北沿尼罗河扩散，最北到达埃及的阿布辛贝。","other":"灰头斑鸠在某些地区可能由于干旱化导致适宜栖息地的扩张，如在苏丹北部沿尼罗河的分布扩展。"},{"name":"红眼斑鸠","english_name":"Red-eyed Dove","scientific_name":"Streptopelia semitorquata","overview":"红眼斑鸠（英文名：Red-eyed Dove，学名：Streptopelia semitorquata），是鸽形目鸠鸽科斑鸠属的鸟类。‘环颈’斑鸠中体型最大、最粗壮的一种。头部呈淡粉色，前额至头顶颜色渐深，眼睛周围环绕着醒目的暗红色皮肤。飞行时，其脏褐色的尾尖与其它‘环颈’斑鸠显著不同。红眼斑鸠广泛分布于非洲南部，包括撒哈拉以南地区、沙特阿拉伯和也门，常见于城市、乡村和野外。","appearance":"体长约30厘米，体重162-310克。头部前额为淡蓝灰色，逐渐过渡到更深的色调至头顶；颈部、胸部和下体呈现深紫罗兰色至酒红色；上体灰褐色，初级飞羽黑色；翼外侧覆羽深石板蓝色；两胁、臀部侧面和翼下覆羽蓝灰色；尾羽基部深灰色，末端半部浅棕灰色；颈项带有黑色半领圈；虹膜颜色从黄色至橙色、红色或橙棕色；眼周皮肤紫红色；喙黑色；腿紫红色。雌雄相似。幼鸟色彩较暗淡，羽毛边缘带红褐色或红棕色，颈圈不明显，限于颈侧；腿、眼周皮肤和虹膜颜色暗淡。","call":"发出连续重复的六音节广告叫声，包含四声节奏低沉的咕咕声，后接两声更强调的咕咕声，形成“cu-cu..cu..cu..COO..COO...”的模式。还有一种三音节的叫声，持续时间较长：先是嘶哑的一声，接着是两声（偶尔三声）咕咕声：“grrrr...whu.whu....grrrr...whu.whu....”。飞行中发出短暂鼻音的‘weh’。","habits":"栖息于茂密的林地和靠近水源的金合欢灌丛；亦可见于河流边的林地、画廊森林、森林边缘和红树林；避开雨林内部；常光顾农田、种植园、公园和城市花园环境。食物包括玉米、向日葵种子、蓖麻籽、牛鞭草、坚果草根茎和浆果。据报道，也会吸食南非山龙血树的花蜜。大量食物在地面摄取，但有时直接从树枝上摘取浆果。","breeding":"繁殖行为在当地有所差异，但在尼日利亚、东非、津巴布韦和南非全年均有记录。巢由树枝平台构成，比同类物种更为坚固；位于树或灌木上，高度从30厘米至18米不等（平均4米）。通常产2枚蛋，但有时仅1枚；孵化期平均14.5天（可能长达17天）；离巢期14-17天。一项研究显示，40%的雏鸟成功离巢。在南非郊区种群中，有罕见的3枚蛋的窝卵现象。","identification":"红眼斑鸠与其它‘环颈’斑鸠的区别在于其独特的红眼圈和飞行时可见的脏褐色尾尖。幼鸟的暗淡色彩和不明显的颈圈也有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于撒哈拉以南非洲、沙特阿拉伯和也门。在非洲南部，从塞内加尔和马里南部向东至厄立特里亚和索马里西北部，向南至纳米比亚北部、博茨瓦纳北部和南非（南至西开普省）。","other":"红眼斑鸠在数量上有所增加，分布范围更广，这得益于水资源保护和植树计划。在冈比亚、塞拉利昂、多哥和尼日利亚非常丰富；在南非的分布比1930年代更为广泛和丰富。"},{"name":"环颈斑鸠","english_name":"Ring-necked Dove","scientific_name":"Streptopelia capicola","overview":"环颈斑鸠（英文名：Ring-necked Dove，学名：Streptopelia capicola），是鸽形目鸠鸽科斑鸠属的鸟类。是广泛分布在东非和南非的一种常见鸽子。以灰褐色为主色调，拥有独特的黑色半领状标记，是非洲草原上最具代表性的声音之一。","appearance":"环颈斑鸠身长约25厘米，重约106至200克。其头部呈淡蓝灰色，冠部颜色较深，眼周有一细窄的黑带，喉部白色，颈侧和前颈呈淡紫色，腹部和尾下覆羽白色。背部、肩羽和内翼覆羽棕色，外翼覆羽、臀部和上尾覆羽呈蓝灰色。初级覆羽、主羽和外次级飞羽黑色，主羽外缘有淡色边缘；下翼暗蓝灰色；虹膜深棕色，眼睑黄色，喙黑色至紫黑色，腿呈红紫色或灰紫色。雌鸟与雄鸟的区别在于雄鸟的臀部颜色更鲜艳，雌鸟的臀部呈暗褐色。幼鸟的颈环缩小为颈部两侧的小斑点，大部分羽毛边缘呈棕褐色。","call":"其典型的叫声为连续重复的三音节‘wuk...crrrrrr-uk....’，在求偶展示中会发出更快节奏的一系列滚动音符。","habits":"环颈斑鸠栖息于林地和开阔的灌木草原，常出现在种植园、农田及村庄周围，避开森林。它们主要食用种子，但也摄取各种无脊椎动物，如蚜虫、蝗虫幼虫、蚯蚓、白蚁和象鼻虫。它们通常在地面觅食，但也会站在高粱上提取种子。","breeding":"繁殖季节因地区而异，但在津巴布韦和南非全年均有记录。一对环颈斑鸠占据大约0.5公顷的繁殖领地，巢间距约25米。巢由脆弱的枝条构成，直径约13厘米，有时用其他材料衬里，藏匿于树叶中，高度从0.5至15米不等。每窝通常产两枚蛋，有时一枚，罕见时产3至4枚；孵化期13至15天；雏鸟离巢时间16至17天。","identification":"与非常相似的酒红斑鸠相比，环颈斑鸠具有蓝灰色的冠部和不同的四音符快速鸣叫。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲东部和南部，以及科摩罗群岛。","other":"环颈斑鸠的叫声是非洲大草原上最常见和典型的声音之一。随着森林砍伐和耕地增加，该物种的分布范围可能正在扩大。"},{"name":"酒红斑鸠","english_name":"Vinaceous Dove","scientific_name":"Streptopelia vinacea","overview":"酒红斑鸠（英文名：Vinaceous Dove，学名：Streptopelia vinacea），是鸽形目鸠鸽科斑鸠属的鸟类。其头部和胸部呈粉灰色，颈部有黑色标记，翅膀上的灰色条纹和尾部的白色边缘在飞行中尤为显眼。广泛分布于北非撒哈拉沙漠南部的萨赫勒地区，常见于小群落中。","appearance":"体长约25厘米，重97-124克。头、颈、胸及下体为酒红色或浅粉色，有时头顶和颈背带灰，腹部渐变为乳白色，尾下覆羽白色。眼睛到喙基部有一条窄黑线，后颈有宽的黑色半环。次级飞羽外缘银灰色，初级飞羽及覆羽黑色，外缘有细白边。中央尾羽灰褐色，外侧尾羽基部黑色，端部灰白色。下翼淡蓝灰色。虹膜深棕色，喙黑色，脚紫色或紫红色。雌鸟相似，但粉红色部位常更偏褐色。幼鸟颜色较暗淡，多数羽毛边缘淡黄或淡红，颈环以颈两侧斑块形式出现。","call":"典型的叫声为连续快速的三音符咕咕声，首音与其他两音不同，第二停顿比第一短，形成节奏感强烈的‘whuo..whu.whu...’。求偶展示时，发出较快的一系列滚动音符，类似环颈斑鸠。飞行时发出特有的响亮双音鼻音‘krr..krrrrr’。","habits":"栖息于从海平面至2000米的干燥林地，亦可见于灌木草原和耕作区。季节性迁徙于灌木草原和河岸生境之间，具体细节不明。在塞拉利昂，仅在9月至次年6月的旱季出现并繁殖。每日往返于栖息地和觅食饮水点。","breeding":"全年均可繁殖，在塞内加尔和马里记录，3月在埃塞俄比亚，东非其余地区在8-9月。成对保卫繁殖领地。巢为脆弱的薄平台，平均离地面约2.5米，使用多种树种，如巴兰蒂斯、刺槐、硬果蒲桃、没药等。产2枚白色蛋；在圈养条件下，孵化期14天，雏鸟间隔一天出生，约13-14天后离巢。","identification":"与环颈斑鸠区别在于前额粉红而非纯灰，粉头斑鸠总体较暗，尤其是下翼。叫声是最佳辨别方式。","protection":"IUCN：LC（无危）。普遍丰富，例如在冈比亚、塞拉利昂北部和多哥北部。尼日利亚甘比亚草原常见，但在萨赫勒和苏丹地带较少见。","distribution":"分布于毛里塔尼亚、塞内加尔和冈比亚至厄立特里亚、埃塞俄比亚和乌干达。在尼日利亚的甘比亚草原中丰度高，但萨赫勒和苏丹地带数量较少。","other":"在某些地区，如塞内加尔和冈比亚，种群似乎因甘蔗种植园的增加而增长。"},{"name":"火斑鸠","english_name":"Red Collared Dove","scientific_name":"Streptopelia tranquebarica","overview":"火斑鸠（英文名：Red Collared Dove，学名：Streptopelia tranquebarica），是鸽形目鸠鸽科斑鸠属的鸟类。又称: 红鸠、红斑鸠、斑甲、红咖追、火鸪鹪，分布于亚洲南部热带区的小型鸠鸽。常见于开阔田野，成群觅食于平原及草地。其特征为雄鸟头部蓝灰色，身体红棕色，雌鸟则整体呈淡棕色，两者皆有明显的黑领环。在中国，自华北以南各地，西至四川、西藏，长江以北地区均有其踪迹。","appearance":"火斑鸠体长20.5至23厘米，体重约104克。雄鸟头部为蓝灰色，过渡至嘴基上方及半领环前部的灰白色；喉部灰白色；背部、上背部、翼覆羽、肩羽及内侧次级飞羽深紫粉色；颈部、胸部和腹部略显苍白，从灰粉色渐变为粉灰色，再转为白色于下尾羽覆羽；下背部、臀部和上尾羽覆羽暗蓝灰色；中央尾羽暗灰色，侧尾羽基部一半暗灰色，远端灰白色；最外侧一对尾羽全白；下翼面淡蓝灰色至灰白色；外翼覆羽具相同蓝灰色边缘；初级飞羽黑色；尾羽基部黑色，远端白色；虹膜颜色从棕色至棕黑色；眼周皮肤灰白色；喙黑色至灰黑色；腿紫色黑或紫红色。雌鸟与雄鸟颜色差异显著，雄鸟的酒红色和蓝灰色部分，雌鸟则为暗棕色。","call":"火斑鸠的鸣唱是一连串连续重复的三至四个音节，音符间稍长的停顿比音节间的停顿更长。音符听起来非常沙哑干燥，例如：“grroh..grroh..grroh... grroh..grroh..grroh....”。第二个音节有时为双音节：“grroh..grroh-uh..grroh”。展示时，会发出急促的“croo..croo..croo..”声。","habits":"火斑鸠偏好开阔地带，如平原、田野、村庄、果园和山麓疏林，以及住宅附近的竹林地带，偶尔出现在低山丘陵和林缘地带。春季迁徙至北方繁殖地，秋季返回南方。成对或成群活动，有时与山斑鸠和珠颈斑鸠混群。飞行快速，常发出“呼呼”的振翅声。","breeding":"繁殖期为2月至8月，北方主要在5月至7月。成对营巢繁殖，巢位于低山或山脚丛林和疏林中乔木树上，巢呈盘状，结构简单，由少许枯树枝交错堆集而成。每窝产卵2枚，卵为卵圆形，白色。","identification":"雌鸟与雄鸟在外表上有明显区别，雌鸟较雄鸟颜色暗淡，整体呈淡棕色。与其他斑鸠种类相比，火斑鸠雌鸟较小，尾羽更短。","protection":"IUCN：LC（无危）。火斑鸠拥有极广的分布范围，虽然有证据显示其种群数量有所下降，但下降速度缓慢。","distribution":"火斑鸠分布于印度、尼泊尔、不丹、孟加拉、缅甸、中南半岛、菲律宾以及中国的自华北以南各地，西至四川、西藏，长江以北地区。夏季迁徙至喜马拉雅山脉海拔800米以下，最高可达1300米（在孟加拉和阿萨姆邦）。","other":"火斑鸠在巴基斯坦、泰国、菲律宾等地十分常见，特别是在苏拉威西中部，被认为是引入种，可能源自附近的菲律宾，或由大约1930年左右从印度移民的人们带来。"},{"name":"菲律宾斑鸠","english_name":"Philippine Collared Dove","scientific_name":"Streptopelia dusumieri","overview":"菲律宾斑鸠（英文名：Philippine Collared Dove，学名：Streptopelia dusumieri），是鸽形目鸠鸽科斑鸠属的鸟类。原生于菲律宾，当地称之为bato-bato de collar，目前在菲律宾的数量正在减少，变得不常见；但在引入的范围内，如关岛和北马里亚纳群岛较为常见。其自然栖息地为开放的草地和有树木与灌木的农业区。","appearance":"体型约30至33厘米，体重介于145.5至173.7克之间。整体呈淡褐色，头颈部粉灰色，颈背有一半环状的暗灰绿色鳞片状斑纹，胸腹部带有粉紫色调，下腹部和尾下覆羽为奶油白色，尾羽基部黑色，虹膜颜色从棕色到橙棕色不等。","call":"发出响亮而略带哀伤的“cOO-cuh-COO”声，声音单调重复，有时会发出“kerr-r-r-r-r, krr-r, krr-rr”的连续叫声。","habits":"偏好开阔的森林边缘地带，在其原生范围内活动；引入的种群常出现在城市区域。在北婆罗洲也有记录，包括红树林地带。可能偶尔有迷鸟或局部引种失败的情况。","breeding":"繁殖季节在菲律宾通常为3月至5月。筑巢高度1至7米，位于低矮树木的枝条上，巢由细枝搭建，通常位于林地边缘、鱼塘旁或红树林中，每窝产2至3枚白色蛋。","identification":"与同属物种如爪哇斑鸠相比，菲律宾斑鸠的尾羽末端更窄，下体颜色更淡，嘴较短，鸣叫声节奏更快，音质纯净无喉音。","protection":"IUCN：VU（易危）。菲律宾本土种群迅速下降，尤其是在吕宋岛，现在许多原本常见的区域变得局部和罕见。威胁主要来自与本地鸽子的竞争，如珠颈斑鸠和火斑鸠。","distribution":"主要分布在菲律宾众多岛屿，包括但不限于阿古塔亚、阿拉巴特、班塔延等。在北婆罗洲的记录情况不明，自1962年后无记录。1700年代被西班牙人引入马里亚纳群岛，从关岛至塞班岛北部，人口波动，受棕色树蛇的严重捕食。","other":"在关岛的种群尽管遭受棕色树蛇的重创，仍幸存下来。在塞班岛和阿古伊根岛的数目似乎在1982年至2007年、2008年间有所增加，而在罗塔岛则在1982年至2004年间减少了60%。"},{"name":"缅甸斑鸠","english_name":"Burmese Collared Dove","scientific_name":"Streptopelia xanthocycla","overview":"缅甸斑鸠（英文名：Burmese Collared Dove，学名：Streptopelia xanthocycla），是鸽形目鸠鸽科斑鸠属的鸟类。羽色柔和的灰褐色，头部呈淡灰色，背部颜色更深，胸部粉黄，颈部有黑色新月形花纹，尾部长而尖端呈方形。体型比火斑鸠大，尾部更长。在中国为留鸟，分布于远东地区的缅甸中部。","appearance":"缅甸斑鸠具有统一的粉黄色体色，头部淡灰，背部色调更深，胸部呈现粉灰色。其显著特征包括黑色的新月形花纹位于颈部，尾部较长，末端方形，白色边缘明显。眼周环绕着独特的淡黄色眼环。体型较火斑鸠更大，尾部更为修长。","call":"缅甸斑鸠的叫声为连续的三音节‘woop-WOOO!-woop’，类似于‘Ooh-OOH-ouh’的咕咕声。","habits":"缅甸斑鸠偏好居住在干燥开阔的低地，常见于农场和郊区，而非茂密森林。它们通常以成对或小型松散群体的形式出现。","identification":"与火斑鸠雌鸟相比，缅甸斑鸠明显体型更大，尾部更长。","distribution":"缅甸斑鸠的自然分布限于中国和缅甸，具体在远东地区的缅甸中部。"},{"name":"珠颈斑鸠","english_name":"Spotted Dove","scientific_name":"Spilopelia chinensis","overview":"珠颈斑鸠（英文名：Spotted Dove，学名：Spilopelia chinensis），是鸽形目鸠鸽科珠颈斑鸠属的鸟类。又名: 鸪雕、鸪鸟、中斑、花斑鸠、花脖斑鸠、珍珠鸠、斑颈鸠、珠颈鸽、斑甲，分布广泛的斑鸠。体长约30厘米，颈部带有独特的黑白珠花图案，脚部红色。在亚洲南部和东南部地区常见，从印度东部至中国东南部，向南至马来半岛、苏门答腊、婆罗洲等地均有分布。此外，人为引入至夏威夷群岛、美国加州南部、澳大利亚、新西兰等地。","appearance":"珠颈斑鸠体型健硕，翅膀相对较短，尾部较长且宽大。全身呈棕色，胸部偏粉红，最显著的特征是颈后部有一块黑白斑点组成的“项链”。羽毛颜色随地域略有差异，西方的种类双翅覆羽中央颜色更深，而东方的种类则更淡。成年鸟与幼鸟的主要区别在于幼鸟的颈斑不明显，且整体色泽更为暗淡。","call":"珠颈斑鸠的鸣叫声为一系列低沉而响亮的“咕咕”声，通常在清晨、黄昏和白天反复鸣叫。","habits":"珠颈斑鸠常出现在开放森林、田野和城市公园，偏好非自然的栖息地，如都市绿化、牧场、果园等。它们飞行迅速，翅膀拍打频率快但持续时间不长。主要以植物种子为食，包括农作物种子，偶尔食用昆虫等动物性食物。","breeding":"珠颈斑鸠通常为一夫一妻制，繁殖期集中在5月至7月，筑巢于树枝或灌木丛间，巢由细枝简单搭建而成。每窝产两枚白色卵，孵化期约为18天，由雌雄共同孵化。幼鸟在出生后两周左右离巢。","identification":"珠颈斑鸠与欧斑鸠的区别在于体型较小，双翅覆羽中央无黑色斑点，颈后为黑白斑点而非条纹。与灰斑鸠、火斑鸠、山斑鸠等同属鸟类相比，其颈部图案、虹膜颜色和脚部颜色有所不同。","protection":"IUCN：LC（无危）","distribution":"珠颈斑鸠原生于南亚至东南亚，包括印度东部、中国东南部、马来半岛、苏门答腊、婆罗洲等。已引入夏威夷群岛、美国加州南部、澳大利亚、新西兰等地。","other":"珠颈斑鸠曾是中式宴席上的佳肴，现在是夏威夷的重要猎物种，但在加州的大部分城市环境中很少被狩猎。"},{"name":"棕斑鸠","english_name":"Laughing Dove","scientific_name":"Spilopelia senegalensis","overview":"棕斑鸠（英文名：Laughing Dove，学名：Spilopelia senegalensis），是鸽形目鸠鸽科珠颈斑鸠属的鸟类。广泛分布于非洲、中东、南亚和澳大利亚西部。其特征为粉色头部与颈部，棕色底色，带点状黑斑的颈环，以及白色尾羽尖端。常见于人类活动区域，如种植园、花园和城市绿地。","appearance":"体长约27厘米，重71-92克。头部、颈部和胸部呈淡紫色，腹部乳白色，尾下覆羽白色。颈部两侧有宽幅展示羽，每根羽基部黑色，顶部铜金色。背部锈红棕色，翼羽蓝灰色至板岩色，初级飞羽深灰棕色，边缘白色至浅黄色。雌鸟较暗淡，背部不如雄鸟红棕色，胸部粉红色较浅；幼鸟缺乏成鸟的铜色颈部羽毛，锈棕色区域变为暗棕色，粉红区域变为淡褐色。","call":"发出重复的‘咕咕噜’声，连续5-8次，音调起伏，先升后降。","habits":"栖息于干燥的环境，如干草原、村庄和城市花园，常在有树木的地方活动。以小于2毫米的种子为主食，也吃水果、花蜜和少量昆虫。一般单独、成对或小群活动，偶尔数百只聚集在水源附近。","breeding":"繁殖期从2月至6月，但在某些地区全年都可繁殖。巢建在树上或灌木丛中，由根、枝条和叶柄构成，直径8-14厘米，深度3-4厘米。每次产卵2枚，孵化期12-13天，雏鸟离巢期同样为12-13天。","identification":"与珠颈斑鸠相比，颈环为黑色和白色相间的方格状图案。在不同亚种间，体型、颜色和色调有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于非洲大部分地区、阿拉伯半岛南部、伊朗、阿富汗、巴基斯坦、印度、尼泊尔、土耳其、巴勒斯坦、叙利亚、澳大利亚西部以及中国新疆。在中国新疆，自1909年和1934年后，半个世纪未再有记录。","other":"历史上，笑鸽曾被引入澳大利亚珀斯，现已在澳大利亚西部建立稳定种群。"},{"name":"斑尾鹃鸠","english_name":"Barred Cuckoo-Dove","scientific_name":"Macropygia unchall","overview":"斑尾鹃鸠（英文名：Barred Cuckoo-Dove，学名：Macropygia unchall），是鸽形目鸠鸽科鹃鸠属的鸟类。分布广泛，从喜马拉雅山脉到东南亚，常见于茂密的森林中。体长约37-41厘米，体重约153-182克，喉部和额头呈淡黄色，头顶转为粉灰，颈后带有绿色或紫色光泽，胸部和颈部有细黑条纹，腹部偏粉灰色，尾部黑色带红褐色横纹。","appearance":"雄性斑尾鹃鸠胸部有明显的黑条纹，雌雄均有颈后青铜绿色光泽。头部和胸部在雌鸟个体中呈红棕色，向脸部和腹部渐变为淡色，背部、翅膀和中央尾羽有黑色和栗色条纹，外侧尾羽蓝灰色，带有宽黑边。虹膜内环淡蓝或棕色，外环粉红色；眼睑紫罗兰色，脚和腿为暗樱桃红或紫棕色。幼鸟类似雌鸟，但年轻的雄鸟颜色更深更红。不同亚种间有细微差异。","call":"最常听到的叫声是重复的、拖长的咕噜声，前有一个只有近距离才能听见的柔和引音，‘hu-whoOOow’，每1.5秒左右发出一次。","habits":"栖息于海拔450-2750米的浓密常绿森林和次生丛林，有时出现在花园和椰子种植园。以种子、谷物、芽、嫩枝、橡实、浆果和小型核果为主食，偶尔在林间空地地面觅食，更多时候在树上活泼地觅食。通常成对或小群活动，最多10只。","breeding":"在印度和尼泊尔，繁殖期至少从3月至7月；马来西亚发现巢穴的时间为12月至3月；在大巽他群岛和小巽他群岛缺乏季节性数据。巢为松散的树枝平台，位于2-8米高的树苗或矮化橡树上。产1枚，偶尔2枚略带光泽的白色或奶油色蛋，可能有少量橄榄黄色斑点；孵化期15-16天；雏鸟离巢时间19天。","identification":"与小鹃鸠相比，斑尾鹃鸠体型更大，颜色更深，背、胸、覆羽和尾部有黑色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至东南亚，包括斯里兰卡、印度、尼泊尔、不丹、孟加拉国、缅甸、中南半岛、马来半岛、印度尼西亚，以及中国的华南地区，北至四川、福建等地。","other":"在中国，斑尾鹃鸠被列为国家二级保护动物。"},{"name":"红胸鹃鸠","english_name":"Amboyna Cuckoo-Dove","scientific_name":"Macropygia amboinensis","overview":"红胸鹃鸠（英文名：Amboyna Cuckoo-Dove，学名：Macropygia amboinensis），是鸽形目鸠鸽科鹃鸠属的大型、长尾棕色鸠，体型庞大，头部和下体呈淡褐色，上体颜色更深，带有赤褐色。雄鸟展示有限的胸部横纹及颈部淡色虹彩斑块，雌鸟颈部横纹更为显著。分布于摩鹿加群岛中部至新几内亚和俾斯麦群岛，常见于森林边缘、林地、花园及次生林区。","appearance":"体长34-37厘米，体重107-179克。额部和面部暗橙褐色，逐渐变为冠部的红褐色；上体大部分为红褐色，翼覆羽最深，呈黑色带红边；初级和次级飞羽棕黑，外缘有狭窄的锈色或赭色边缘；颈侧和背颈、肩部锈褐色，饰有细小的黑色点状斑；颈羽边缘银绿或银粉色；喉部浅棕色；胸部金棕色，带粉红色调；窄黑横纹和棕粉色尖端赋予胸部斑驳效果；腹部和尾下覆羽栗色；中央尾羽深红褐色；较短的外侧尾羽栗色，末端具黑色横带；虹膜灰或蓝色，外圈红色、橙色或黄色；喙棕色或黑色；脚红色至紫色。雌鸟横纹更重，上体更红；颈部虹彩缺失；前额和冠部红棕色，饰以黑色斑点；翼覆羽黑色带宽的锈色或红棕色边缘；后颈和上肩红棕色，饰有细密的暗色波状纹；眼下方有淡色条纹，雄鸟缺乏。幼鸟后颈、肩部和尾上覆羽羽毛具黑色亚端横纹和锈色边缘。下体（包括前颈）比成年个体更红，横纹更密。","call":"发出单调重复的“whop-whop-whop-whop...”声，有时音调上升，频率为每2-2.5秒两次，持续2-12秒。在不同的亚种中，叫声存在细微差异。","habits":"栖息于森林边缘、画廊林地、草地上的孤立树群、森林、次生林和花园，但也出现在原始森林中。常见于低地至海拔1800米（局部至2100米）的环境。通常单独或成对出现，偶尔形成8-20只的小群体。","breeding":"可能全年繁殖，筑巢材料包括枝条、树叶碎片，巢深约9厘米，直径25-30厘米，位于地面以上0.8-6米的高度。一窝产一枚白色或黄白色的蛋，由双亲共同孵化。","identification":"与Black-billed Cuckoo-Dove相比，体型更大，下体颜色更浅，无尾部横纹；与棕鹃鸠相比，体型更大，无胸部斑点；与赤灰长尾鸠相比，体型较小，下体呈棕色，与后者明显不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体包括印尼摩鹿加群岛中部至新几内亚和俾斯麦群岛。"},{"name":"苏坦氏鹃鸠","english_name":"Sultan's Cuckoo-Dove","scientific_name":"Macropygia doreya","overview":"苏坦氏鹃鸠（英文名：Sultan's Cuckoo-Dove，学名：Macropygia doreya），是鸽形目鸠鸽科鹃鸠属的大型、长尾棕色鸠，广泛分布于北摩鹿加群岛、苏拉威西岛至新几内亚及巴布亚岛西部。该鸟种在2016年从黑嘴鹃鸠中分离出来，定义了三个新物种之一。其特征包括淡棕色头部与下部，暗红棕色上部，雄鸟颈部略带玫瑰绿光泽。","appearance":"体长34至37厘米，体重107至179克。前额和面部深橙棕色，头顶转为红棕色；背部大多红棕色，翼覆羽最暗呈黑色，带有红色尖端；初级和次级飞羽棕黑，外缘有狭窄的锈色或赭色边缘；颈侧、背颈和肩羽锈棕色，饰有细微的黑色斑点；颈羽带有银绿色或银粉色边缘；喉部淡棕色；胸部金棕色，微泛粉红；胸羽有狭窄的黑色条纹和棕色粉色尖端，形成斑驳效果；腹部和尾下覆羽栗色；中央尾羽暗红棕色；较短的外侧尾羽栗色，带有黑色次端带；虹膜灰色或蓝色，外围有红、橙或黄色环；喙棕色或黑色；脚部红色至紫色。雌鸟比雄鸟更重条纹，上方更红，颈部羽毛的虹彩缺失；额头和头顶红棕色，点缀黑色斑点；翼覆羽黑色，带有宽广的锈色或红棕色边缘；后颈和上肩红棕色，饰有细密的暗色虫蚀状花纹。幼鸟类似雌鸟，但后颈、肩羽和上尾覆羽羽毛带有黑色次端条纹和锈色边缘。下部（包括前颈）比成鸟更红，条纹更紧密。","call":"发出独特的两音节叫声，最后一部分上升：'puk-hooa'。叫声高亢，节奏为每2至2.5秒两次，持续2至12秒。在不同地区，叫声有所不同，如在巴布亚新几内亚、新不列颠和马努斯岛，会发出单调重复的'whop-whop-whop...'声，音调逐渐升高；而在沃格尔科普半岛和哈马黑拉岛，则发出较慢的双音节'h-u-woot, h-u-woot...'声，或者在托吉安岛上发出升调的'wu-up'声。","habits":"栖息于森林边缘、画廊林地、草地上的孤立树群、森林、次生林和花园，也出现在原始森林中。在新几内亚大陆，海拔高度从海平面到1800米，局部可达2100米；在苏拉威西岛，海拔高达2000米；在奥比群岛的森林和森林边缘，从海平面到1210米都能见到它们的身影。通常单独或成对出现，偶尔形成8至20只的小群体。以小型果实、种子（包括Macaranga sp.、Symplocus sp.、Euodia sp.）和坚果为食，偶尔在地面进食草籽或沙砾。","breeding":"繁殖季节数据有限，可能全年繁殖。在托吉安群岛，12月底发现巢中有卵；在布鲁岛，11月观察到求偶行为；在哈马黑拉岛，8月底发现巢中有卵。求偶飞行从低枝开始，雄鸟翅膀张开，尾部半展开，陡峭向上飞至树冠层，随后沿半圆形路径下降，翅膀紧贴向下，尾部完全展开。巢由树枝、树叶碎片和蕨类植物构成，直径25至30厘米，深度9厘米，距离地面0.8至6米。巢筑在藤蔓和蕨类植物丛中，大叶潘丹树上，或小树顶端的树枝群附近，靠近树干。每次产一枚白色或淡黄色卵，由双方共同孵化。","identification":"与Black-billed Cuckoo-Dove相比，体型更大，下部颜色更浅，尾部无条纹。与（新几内亚）、（俾斯麦群岛）、（苏拉威西岛及其卫星岛）、（摩鹿加群岛和新几内亚）和（俾斯麦群岛）有明显区别，主要体现在体型、颜色、条纹等方面。不同亚种之间在颜色和条纹程度上存在微妙差异。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚新几内亚区的北摩鹿加群岛、苏拉威西岛至新几内亚北部和巴布亚岛西部。在新几内亚广泛分布，被认为是相当常见。","other":"适应力强，能适应受扰动的栖息地，暗示该物种目前相对安全。"},{"name":"印尼鹃鸠","english_name":"Ruddy Cuckoo-Dove","scientific_name":"Macropygia emiliana","overview":"印尼鹃鸠（英文名：Ruddy Cuckoo-Dove，学名：Macropygia emiliana），是鸽形目鸠鸽科鹃鸠属的鸟类。中型的红褐色鸠鸽，广泛分布于婆罗洲、爪哇、巴厘岛和弗洛勒斯岛等地。其头部颜色较淡，带有姜黄色调，全身呈锈褐色，具有独特的粉色光泽颈部。","appearance":"印尼鹃鸠全长约30至37厘米，通体红褐色，胸部紫褐色并带有不明显的黑色条纹，颈部和胸部可见粉红色金属光泽。虹膜内部有一圈淡蓝色，外环为红色；喙色奶油灰，脚部呈紫红色。雌鸟与雄鸟相似，但缺乏颈部和胸部的光泽，背羽上的暗色条纹更为明显。幼鸟喉部下方的羽毛黑底红心。亚种差异主要体现在体型、色彩饱和度和条纹密集程度上，如cinnamomea亚种色泽更鲜艳，呈肉桂色。","call":"印尼鹃鸠发出一系列咕咕声的呼唤，通常包含数个间隔的轻柔连接音节（\"WHOOhuhuWHOOhuhuWHOO\"），在远处可能难以听到。还有一种更明显的两部分鸣叫\"huWOO, huWOO\"。","habits":"主要栖息于低地和山麓森林、林地及林木种植园，偶尔在开阔地带休息或觅食。常见于海拔1500米以下的地区，如爪哇的低地至1500米，婆罗洲至1000米，龙目岛至400至1520米，松巴哇岛至300至1000米，弗洛勒斯岛从海平面至1200米。通常避开耕作区，但在小巽他群岛会利用林木栽培地。以地面觅食和饮水为主，单只或成对活动。","breeding":"繁殖信息有限，但据知在爪哇和巴厘岛全年都有筑巢现象，弗洛勒斯岛则在4月至7月间。会在小树上搭建简单的树枝巢，每次产一枚奶油色的蛋。","identification":"与小鹃鸠相比，印尼鹃鸠体型更大，胸腹部颜色更深，且在栽培环境中更为罕见。雌雄之间通过颈部和胸部的光泽差异来区分，幼鸟通过喉部下方的特殊羽毛图案识别。","protection":"IUCN：LC（最不受关注）","distribution":"分布于远东地区，包括拉卡塔岛（爪哇岛西面）、爪哇岛、巴厘岛、龙目岛至弗洛勒斯岛（小巽他群岛西部和中部）。","other":"该物种于2003年从slender-billed cuckoo-dove中分离出来，具有两个现存的亚种。"},{"name":"恩加诺鹃鸠","english_name":"Enggano Cuckoo-Dove","scientific_name":"Macropygia cinnamomea","overview":"恩加诺鹃鸠（英文名：Enggano Cuckoo-Dove，学名：Macropygia cinnamomea），是鸽形目鸠鸽科鹃鸠属的鸟类。独特的鸟类，该物种仅在印度尼西亚的恩加诺岛发现，此前曾被认为是红褐色鹃鸠的一个亚种。其最显著的外部特征为带有斑点的‘鳞状’胸部和上部，全身呈姜黄色至棕色。在恩加诺岛上是唯一的鹃鸠种类。","appearance":"恩加诺鹃鸠体长30-37厘米，整体颜色为丰富的红棕色，胸部呈紫棕色，具有不显眼的黑色条纹。颈部和胸部带有粉红色的金属光泽，虹膜具有淡蓝色的内环和红色的外环。喙为奶油灰色，脚为紫红色。雌鸟与雄鸟相似，但缺乏颈部和胸部的金属光泽，肩部的暗色条纹更明显。幼鸟下喉部的羽毛为黑色，中心为赤褐色。不同亚种在大小、色彩和条纹强度上有所不同，指名亚种cinnamomea的色彩更为明亮的红肉桂色。","call":"恩加诺鹃鸠的鸣唱是一系列重复的、拖长的哨音，通常结合一到两个较弱且更短的音符，后者只有在近距离时才能听到。大多数亚种拥有三音节的短语，例如“wuh...wuh....wUUw.....wuh..wuh...wUUw...”，而指名亚种（在爪哇和巴厘岛）发出的是两音节的“wuh..wUUw...wuh...wUUw...”。","habits":"栖息于原始森林、高大的次生林、林间空地和小片开阔地带；在爪哇岛低地至海拔1500米，在婆罗洲至海拔1000米，在龙目岛海拔400-1520米，在松巴哇岛约300-1000米，在弗洛雷斯岛从海平面至1200米。通常避开耕作地，但在小巽他群岛会利用树木覆盖的耕地。在地面觅食和饮水。一般单独或成对出现。飞行速度明显慢于小鹃鸠。","breeding":"关于繁殖的信息较少。在爪哇和巴厘岛似乎全年都在筑巢；在弗洛雷斯岛为4月至7月。在小树上构建简单的树枝巢，每窝产一枚乳白色蛋。","identification":"恩加诺鹃鸠与其他鹃鸠的区别在于其独特的‘鳞状’胸部和上部的斑点图案，以及特有的鸣叫声。与小鹃鸠相比，飞行速度较慢。","protection":"IUCN：NT（近危）","distribution":"恩加诺鹃鸠仅限于印度尼西亚恩加诺岛，位于苏门答腊岛西南部海岸外。2009年在弗洛雷斯群岛的阿拉克岛被发现。在苏门答腊西面岛屿上的现状尚不清楚，尽管有零星的目击记录。在苏门答腊大陆的状态不确定，可能仅为迷鸟。","other":"在婆罗洲、爪哇、巴厘岛和弗洛雷斯岛的山区森林中局部常见。"},{"name":"巴鲁珊鹃鸠","english_name":"Barusan Cuckoo-Dove","scientific_name":"Macropygia modiglianii","overview":"巴鲁珊鹃鸠（英文名：Barusan Cuckoo-Dove，学名：Macropygia modiglianii），是鸽形目鸠鸽科鹃鸠属的鸟类。仅分布于苏门答腊西北海岸的巴鲁珊群岛，全身呈深姜棕色，头部略浅。巴鲁珊群岛特有的鹃鸠，除了在锡默卢岛，那里还有小鹃鸠与之共存，注意巴鲁珊鹃鸠体型更大，胸部呈更深的红褐色。","appearance":"巴鲁珊鹃鸠体长30至37厘米，整体呈丰富的红褐色，胸部紫褐色，带有不明显的黑色条纹，颈部和胸部有粉色金属光泽，眼睛具有淡蓝色内环和红色外环，喙为乳灰色，脚为紫红色。雌鸟与雄鸟相似，但缺乏颈部和胸部的金属光泽，背部的暗色条纹更为明显。幼年雌鸟下喉部羽毛为黑色，中心呈赤褐色。不同亚种主要在体型、色彩和条纹强度上有所不同，例如cinnamomea亚种颜色更亮，呈红肉桂色。","call":"巴鲁珊鹃鸠发出三声系列的咕咕叫声，'woo-woo-wooOOH'，在远处听起来可能像一声升高的呼噜声。","habits":"巴鲁珊鹃鸠栖息在低地和丘陵森林地带，通常单独或成对出现在森林的中层和下层。它们在地面觅食和饮水，主要在主林、高大的次生林、林间空地和小片开阔地活动。它们在较低的树冠层中觅食。飞行速度比印尼鹃鸠慢。","breeding":"有关繁殖的信息很少。在爪哇和巴厘岛，筑巢似乎全年都在发生；在弗洛雷斯岛，则在4月至7月。它们在小树上建造简单的树枝巢，每次产一枚奶油色的蛋。","identification":"与印尼鹃鸠相比，巴鲁珊鹃鸠体型更大，胸部颜色更深，叫声独特。","protection":"IUCN：LC（无危）；巴鲁珊鹃鸠在婆罗洲、爪哇、巴厘岛和弗洛雷斯岛的山林中局部常见。2009年在弗洛雷斯链的阿拉克岛上被发现。在苏门答腊西边的岛屿上并不罕见，但在锡默卢岛上的现状需要进一步调查。在苏门答腊大陆的状态不确定，可能只是迷鸟。","distribution":"巴鲁珊鹃鸠主要分布在苏门答腊西部的岛屿上（除恩加诺岛外）。在婆罗洲、爪哇、巴厘岛和弗洛雷斯岛的山林中局部常见。","other":"2016年的一项声学研究结果促成了巴鲁珊鹃鸠从印尼鹃鸠中独立出来，被提升为独立物种。"},{"name":"大鹃鸠","english_name":"Timor Cuckoo-Dove","scientific_name":"Macropygia magna","overview":"大鹃鸠（英文名：Timor Cuckoo-Dove，学名：Macropygia magna），是鸽形目鸠鸽科鹃鸠属的鸟类。体型较大的鸠类，以深赤褐色背部和广泛条纹著称，头部颜色较淡，腹部呈淡黄色至红棕色，广泛分布于帝汶岛、Alor、Wetar、Romang、Kisar、Leti、Moa和Sermata（小巽他群岛东部）。","appearance":"大鹃鸠身长44厘米，头呈金色至栗红色，有微弱黑色条纹；喉部浅稻草色；颈、上背、胸及下体为浅金棕色，有黑色条纹；背部和臀部颜色更深，有微弱条纹；覆羽深红棕色，带有黑色条纹和暗灰色斑点；初级飞羽和最外侧次级飞羽黑色边缘呈淡黄色；翼下红褐色；尾下覆羽浅红褐色；尾羽暗红棕色，最外侧一对尾羽有模糊的黑色亚端带；虹膜蓝灰色，外环为红色或橙色；喙棕至黑色，下颚尖端较浅；脚为棕色或紫红色。雌鸟类似，但胸部主要为红棕色，有淡色斑点和微弱条纹。幼鸟似雌鸟。","call":"发出短暂的三音节沙哑叫声，起始音调上升，然后在最后一个音符下降，如'whoOP-woo-hoo'。","habits":"生活在低地和丘陵地带的原始森林和高大的次生林中，高度可达至少1000米。单独、成对或小群出现。","breeding":"繁殖信息未知。","identification":"与小鹃鸠相比，更大的大鹃鸠在上部和下部（雄鸟）显示出明显的条纹。不同亚种主要在羽毛色调上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界：帝汶岛，Alor，Wetar，Romang，Kisar，Leti，Moa和Sermata（小巽他群岛东部）。","other":"与印尼鹃鸠、菲律宾鹃鸠、红胸鹃鸠和褐鹃鸠密切相关，有时被认为同种；与红胸鹃鸠和褐鹃鸠关系最近；物种界限尚不清楚，需要进一步研究以明确其复杂关系内的确切联系。"},{"name":"塔宁巴鹃鸠","english_name":"Tanimbar Cuckoo-Dove","scientific_name":"Macropygia timorlaoensis","overview":"塔宁巴鹃鸠（英文名：Tanimbar Cuckoo-Dove，学名：Macropygia timorlaoensis），是鸽形目鸠鸽科鹃鸠属的鸟类。大型、长尾的鸠鸽科鸟类，主要分布在印度尼西亚的塔宁巴尔群岛。曾被归类为暗色或颈带帝汶姬地鸠鸽的成员之一。雄鸟的上体颜色深沉，下体较淡，全身布满明显的暗色条纹；雌鸟和幼鸟的特征较为模糊，胸羽呈红褐色，条纹较弱。该岛群中唯一的鸠鸽。","appearance":"体长约44厘米。头部呈金棕色至栗红色，带有微弱的黑色条纹；喉咙为浅麦黄色；颈部、上背、胸部和下体为浅金棕色，覆以黑色条纹；背部和臀部颜色较深，有微弱的条纹；翼羽为深红棕色，混杂着黑色条纹和暗灰色斑点；初级飞羽和次级飞羽边缘呈淡褐色；下翼为栗色；尾下覆羽为浅栗色；尾羽为暗红棕色，最外侧一对有不明显的黑色次端斑。虹膜蓝灰色，外圈为红色或橙色；喙为棕色至黑褐色，下颚尖端较浅；脚为棕红色或紫红色。雌鸟与雄鸟相似，但胸部主要为红褐色，斑点和条纹非常淡。幼鸟与雌鸟类似。不同的亚种主要在羽毛色调上有差异。","call":"发出重复的两音节沙哑哨声，首音上升并放大，第二音下降且哀婉，如‘woooOOp-wooo’。","habits":"生活在低地的森林、林地和种植园中，单个、成对或小群体出现。其食物和觅食习惯尚不清楚，可能与近缘物种相似，主要在中层和下层树冠觅食。","breeding":"关于繁殖行为的信息目前未知。","identification":"与帝汶姬地鸠相比，体型更大，上体颜色更深。与红翅鹃鸠、印尼鹃鸠、菲律宾鹃鸠、红胸鹃鸠和褐鹃鸠关系密切，但具体物种界限不清，需进一步研究。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，主要集中在印度尼西亚的塔宁巴尔群岛（南摩鹿加群岛）。","other":"系统发育历史显示，与红翅鹃鸠、印尼鹃鸠、菲律宾鹃鸠、红胸鹃鸠和褐鹃鸠关系密切，但物种界限尚不明确，需进一步研究以澄清其复杂的关系。"},{"name":"弗洛勒斯海鹃鸠","english_name":"Flores Sea Cuckoo-Dove","scientific_name":"Macropygia macassariensis","overview":"弗洛勒斯海鹃鸠（英文名：Flores Sea Cuckoo-Dove，学名：Macropygia macassariensis），是鸽形目鸠鸽科鹃鸠属的鸟类。大型、长尾，分布于印尼弗洛勒斯海的若干岛屿及可能的西南苏拉威西岛。该物种具有土黄色的下体，带有条纹，上体呈均匀的棕褐色，雄鸟的头部和颈背呈棕色，而雌鸟头部较淡，颈背带条纹。幼鸟外观类似雌鸟。","appearance":"弗洛勒斯海鹃鸠体长44厘米，头部色泽从金棕色到栗红色，带有隐约的黑色条纹；喉部呈淡麦秆色；颈、上背、胸部和下体为浅金棕色，带有黑色条纹；背部和臀部颜色较深，带有微弱的条纹；翼覆羽呈暗红棕色，混杂着黑色条纹和深灰色斑点；初级飞羽和外侧次级飞羽边缘为淡褐色；下翼为栗色；尾下覆羽为浅栗色；尾羽为暗红棕色，最外侧一对有不明显的黑色亚端斑；虹膜为蓝灰色，外环为红色或橙色；喙为棕色至黑色，下颚尖端较浅；脚为褐红色或紫红色。雌鸟相似，但胸部大多为红棕色，淡色斑点和条纹非常淡。幼鸟与雌鸟相似。不同亚种主要在羽毛色调上有差异。","call":"弗洛勒斯海鹃鸠的叫声在地理上有所变化。指名亚种为macassariensis的亚种发出三音节的叫声，其中第一个音节上升并最长，所有音节听起来都有些模糊，例如“rruah..rhuu.rhuw”。timorlaoensis亚种的叫声由两个音节组成，第一个音节较短并上升，第二个音节拉长且过度模糊，例如“whuA..whoOOoh”。","habits":"弗洛勒斯海鹃鸠栖息于原始森林和高达至少1000米的高大次生林中，也可能出现在季雨林、次生林和森林边缘。它们单独、成对或小群体出现。食物信息不详，但可能与近缘物种类似，主要在树冠中层和下层觅食。","breeding":"关于繁殖的信息尚未可知。","identification":"弗洛勒斯海鹃鸠与苏坦氏鹃鸠的区别在于其完全条纹的下体。此外，与红翅鹃鸠、印尼鹃鸠、菲律宾鹃鸠、红胸鹃鸠和褐鹃鸠关系密切，物种界限尚不清楚，需要进一步研究以明确其关系。","protection":"IUCN：LC（无危）。在一些地方似乎并不罕见，如Tanahjampea岛、Kalaoato和Yamdena岛以及Wetar岛上广泛且频繁出现，但在Timor较为少见。在苏拉威西岛上的状况不明，自模式标本收集以来没有记录，但近期在Tana Keke岛的发现暗示可能存在零星个体或曾有小型种群。","distribution":"弗洛勒斯海鹃鸠分布于澳大利亚-新西兰生态区的弗洛勒斯海岛屿南部，以及可能的印尼苏拉威西岛南部。"},{"name":"菲律宾鹃鸠","english_name":"Philippine Cuckoo-Dove","scientific_name":"Macropygia tenuirostris","overview":"菲律宾鹃鸠（英文名：Philippine Cuckoo-Dove，学名：Macropygia tenuirostris），是鸽形目鸠鸽科鹃鸠属的鸟类。体型较大的鸠鸽科鸟类，以其长而宽的尾巴和深褐色的外观著称。分布于菲律宾和台湾，尤其在森林、次生林和林间空地常见，能适应一定的人类活动区。具有独特的头部和腹面红褐色，背部暗灰，颈后部在良好光照下可见微紫光泽。","appearance":"菲律宾鹃鸠体长35.5至40.8厘米，体重157至191克。头部和颈部为肉桂红棕色，颈后部和上背有淡紫色光泽，背部、臀部、翅膀和尾巴为深栗色，略带紫色。初级飞羽为棕色，次级飞羽内缘和下翼覆羽呈肉桂红棕色。最外侧三枚尾羽明亮的红棕色，内侧网状结构基部有宽大的黑色带纹。虹膜黄色，外围有红色环，眼周环和喙基红色，喙浅棕色，脚为鲜红色。雌鸟头部和下体为肉桂色，喉部浅红棕色，胸部有显著的灰色基部和肉桂色边缘；上体深棕色，颈后部和上背有赤褐色和黑色条纹；臀部和尾上覆羽深栗色，有微小的棕色斑点。幼鸟颜色似成年雌鸟，但上翼覆羽和次级飞羽内侧边缘为肉桂色。","call":"菲律宾鹃鸠的鸣叫声为重复的拖长哨音，结合两个较弱和较短的音符，只有在近距离时才可听见：\"wuh...wuh....wUUw.....wuh..wuh...wUUw...\"，每次鸣叫持续约1.6秒，第三和第四音符之间有0.6秒的停顿，间隔3到4秒重复一次。","habits":"栖息于森林、次生林和林间空地，偏好浓密的树林和溪谷地带。活动范围从低地到海拔约2000米的高度。飞行快速，常在树冠层上方穿梭。以水果为主食，常在新清理的林地、林缘旁的耕作区和次生林中觅食，偶尔在地面觅食和饮水。单独或成对活动，有时以5至8只的小群体出现。","breeding":"繁殖信息有限，已知会在封闭森林下的垂直峭壁凹陷处筑巢，单次产一枚蛋。繁殖季节从3月到6月，具体时间因地区而异。雌鸟在4月底可能准备产硬壳蛋，雄鸟在3月会有增大的生殖腺，雌鸟在2月和5月有增大的卵巢。巢为简单的枝条构成，位于小树上，产一粒乳白色的蛋。","identification":"与其他森林鸠鸽相比，菲律宾鹃鸠颜色更深，尾巴更长，斑点较少。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾群岛，包括Batan、Calayan、Luzon、Mindoro、Sibuyan、Palawan、Negros、Bohol、Siquijor、Mindanao和Sulu群岛。在台湾和附近的兰屿也有分布。","other":"自1998年起，被IUCN列为无危等级，因其广泛分布和稳定的人口趋势。"},{"name":"褐鹃鸠","english_name":"Brown Cuckoo-Dove","scientific_name":"Macropygia phasianella","overview":"褐鹃鸠（英文名：Brown Cuckoo-Dove，学名：Macropygia phasianella），是鸽形目鸠鸽科鹃鸠属的鸟类。中等体型的鸟类，尾部较长，全身呈褐色，头部及下体为粉褐色。常见于澳大利亚东部的雨林地带，以果实和种子为食，通常听到其声音多于见到其身影。","appearance":"体长39至45厘米，体重150至240克。头部、颈部和下体为赤褐色，冠部和颈背颜色较灰。雄鸟的颈背有绿色或紫色金属光泽，雌鸟通常有明亮的栗色顶帽，颈部和胸部有明显的暗褐色鳞状斑纹，下体缺乏粉色色调，上体无金属光泽。幼鸟与雌鸟相似，但栗色顶帽更为明显，脸颊和耳羽呈淡黄色，有细密的暗色条纹。","call":"繁殖季节时发出深沉的“wuh..whooaa”重复两音节的叫声，第一个音节短而微弱，第二个音节更长且上扬。","habits":"栖息于雨林和湿润硬叶林，尤其偏好边缘地带、空旷地和早期次生林。常成对或小群出现，食物丰富时数量会显著增加。飞行直接而有力，通常在树下层进行，很少飞越树冠。","breeding":"繁殖季节延长，春季和初夏为高峰期。巢由干枝构成，放置于各种位置，包括水平的树叉、藤蔓缠绕处或树蕨顶部。每巢产一到两个蛋，孵化期为16至18天。雏鸟孵化时覆盖着厚厚的黄色绒毛，体重约10克。雏鸟在第7天时，身体各部位的羽毛开始显现，主翼羽开始生长。离巢发生在16天左右。","identification":"与斑尾鹃鸠相比，上体无黑色横纹，颈背无绿色光泽，尾下覆羽为黄褐色。雌鸟特有浅黄褐色的前额和头顶，下体具黑色细横纹。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从北端的约克角半岛尖端（北昆士兰州）至维多利亚州东部，沿海地区及邻近高地。"},{"name":"红翅鹃鸠","english_name":"Andaman Cuckoo-Dove","scientific_name":"Macropygia rufipennis","overview":"红翅鹃鸠（英文名：Andaman Cuckoo-Dove，学名：Macropygia rufipennis），是鸽形目鸠鸽科鹃鸠属的鸟类。其最显著的外部特征是锈色羽毛，常见于安达曼群岛和尼科巴群岛的森林中。","appearance":"红翅鹃鸠体型修长，尾部长，头部和腿小。全身锈色，颈部和胸部有微弱的条纹。头颈至颈背呈锈色至栗色，脸颊和喉咙颜色较淡；颈背红棕色至淡黄褐色，有黑色条纹和斑点；颈侧和胸腹红棕至栗色，有黑色条纹，腹部有暗色条纹和斑点；下尾覆羽栗色；翼上覆羽有锈色边缘，初级和次级飞羽大多锈色栗色，尖端和斑点黑色。雌鸟整体更红，冠部更锈色，有黑色斑点；雄鸟和雌鸟相似，但幼鸟颈背和披肩有更明显的条纹，整体颜色不如成鸟红。","call":"发出一系列细长而坚持的滑音咕咕声，具体为重复的两音节叫声，“whaw-whup..whaw-wup...”，类似大杜鹃的叫声。","habits":"栖息于茂密的常绿林和次生林，以各种水果和浆果为食，尤其是葡萄（Vitis）和Leae属的果实。在某些地区，主要食物似乎是鸟眼辣椒（Capsicum fastigiatum），这种辣椒在次生丛林和清理区边缘常见。通常在树上觅食，偶尔也在地面觅食。","identification":"与同属其他物种相比，红翅鹃鸠具有更为鲜明的锈色外观，叫声独特，生活于特定的岛屿环境。","protection":"IUCN：LC（无危）","distribution":"主要分布于安达曼群岛和尼科巴群岛，这些地区是其特有栖息地。","other":"尽管物种数量似乎稳定，但对红翅鹃鸠的生物学了解甚少，需要更多的研究来了解其生态和保护状况。"},{"name":"黑嘴鹃鸠","english_name":"Bar-tailed Cuckoo-Dove","scientific_name":"Macropygia nigrirostris","overview":"黑嘴鹃鸠（英文名：Bar-tailed Cuckoo-Dove，学名：Macropygia nigrirostris），是鸽形目鸠鸽科鹃鸠属的鸟类。以棕色为主色调，拥有长长的尾巴和黑色的粗壮喙。常见于新几内亚及周边岛屿，通常单独或成对出现在森林边缘，有时也会形成多达20只的小群体在果树上觅食。其特征性的条纹尾羽和臀部是识别的关键。","appearance":"体型较小，体长29至30厘米，体重66至104克。全身呈丰富的栗红色，翅膀颜色较深，腹部颜色较浅；初级飞羽和次级飞羽边缘呈褐色，带锈色边缘；上尾覆羽有淡黑色条纹；中央尾羽栗红色带黑色条纹；最外侧尾羽淡栗色，带有宽黑色亚端斑；肩部和胸部有轻微条纹；眼睛周围有灰白色虹膜，被黑色环包围，外圈为红橙色到黄色；眼周皮肤红色；脚部颜色为红色、紫色或粉色；喙全黑，或呈棕黑色。雌鸟较浅的栗色，背部金色，有明显的黑色条纹；尾部类似雄鸟，但条纹更明显；脚部呈棕色。幼鸟与雌鸟相似，但尾部条纹不规则。","call":"常发出快速下降的一系列约12个模糊的“woi”或“koik”音符，每秒约3个音节，音量逐渐减弱。叫声比更高亢且更快速。","habits":"栖息于新几内亚从海平面至海拔2600米的低地和山地森林边缘，以及再生林。主要在树上觅食果实和种子，偶尔会下地喝水。在干季期间，可能会下地饮水。","breeding":"关于季节性的数据很少，但在10月曾发现雏鸟和幼鸟。两个地面巢穴在Wau附近的陡峭山坡上被发现；一些鸟会在较高的位置筑巢，如小树上的附生蕨类植物中。一窝通常只有1枚蛋，但曾记录到一窝有2枚蛋的情况。在圈养条件下，雏鸟在17天后孵化。","identification":"与褐鹃鸠和棕鹃鸠相似，但可通过条纹尾羽和臀部、一致的栗褐色羽毛和喙的颜色进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚、Yapen岛（鸟头湾，新几内亚西北部）、Karkar岛（新几内亚东北部北部）、Goodenough和Fergusson岛（巴布亚新几内亚当特尔卡斯托群岛，东部，新几内亚东南部）以及俾斯麦群岛东部。"},{"name":"棕鹃鸠","english_name":"MacKinlay's Cuckoo-Dove","scientific_name":"Macropygia mackinlayi","overview":"棕鹃鸠（英文名：Spot-breasted Cuckoo-Dove，学名：Macropygia mackinlayi），是鸽形目鸠鸽科鹃鸠属的鸟类。广泛分布于澳新界的俾斯麦群岛至瓦努阿图。其体色以灰褐或红褐色为主，独特的羽毛形态使它在同类中独树一帜。","appearance":"棕鹃鸠体长27至31厘米，体重约87克，拥有灰色或红褐色两种色型。红褐色型雄鸟全身深红褐色，上体最暗，头部和颈部较淡，翼端和次级飞羽呈棕色黑边，尾羽中央深棕色，外侧灰红带黑色亚端带。灰色型雄鸟上体暗灰，多数羽毛边缘浅灰，头和下体淡灰，有时额头、喉部和胸部淡黄银色，斑点灰或灰黄色。雌鸟和幼鸟色彩各异，幼鸟更显条纹。","call":"经常被听到发出旋律优美的‘vo ku’声，首音节高于次音节，重复而富有节奏感。","habits":"栖息于次生林、开阔地带、花园和受干扰森林区域的中层和低冠层，常见于海拔200至800米处，最高可达1500米。以种子和小果实为食，包括引进的辣椒灌木和大花九里香灌木的果实，偶尔会到地面觅食。在小型树木中觅食，偏好在较低的果树林中活动。","breeding":"繁殖季节在瓦努阿图为9月至2月，筑巢于树上，高度3至6米，通常为盘状结构，使用典型的鸽子巢材，产1至2枚白色蛋。","identification":"与细喙鹃鸠相比，体型较小，喙较短，上体颜色更深，下体颜色更淡，且胸羽分裂，造成斑点效果。与黑嘴鹃鸠区别在于体型略小，羽毛色泽更丰富，但头部和下体颜色更淡。","protection":"IUCN：LC（无危）","distribution":"分布于俾斯麦群岛至瓦努阿图，包括所罗门群岛和巴布亚新几内亚的部分地区。","other":"以苏格兰自然学家Archibald Mackinlay命名，是当地常见的物种，但在新不列颠岛和安提基岛较为罕见。"},{"name":"赤灰长尾鸠","english_name":"Great Cuckoo-Dove","scientific_name":"Reinwardtoena reinwardti","overview":"赤灰长尾鸠（英文名：Great Cuckoo-Dove，学名：Reinwardtoena reinwardti），是鸽形目鸠鸽科长尾鸠属的鸟类。体型较大，最显著的特征为非常长的尾巴，背、翼和尾呈深栗褐色，头颈胸腹部分颜色淡雅，白或淡灰色。分布于印尼摩鹿加群岛和新几内亚地区。","appearance":"体长47.5至52.5厘米，体重208至305克。头部、颈部、胸部及腹部为淡蓝灰色，喉部白色，胸部羽毛可能带有粉红色调。背部、翅膀上覆羽、肩羽和尾羽中央为富丽的栗色，翅膀下覆羽和次级飞羽黑色，尾羽外侧具黑带和灰尖。幼鸟为灰褐色，喉部和腹部脏白色，翼覆羽和尾上覆羽红棕色。雌雄差异主要在于虹膜颜色和眼周皮肤的亮度。","call":"发出重复的‘cookuwook cookuwook cookuwook’声，类似，但音速更慢，音节更三音节，还发出约12个低沉的‘hoo’音，音调逐渐下降并加速。","habits":"栖息于原始森林冠层和中层，也见于森林边缘、次生林和画廊森林，海拔从海平面到3380米。以小种子和果实为食，偏好Schefflera和Araliaceae科植物果实。偶尔到地面觅食。","breeding":"繁殖季节全年，可能在10月至12月达到高峰。巢为平台状，由细枝、苔藓、根和蕨类植物构成，内衬较细的植物材料，通常位于树或灌木丛中1.2至5米高处。每次产一枚白色卵，双亲共同孵化，孵化期约16至22天。","identification":"与较小的区别在于体型更大，下体颜色更淡，上体色彩更丰富。亚种间差异体现在大小、颜色深浅及分布区域。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体包括印尼的摩鹿加群岛和新几内亚区域。","other":"在Crater Mountain Wildlife Management Area密度为4至6只/平方公里，局部地区常见。"},{"name":"黑白长尾鸠","english_name":"Pied Cuckoo-Dove","scientific_name":"Reinwardtoena browni","overview":"黑白长尾鸠（英文名：Pied Cuckoo-Dove，学名：Reinwardtoena browni），是鸽形目鸠鸽科长尾鸠属的大型鸠类。又称Brown's cuckoo-dove，由英国动物学家Philip Sclater于1877年首次描述。其独特银黑相间的外观，使它在同类中极为醒目，主要分布于新几内亚东北的阿德默尔蒂群岛，包括新汉诺威（Lavongai）、新爱尔兰和新不列颠岛及其周边岛屿。","appearance":"成年黑白长尾鸠体长约40至46厘米，体重介于279至325克之间。头部和下体呈灰白色，逐渐过渡到顶部的银灰色，而背部、翅膀和尾巴则呈现深黑色，翼羽和中央尾羽带光泽。尾羽具有灰色斑纹，外侧三根尾羽带有模糊的灰色横带。下体白色延伸至腹部，接近尾下覆羽和胁部转为暗蓝灰色。虹膜红或黄色，喙灰或褐色，基部红色，脚为深红色。雌雄相似，幼鸟以烟灰色为主色调。","call":"其广告叫声为一系列远距离传播的音符，开始是一个短暂音节，随后是上升调的哀怨音节，最后以两个低沉音符结束，第二个音符为整串叫声中最深沉的部分。","habits":"主要栖息于低地和山地雨林，最高可达海拔1000米，偏好高大森林，常见于山丘地带。在适度退化的森林中仍能生存，但不会出现在严重退化且缺乏树冠覆盖的森林中。通常单独或成对出现，于森林中层或树冠层活动，以果实为食。","breeding":"繁殖生态知之甚少。已知筑巢行为发生在3月至5月间，巢由枝条简单构建，位于新不列颠岛一处溪流上方岩石的突出位置，巢内含一枚白色卵，仅观察到雌鸟孵卵。卵的尺寸约为34.71毫米×25.03毫米。","identification":"与近缘种赤灰长尾鸠相比，其尾较短且羽毛中不含栗棕色。由于独特的黑白配色，与其他共域物种不易混淆。","protection":"IUCN：NT（近危）","distribution":"分布于新几内亚东北部的阿德默尔蒂群岛，包括新汉诺威（Lavongai）、新爱尔兰和新不列颠岛及其卫星岛屿（俾斯麦群岛西北部、东部）。","other":"全球估计数量为15,000至30,000只成熟个体，面临的主要威胁是森林砍伐和可能的狩猎压力。"},{"name":"凤头长尾鸠","english_name":"Crested Cuckoo-Dove","scientific_name":"Reinwardtoena crassirostris","overview":"凤头长尾鸠（英文名：Crested Cuckoo-Dove，学名：Reinwardtoena crassirostris），是鸽形目鸠鸽科长尾鸠属的鸠类。以独特的淡紫色羽冠著称。首次由英国动物学家约翰·古尔德于1856年描述，此物种仅见于所罗门群岛，主要栖息于山地森林，海拔高度约500-900米。其体长40-42厘米，灰蓝为主色，喉部灰白，尾羽深黑，喙尖黄色，腿红。雌雄相似，幼鸟无羽冠，翼羽较暗。","appearance":"成鸟头部和羽冠呈淡紫灰色，颈侧至胸蓝灰色，腹部有时泛黄褐色，上体及中央尾羽黑色，最外侧尾羽外缘灰白，基部灰色，具黑色次端斑点。虹膜黄色，周围有红色环，眼周皮肤紫红或红色，喙橙黄色，基部红色或紫红，尖端橙色，上喙强烈钩状，腿脚红色。雌鸟与雄鸟外观相似。幼鸟无长羽冠，翅膀颜色较暗，边缘锈色，头部羽毛暗淡，具黑色次端横纹和锈色尖端。","call":"广告鸣叫声由两个交替的、远传的、哨声组成，第一个音调上升，第二个音调拉长且模糊：“wha...whuaaw...wha...whuaaw...”。","habits":"栖息于从海平面到至少1100米的低地和山地森林及偶尔的次生植被区。常单独或成对出现。疑似游荡性，但缺乏具体细节。主要以树上的果实为食，如Boerlagiodendron和Schefflera属植物的果实，偶尔下地觅食。","breeding":"已知巢穴含一枚蛋，由双亲共同孵化，但具体繁殖细节未知。","identification":"与黑白长尾鸠不同，但两物种的分布区域不重叠。棕鹃鸠较小，体型更纤细，棕色而非灰色，且尾部明显较长。","protection":"IUCN：LC（无危）","distribution":"分布于所罗门群岛，自布干维尔岛山区至马基拉岛（San Cristobal）及周边岛屿，北至所罗门群岛东南部。","other":"被列为近危物种，由于其种群数量估计为适度规模且正在下降，主要是因为在其分布范围内低地森林广泛遭到砍伐。"},{"name":"白脸蕉鸠","english_name":"White-faced Cuckoo-Dove","scientific_name":"Turacoena manadensis","overview":"白脸蕉鸠（英文名：White-faced Cuckoo-Dove，学名：Turacoena manadensis），是鸽形目鸠鸽科蕉鸠属的鸟类。显著特征为全暗色的身体和鲜明的奶油色脸部，分布于印尼的苏拉威西岛及其周边小岛，包括托吉安群岛。","appearance":"体型较大，尾部较长，全身呈深色，脸部为对比明显的奶油白色。具有红色眼环和颈后闪烁着虹彩绿光的披肩。幼鸟色彩较暗淡，脸部为灰色。雄雌外观相似。","call":"叫声为三音节的歌曲：“uk-woo-wooop”。首音轻柔，近听才可闻；末音较长。","habits":"栖息于森林边缘上层和低地山丘的较开阔林区，常成对或单独出现。有时从树顶滑翔展示飞行。以果实和浆果为食，包括兰塔纳卡马拉的果实和小橙色无花果。","breeding":"雄鸟在繁殖季节会进行展示飞行，先陡升再俯冲。","identification":"与苏拉蕉鸠和黑蕉鸠有密切关系，但基于声学差异被划分为独立物种。","protection":"IUCN：LC（无危）。在苏拉威西岛，常见于次生林和森林边缘。","distribution":"分布于苏拉威西岛和周边小岛，包括托吉安群岛、穆纳岛和布通岛。","other":"曾与Sula蕉鸠视为同一物种，后因研究发现声音差异而被重新分类为独立物种。"},{"name":"苏拉蕉鸠","english_name":"Sula Cuckoo-Dove","scientific_name":"Turacoena sulaensis","overview":"苏拉蕉鸠（英文名：Sula Cuckoo-Dove，学名：Turacoena sulaensis），是鸽形目鸠鸽科蕉鸠属的大型鸟类，拥有醒目的白色面部和长长的尾巴。主要分布于印尼的苏拉群岛和邦盖群岛，是该区域的独特物种。2016年以前，苏拉蕉鸠被认为是白脸蕉鸠的一个亚种。","appearance":"成鸟具有明显的白色额头、脸部和喉咙，其余羽毛呈板岩灰色，颈部两侧带有金属绿色光泽。幼鸟颜色较暗淡，脸部泛灰，缺乏成鸟颈部的绿色或紫色光泽。雄雌外观相似。","call":"其叫声通常是一系列六音节的‘woo-ooo-woop-woop-woop’，有时前缀以柔和的‘pip-pip-pip’声。","habits":"苏拉蕉鸠常单独或成对出现，栖息于森林上层及森林边缘，也会在较为分散的开阔林区活动。它们在树冠层生活，被记录到的高度可达500米以上。","breeding":"关于苏拉蕉鸠的繁殖生物学信息有限，预计与白脸蕉鸠类似。","identification":"与白脸蕉鸠相比，苏拉蕉鸠头部和脸部的白色较少，灰色和光泽延伸至颈背更高位置，面部侧边近眼处有更暗的斑纹。","protection":"IUCN：LC（无危）。基于岛屿面积和生境质量，苏拉蕉鸠可能至少为‘近危’状态，甚至符合‘易危’标准。","distribution":"分布于印尼的苏拉群岛和邦盖群岛（东部，苏拉威西岛东侧）。","other":"2016年之前，苏拉蕉鸠被认为是白脸蕉鸠的一个亚种，后因声音差异显著而被认定为独立物种。"},{"name":"绿点森鸠","english_name":"Emerald-spotted Wood Dove","scientific_name":"Turtur chalcospilos","overview":"绿点森鸠（英文名：Emerald-spotted Wood Dove，学名：Turtur chalcospilos），是鸽形目鸠鸽科森鸠属的体型较小的鸠类，广泛分布于东非和南部非洲的干燥林地和次生林区。其最显著的特征是在翅膀上拥有两排闪烁的绿色斑点。","appearance":"绿点森鸠长约20厘米，重50-71克。头部前额白色或淡灰色，逐渐变为蓝灰色；颈部两侧和下部呈淡粉紫色，腹部中央粉白；上体颜色为浅棕色到灰褐色。翅膀闭合时，内侧可见两个大的虹彩斑块，颜色为翡翠绿至金绿，或偶尔为蓝绿色。背部有两条水平的黑带，中间隔以白色带；尾巴基部有2-3条暗带；中央尾羽灰褐，端部暗色模糊；其他尾羽蓝灰，端部黑色；翼尖和次级飞羽外缘深棕；初级飞羽和下翼栗色；下尾和最长的下尾覆羽黑色；眼睛棕色至深棕色；腿和脚紫色至紫红色；喙基部红紫色，前端黑色。雌雄相似，幼鸟全身有斑纹，翼斑较小，光泽较弱。","call":"绿点森鸠的叫声哀婉，持续约12秒，音调先轻柔渐强，速度加快，最后以略低音的结巴音符结束，共25-30个音符，通常每分钟重复3次，与近亲种类的叫声相似，但有细微差别。","habits":"绿点森鸠偏好在干燥的林地和灌木丛中活动，海拔高度可达2000米，但多数出现在1600米以下。它们通常在地上寻找小种子、草本植物和少量无脊椎动物（如软体动物、白蚁）作为食物。","breeding":"繁殖季节在不同地区有所不同，筑巢于树或灌木中，高0.5-6米，通常由枝条、根须和草茎构成直径约10厘米的平台巢，有时位于藤蔓中。每次产2枚乳白色的蛋，极少数巢中仅含1枚。孵化期13天，雏鸟淡棕色肉色，头、肩和背部有长黄色绒毛，每日喂养5次，离巢时间为16-18天。","identification":"绿点森鸠与蓝斑森鸠的区别在于后者有红色的喙尖，翼上的斑点为蓝色，且偏好湿润的森林环境。","protection":"IUCN：LC（无危）","distribution":"绿点森鸠分布在东南苏丹、埃塞俄比亚、西北索马里至安哥拉、纳米比亚和南非，包括沿海加蓬至西南安哥拉。"},{"name":"黑嘴森鸠","english_name":"Black-billed Wood Dove","scientific_name":"Turtur abyssinicus","overview":"黑嘴森鸠（英文名：Black-billed Wood Dove，学名：Turtur abyssinicus），是鸽形目鸠鸽科森鸠属的鸟类。如沙漠边缘、灌木丛和草原。筑巢于树上，常选择金合欢树，产淡奶油色的蛋。飞行迅速，翅膀偶尔快速拍打，飞行高度较低。","appearance":"黑嘴森鸠体型丰满，约20厘米长。背部、后颈、翅膀和尾巴呈浅灰褐色，翅膀折叠时可见暗金属色斑块。额头、头顶和颈背为蓝灰色，面部渐变为白色。腹部颜色由粉红渐变为白色。其特征性的黑色喙尤为醒目。飞行时，下翼显现出栗色。雏鸟较成鸟暗淡，下方具鳞状斑纹，缺乏成鸟的翅膀斑点。","call":"鸣声为持续的颤音‘coo-coo-cu-coo’，起初声音微弱犹豫，随后逐渐增强加快。","habits":"栖息于近沙漠、灌木丛和草原。以草籽和其他小型种子为主食，通常在地上觅食。虽不十分群居，但在水源附近会形成大群。","breeding":"繁殖季节在西非为8月至次年4月，在苏丹为9月至10月和1月。巢由细枝构成，隐蔽在植被中，如金合欢树，离地面1至2.5米高。每窝产两枚淡奶油色的蛋，孵化期15天，幼鸟离巢期17天。","identification":"与绿点森鸠相似，但整体色调更淡，头部尤其如此；翼斑为深蓝色且较小；喙全黑。与蓝斑鸠的区别在于全黑的喙。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚南部、塞内加尔、冈比亚至东非的厄立特里亚、埃塞俄比亚和乌干达。","other":"尽管被列为IUCN的无危等级，但自2004年以来，其种群数量显著减少。"},{"name":"蓝斑森鸠","english_name":"Blue-spotted Wood Dove","scientific_name":"Turtur afer","overview":"蓝斑森鸠（英文名：Blue-spotted Wood Dove，学名：Turtur afer），是鸽形目鸠鸽科森鸠属的鸟类。以其红黄色的喙和翅膀上的蓝色小斑点而著称。分布区域从塞内加尔至埃塞俄比亚，南至安哥拉、南非北部和莫桑比克。","appearance":"蓝斑森鸠是一种体型较小、色泽淡雅的鸽类，其喙呈现红色，尖端带黄。翼上可见微小的暗色虹彩斑点，颜色为蓝色，但在一般观察下较难辨认。飞行时，翅膀展示出赤褐色的斑块，尾巴末端白色并带有黑色条纹。雌雄外观相似，幼鸟较成鸟更显棕色，背部覆以淡色尖端和条纹，翅膀上的斑点更小且色泽较暗淡。","call":"鸣唱为一系列悠长的‘呼’声，音调逐渐加快，声音空洞而哀婉，通常持续约10至14秒，音量和速度逐渐增强，结尾时音符略有下降，每分钟重复约三次。","habits":"蓝斑森鸠偏好湿润的栖息环境，如茂密的草原、森林边缘、灌木丛和稀树草原中的常绿灌木丛，海拔可达2000米。它们也会出现在花园、农田、红树林和桉树种植园。主要以草籽为食，偶尔也食用蓖麻籽、白蚁和小型蜗牛。它们在地上觅食，单独或成对出现，有时会在食物丰富的区域聚集小群。","breeding":"筑巢活动全年可见，但在东非主要集中在10月至次年3月或4月，西非也有记录。巢为直径8至20厘米的平台状，由树枝、细根、藤蔓和毛茸茸的材料构成，置于地面1至3米高的灌木、树木或树桩上。已知两次使用旧鸫鸟巢的情况。每窝产2枚白色至奶油色的蛋，孵化期13天，雏鸟离巢期13至14天。","identification":"与绿点森鸠相比，蓝斑森鸠具有更小的紫蓝色翅膀斑点，外侧尾羽外网基部呈淡灰色而非白色，喙酒红色，尖端橙黄色。它在更湿润的环境中被发现。","protection":"IUCN：LC（无危）。在大部分分布区广泛且普遍常见，但在索马里南部、肯尼亚南部和坦桑尼亚分布较为碎片化。","distribution":"分布于非洲，从塞内加尔和冈比亚至厄立特里亚、埃塞俄比亚和乌干达，南至安哥拉、南非北部和莫桑比克。在肯尼亚，主要分布在年降水量超过1000毫米的地区。","other":"物种由Mathurin Jacques Brisson首次描述，后由Carl Linnaeus分类并命名为Columba afra，现归入Turtur属，为单型种，无亚种划分。"},{"name":"白胸森鸠","english_name":"Tambourine Dove","scientific_name":"Turtur tympanistria","overview":"白胸森鸠（英文名：Tambourine Dove，学名：Turtur tympanistria），是鸽形目鸠鸽科森鸠属的鸟类。广泛分布于非洲南部的，自几内亚至埃塞俄比亚，向南延伸至安哥拉、赞比亚和南非，亦可见于科摩罗群岛。此鸟种偏好森林地带，包括密集的花园与种植园，如蓖麻油、可可和橡胶树种植区。","appearance":"成年白胸森鸠体长约22厘米，体重介于51至85克（雄鸟）和52至77克（雌鸟）。雄鸟额头、眼周、喉部、胸部及下身白色，背部深棕色略带橄榄色，头部和颈部灰染；两道黑色横带位于下背，中间以淡色带隔开；翅膀上有紫或暗蓝绿色斑点；初级飞羽内侧及下翼覆羽呈栗色；中央尾羽深紫色，外侧尾羽蓝灰色，末端有暗灰色亚端带；下尾覆羽深棕色；虹膜棕至深棕色；喙红紫色，尖端暗棕色至黑色；腿脚紫红色。雌鸟外观较雄鸟暗淡，仅腹部保留白色，面部和胸部为浅灰褐色；冠羽灰棕色，缺乏雄鸟的蓝灰色。幼鸟羽毛边缘呈栗色和黑色条纹，下身有灰色斑点，腹部中心白色。","call":"发出一系列持续重复的“du-du-du-du-du”声音，共约40个音节，持续15至16秒，用于领地防御和吸引伴侣，起始部分音调低沉，随后节奏均匀下降，最后音符逐渐减弱。","habits":"栖息于深林、山地、低地和河岸区域，包括画廊森林和次生林，海拔从海平面至肯尼亚的3000米和埃塞俄比亚的2150米。主要在雨量适中的地区活动，如肯尼亚的500至1000毫米年降雨量区域。在旱季，会做日常迁徙至饮水点。以种子、果实为主食，如蓖麻油种子、桑葚、Solanum属水果、Syzygium、Trema orientalis（鸽木）等，偶尔食用小昆虫和软体动物。通常单独或成对活动，有时形成六只左右的小群。","breeding":"繁殖季节因地区而异，全年皆有可能繁殖，如在南非为9月至次年5月，除最冷三个月外；在刚果共和国全年繁殖。筑巢于树或灌木近干处，平台式巢由细枝和根须构成，高度1至10米，平均2.5米。每巢通常产2枚，偶尔1枚，乳白色蛋，尺寸约为23至27毫米×17.7至19.5毫米。孵化期17至20天，主要由雌鸟承担。幼鸟13至22天离巢，14天即可飞行，离巢一周后独立，但会与家庭群保持联系直到亲鸟再次繁殖。约20%的个体至少生存三年，最长记录为七年。","identification":"与其他小型非洲鸽相比，白胸森鸠下身颜色更浅，背部较暗，脸部和下身较淡。雌鸟与幼鸟相似，但雌鸟仅腹部白色，其余部位灰褐色，幼鸟羽毛边缘有栗色和黑色条纹。","protection":"IUCN：LC（无危）；CITES III在加纳。","distribution":"分布于非洲几内亚至埃塞俄比亚，南部至安哥拉、赞比亚和南非，以及科摩罗群岛。","other":"白胸森鸠在某些地区的数量似乎随着蓖麻油种植园的增加而上升，如南非沿海沙丘森林中，尽管许多鸟类种类在此下降，但该物种的数量保持稳定。"},{"name":"蓝头森鸠","english_name":"Blue-headed Wood Dove","scientific_name":"Turtur brehmeri","overview":"蓝头森鸠（英文名：Blue-headed Wood Dove，学名：Turtur brehmeri），是鸽形目鸠鸽科森鸠属的中等体型的森林鸠类，体长约25厘米。其最显著特征为蓝色头部和均匀的赤褐色羽毛，常见于非洲热带雨林地带。","appearance":"蓝头森鸠全身呈暗栗色，背部、颈部和翅膀覆羽带有强烈的红紫色调，臀部和尾巴的紫红色较淡。翅膀折叠时可见2至6个金铜色或绿金色斑点。初级飞羽和次级飞羽末端为蓝灰色，带黑色亚端带和栗色终端带。头部前方和前额为明亮的灰蓝色，逐渐变深至后冠和颈背。嘴基部暗紫色，尖端绿色，腿和脚为紫红色或粉紫色。雌雄相似，幼鸟颜色较暗，面部、前额和下巴为肉桂棕色，胸腹部有不明显的栗色和黑色条纹。","call":"蓝头森鸠的叫声为一系列空洞的呼噜声，速度逐渐加快，有时音调略有波动。其鸣唱与同类其他鸽子相似，但在音符加速上独特。","habits":"栖息于低地原始森林和老生次生林，海拔可达至少750米，避免耕作区和严重干扰的森林。偶尔出现在附近有森林的花园。飞行快速直接。主要以种子、昆虫及其幼虫、蛞蝓为食，常在森林地面的叶子间觅食。通常单独或成对出现，偶尔小群活动。","breeding":"繁殖期在不同地区有所不同，如塞拉利昂的1月，喀麦隆的8月，加蓬的12月至5月，扎伊尔的7月至10月。巢为杯状，直径约15至20厘米，由小枝条和根构成，放置于离地面2.5至5.5米高的横枝上，位于茂密的叶丛中。每次产卵1至2枚，蛋色为奶油色或深黄色，带有橄榄光泽，由双亲共同喂养，雏鸟约14天后离巢。","identification":"蓝头森鸠以其独特的蓝灰色头部和翅膀上的金属光泽斑点与其它小型非洲鸽子相区别。与同类相比，它的叫声仅由逐渐加速的单音符组成，缺乏双音或三音的节奏。","protection":"IUCN：LC（无危）","distribution":"分布于非洲西部和中部的热带雨林，具体包括塞拉利昂、加纳、尼日利亚、多哥等地，可能由于早期世纪以来的森林破坏而数量减少。"},{"name":"小长尾鸠","english_name":"Namaqua Dove","scientific_name":"Oena capensis","overview":"小长尾鸠（英文名：Namaqua Dove，学名：Oena capensis），是鸽形目鸠鸽科小长尾鸠属的鸟类。本属唯一物种。体型小巧，分布广泛，常见于非洲南部至阿拉伯半岛，以及马达加斯加。以其独特的黑色长尾和灰白腹部著称。","appearance":"小长尾鸠长约22厘米，翼展28-33厘米，体重约40克。雄鸟额头、面部、喉咙及胸前黑色，边缘灰色；头部、颈侧、胸部及大部分翅膀覆羽蓝灰色；背部、肩部、内翼覆羽、肩羽及内侧次级飞羽浅驼色至棕色；翅膀有2-5个紫色或深蓝色斑点；初级飞羽栗色，尖端黑色，外缘黑色；背部和臀部暗褐色，下背有水平淡色带，两侧有黑色条纹；尾上覆羽棕色至灰色，尖端黑色形成尾部横纹；下翼黑色和栗色；中央尾羽基部暗银灰色，向尖端渐变为黑色；外侧尾羽蓝灰色，具黑色次末端横斑，最外侧一对尾羽外缘白色；下尾黑色；虹膜深棕色，周围有紫灰色至灰色眼周皮肤；喙由紫红色至橙红色基部变化，顶端橙色至橙黄色；腿和脚紫红色。雌鸟头部、颈部和胸部灰褐色，无黑面罩，喙呈紫黑色；幼鸟全身覆羽有黑色亚端斑点，黄色至白色尖端，呈现出斑驳外观；一些雄鸟幼鸟胸羽黑色，尖端为驼色。","call":"发出低沉的双音‘hoo-oooooo’，首音较短，第二音拉长且响亮，哀婉并频繁重复。","habits":"栖息于开阔地带，如金合欢树灌木丛和荆棘林，特别是在沙质地带；也见于草地有灌木的地方、河岸附近的开阔地带和耕作区；避开森林，但在埃及发现其在红树林边缘繁殖。活动于热带和亚热带低地，海拔高度可达约1600米；在肯尼亚记录到迁徙至3000米高处；在马达加斯加，栖息于低地至1500米海拔。","breeding":"全年繁殖，东非干旱季节或雨季后期达到高峰；阿拉伯，3月筑巢，5月产卵，6月幼鸟出壳；以色列，5月中旬产卵；马达加斯加仅记录于9月至3月。巢为小平台，直径5.5-8.5厘米，由交织的小枝条、根须和藤蔓构成，内部铺草；多数位于低矮灌木（如金合欢或柽柳）0.5-5米高处，平均3米；偶尔靠近地面甚至地上；少数在芦苇或草丛中，甚至墙上。通常产两枚蛋（1-3枚），一枚四枚蛋可能由两只雌鸟所产；蛋色淡黄至象牙色；孵化期13-16天，由双亲共同孵化；幼鸟16天离巢。","identification":"与分布范围内其他鸽子相比，小长尾鸠以其小体型和长尾形状显著区分。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲，中东从塞浦路斯至伊朗西南部。","other":"自1970年代中期以来，以色列和阿拉伯的种群数量增加，分布范围扩大；在马达加斯加，主要分布在岛屿北部、南部和西部，但在高原和东部地区逐渐扩散。"},{"name":"绿翅金鸠","english_name":"Common Emerald Dove","scientific_name":"Chalcophaps indica","overview":"绿翅金鸠（英文名：Common Emerald Dove，学名：Chalcophaps indica），是鸽形目鸠鸽科金鸠属的鸟类。俗名: 绿背金鸠，又称亚洲绿鸠，美丽的森林居民，广泛分布于印度次大陆及东南亚的热带和亚热带区域。这种绿鸠也被称为绿鸽或绿翼鸽，是印度泰米尔纳德邦的州鸟。太平洋绿鸠和Stephan's绿鸠曾被视为其同种。","appearance":"绿翅金鸠是一种中等体型的鸽子，体长23至27厘米，背部和翅膀呈现鲜艳的翡翠绿色。飞行羽毛和尾巴呈黑色，飞行时可见下背宽阔的黑白条纹。头部和下体为深紫红色，逐渐变为腹部下方的灰色。雄鸟拥有肩部白色斑块和灰色冠顶，雌鸟则无，且颜色更偏向棕色。幼鸟类似雌鸟，但体羽和翼羽上带有褐色斑点。","call":"绿翅金鸠的叫声为低沉柔和的哀鸣声，通常由六到七个音节组成，声音由弱渐强。","habits":"绿翅金鸠常见于热带森林、湿润的森林边缘、农场及红树林地带。它们在树上筑简易的巢，高度可达五米，每次产两枚乳白色蛋。它们以种子和果实为主食，种类繁多，包括Arecaceae、Cyperaceae、Lauraceae、Fabaceae、Phytolaccaceae和Solanaceae等植物家族。","breeding":"绿翅金鸠在许多地区全年繁殖，高峰期通常在旱季末至雨季期间。巢穴建于密集的树叶间，高1至11米。产两枚象牙色或奶油色的蛋，但一般仅能成功抚养一只幼鸟。幼鸟孵化需14至16天，由双亲照料，出生时半留鸟，覆盖着稀疏的黄色绒毛。大约7至8天后，翅膀完全长出羽毛，12至16天后离巢。","identification":"雄性绿翅金鸠与雌鸟的主要区别在于肩部的白色斑块和灰色的冠顶。幼鸟则在体羽和翼羽上有明显的褐色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于远东和澳大利亚-新西兰界，包括印度和斯里兰卡东部，中国东南部，台湾，菲律宾，印度尼西亚群岛，以及新几内亚西北部的四王群岛（Raja Ampat Is.）。在中国，主要分布于东南部地区。","other":"绿翅金鸠适应力强，能在次生林和森林边缘生存，但在一些地区，如爪哇和巴厘岛，数量有所下降。"},{"name":"太平洋金鸠","english_name":"Pacific Emerald Dove","scientific_name":"Chalcophaps longirostris","overview":"太平洋金鸠（英文名：Pacific Emerald Dove，学名：Chalcophaps longirostris），是鸽形目鸠鸽科金鸠属的常见鸟类。广泛分布于印尼至澳大利亚北部和东部的热带与亚热带地区。体长23至28厘米，背部与翅膀呈鲜艳的翡翠绿色，头部及下体为深酒红色，逐渐转灰至腹部下方。眼睛深棕色，喙鲜红，腿足红褐色。","appearance":"太平洋金鸠体型中等偏大，体长23至27厘米，体重介于100至192克之间。雄鸟具有灰色带紫的头部和下体，翅膀和肩部有醒目的白色斑块；雌鸟头部和下体为灰褐色，肩部仅有小块灰斑。幼鸟胸部有模糊的条纹，翼羽尖端呈褐色，缺乏成鸟的白色翼斑。不同亚种在色彩和大小上略有差异。","call":"太平洋金鸠的叫声为一系列低沉、哀伤的咕咕声，起初轻柔而后音量和音调逐渐升高。","habits":"太平洋金鸠主要栖息于各种森林边缘、果园、花园、椰子种植园和森林附近的环境，包括澳大利亚的雨林、封闭的画廊森林、湿硬叶林和季风雨林。它们偏好低地和山脚地带，最高可达1300米海拔。它们通常在地上觅食，以种子和果实为主食，偶尔也会食用无脊椎动物。","breeding":"全年均可繁殖，但在不同地区有所差异。筑巢于树上，高至5米，巢由树枝构成，直径约30厘米，深度约10厘米。每窝产两枚乳白色的蛋，孵化期14至16天。幼鸟出生时覆盖着稀疏的黄色绒毛，平均重量约为6.4克。大约5周后，幼鸟能够自由飞翔。","identification":"太平洋金鸠与同属其他物种的区别在于其独特的绿色翅膀和巧克力色的身体。雄鸟与雌鸟的主要区别在于头部颜色和白色翼斑的存在。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚东南部、北部、中部，新几内亚东部和东南部的卫星岛屿，直至瓦努阿图和新喀里多尼亚。在澳大利亚，它出现在雨林、封闭的画廊森林、湿硬叶林和季风雨林中。","other":"太平洋金鸠能够适应次生林和林缘环境，因此在许多地区分布广泛且数量较多。"},{"name":"褐背金鸠","english_name":"Stephan's Emerald Dove","scientific_name":"Chalcophaps stephani","overview":"褐背金鸠（英文名：Stephan's Emerald Dove，学名：Chalcophaps stephani），是鸽形目鸠鸽科金鸠属的小型鸟类。广泛分布于澳新界的苏拉威西岛至新几内亚和俾斯麦群岛卫星岛，以及所罗门群岛。以其独特的外观和生态习性而闻名。","appearance":"褐背金鸠是一种体型较小的鸽子，长约23至25厘米，体重介于118至126克之间。它具有醒目的翡翠绿色翅膀，橙色的喙，以及前额处的淡色斑块。雄鸟的前额呈白色，而雌鸟则为灰色。幼鸟的裸露部位颜色较暗淡，羽毛上有一些条纹，且虹彩效果较弱。整体羽毛呈现栗褐色，最显著的是翅膀上的翡翠绿或青铜绿虹彩羽覆。背部和颈部侧面带有红紫色光泽，额头纯白，与褐色的头部和颈部形成鲜明对比。飞行时可见其更长的翅膀和尾巴。","call":"其鸣唱为柔和的‘hoo-hoo-hoo-hoo’声，逐渐升高并加速。","habits":"褐背金鸠栖息于湿润的常绿森林内部和干燥的次生沿海森林，主要活动于海拔500米以下，但在苏拉威西岛北部曾被记录到1375米的高度。在新几内亚，它们居住在森林边缘和次生植被区，主要分布在低地，偶尔可达1200米，但通常靠近海平面。它们有时会与同属物种共享生态位，如在凯岛，两种鸽子在生态上分离，本种仅出现在森林内部，而另一种则占据边缘地带、较为开放的生境和次生植被。","breeding":"繁殖季节主要集中在1月至5月间，但在新几内亚有记录到7月中旬的巢穴。巢由树枝构成，通常位于地面附近或积聚的落叶和碎片之上。已知的巢穴高度从地面1米至树叉约10米不等。每窝产两枚乳白色或无光泽的黄色蛋。","identification":"与亚洲和太平洋地区的金鸠相比，褐背金鸠的前额仅限于白色斑块，结合棕色背部和棕色尾巴，使其易于区分。雌鸟和雄鸟在虹彩表现和前额颜色上有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉威西岛至新几内亚和俾斯麦群岛卫星岛，以及所罗门群岛。","other":"在一些地方，如苏拉威西的Gunung Ambang自然保护区，褐背金鸠的种群数量稳定。"},{"name":"白顶地鸽","english_name":"New Guinea Bronzewing","scientific_name":"Henicophaps albifrons","overview":"白顶地鸽（英文名：New Guinea Bronzewing，学名：Henicophaps albifrons），是鸽形目鸠鸽科白顶地鸠属的鸟类，分布于澳新界的低地和山地森林，包括新几内亚和其部分西部卫星岛。该鸟以其独特的长喙和白色前额而著称，羽毛呈现金属光泽，色彩斑斓。","appearance":"体型较大，约34至41厘米长，重约247克，具有显著的长而粗的喙。全身羽毛呈烟灰色至黑色，前额白色，翅膀覆羽和次级飞羽上有金色至青铜绿或蓝色的金属光泽斑块。初级飞羽暗紫色，下尾覆羽栗色。喙棕色，脚和腿红色。雌雄相似，但雌鸟略小，翼展184至194毫米，雄鸟193至214毫米。幼鸟前额灰或褐色，金属光泽的翅膀斑块较小。","call":"发出一连串快速上升的‘whup’音符，重复速度为每秒3到4个音节，持续时间可达27秒，通常为6至12秒，声音空洞而略微上升，类似的歌声但更为急促。","habits":"栖息于湿润森林和季风林，有时也会出现在种植园、干燥的次生林和森林边缘。海拔高度从海平面到1200米，偶尔可达2150米。飞行强健且异常安静，即使从地面起飞也很少发出声响。以地面的果实、虫子和昆虫为食，也会取食树上的果实。","breeding":"繁殖期推测至少在旱季和雨季早期（6月至7月）。首个被描述的巢穴位于伊里安查亚的慢流溪边的沼泽森林中，距地面约1.5米，巢由小枝条搭建，直径约30厘米，高5至10厘米，含有一枚白色的单卵。","identification":"与厚嘴地鸽相比，白顶地鸽具有白色前额而非脸颊，且翅膀上的金属光泽更为明显。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚及其周边西部岛屿，包括低地和山地森林。"},{"name":"栗顶地鸽","english_name":"New Britain Bronzewing","scientific_name":"Henicophaps foersteri","overview":"栗顶地鸽（英文名：New Britain Bronzewing，学名：Henicophaps foersteri），是鸽形目鸠鸽科白顶地鸠属的鸟类。分布于东南亚太平洋诸岛屿，包括新不列颠岛、Umboi和Lolobau等地。这种鸟以其独特的外观和稀少的数量而闻名。","appearance":"该鸽种具有长喙和翅膀上色彩斑斓的金属光泽。其下体和脸部呈白色，从头顶至背部上端及胸部两侧呈现赤褐色。体型与颜色在地面觅食的鸽类中独一无二。","call":"声乐特征记录不足，但据说有单调重复的‘pip-yia’叫声，第二音节音调较高并上扬。","habits":"栖息于低地原始森林，主要在新不列颠岛的低地和丘陵地带的成熟林区。它们在地上觅食，受惊飞起时会落在枝头，头部上下摆动。属于地面觅食的鸽类，以种子和其他植物物质为食。","breeding":"关于其繁殖行为的信息有限。","identification":"与其它鸽类相比，栗顶地鸽的长喙和独特的羽色使其易于识别。","protection":"IUCN：VU（易危）","distribution":"分布于澳新界，具体包括新不列颠岛、Umboi（西部）和Lolobau（位于新不列颠岛东北部，俾斯麦群岛东南部）。","other":"受到森林砍伐、油棕榈种植园扩张和自给农业的威胁，导致其栖息地丧失。"},{"name":"铜翅鸠","english_name":"Common Bronzewing","scientific_name":"Phaps chalcoptera","overview":"铜翅鸠（英文名：Common Bronzewing，学名：Phaps chalcoptera），是鸽形目鸠鸽科铜翅鸠属的鸟类。尤其偏爱靠近水源的地区。雄鸟拥有明亮的黄白前额和粉红胸部，两性均具有眼周显著的白色线条，翅膀上独特的红蓝绿斑点是其显著特征。年轻个体色彩较暗淡。","appearance":"成年铜翅鸠体长28至36厘米，雄鸟体重331至356克，雌鸟310至333克。前额呈淡黄色至黄白色，头顶有深紫色条纹环绕，其余部分为棕色；颈部两侧有蓝色灰带，逐渐过渡到粉棕色的下喉和腹部；上体橄榄棕色，翼下部呈蓝灰色，有黑色次端带和宽淡色尖端；翅膀上有变化多端的绿色、黄色、青铜色或紫色虹彩斑点；胸和侧腹为粉棕色，其余下体蓝灰色。喙黑褐色，腿和脚为暗粉色至红色。雌鸟较暗淡，缺乏雄鸟的前额黄斑，上翼虹彩较少，胸部为暗红棕色。","call":"广告叫声为连续的低沉、单调的呼呼声，持续约0.75秒，起初音量增大，类似吹空瓶声，每2至3秒重复一次。还有咆哮式的求救叫声。","habits":"偏好各种林木环境，包括沿海灌丛、干旱灌木丛和多种硬叶林，也见于盐沼平原、开阔草地和有人工改造的环境，如农田、花园和路边。基本定居，局部迁徙，飞行迅速，连续拍打翅膀。主要以种子为食，辅以少量叶状物和偶尔的昆虫。","breeding":"全年均可繁殖，高峰在晚春至早夏，不受降雨影响。巢由细枝构成，高度多在4米以下，选址多样，包括水平叉枝、藤蔓缠绕处、废弃的鸟巢或兽巢，甚至树桩顶部。每次产2枚光滑的奶油色蛋，孵化期14至16天，雏鸟重8至9克，覆盖沙色绒羽。幼鸟的翼部虹彩斑点在28天左右开始显现，后幼年主羽更换约在50天开始。","identification":"与同属其他种类相比，铜翅鸠的前额颜色、虹彩翅膀斑点和叫声特征明显，用于区分。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚大陆，包括塔斯马尼亚州，但在西澳大利亚的Nullabor平原和大型沙漠区域较为稀少。","other":"曾尝试引入新西兰，但未能成功建立稳定种群。"},{"name":"灌丛铜翅鸠","english_name":"Brush Bronzewing","scientific_name":"Phaps elegans","overview":"灌丛铜翅鸠（英文名：Brush Bronzewing，学名：Phaps elegans），是鸽形目鸠鸽科铜翅鸠属的鸟类。英文名灌丛铜翅鸠，又被称为刷羽铜翅鸠。此物种主要分布在澳大利亚，拥有两个地理上分离的亚种。其最显著的特征是翼部的铜绿色光泽羽毛，体色主要为红褐色和灰底色。分布于澳大利亚南部，包括昆士兰、新南威尔士、维多利亚、南澳大利亚、西澳大利亚以及塔斯马尼亚。","appearance":"体型紧凑，长约25至33厘米，雄鸟体重170至260克，雌鸟140至235克。头部、颈侧和下喉蓝灰色，额头至前额红棕色至浅棕色，暗棕色眼纹，颈部红棕色，背部红棕色渐变为均匀棕色，翼部有绿色或紫色光泽，次级飞羽上有大型虹彩斑块，腹面主要蓝灰色，胸侧近翼弯处红棕色。喙黑色，脚和腿红色。雌鸟相似但颜色较暗淡，幼鸟比成鸟更暗更淡。","call":"广告叫声为重复的低沉、略带沙哑的呼噜声，持续约0.35秒，音调类似'rrooh...'或'rruoo...'，每1.5秒重复一次。","habits":"偏好密集的海岸灌木丛、湿润或干燥的硬叶林、林地和一些灌木丛区。主要以本地和外来植物种子为食，少量昆虫。在清晨或黄昏时分到水源处饮水，通常单独或成对活动。","breeding":"全年均可繁殖，春季和初夏为高峰期。筑巢于地面、灌木或小树上，有时利用其他鸟类或负鼠废弃的巢穴。每次产2枚光滑白色蛋，孵化期约16天，雏鸟出生时重12克，覆盖着淡沙色绒毛，离巢时间16至20天，幼鸟换羽始于40至50天，100天内完成。","identification":"与常见铜翅鸠相比，体型更短、更健壮，翅膀上的虹彩更为显著。亚种emoccidentalis/em体型更大，颜色更浅。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚南部，包括昆士兰、新南威尔士、维多利亚、南澳大利亚、西澳大利亚以及塔斯马尼亚。在西澳大利亚州西南部有独立的亚种分布。","other":"在适宜的生境中数量似乎有所下降，可能受到引入的猫和狐狸捕食的威胁，以及农业和住宅开发对其栖息地的影响。"},{"name":"聚群铜翅鸠","english_name":"Flock Bronzewing","scientific_name":"Phaps histrionica","overview":"聚群铜翅鸠（英文名：Flock Bronzewing，学名：Phaps histrionica），是鸽形目鸠鸽科铜翅鸠属的鸟类。为澳大利亚干旱地区特有种。其显著特征为成年雄鸟头部黑白相间，雌鸟及幼鸟色彩较淡，分布于澳大利亚中北部，从西澳大利亚至新南威尔士州西北部。","appearance":"体长280-305毫米，翼展189-216毫米，体重260-320克。成年雄鸟头部除白色前额、喉部及眼后白线外均为黑色，上体和翅膀呈红褐色。雌鸟头部色彩较淡，沙棕色覆盖头顶至前颈，初级飞羽尖端不具白色。幼鸟面部标记不明显，初级和次级飞羽尖端为棕色，喙呈角质色。","call":"展示时发出深沉滚动的咕咕声，群鸟时发出柔和的低语联系声。","habits":"栖息于澳大利亚内陆年降水量200-500毫米的开阔草原，以草籽、草本植物和灌木种子为食。高度游荡，常在清晨或傍晚成群快速飞行至水源处饮水。飞行直接有力，受惊时翅膀发出响亮的呼呼声。","breeding":"繁殖季节随食物供应而变，南部春季至早夏，北部旱季早期至中期。筑巢于地面凹陷处，通常位于草丛或灌木下，巢内铺有少量草和细枝，每窝产2枚白色蛋。孵卵期16天，雏鸟出生时重约9克，覆有沙色绒羽。","identification":"与常见铜翅鸠的区别在于后者翅膀上有金属光泽的斑块，而聚群铜翅鸠上翼纯褐色，外侧翼灰色。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚中北部，包括西澳大利亚、北领地的热带草原地带、昆士兰州西部和西南部，新南威尔士州西北部，以及偶尔出现在南澳大利亚北部和西澳大利亚的金伯利地区。","other":"历史上曾有庞大群集的记录，但因牧业扩张和农业发展导致其栖息地退化，数量大幅减少。"},{"name":"冠鸠","english_name":"Crested Pigeon","scientific_name":"Ocyphaps lophotes","overview":"冠鸠（英文名：Crested Pigeon，学名：Ocyphaps lophotes），是鸽形目鸠鸽科冠鸠属的鸟类。一种特有于澳洲大陆的鸟类。除澳大利亚北部热带区域外，冠鸠广泛分布于整个澳大利亚，以其独特的头部羽冠和灰褐色调的羽毛著称。体型长约30至34厘米，常见于草地、灌木丛和林地中，也适应人类居住区如牧场、公园和运动场。","appearance":"冠鸠的体长在31至36厘米之间，体重约150至250克。头部和颈部主要呈浅灰色，特征性的长尖羽冠位于后顶冠，由灰色至黑色的羽毛构成，可竖立或扁平。颈背、肩部、背部和臀部为棕色灰色，逐渐过渡到颈部两侧、肩部和上胸部的粉棕色。上尾覆羽黑褐色，略带绿或紫光泽，末端白色窄边；次级飞羽覆羽灰色，有明显的黑色和粉棕色条纹；大部分大次级飞羽覆羽和内侧次级飞羽呈现绿、青铜或紫色光泽，边缘白色；下体浅灰色，两胁和腹部粉棕色。喙灰黑色；眼周有厚实的粉红色眶环；腿和脚粉红色。雌雄相似。幼鸟羽冠较短，羽毛圆钝而非尖锐，整体较暗淡，翼和尾的虹彩较少。亚种emwhitlocki/em非常相似，平均体型略小，尾部白色尖端更窄。","call":"冠鸠发出重复的、变调的‘whoOow...whoOow...’叫声，有时单个音节作为警报声。在求偶展示时，会发出短促的爆裂声与模糊的吼声交替，‘tok..rrrooh...tok..rrrooh...’。","habits":"冠鸠原生于干旱和半干旱地区的轻度林木草原，随着沿海密林的砍伐，其分布范围扩展至农业区和城镇。在澳大利亚大部分地区，除了最干旱和无树木的沙漠以及最密集的森林，都能找到它们。冠鸠似乎过着定居生活，飞行时翅膀快速拍打，随后保持刚性伸展滑翔，拍打翅膀时产生金属般的哨声。它们以种子和叶子为主食，偶尔摄取昆虫和其他小型无脊椎动物。在谷物种植区，大量食用散落的小麦。通常在地面觅食，形成5至6只的小群体，但在干旱期间靠近水源可能形成大群。","breeding":"繁殖活动全年均可发生，冬季相对较少，4月至7月更为普遍。一对冠鸠一年内可能尝试孵化多达5至6窝。巢为脆弱的枝条平台，一般置于5米高以下的浓密树木或灌木中。每窝产2枚光滑的白色卵，孵化期18至20天。孵化后，雏鸟体重约9.5克，全身被覆棕色上部和乳白色下部的浓密绒羽。13至15天后，雏鸟羽毛丰满，成为成鸟的迷你版，已长出羽冠。人工饲养下，雏鸟离巢时间为16至25天。","identification":"冠鸠与冠翎鹑鸠是仅有的两种拥有竖立羽冠的澳大利亚鸽类，但冠鸠体型更大。通过羽冠的形状、色彩以及特定的飞行叫声，可与其他鸽类区分开来。","protection":"IUCN：LC（无危）","distribution":"冠鸠遍布澳大利亚大陆，除了最北端的热带地区和塔斯马尼亚岛，以及最干旱和无树木的沙漠。","other":"冠鸠因欧洲殖民和相关森林清除而受益，以及为牲畜提供的水源，为其创造了更适宜的生活条件。"},{"name":"冠翎鹑鸠","english_name":"Spinifex Pigeon","scientific_name":"Geophaps plumifera","overview":"冠翎鹑鸠（英文名：Spinifex Pigeon，学名：Geophaps plumifera），是鸽形目鸠鸽科岩鸠属的鸟类。是澳大利亚特有的小型鸟类，以其独特的长羽冠和锈褐色的羽毛著称。广泛分布于澳大利亚中西部至中东部的干旱地带，偏好有刺草丛生的环境，且附近需有稳定的水源。","appearance":"冠翎鹑鸠体长20至24厘米，翼展30至35厘米，体重73至130克（雄鸟）和70至110克（雌鸟）。头部和颈部呈淡棕色至锈褐色，面部有醒目的标记：黑色眉纹延伸过鲜红色的面罩至耳羽上部，被灰色额头和王冠两侧的灰线所框边；黑色髭纹与下巴相连，从下颌基部下方穿过面罩；一条宽阔的白色带子横跨喉咙，到眼睛下方逐渐变窄，延伸至颈侧；下喉和下耳羽黑色，向上渐变为灰色；王冠、羽冠、颈背和颈后部为红褐色；背部浅灰棕色，带有深棕色条纹；肩羽深棕色，有较淡的条纹；其余上体和尾巴棕色，尾羽外侧有黑色尖端；次级覆羽红棕色，有黑灰相间的条纹；次级飞羽棕色，最外侧次级飞羽有淡黄色边缘，内侧次级飞羽上有绿色或紫色光泽斑块；外翼红棕色，有宽大的深棕色后缘和覆羽上的棕色斑点；下体通常为浅红棕色，腹部和臀部白色，胸部有黑色带纹，上面有一条狭窄的白色带纹；虹膜橙色至黄色；喙灰黑色至黑色；面部皮肤和眼环红色，腿和脚暗紫灰色至紫棕色。幼鸟头部和颈部主要是锈褐色，缺乏成鸟的面部图案，仅保留黑色眉纹和咽喉及颈侧散落的白黑羽毛；羽冠比成鸟短；上体主要是棕色，有锈色鳞片和闪光的深色条纹；上翼覆羽淡红棕色，次级覆羽上有较暗的斑点和大覆羽上的淡色条纹；下体淡黄棕色，胸带模糊；虹膜绿黄色；喙棕红色；眼周皮肤淡色；腿和脚红棕色。","call":"发出柔和高音的‘coo’声或‘cooloo-coo’声，最后一个音节响亮、清晰且略高；还有音乐般的‘u-coorh(wa)-coorh(wa)’声，单个音符后跟明显的吸气声，这是在展示动作的每次点头时发出的；以及接触时发出的低沉、浑厚的‘coo-r-r-r’声。","habits":"几乎完全以谷物为食，偶尔摄取少量昆虫；在西澳大利亚州的一项研究中，其饮食由禾本科（Sporobolus australasicus、Triodia pungens）、苋科（Amaranthus、Gomphrena）、紫草科（Halgania cyanea、Trichodesma zeylanicum）、白花菜科（Cleome viscosa）、大戟科（Euphorbia australis、E. tannensis、Phyllanthus sp.、P. maderaspatensis）、豆科（Psoralea、Tephrosia）、含羞草科（Mollugo molluginis）、桃金娘科（Eucalyptus）、千屈菜科（Polygala rhinanthoides）以及等翅目、鞘翅目、双翅目和膜翅目的昆虫组成。仅在地上觅食；通常在小群中觅食，但也可能遇到成对或多达150只的大群。一天中大部分时间保持活跃；主要在清晨和傍晚觅食，主要是在中午前。据说每天喝水两次甚至更多，会行进超过2公里到达水源。","breeding":"能全年繁殖，但大多数筑巢发生在春季和初夏（例如8月至9月），尽管有记录显示5月份在奇切斯特山脉有雌鸟正在孵化两枚蛋；繁殖受降雨刺激，但即使在除最严重干旱之外的所有条件下，物种都有能力繁殖。据报道，它们一生结对并且在圈养中表现出领地性，目前大部分数据来源于圈养环境。巢是一个位于刺草丛、灌木或岩石下的凹坑，直径约13厘米，可能有衬垫也可能没有，巢之间的距离可以少至100米。有时会连续孵育两窝。产两枚浅奶油色、乳白色或白色的蛋，尺寸为22.9至29.7毫米×18.8至22.1毫米；孵化期16至18天，由两性共同承担，在圈养环境中观察到；孵化后，雏鸟体重4.5至4.8克，全身覆盖着长而沙色的绒毛；雏鸟在仅7至9天大时就会离开巢穴，跟随父母。在圈养中，身体部位的生长持续到32天，体重增加直到70天，幼鸟可能会在离巢后4至6周内继续与成鸟一起生活。","identification":"与其他澳大利亚鸽子种类的区别在于其较小的体型、锈褐色的羽毛、独特的面部标记以及沙漠栖息地的出现。与有羽冠的鸽子相比，冠翎鹑鸠通过其更小的体型、锈色羽毛、独特的面部标记和沙漠环境的居住地而容易识别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中西部至中东部的干旱地带，具体范围从德格雷河以南至加斯科因河，向东至卡纳文山脉；在西金伯利地区存在一个混血种群。","other":"冠翎鹑鸠是澳大利亚干旱区少数几种几乎完全定居的鸟类之一，仅进行局部移动并在干旱期间聚集在水塘周围。"},{"name":"鹑鸠","english_name":"Squatter Pigeon","scientific_name":"Geophaps scripta","overview":"鹑鸠（英文名：Squatter Pigeon，学名：Geophaps scripta），是鸽形目鸠鸽科岩鸠属的鸟类。以其鲜明的黑白面部条纹和腹部至肩部的白色条纹而著称。分布于澳大利亚东北部和中东部的干旱地区，尤其在昆士兰北部更为常见。","appearance":"鹑鸠体型较大，长度约26-32厘米，体重200-225克。其脸部和喉咙有明显的黑白色条纹，头部、颈部和背部呈淡灰棕色，边缘较浅形成鳞片状外观，尤其是肩羽处。尾巴为深褐色，中心略淡；上翼覆羽暗棕色，大多数覆羽边缘较浅，内侧大次级飞羽上有虹彩绿或紫色斑块；翅膀黑色带细浅色边和尖端；内侧次级飞羽褐色，带有暗淡虹彩绿或紫色斑点；上胸淡灰棕色，向下渐变为蓝灰色，与腹部白色部分形成对比，形成一个被白色侧面和腹部包围的深色三角形；侧面、臀部和尾下覆羽为棕灰色，带有宽大的白色鳞片；尾下覆羽深褐色，中心略淡；喙黑色；眼周皮肤蓝灰色；腿和脚为暗紫色。雌雄相似。幼鸟面部图案模糊不全，头部、颈部和背部比成年鸟更暗淡的棕色，逐渐变为上尾覆羽的浅棕色；肩羽奶油色到淡黄色；背部的浅色斑点形成模糊的浅色带；尾巴大部分为深棕色，边缘颜色较浅，具有宽阔、不完整的深棕色亚终端带和黑棕色外侧羽毛带浅色尖端；面部皮肤淡黄色至黄色。半岛亚种主要差异在于其红色的眼周皮肤，年轻个体呈黄色。","call":"鹑鸠通常不是很吵闹。在求偶展示时，会发出轻微的三声温和咕咕声，首声最短，但所有声音都在同一音高：“pu..poo..poo”。受惊时，会发出类似但音调更高的咕咕声。伴侣或群体成员之间通过低沉哀婉的吟唱保持联系。","habits":"鹑鸠栖息于开阔的桉树林和相关草原。过去可能在其分布范围南部的开阔平原上也有发现，但现在非常罕见。它似乎仅在当地范围内活动，像裸眼鹑鸠一样，主要在地面活动，当受到惊吓时，会以鹌鹑般的爆炸式飞行逃离。","breeding":"有限的数据表明，鹑鸠全年均可繁殖，但在旱季达到高峰；繁殖准备显然受环境条件强烈影响。巢建在地面的一个浅坑中，仅有少量草覆盖，隐藏在草丛或灌木下。每次产2枚光滑的白色蛋。在圈养条件下，孵化期约为17天，幼鸟离巢时间为9天。雏鸟出生时全身覆盖着浅褐色绒毛。","identification":"鹑鸠与铜翅鸠的区别在于其苍白的白色翅膀下方，而后者翅膀下方为红褐色。此外，其独特的黑白面部标记和侧腹至肩部的白色条纹也是辨识的关键。","protection":"IUCN：LC（无危）。尽管全球并不面临威胁，但其状态知之甚少，需要更多的调查工作。指名亚种被认为处于脆弱状态。没有可用的人口估计数据。在整个分布范围内，该物种数量严重下降，几乎在新南威尔士州灭绝；目前仅在开普约克半岛内陆较为常见。过度放牧，尤其是在分布范围南部的绵羊和北部的牛群，可能是导致其种群下降的最重要因素，但狩猎压力也可能有所贡献。","distribution":"分布于澳大利亚东北部和中东部，特别是在昆士兰北部较为常见。在过去的分布记录中，可能也存在于其南部范围内的开阔平原，但现在极为罕见。"},{"name":"厚嘴地鸠","english_name":"Thick-billed Ground Pigeon","scientific_name":"Trugon terrestris","overview":"厚嘴地鸠（英文名：Thick-billed Ground Pigeon，学名：Trugon terrestris），是鸽形目鸠鸽科厚嘴地鸠属的鸟类。又称丛林鸠或灰地鸠，特有种，仅见于新几内亚的低地热带雨林。其最显著的特征是拥有厚重的喙和白色的颊部。","appearance":"体型较大，长度约33厘米，体重介于323至400克之间。上体呈深色，下体淡红褐色。头部有白色脸颊和低矮的冠羽，眼红色鲜艳，腿粉色。喙基部暗灰色，尖端粉白色，厚实而钝。性别相似，雌鸟翼覆羽略带紫色。幼鸟虹膜较暗，有黑色冠脊中线，翼羽边缘锈色。","call":"发出单调的鼻音‘呼欧’声，间隔约五秒重复，偶尔会发出各种单一的咕咕声。","habits":"栖息于低地和丘陵森林，最高可达640米，有时可达1000米。通常单独或成对活动于地面，以种子和果实为食，利用其特殊的喙打开果壳。有时访问丽色极乐鸟的展示区，寻找吐出的种子。","breeding":"繁殖记录显示在湿季和干季都有筑巢行为，巢可简单或复杂，位于地面，由树枝、苔藓和枯叶构成，常藏于树干或根部。每次产一枚白色卵，双亲轮流孵卵，雄鸟白天，雌鸟夜间。","identification":"厚喙和白色脸颊明显区别于其他相似体型的地面鸟类。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚岛和印度尼西亚的萨拉瓦蒂岛（四王群岛西北部）。","other":"在一些地区，厚嘴地鸠被认为是当地常见的物种，但由于其性格安静且难以察觉，实际数量可能难以准确评估。"},{"name":"巨地鸠","english_name":"Wonga Pigeon","scientific_name":"Leucosarcia melanoleuca","overview":"巨地鸠（英文名：Wonga Pigeon，学名：Leucosarcia melanoleuca），是鸽形目鸠鸽科巨地鸠属的鸟类。体型丰满，拥有短颈、宽翅和长尾，长度介于38至45厘米之间。其分布范围自澳大利亚昆士兰州中部至维多利亚州东部，最南可达墨尔本，内陆延伸可达400公里。","appearance":"成年巨地鸠上体呈石板灰色，尾巴蓝黑色，除中央尾羽外其余尾羽尖端白色。翅膀黑色带褐色，头部前额、前冠、下颌和上喉白色，逐渐变为灰色直至头顶和颈部。眼周黑色，胸部灰色渐窄至腹部形成显著的白色V字形图案。腹部和两胁白色，带有棕色黑色的半月形或楔形标记。下覆羽深棕色，边缘淡黄色。喙基部红色，远端棕色，腿脚深粉红红色。雌雄相似，幼鸟与成鸟类似，但肩羽和上翼覆羽棕灰色，上翼初级和次级飞羽具窄奶油色边缘，腹部标记不甚明显。","call":"巨地鸠的鸣叫声为响亮的‘咕’声，重复频率约每秒两次，声音单调而悠远。","habits":"巨地鸠通常生活在茂密的温带和亚热带雨林、湿润硬叶林、次生林和灌木森林中，尤其偏爱有Acacia、Casuarina或Exocarpus下层植被的环境。有时出现在开阔的林地，只要下层植被茂盛即可。它们在森林中的空地、路边和花园中觅食，要求有足够的遮蔽和相对干净的林地表面以利于行走。在新南威尔士州，它们可在所有海拔高度出现，最高可达900米，但在大分水岭的其他地方记录到高达1800米。","breeding":"全年均可繁殖，春季和夏季（9月至2月）为高峰期。巢筑于大树水平枝杈中，直径约30厘米，深度9厘米，离地面2至20米。每窝产两枚白色卵，由双亲共同孵化16至18天。幼鸟在26至27天后离巢，也有报道指出18至19天即可离巢。","identification":"巨地鸠以其独特的石板灰色上体、白色腹部和胸部显著的白色V字形图案而易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从昆士兰州中部向南延伸至维多利亚州东南部，包括昆士兰州南部至维多利亚州墨尔本。内陆最远可达卡纳文山脉。","other":"尽管在许多地区仍然常见，但其数量已在其分布范围内普遍下降，特别是在昆士兰北部、维多利亚州和新南威尔士州北部，这主要是由于狩猎、森林砍伐以及狐狸和野猫的捕食。"},{"name":"栗翅岩鸠","english_name":"Chestnut-quilled Rock Pigeon","scientific_name":"Petrophassa rufipennis","overview":"栗翅岩鸠（英文名：Chestnut-quilled Rock Pigeon，学名：Petrophassa rufipennis），是鸽形目鸠鸽科栗翅岩鸠属的鸟类。其羽毛上有着微弱的浅色斑点。在飞行时，会展现出醒目的栗色翼斑，伴随着翅膀拍打时响亮的啪嗒声。该物种仅在澳大利亚北领地阿纳姆地的砂岩区发现，广泛分布于卡卡杜国家公园及其周边地区。常在高耸的岩石悬崖或砂岩塔顶栖息，黎明和黄昏时分会降落至沙地地面活动。","appearance":"体型丰满，身长28至31厘米，体重约160克，是一种地面栖息的鸽子，拥有长而圆的尾巴和短而宽的翅膀，当停栖时翅膀常常垂于尾巴下方。头部和颈部主要为黑褐色，点缀着淡灰色斑点；眼睑呈虹彩般的黑绿色，上方有一条细长的淡灰色线从喙部延伸，绕过眼睛，下方有一条薄白线从喙基部，经眼至耳羽上方；下巴和喉部为白色，带有淡黄色斑纹。背部、尾部和翅膀上部为深炭灰色，有细小的棕色鳞状斑纹，外侧翅膀上有一片鲜亮的栗色斑块，被深棕色的次级飞羽和覆羽覆盖，仅在飞行或展翅时显眼；下体为深褐色；喙黑色；腿和脚为紫黑色。雌雄外观相似。幼鸟与成鸟非常相似，但体型较小，翼覆羽倾向于具有红褐色的尖端。","call":"关于声音和鸣叫行为的记录不多。发出重复的单一柔和的咕噜声，持续大约1秒，音调最初上升，听起来相当高亢（最大频率约700赫兹）“呼...呼...呼...”。在展示时，也会发出奇特的鼻音低吼声“拉...拉..拉..”。","habits":"它是一种专门栖息在开阔、干旱、砂岩峡谷和巨石地带及邻近林地和针茅丛生环境中的鸽子；其栖息地的林地主要由桉树主导；针茅群落则以形成草丛的草类为主，伴有多种草本植物组成的多样化社区。","identification":"与白羽岩鸠行为和栖息地非常相似，但仅限于澳大利亚北领地阿纳姆地的砂岩区域。可以通过其独特的面部淡色线条环绕眼睛上方和下方，以及飞行时可见的栗色翼斑进行辨识。","protection":"IUCN：LC（无危）","distribution":"澳大利亚中北部：主要分布在Top End中北部，北领地北部（澳大利亚中北部），从奥恩佩利向南至凯瑟琳，向东至曼河、东鳄鱼河和古马德河源头；偶尔更远至东部。"},{"name":"白翅岩鸠","english_name":"White-quilled Rock Pigeon","scientific_name":"Petrophassa albipennis","overview":"白翅岩鸠（英文名：White-quilled Rock Pigeon，学名：Petrophassa albipennis），是鸽形目鸠鸽科栗翅岩鸠属的鸟类。体型较大的暗褐色岩鸠，以翼上的白色斑块和面部独特的淡色条纹著称。主要栖息于澳大利亚中北部的砂岩峭壁和石灰岩高原，是该地区的特有种。","appearance":"白翅岩鸠身长28至30厘米，体重介于103至156克之间。体态丰满，尾部圆长，翅膀短而宽，静止时翅膀常下垂至尾部下方。头部额、冠及颈背呈斑驳的灰棕色，眼周有黑色光泽，上眼线和下眼线为白色细线，延伸至耳羽上方。下巴和喉咙黑色，点缀以细小白点。头颈其余部分为棕灰色。背部、尾部及上翼覆羽深棕色，边缘带浅色形成鳞状外观。一级飞羽上有明显的白色斑块，在飞行中尤为显眼。喙黑，腿呈紫黑色。幼鸟与成鸟相似，但上翼覆羽边缘为红褐色。亚种boothi翼斑较小或缺失，下体颜色较上体更深。","call":"记录不足。已知的广告叫声略带音乐感，如“coo-coo roo roo coo roo”，有时音节较少。还有类似人类笑声的叫声。","habits":"栖息于岩石砂岩和石灰岩高原及其相关沟壑和悬崖，偏好裸露岩石地带，周围植被为干旱开阔的林地和刺草草原。通常距离永久水源不远。飞行时翅膀拍打声大，交替扑扇和滑翔。主要在地面觅食，以多种植物种子为食，包括豆科、莎草科、禾本科和蒺藜科植物。","breeding":"繁殖全年皆可发生，但二月至四月、九月至十二月较少。巢筑于岩石间，有的仅用树枝简单搭建，有的则较为坚固并铺垫有刺草。也有在地面凹洞中筑巢，铺以草料。每窝产两枚乳白色蛋，孵化期17至19天。雏鸟出生时重约4.5克，全身覆盖沙色绒毛，头部颜色最深。12天大的雏鸟若巢被干扰能奔跑和藏匿。大约15天后可能永久离巢。","identification":"与栗翅岩鸠通过翼上的白色斑块和面部特征区分。亚种boothi翼斑较小或缺失，下体颜色较上体更深。","protection":"IUCN：LC（无危）。在北领地的保护状态为Near Threatened（近危）。可能因野猫数量众多构成最大威胁。","distribution":"分布于澳大利亚中北部，主要在金伯利地区和维多利亚河以东的北领地，但不包括Top End地区。","other":"历史系统学记录了两个亚种，albipennis和boothi，后者翼斑较小。"},{"name":"姬地鸠","english_name":"Diamond Dove","scientific_name":"Geopelia cuneata","overview":"姬地鸠（英文名：Diamond Dove，学名：Geopelia cuneata），是鸽形目鸠鸽科姬地鸠属的鸟类。又名: 宝石姬地鸠、钻石姬地鸠，是世界上体型最小的鸠类之一。分布于澳大利亚西部及半干旱沙漠地带，以其精致的外观和适应性强著称。","appearance":"姬地鸠体长约19至24厘米，体重约28至43克，拥有细长尖锐的尾巴。雄鸟头颈胸及两侧淡蓝灰色，下颌色浅；上体及中央尾羽暗棕或灰棕色，肩羽和次级飞羽覆羽具许多小白斑点，形成独特的斑块；上翼深棕色，初级飞羽有显著的栗色板块；尾羽外侧黑色带宽白尖，展开时尾部可见明显白边；下尾羽闭合时白色，展尾时中央有黑色条纹；腹部、肛周及下尾羽覆羽白色；喙暗灰色至黑色；虹膜鲜红，眼环深粉至亮红色；腿脚粉色。雌鸟相似，但上体更偏棕色，眼环颜色较暗淡。幼鸟颈部、胸部和上体有细密的条纹，肩羽和覆羽上的小白斑较少，蓝灰色部分较暗淡，近似浅灰色；喙淡灰褐色，端黑；虹膜淡棕色；眼环淡灰或棕色至浅橙色；腿脚灰色至棕色。","call":"其广告叫声为重复的两音节咕咕声，第一个音节沙哑且稍长于第二个，后者较为纯净，最多带有沙哑的结尾，‘currrrrrrrh..cooorh’。还有一种较长且节奏感较强的五音节旋律，其中一些音节双音节，‘coo..cuu-uh...coo...cu...cu-uh’。两种鸣叫声可能由同一只鸟交替发出。展示时会发出重复的单一沙哑咕咕声。","habits":"栖息于轻度林木覆盖的干旱或半干旱草原，附近需有稳定的水源。常见于道路和小径旁。迁徙模式为游荡性，有时因水和食物的可获得性而移动相当远的距离。旱季时倾向于聚集在水源周围，雨季时分散得更广泛。飞行快速、有力且呈波浪状。","breeding":"繁殖季节受降雨和食物可得性影响，通常春季和初夏为高峰期，但一年中任何时候都可能筑巢。巢为脆弱的枝条或干草平台，建于灌木、树木或其他支撑物上。双方共同筑巢、孵化和照顾幼鸟。产2枚白色蛋，孵化期13天；刚出生的小鸟仅重2至4克，全身覆盖着长而沙色的绒毛。圈养条件下，离巢时间11至14天；雏鸟由成鸟喂养两周后离巢；能在3个月大后不久开始繁殖。","identification":"与和平鸽相比，姬地鸠的尾巴更长更尖，且具有明显的白色尾羽边缘。此外，姬地鸠的上体和尾羽上有独特的白色斑点，这是识别的重要特征。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆干旱地区，主要集中在西澳、北领地及中部地区；在南澳的公园和花园中偶尔可见，尤其是在澳大利亚中心非常干燥时。","other":"姬地鸠因其翅膀上的白色斑点而得名‘钻石’。尽管体型惊人地小（平均约35克），但它们对高温有极高的耐受力，这得益于体温、代谢、呼吸、水分平衡和行为上的适应。"},{"name":"斑姬地鸠","english_name":"Zebra Dove","scientific_name":"Geopelia striata","overview":"斑姬地鸠（英文名：Zebra Dove，学名：Geopelia striata），是鸽形目鸠鸽科姬地鸠属的鸟类。原生于东南亚，现已广泛引入至多个地区，包括夏威夷。其最显著的特征是胸部和背部的深色条纹，以及眼周的蓝色裸皮。城市和郊区是其常见栖息地。","appearance":"体长约20.5-21.5厘米，重50-72克。头部前额、面部及喉咙呈淡蓝灰色，头顶及颈背为灰棕色，颈后部具细白棕色和黑色条纹，颈侧、胸及腹侧有黑色条纹。胸部中央为紫粉色，腹部和尾下覆羽白色。上体浅棕色，翼覆羽渐变为灰色，具黑色边缘形成条纹效果。次级飞羽和初级飞羽暗灰棕色，内侧基部有栗色形成翼下模糊斑块。下翼覆羽淡赤褐色，条纹黑色。中央尾羽灰色，外侧四对黑色，有明显白色尖端。眼周皮肤蓝色，喙灰色或灰棕色，基部蓝灰色或绿灰色，脚和腿为暗粉色。雌雄相似，但雌鸟的胸部粉红色部分较窄，条纹更密集。幼鸟颜色更淡，背部和翼覆羽的条纹边缘为肉桂色，条纹延展至头冠和颈背，整个胸部亦有条纹，但不明显。","call":"发出一系列柔和、断续的‘咕咕’声，旋律悦耳，每段开始时高音清脆，随后是急促的‘咕’音。","habits":"栖息于多种开阔地带，包括干燥林地、灌木地、农田、花园和城市区域，偏好低海拔地带，最高可达900米。以小种子为主食，包括杂草和谷物种子，辅以少量昆虫。清晨常见于路边觅食，通常成对或小群活动，有时会在丰饶的食物或水源处聚集较大群体。","breeding":"繁殖季节在马来西亚半岛为9月至次年6月，在菲律宾为2月中旬至5月底，在婆罗洲为10月。雄鸟求偶时会展示翅膀，随后滑翔至地面或栖息处。巢位于1-12米高的树叉或棕榈基部，有时地面筑巢。每次产两枚白色卵，孵化期约13天，幼鸟约11-12天离巢。","identification":"与较大的有潜在重叠，后者喉部和胸部有条纹，翼下覆羽和初级飞羽内侧基部为丰富的栗色，无黑色条纹。","protection":"IUCN：LC（无危）","distribution":"原产于泰国南部、马来半岛、苏门答腊和爪哇。已广泛引入至其他地区，包括夏威夷、塔希提岛、新喀里多尼亚、塞舌尔群岛、查戈斯群岛、毛里求斯、留尼汪岛和圣赫勒拿岛。在东南亚本土范围以外的许多岛屿上也建立了种群。","other":"在印尼，斑姬地鸠是最受欢迎的笼鸟之一，与并列，大约五分之一的印尼人养鸟。"},{"name":"戈氏姬地鸠","english_name":"Peaceful Dove","scientific_name":"Geopelia placida","overview":"戈氏姬地鸠（英文名：Peaceful Dove，学名：Geopelia placida），是鸽形目鸠鸽科姬地鸠属的鸟类。颈部和胸部有显著的条纹，眼睛周围环绕着淡蓝色的眼圈。分布广泛，主要栖息于澳大利亚和新几内亚的开放生境中。","appearance":"戈氏姬地鸠体长20至24厘米，体重41至66克。整体颜色较淡，颈部和胸部有密集的条纹，翅膀比斑姬地鸠更长更尖，翼羽内部无栗色，但下翼覆羽呈深栗色。腿和脚为粉红色，前部有深棕色鳞片。不同的亚种在色彩上有所变化，clelandi亚种略显浅棕色。","call":"戈氏姬地鸠的鸣声是一连串的假声音乐般的'doodle-doo'声，还有一种假声'co-co-coo'和展示时强调的'croorrr'声。","habits":"它们占据各种开阔生境，如硬叶林、灌木丛和高草丛地带，主要食物为小种子，偶尔也会吃昆虫和其他无脊椎动物。通常在地面觅食，成对或小群体活动。","breeding":"全年均可繁殖，但在干季高峰期活动减少。一对可能在单个季节内筑多个巢（多达8个）。巢由小枝构成，位于树叉、藤蔓或寄生植物中，距地面0.6至16米。每次产2枚白色卵，孵化期13至14天，由双亲共同孵化。雏鸟为半晚成鸟，孵化后6天羽毛开始生长，约16天后离巢，24天后换羽基本完成，成年后数周内仍由父母喂养。","identification":"与斑姬地鸠相比，戈氏姬地鸠翅膀更长更尖，整体颜色更浅，条纹更广泛，延伸至胸中部，翼羽内部无栗色，下翼覆羽深栗色，无条纹，腿和脚呈粉红色。","protection":"IUCN：LC（无危）","distribution":"戈氏姬地鸠分布在澳大利亚（除塔斯马尼亚州和西南部）和新几内亚（主要在南部，东北部和东南部，北部几个地点和Aru群岛）。","other":"戈氏姬地鸠适应性强，常见于其分布范围内，能适应城市环境和利用农业土地，目前物种安全。"},{"name":"帝汶姬地鸠","english_name":"Barred Dove","scientific_name":"Geopelia maugeus","overview":"帝汶姬地鸠（英文名：Barred Dove，学名：Geopelia maugeus），是鸽形目鸠鸽科姬地鸠属的鸟类。小型鸽类，原产于印尼的 Lesser Sunda Islands，具有独特的橙色眼环和遍布全身的条纹。与东南亚的斑姬地鸠和澳大利亚与新几内亚的戈氏姬地鸠关系密切。帝汶姬地鸠在低地地区的灌木丛、农田和林缘地带安家。","appearance":"帝汶姬地鸠体型小巧，尾巴较长，体长22至25厘米。头部呈淡灰色，具醒目的橙色眼环。上身布满棕色条纹，腹部颜色较浅，同样带有强烈的条纹，仅腹部为白色。翅膀和胸部有广泛的栗色区域，翼下覆羽也是栗色。眼周皮肤为铬黄色，虹膜为淡黄色。","call":"帝汶姬地鸠的鸣叫声高亢而明显，为双音节的‘wa-dloo’重复声，间隔约为2至3秒。此外，还会发出持续的、下滑的咕噜声‘grrrrrr’。","habits":"帝汶姬地鸠在从海平面到山脚的开阔地区活动，包括稀疏的林地、开放的季风林边缘、红树林边缘，以及农田、草地和村庄周围的环境。活动范围可达海拔500米以上（Sumba）、1100米（Timor）和1400米（Flores）。通常单独、成对或小群出现。","breeding":"帝汶姬地鸠的繁殖期在Sumbawa和Flores至少从四月至七月，基于已收集的标本证据。具体繁殖细节尚不清楚。","identification":"与斑姬地鸠相似，但颜色更深，条纹更强烈，条纹延伸至下胸和侧腹，腹部为白色。翼羽和胸下覆羽有广泛的栗色区域。眼周皮肤为铬黄色，虹膜为淡黄色。","protection":"IUCN：LC（无危）","distribution":"帝汶姬地鸠分布在从Sumbawa向东至Tanimbar Islands，以及东南摩鹿加群岛（Tayandu Islands和Kai Islands）。也在Tukangbesi Islands（Tomea）有记录，可能为放生群体，位于苏拉威东南部附近。"},{"name":"斑肩姬地鸠","english_name":"Bar-shouldered Dove","scientific_name":"Geopelia humeralis","overview":"斑肩姬地鸠（英文名：Bar-shouldered Dove，学名：Geopelia humeralis），是鸽形目鸠鸽科姬地鸠属的鸟类。体型介于26至30厘米，重量约110至150克。其显著特征包括颈部后方的金属铜色斑块，灰色的脸和颈，以及粉红色的腹部。常见于澳大利亚北部及新几内亚南部和东南部的木地、城镇、公园和花园。","appearance":"上体呈浅灰褐色，翼上覆羽较淡且带粉红色，形成独特的粉红肩条；初级飞羽上有大块的栗色斑点，在飞行时尤为突出；后颈和背部上部为铜色，饰有明显的黑色鳞状斑纹；头部、颈侧和胸部为蓝灰色，前额颜色较浅；下胸和两胁为粉红色，与蓝灰色上胸有明显分界；腹部、肛周和下尾覆羽为黄白色；除前额外的所有上体轮廓羽有窄黑端带，产生鳞片状效果；四根中央尾羽为灰褐色，其余为栗色，末端宽白；眼眶皮肤和喙为蓝灰色；脚为暗红色。雌雄相似。幼鸟比成鸟暗淡，大多数羽毛边缘呈肉色，灰色部位有肉色和棕色的横纹。不同亚种主要在色彩上有所不同：headlandi体型较小，下体更粉红，上体颜色较淡。","call":"叫声通常是一连串六音节的旋律（低-低-高，低-低-高）。","habits":"栖息于灌木丛生的林地和林地与沼泽或红树林之间的过渡地带，是潘达努斯沼泽的标志性物种，该沼泽将林地与泛滥平原分隔开。在热带城镇和有残存树木的农业区域很常见。在半干旱地区，物种通常局限于沼泽或溪流边缘。与重叠分布时，本物种一般出现在更湿润、灌木更多的区域。飞行强劲而直接，没有波动。","breeding":"可全年繁殖，但在晚雨季和旱季早期最为频繁，此时正是以种子为食的鸟类食物丰富的时期。巢为小而脆弱的树枝平台，通常位于灌木或小树的低处。产2枚光滑的白色卵；孵化期14至16天；雏鸟出生时体重约8克，覆盖着浅驼色绒毛。在圈养条件下，离巢时间为16至21天。","identification":"与戈氏姬地鸠相比，其喉部羽毛不具条纹，后颈羽毛为铜色。有时会被误认为是引入的珠颈斑鸠。幼鸟颜色较为暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中部和南部，澳大利亚北部和东部，包括蓝山和伊拉瓦拉地区，向北至约克角半岛，西至皮尔巴拉地区（约Onslow，西澳大利亚州）。在南澳大利亚，尤其是在西北维多利亚州，观察频率增加。","other":"受《1974年国家公园和野生动物法》保护。"},{"name":"印加地鸠","english_name":"Inca Dove","scientific_name":"Columbina inca","overview":"印加地鸠（英文名：Inca Dove，学名：Columbina inca），是鸽形目鸠鸽科地鸠属的鸟类。以其灰褐色的体色和独特的鳞状羽毛图案而著称。原生于墨西哥、中美洲北部至哥斯达黎加一带，近年来其分布范围向北扩展至美国西南部，向南继续扩张。这种地鸠偏好干旱的沙漠、灌木丛生地带及耕作区，甚至在城市和公园中也能找到它们的身影。","appearance":"印加地鸠身长16.5-23厘米，体重30-58克，体型纤细，拥有长而方尾，尾羽边缘白色，在飞行中尤为明显。上体呈灰褐色，下体较浅，全身羽毛呈现鳞状花纹，由深棕色的羽毛尖端造成。飞行时，翼下的红褐色斑块和白色的尾羽边缘格外显眼。喙黑色，略厚于尖端。幼鸟与成鸟相似，但翼覆羽和肩羽上有灰色亚端条纹。","call":"印加地鸠的鸣声为有力的咕咕声，常被描述为‘cowl-coo’、‘POO-pup’或‘NO-hope’，这种声音可以从树上、电线上或其他开阔的高处发出。","habits":"印加地鸠生活在干旱的开放地带，包括沙漠、灌木丛和农业区，常见于人类居住的环境，如城市和公园。冬季时，它们会群居于金字塔形的密集栖息地以保持体温。它们通常在地面上觅食，寻找草籽和其他种子。","breeding":"繁殖期间，印加地鸠会在树上或灌木中筑巢，巢由树枝、草、杂草茎和叶子构成，随着粪便的积累而加固。雌雄共同参与巢材的收集，雌鸟主要负责筑巢。它们可能一年四季都在某些地区繁殖，每次产卵两枚。","identification":"与普通地面鸽相比，印加地鸠体型稍大，尾部相对更长，且全身覆盖着类似鳞片的羽毛图案。飞行时，白边的尾羽和红褐色的翼下是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"印加地鸠分布于北美和中美，从美国西南部至哥斯达黎加。近年来，其分布范围持续向南北两端扩张。","other":"印加地鸠对寒冷敏感，采用多种方式抵御低温，包括夜间体温下降和金字塔式群居以保暖。"},{"name":"鳞斑地鸠","english_name":"Scaled Dove","scientific_name":"Columbina squammata","overview":"鳞斑地鸠（英文名：Scaled Dove，学名：Columbina squammata），是鸽形目鸠鸽科地鸠属的鸟类。常见于巴西、玻利维亚、阿根廷等地。其自然栖息地包括热带干灌木丛、季节性湿地及退化森林地带。具有独特的灰白羽毛边缘，呈现出鳞状外观。","appearance":"成年鳞斑地鸠长约18至22厘米，体重介于48至60克之间。上体呈灰褐色，脸部和胸部为粉灰色，喉部白色，翅膀末端覆羽白色，形成闭合翅膀上的显眼斑块。尾部暗色，尾羽尖端白色，飞行时可见白色翼带。眼睛深色，腿脚粉色，喙灰色。幼鸟的羽毛边缘呈淡黄色，与成鸟有别。","call":"其鸣唱为响亮的三音节节奏'pow-co-pow'，每2至3秒重复一次。叫声还包括反复的'crrrrowr'，通常伴有中间的短促模糊音。","habits":"常栖息于干旱热带草原、林缘、草地及城市区域，高度可达1200米。通常是定居的，偶尔游荡到特立尼达岛。以种子和蜗牛为食，单独或成对出现，有时也会组成小群。","breeding":"筑巢活动在哥伦比亚的3月和8月观察到，而在委内瑞拉东北部，繁殖期为1月至6月及9月至10月。通常在小树上1至2米高处筑巢，偶尔在地面。巢为树枝构成的杯状，每次产2枚白色蛋。","identification":"与锈胸星额蜂鸟相似，但颜色较浅；翼端覆羽外缘白色，形成明显斑块；初级飞羽基部黑色（锈胸星额蜂鸟为栗色）；中央尾羽更偏灰色，外侧黑白相间。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲北部和东部，包括巴西、玻利维亚、阿根廷、哥伦比亚、法属圭亚那、巴拉圭、特立尼达和多巴哥及委内瑞拉。","other":"物种的生态学和生物学信息研究不足，需进一步调查。"},{"name":"地鸠","english_name":"Common Ground Dove","scientific_name":"Columbina passerina","appearance":"地鸠是一种极小型的鸽类，体长15-18厘米，体重26-40克。头部较小，尾部短而方，颈部和胸部有鳞状图案，雌雄差异在于雄鸟头部呈蓝灰色，腹部粉灰色，而雌鸟更偏灰，颜色均匀。喙部两色，基部粉红至橙红色，尖端深色。飞行时可见栗色翼缘和翼下亮栗色。","call":"发出柔和的渐升音调的呼呼声，常重复，声音独特。","habits":"居住于开放或灌木地带，偏好高草丛或树丛环境，包括河流走廊和开阔草原；也见于城镇及人类居住区附近。通常成对或小群活动于地面，也会在低矮树木和灌木上停留。以种子、谷物和少量昆虫为食。","breeding":"形成永久伴侣关系，巢筑于地面植被中或稍高的灌木上，巢结构简单。繁殖季节主要在春季至夏季，每窝产2枚白色蛋，双亲共同孵卵12-14天。幼鸟出生时为晚成雏，覆盖少许灰色绒羽，约11天后即可离巢。","identification":"与印加地鸠e和红地鸠区分明显，前者翅膀上有白边，体型略大；后者雌鸟无头颈鳞纹，翼下黑色，斑点形状不同。","protection":"IUCN：LC（无危）","distribution":"分布于美国南部至巴西东南部，包括中美洲、加勒比海岛屿及南美洲北部三分之一区域。","other":"尽管繁殖潜力较大，但在北美的部分地区数量正在减少，可能与早期生境丧失有关。"},{"name":"纯胸地鸠","english_name":"Plain-breasted Ground Dove","scientific_name":"Columbina minuta","appearance":"纯胸地鸠体型小巧，长度约14至16厘米，体重24至26克，略小于常见的地鸠。整体外观朴素，背部有诊断性的紫色标记，颜色可能难以察觉。雌雄相似，但雌鸟色彩更淡，下体呈灰棕色。头部和胸部的羽毛无斑点，与地鸠形成对比。幼鸟比雌鸟更暗淡，呈灰棕色，翅膀覆羽上的黑色斑点不明显。不同亚种在色泽上有所差异，emelaeodes/em亚种上部颜色更深，下部呈深紫红色。","call":"鸣唱是一系列间隔均匀、低沉的上升音调‘whoop....whoop....whoop...’，每秒约1.2至1.6个音符，音符长度明显短于停顿。","habits":"栖息于低地和山麓，偏好干旱沙质地带的灌木丛、轻型金合欢林下层开阔的环境。在中美洲和南美洲，亦见于次生林和耕作区，以及草原和草地。通常成对或小群活动，偶尔在灌木低处栖息。以草籽为主食，觅食于田野、灌木边缘或下层植被中，有时以单个或小群（最多10至15只）的形式出现。","breeding":"繁殖期疑似全年，尤其在哥伦比亚和哥斯达黎加，主要集中在5月至7月的太平洋西北部和1月的Parrita地区；特立尼达岛的繁殖期为3月至9月，高峰在6月，且可能全年繁殖（干湿季皆有）。在巴拿马，筑巢期为3月至6月；墨西哥（韦拉克鲁斯州）的雌鸟在4月处于繁殖状态，奥阿哈卡州5月发现巢穴，尤卡坦州8月有记录。雄鸟会在低矮的枝条上做短暂的展示飞行。巢类似地鸠，但较小，直径约12至13厘米，有时中央有7厘米的凹陷，由草、茎、根和羽毛构成的脆弱平台。巢位于地面或树或灌木上，高达9米。每窝产两枚白色卵，尺寸19.4至21毫米×14.8至15.6毫米，孵化期13至14天，幼鸟在12至14天后离巢。","identification":"与更为常见的红地鸠容易混淆，后者更大，全身更暖棕色，而纯胸地鸠胸部纯色，体型更小。与红地鸠相比，后者体型更大，尾巴比例较长，翅膀和臀部更红褐色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，包括阿根廷、伯利兹、玻利维亚、巴西、哥伦比亚、哥斯达黎加、厄瓜多尔、萨尔瓦多、法属圭亚那、危地马拉、圭亚那、洪都拉斯、墨西哥、尼加拉瓜、巴拿马、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥以及委内瑞拉。","other":"物种在某些地区可能正在减少，因为地鸠可能在共存的区域逐渐取代它，但考虑到城市化和农业化的扩张，总体上该物种可能正在增加。"},{"name":"厄瓜多尔地鸠","english_name":"Ecuadorian Ground Dove","scientific_name":"Columbina buckleyi","overview":"厄瓜多尔地鸠（英文名：Ecuadorian Ground Dove，学名：Columbina buckleyi），是鸽形目鸠鸽科地鸠属的鸟类。小型地鸠，以方形尾巴为显著特征。主要分布在厄瓜多尔西部，同时也在哥伦比亚最南部和秘鲁北部可见踪迹。该鸟种常见于低地和丘陵地带，通常在开阔的农业区或灌木丛生的林地中成对或小群体活动。","appearance":"成年厄瓜多尔地鸠体长约18厘米，体重约57克。雄性地鸠整体呈淡灰褐色，头部和颈背为蓝灰色，翅膀上有黑色斑点，腿脚为粉红色。雌鸟外观与雄鸟相似，但颜色略显暖棕色，头部缺少灰色，腿色较暗淡。飞行时，两性翅膀均无红褐色痕迹。幼鸟为棕色，羽毛边缘或中心带有浅色。","call":"其鸣唱为一系列间隔均匀的低音调、略微上扬的咕咕声，每秒约0.6-0.9个音符。音节通常为双音节，但从远处听来几乎无法分辨：\"huWOO...huWOO...huWOO....\"，音符长度短于停顿。","habits":"栖息于开放、干燥的落叶或半落叶林地，以及更密集的林地，甚至在花园、开阔地、农田和湿润低地的年轻次生植被中也能发现它们的身影，海拔高度从海平面到2000米。它们的活动范围和迁徙模式尚不明确，但在秘鲁的Bosque Nacional de Tumbes仅在6月至7月被记录，而2月至3月期间未见。","breeding":"筑巢行为独特，巢穴结实且呈杯状，与大多数鸽子的巢穴形成鲜明对比。已知四座活跃的巢穴位于1至7米高的灌木或树木中，其中三座巢穴含有两个卵。卵呈椭圆形，白色，平均尺寸约为23.3毫米x17.3毫米，新鲜重量约3.8克。","identification":"与同属的红地鸠相比，厄瓜多尔地鸠的头部颜色更深，翅膀上的黑斑更为明显。雌雄之间最明显的差异在于颜色深浅和腿的颜色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在南美的厄瓜多尔，从埃斯梅拉达斯省向南延伸至秘鲁的西北部（Tumbes省）。此外，C. b. dorsti亚种分布在秘鲁西北部的马兰翁谷。","other":"关于其生物学信息的缺乏，表明了对这一物种的基本研究需求。"},{"name":"红地鸠","english_name":"Ruddy Ground Dove","scientific_name":"Columbina talpacoti","overview":"红地鸠（英文名：Ruddy Ground Dove，学名：Columbina talpacoti），是鸽形目鸠鸽科地鸠属的鸟类。以其醒目的红色羽毛著称，常见于中美至南美的开阔湿润地带，包括村落甚至城镇。分布广泛，从墨西哥南部至巴西、秘鲁、巴拉圭和阿根廷北部，以及特立尼达和多巴哥。偶尔可见于美国西南部，从德克萨斯州南部至加州最南端，主要冬季出现。","appearance":"成年雄性红地鸠拥有蓝灰色头部与颈部，上体呈丰富的赤褐色，翼上有黑色斑点，下体较淡的棕色。尾部边缘黑色，翅膀下方为肉桂色和黑色。雌鸟颜色较浅，整体偏灰棕色，头部与身体色彩对比不如雄鸟明显。幼鸟类似雌鸟，但有鳞状外观。全长约17厘米，体重40-56.5克。","call":"其叫声为柔和的咕咕声，通常发音为cur-WOO。","habits":"适应力强，常出现在人类创造的环境，如农田和城市中心，与家鸽共同觅食谷物。偏好开放地带，包括被砍伐后的区域，用于耕作或放牧。它们的飞行快速直接，翅膀拍打规律，偶尔快速抖动。","breeding":"营巢于树上，用枝条搭建简单杯状巢，每次产两枚白色蛋，由双亲共同孵化12-13天。幼鸟大约两周后离巢，若条件适宜，会继续产第二或第三窝。","identification":"雄性红地鸠通过其鲜明的赤褐色羽毛和翼上的黑斑易于识别。雌鸟与灰褐色的地鸠区别在于体型更大，更带赤褐色，且下体单一色，而非斑驳色。雌鸟还与蓝地鸠的雌鸟区分开，后者体型更大，翼上有黑斑。","protection":"IUCN：LC（无危）","distribution":"繁殖区域遍布中美洲至南美洲东部，包括墨西哥至阿根廷北部，特立尼达和多巴哥。非繁殖季节，个体可能出现在美国西南部。","other":"红地鸠在某些地区可能面临另一种鸽子的竞争，尤其是在城市环境中，但它们在城市广场和花园中仍然常见。"},{"name":"白翅地鸠","english_name":"Picui Ground Dove","scientific_name":"Columbina picui","overview":"白翅地鸠（英文名：Picui Ground Dove，学名：Columbina picui），是鸽形目鸠鸽科地鸠属的鸟类。小型地鸠。其主要特征是淡棕色灰体色与黑色喙和虹膜形成鲜明对比，翼上有一道淡色条纹被黑色边缘包围。广泛分布于南美洲，从巴西东北部至智利中部和阿根廷南部。","appearance":"成年白翅地鸠长约18厘米，体重介于42至59克之间。头部前额和喉部呈白色，眼上方有窄黑纹。冠羽和颈背灰色，逐渐变为肩部、背部、臀部及中央尾羽的棕灰色。翅膀折叠时显现出粉色鹿皮色，上有两条白色带纹由黑色边框。颈部和胸部粉灰，腹部白色。雌鸟较雄鸟颜色稍暗淡，粉色调不明显。幼鸟比成鸟更暗淡且棕色，羽缘苍白，翼覆羽和胸羽中心呈红褐色或淡黄色。亚种strepitans上体和翅膀比指名亚种更灰，粉色调减少。","call":"白翅地鸠的鸣唱为一系列均匀间隔的低沉咕咕声，每秒约1.4至1.6个音符。双音节音符强调滑音的第二音节，发音为“cuWOOo...cuWOOo...cuWOOo...”。","habits":"主要栖息于干旱地带，包括森林边缘、灌木草原、开阔草地，散布着树木和其他遮蔽处。在安第斯山脉，常见于开放的Prosopis灌木林。进入郊区、花园和农田，偏好近期焚烧或耕作过的土地。海拔分布范围从低地至阿根廷西北部3000米，玻利维亚Yungas地区高达3700米；但在大部分范围内很少高于1250米。","breeding":"繁殖季节在阿根廷为10月至次年4月。巢由细枝构成，内部铺以柔软材料，筑于灌木或树上，偶尔也在屋顶。每次产2枚白色蛋，双方轮流孵卵。可能每年抚育两窝。","identification":"与同属其他物种相比，白翅地鸠的翼部特征和声音可作为辨识要点。亚种strepitans与指名亚种的区别在于更灰的颜色和较少的粉红色调。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括巴西东北部、智利中部、阿根廷南部，以及玻利维亚、巴拉圭、南部巴西、乌拉圭、秘鲁和哥伦比亚的部分地区。冬季向北至秘鲁东部。","other":"在一些地区非常丰富，如阿根廷西北部的干旱查科地区和智利北部的低地。"},{"name":"斑嘴地鸠","english_name":"Croaking Ground Dove","scientific_name":"Columbina cruziana","overview":"斑嘴地鸠（英文名：Croaking Ground Dove，学名：Columbina cruziana），是鸽形目鸠鸽科地鸠属的鸟类。以其独特的斑嘴而得名。分布于南美洲，从厄瓜多尔北部至智利北部，常见于人类居住区附近。","appearance":"体长约15厘米，雄鸟体重约52克，雌鸟约46克。头部蓝灰色，上体转为褐色，尾羽中央深灰，外侧黑底白尖；翼覆羽粉灰色，有黑色斑点，翼下可见紫色斑纹形成横带；胸腹淡紫粉色。虹膜红色，外围有白色环，眼周黄色裸皮；喙基部鲜黄或金黄色，尖端黑色，比同类物种更长；脚粉红。雌鸟头部呈褐色，翼斑较淡。幼鸟似雌鸟，但羽尖具淡黄色。","call":"发出一系列奇特的非典型鸽鸣，低沉含混的\"rrRwl\"音节，每2-4秒一次，还有轻微的哼鸣和嘟囔声。","habits":"栖息于干旱和半干旱地区，偏好亚热带灌木丛和河岸林地，频繁出现在农田、花园和公园中。主要地面活动，有时可达2400米高度。以种子为食，从地面捡食。","breeding":"全年均可繁殖，除9-10月在西南厄瓜多尔；通常筑巢于灌木或树上，偶尔于地面或建筑边缘、土堤或低崖。每次产卵2枚白色蛋，孵化期12-15天，雏鸟离巢期10-12天。","identification":"通过其独特的斑嘴和鲜艳的黄色基部识别，以及低沉的叫声区别于其他地鸠。","protection":"IUCN：LC（无危）","distribution":"分布于南美，北起厄瓜多尔北部，南至智利北部，包括哥伦比亚、厄瓜多尔和秘鲁的部分地区。"},{"name":"蓝眼地鸠","english_name":"Blue-eyed Ground Dove","scientific_name":"Columbina cyanopis","overview":"蓝眼地鸠（英文名：Blue-eyed Ground Dove，学名：Columbina cyanopis），是鸽形目鸠鸽科地鸠属的鸟类。在南美巴西中南部特有。以其梦幻般的蓝色眼睛和翅膀上的蓝色斑点而引人注目，全身呈现肉桂色，腹部颜色较淡。仅在巴西米纳斯吉拉斯州的一个特定地点被发现，栖息于开阔的稀树草原和白沙滩上的草地。","appearance":"蓝眼地鸠长约15.5厘米。头部、颈部、翼覆羽、上尾覆羽和胸部呈紫红褐色，腹部、两胁、肩部和背部颜色更偏棕色。腹下部和尾下覆羽白色，闭合的翅膀上可见深棕色和栗色带蓝色闪光的斑点。中央尾羽为红褐色，外侧尾羽颜色更深。眼睛为醒目的蓝色，眼周裸露的皮肤为灰色。雌鸟整体颜色更淡，尤其腹部更为浅色。幼鸟羽毛边缘呈红褐色，翅膀上的斑点模糊。","call":"蓝眼地鸠的鸣唱是一系列均匀间隔的柔和咕咕声，通常以短促的上扬音“wah”或更低调的“wuh”重复，偶尔发出类似“prrah”的喉音。","habits":"栖息于开阔的稀树草原和草地环境，最高记录到海拔800米。这种地面生活的物种通常单独或成对出现。","identification":"蓝眼地鸠的特征在于其独特的蓝色眼睛和翅膀上的蓝色斑点，与同属其他物种相比，具有明显的色彩差异。","protection":"IUCN：CR（极危）","distribution":"蓝眼地鸠分布在巴西中南部，确切记录自米纳斯吉拉斯州、马托格罗索州南部、南马托格罗索州中部等地。","other":"蓝眼地鸠的种群数量极为稀少，自20世纪80年代以来的记录极少，至2017年仅知27个个体存在于唯一已知群体中。"},{"name":"蓝地鸠","english_name":"Blue Ground Dove","scientific_name":"Claravis pretiosa","overview":"蓝地鸠（英文名：Blue Ground Dove，学名：Claravis pretiosa），是鸽形目鸠鸽科蓝地鸠属的鸟类。广泛分布于中美洲至南美洲，自墨西哥东部延伸至阿根廷北部和巴西东南部。其最显著的特点是雄鸟的珍珠蓝色外观和雌鸟的红褐色臀部。常见于热带低地的湿润森林边缘和空旷地带。","appearance":"雄性蓝地鸠全身呈蓝灰色，背部和翅膀较深，翼覆羽和次级飞羽上有数量不一的黑色斑点，而主飞羽全黑。雌鸟则为橄榄棕到肉桂棕色，尾上覆羽和中央尾羽变为赤褐色，头部和喉咙为灰褐色，胸部为淡橄榄色，腹部白色，尾下覆羽为赤褐色。雌雄差异明显，雌鸟比雄鸟略小。","call":"蓝地鸠发出较为单调的连续咕咕声，这是确认其存在的良好指示。","habits":"蓝地鸠栖息于开放林地、森林边缘、空地和路边，尤其偏好潮湿环境，海拔高度可达约1200米。它们单独、成对或以家庭群的形式活动，主要以种子和小昆虫为食，也会摄入砂石。","breeding":"蓝地鸠会在树上或灌木丛中用小枝条搭建松散的巢穴，高1-11米，每次产两枚白色的蛋。","identification":"雄性蓝地鸠的特征独特，不易混淆；雌鸟可能与Paraclaravis属的雌鸟相似，但通常与较小的红地鸠混淆，后者翼上的标记为黑色而非栗棕色。","protection":"IUCN：LC（无危）","distribution":"蓝地鸠分布于中美洲和南美洲，从墨西哥东部至阿根廷北部，以及巴西东南部。在繁殖季节，它们遍布上述区域。","other":"蓝地鸠属（Claravis）曾包含紫翅地鸠和紫胸地鸠，但后两者因系统发育研究被重新分类至Paraclaravis属。"},{"name":"紫翅地鸠","english_name":"Purple-winged Ground Dove","scientific_name":"Paraclaravis geoffroyi","overview":"紫翅地鸠（英文名：Purple-winged Ground Dove，学名：Paraclaravis geoffroyi），是鸽形目鸠鸽科 Paraclaravis 属的鸟类。以羽色鲜艳、栖息于热带森林中而著称，主要食果，分布于南美洲的巴西东南部、巴拉圭东部和阿根廷东北部（仅限Misiones省）。该物种曾常见于沿海地带，如今因栖息地丧失和可能的非法贸易面临严重威胁。","appearance":"成年紫翅地鸠体长19至23厘米，雄鸟上体呈暗蓝灰色，下体颜色较淡，翅膀折叠时可见两条宽大的深紫色带，较小的紫色带跨越次级飞羽；中央尾羽灰，最外侧四根尾羽白色，其余灰白。雌鸟总体呈棕色，翅膀带比雄鸟的略淡；中央尾羽棕，外侧尾羽黑，带有宽阔的黄褐色尖端。喙黑色，腿呈深黄褐色。雌鸟幼体比成年个体更浅，羽毛末端呈灰暗色，边缘黄褐色；雄鸟幼体比雌鸟幼体颜色更深。","call":"紫翅地鸠的叫声被描述为双音节的“oo-OOT...”，与蓝地鸠的单音节叫声形成对比，但目前没有录音记录。","habits":"紫翅地鸠是一种游荡物种，追踪大西洋森林中特定Guadua竹种的开花事件，包括takuarusu(Guadua chacoensis)和yatevó(Guadua trinii)。其生活方式高度依赖于竹子，与近缘物种——紫胸地鸠相似，后者专注于安第斯山脉的竹子。","breeding":"关于紫翅地鸠的繁殖生态细节尚未充分了解，需要更多的研究。","identification":"与蓝地鸠在相同生境中共存，紫翅地鸠可通过其特有的双音节鸣叫和深紫色翼带加以区分。此外，其栖息地偏好和行为模式也提供了辨识依据。","protection":"IUCN：CR（极危）；自1973年起受巴西法律保护。基于已知记录，估计成熟个体数量少于250只。自1980年代以来，仅记录到少数目击，且群体规模很小。栖息地丧失是其数量急剧下降的主要原因。","distribution":"分布于巴西东南部（从Bahia南部至Santa Catarina南部）、巴拉圭东部和阿根廷东北部（仅限Misiones省）。当前分布极为分散，主要见于巴西的几个保护区，包括Palmito州立森林（Parana）、Augusto Ruschi生物保护区（Espirito Santo）和Serra do Mar的多个地点，以及阿根廷的Iguazú国家公园。","other":"紫翅地鸠曾是巴西里约热内卢市场上的常见品种，且在20世纪30年代后期有数百只被进口到法国和其他欧洲地区。然而，由于栖息地破坏和可能的野生鸟类贸易，该物种数量急剧减少，甚至可能已经灭绝。"},{"name":"紫胸地鸠","english_name":"Maroon-chested Ground Dove","scientific_name":"Paraclaravis mondetoura","overview":"紫胸地鸠（英文名：Maroon-chested Ground Dove，学名：Paraclaravis mondetoura），是鸽形目鸠鸽科 Paraclaravis 属的鸟类。从墨西哥东南部延伸至玻利维亚中西部。拥有深蓝色灰身配以紫色翼带和醒目的紫胸，雌雄色彩差异明显。栖息于山地湿润森林，偏好竹林地带。","appearance":"雄鸟长约18-24厘米，体重89-95克，额头、脸和下巴呈灰色，胸部暗紫色，腹部渐变为灰色。雌鸟略小，全身棕色，面部肉桂色，翅膀带有暗红褐色条纹。幼鸟比雌鸟更偏赤褐色，翼缘锈色，翅上有模糊的暗棕色斑点。","call":"其鸣唱为一系列低沉、略有升调的双音节咕咕声，节奏约为每秒0.8-1个音符，音符长度短于停顿。","habits":"偏好湿润的山地森林底层植被，尤其是竹林，当竹子结籽时尤为活跃。主要摄食种子和落果，偶尔在地面觅食。通常单独或成对活动，有时形成10-15只的小群。","breeding":"繁殖习性知之甚少，可能集群筑巢。巢为简单平台，位于竹林中，高约2.1米。每窝产两枚白色蛋，双亲共同孵化15天，雏鸟由双亲照料，14天后离巢。","identification":"雄鸟与C. geoffroyi相比颜色更深，额头、脸和下巴呈灰白，胸部深紫色。雌鸟较C. geoffroyi雌鸟稍暗，面部肉桂色。亚种间色彩差异较小，可能部分源于个体变异。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东南部至玻利维亚中西部，包括中美洲和南美洲的部分地区，如哥伦比亚、哥斯达黎加、厄瓜多尔、萨尔瓦多、危地马拉、洪都拉斯、秘鲁、委内瑞拉等地。","other":"紫胸地鸠的出现具有不可预测性，因栖息地丧失而面临潜在的种群下降风险。"},{"name":"裸脸地鸠","english_name":"Bare-faced Ground Dove","scientific_name":"Metriopelia ceciliae","overview":"裸脸地鸠（英文名：Bare-faced Ground Dove，学名：Metriopelia ceciliae），是鸽形目鸠鸽科裸脸地鸠属的鸟类。分布于南美洲。以独特的橙色眼环和淡斑点状羽翼而著称，常见于安第斯山脉的岩石和灌木斜坡上，通常靠近人类居住区。体型较小，容易被忽视，但分布较为广泛。","appearance":"裸脸地鸠体长约16-17厘米，体重约66克。背部呈灰褐色或暗褐色，羽毛尖端有白色或浅黄色，形成斑点效果。颈部和胸部灰色，带粉红色调。腹部和尾下覆羽呈土黄色。初级飞羽、次级飞羽、外侧尾羽黑色，内缘和下部具红棕色。中央尾羽较暗，外侧尾羽黑底白尖。眼睛蓝或蓝白色，眼周有明显橙色裸露皮肤。脚和腿粉色。雌雄相似，但雌鸟胸部粉红色较淡。幼鸟类似成鸟，但色彩较暗淡，裸露部分颜色较淡。不同亚种间有颜色深浅和色调差异。","call":"其最显著的声音是非声乐性的，起飞时翅膀发出响亮的颤音。也有记录显示，它会发出一系列五声相似的上升后突然下降的双重咕咕声，以及类似低吼的'Wo ow'声。","habits":"栖息于安第斯山脉的贫瘠和半贫瘠地带，海拔2000-4500米，偏好沙地和稀疏植被环境。常在仙人掌地带和灌木或轻微林木覆盖的斜坡上发现。与人类居住地密切相关，尤其在高海拔地区。在一些山谷季节性下降至600米，偶尔在秘鲁南部降至海平面附近。地面觅食，小群活动。","breeding":"繁殖信息极少，已知在智利3月和秘鲁冬季筑巢。巢位设于地面、悬崖或建筑物洞穴中。","identification":"通过橙色眼环和淡斑点状的羽翼可与其它鸽类区分开。与黑翅地鸠相比，避免出现在Puya丛生的地带。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲，从秘鲁到智利北部，包括玻利维亚、阿根廷的部分地区。在较高海拔地区，它与人类居住地紧密相连。","other":"尽管其分布广泛，但在某些局部地区数量较少，如智利北部和阿根廷西北部。"},{"name":"裸眶地鸠","english_name":"Moreno's Ground Dove","scientific_name":"Metriopelia morenoi","overview":"裸眶地鸠（英文名：Moreno's Ground Dove，学名：Metriopelia morenoi），是鸽形目鸠鸽科裸脸地鸠属的鸟类。分布于南美洲阿根廷西北部的高海拔安第斯山脉地区。这种地鸠以明亮的橙红色面部皮肤和显著的裸眼环而著称。","appearance":"体长约17厘米，上体呈暗褐色，头部和肩部灰褐色，尾羽覆羽红棕色；喉部灰白色，余下体淡棕灰色，腹部转为淡黄色，尾下覆羽红棕色；外侧尾羽黑底白尖；眼蓝色，环绕着鲜亮的橙色裸皮，边缘有细黑线；腿脚粉红色。雌雄相似，但雌鸟眼周裸皮色彩较淡。幼鸟似成鸟，但冠羽和上体羽缘有红棕色边。","call":"会发出一系列轻柔鼻音的“cuEec cuEec cuEec”和更快更深沉的“coo coo coo coo coo”声，以及在伸长颈部张嘴时发出的尖锐“wreeeg”声。","habits":"栖息于温带和普纳地带，海拔1800至3200米，偏好柱状仙人掌、灌木丛和零星树木覆盖的沙石丘陵。群居地面觅食，具体饮食细节未知。","breeding":"在泥墙和土岸洞穴中筑巢，产两枚白色蛋，关于其繁殖生态的其他信息尚未公开。","identification":"与区域内其他地鸠区别在于其无斑纹的翅膀和围绕眼睛的广泛裸皮。","protection":"IUCN：LC（无危）","distribution":"仅限于阿根廷西北部，包括温带和普纳地带，海拔1800至至少3200米。","other":"属于鸽形目鸠鸽科裸脸地鸠属，是该属的单型物种。"},{"name":"黑翅地鸠","english_name":"Black-winged Ground Dove","scientific_name":"Metriopelia melanoptera","appearance":"黑翅地鸠长约21-23厘米，雄鸟体重89.1-114克，雌鸟体重86-96.1克。上体呈灰褐色或土褐色，带有微弱的粉色色调；喉部白色；肩部和翅膀边缘白色；主翼羽、覆羽、次级飞羽和大部分下翼黑色；尾羽中央灰色，外侧黑色；下体淡粉色，腹部较浅，两侧逐渐变为灰色；尾下覆羽和尾下部黑色；虹膜颜色变化大，可为蓝色、紫色、黄色或鲜绿色，外围有窄红色环；眼周皮肤为鲑鱼粉、橙色或黄色；腿和脚为深棕色至黑色；喙黑色。雌鸟比雄鸟上体颜色略暗，下体粉色较少。幼鸟羽毛边缘有淡褐色，缺乏成鸟的粉色色调。saturatior亚种上体颜色更深更灰，下体颜色更少粉色。","call":"黑翅地鸠的鸣唱是一系列相对高音的双音节‘rrree-up...rrree-up...rrreee-up...’。第一个音节上滑，有模糊质感，第二个音节下滑。双音节每2.5-3秒重复一次。此外，还会发出短促的‘piu’声，类似于某些鸣禽的叫声，伴随着尾巴突然向上倾斜的动作。飞行时翅膀发出哨声，尤其是在受惊飞起时。","habits":"黑翅地鸠主要栖息于安第斯山脉的páramo区和puna区，常见于树线附近的干燥和半干旱地区，如草甸、远离树木的灌木草原，但也出现在Polylepis树林（它们在此过夜）和柱状仙人掌或caulescent bromeliads（Puya）丛中。在冬季，它们会迁移到较低海拔的地区。以地面觅食为主，主要食物是草籽。","breeding":"繁殖季节随纬度而变，哥伦比亚和厄瓜多尔的繁殖期为8月至10月，南部地区则延续到2月。巢为脆弱的枝条平台，有时衬以细根和草，位于浓密的灌木、Puya bromeliads或仙人掌中，距地面高度可达3米；有时在地面或建筑物上筑巢。每次产两枚白色蛋，孵化期和离巢期未知。","identification":"与同属的斑颊哀鸽相比，黑翅地鸠体型较小，翅膀上没有大的黑斑。其独特的识别特征包括眼下的橙色泪滴状斑纹和飞行时最明显的白色‘肩部’闪光。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲的哥伦比亚、玻利维亚、智利、哥伦比亚、厄瓜多尔和秘鲁。在哥伦比亚至智利南部广泛分布，从2000米至4400米的海拔范围内，但在智利的分布高度为900至4900米，主要在冬季下降至较低海拔。"},{"name":"斑翅地鸠","english_name":"Golden-spotted Ground Dove","scientific_name":"Metriopelia aymara","overview":"斑翅地鸠（英文名：Golden-spotted Ground Dove，学名：Metriopelia aymara），是鸽形目鸠鸽科裸脸地鸠属的鸟类。分布于南美洲中部，自秘鲁中南部至智利北部，常见于高海拔安第斯山脉的半干旱地带。","appearance":"成年斑翅地鸠体型较小而健壮，上部呈淡土黄色，略带紫红色调；下体紫红至喉部白色，腹部转为淡褐色；中央尾羽灰褐，尖端黑色，外侧尾羽紫黑色；翼上覆羽长，接近闭合尾羽末端；翼下覆羽和初级飞羽黑色，后者基部呈栗色；翼上有独特的金色金属光泽斑点；肩羽和最内侧次级飞羽上有两块紫黑色斑；眼睛棕色；喙黑，腿脚粉红色。雄雌相似。幼鸟颜色较浅，缺乏金色斑点。","call":"鸣叫特征未知，但在起飞时翅膀会发出响亮的颤音，持续飞行时尤其在展示飞行中，可听到类似哨声的翅膀振动声。","habits":"栖息于安第斯山脉的普纳地带，偏好沙质和细石土壤的草原，村庄附近及相邻农田，常见于海拔2800至5000米间，南部部分地区低至300米。以小群或大群形式活动，地面觅食，羽色有助于隐蔽。","breeding":"繁殖季节在4月至8月期间，筑巢于草丛中，有时也在树上或岩石间。每窝产2枚白色蛋。","identification":"与黑翅地鸠相比，体型更小，尾巴较短，翅膀下部为黑色，无白色‘肩部’闪光。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中南部至智利北部，包括阿根廷和玻利维亚的部分地区。","other":"生物学和生态学细节尚待研究。"},{"name":"长尾地鸠","english_name":"Long-tailed Ground Dove","scientific_name":"Uropelia campestris","overview":"长尾地鸠（英文名：Long-tailed Ground Dove，学名：Uropelia campestris），是鸽形目鸠鸽科长尾地鸠属的鸟类。本属唯一物种。主要分布在南美的中央地带，包括巴西中北部、中部、中西部以及玻利维亚北部和东部。以其独特的长尾和地面活动的习性而著称。","appearance":"成年长尾地鸠体长介于15.7至17.7厘米之间。雄鸟头部前额和前冠呈蓝灰色，背部棕色，后颈带粉红色。翅膀折叠时可见两条紫色带纹和一排大型黑紫色斑点。喉咙、颈部两侧及胸部为淡紫粉色，逐渐过渡到腹部的白色。长尾的中央羽毛为棕色，外侧为黑色并带有白色尖端。雌鸟眼周较淡，下体颜色更浅，上体灰度更高。幼鸟整体色彩较为暗淡，多呈灰褐色。","call":"长尾地鸠的鸣声为一系列较高音调的双音节‘wha-ooop...wha-ooop...wha-ooop...’音符，每秒约发出一次，连续5至6个乐句后稍作停顿。","habits":"长尾地鸠栖息于季节性湿润的草地、稀树草原和靠近水源的灌木边缘，海拔高度可达1100米。它们通常在干燥季节以2至5只的小群出现，偏好在裸露的路旁觅食种子。","breeding":"关于长尾地鸠的繁殖生态信息目前未知。","identification":"长尾地鸠具有独特的V形尾羽，尾部外侧黑色，尖端白色，易于识别。与Columbina属和Claravis属鸽子有相似之处，但其独特的尾羽和色彩组合使其容易区别。","protection":"IUCN：LC（无危）","distribution":"长尾地鸠主要分布于南美洲的巴西中北部、中部、中西部以及玻利维亚北部和东部。","other":"长尾地鸠在一些地区被视为常见，但在其分布范围内受到栖息地破坏和改变的威胁。"},{"name":"蓝头鹑鸠","english_name":"Blue-headed Quail-Dove","scientific_name":"Starnoenas cyanocephala","overview":"蓝头鹑鸠（英文名：Blue-headed Quail-Dove，学名：Starnoenas cyanocephala），是鸽形目鸠鸽科蓝头鹑鸠属的鸟类。主要分布在古巴。其最显著的特征是拥有亮蓝色的头部，黑色的眼纹，白色的脸部条纹，以及黑色的喉部饰羽边缘。体长30至33厘米。","appearance":"成年蓝头鹑鸠雄鸟和雌鸟基本相似，前额和头顶呈鲜亮的蓝色，由眼周至颈背有一条黑色线条，面部和喉咙为黑色，胸部粉紫色逐渐变为橄榄棕色，腹部和大部分羽毛为棕褐色，翼羽颜色最深，尾羽外侧灰蓝色。喙基部红色，尖端淡蓝色；跗跖深红色，腿脚粉红色。幼鸟较成鸟色彩暗淡，背部、肩羽和翼羽边缘呈浅棕，胸部羽毛有浅色边缘；头部蓝色较淡，腿脚呈暗红色。","call":"其鸣唱为一系列短促、空洞的双音节音符，‘whooo-up’或‘hoooo-up’，最后一个音节有明显的上扬，每2至4秒重复一次，最后突然停止。","habits":"主要栖息于低地森林，包括湿地沼泽，偶尔出现在海拔至少500米的高地。偏好有厚实树冠遮蔽而林地地面开阔的环境，偏爱石质底基和丰富落叶的地方。通常在干燥地带活动，与共存。主要以种子、浆果、蜗牛为食，也会食用昆虫、虫蛹和毛虫。通常在地面觅食，经常成对或小群（最多15只）活动。","breeding":"繁殖季节主要在3月至6月。巢穴简单，尺寸约为15至21厘米×10至12厘米，深度约1.5厘米，由树枝和根须编织而成，建在低矮灌木丛或地面上，常被灌木或树根遮蔽。巢位有时高达6至8米。产卵数量为1至2枚，蛋壳呈哑光的白色至奶油色，孵化期约为17天。","identification":"与新世界其他鸠鸽科物种相比，蓝头鹑鸠的特征独特，尤其是头部的蓝色、黑色和白色图案。与澳大利亚的Geophaps属和相关陆地鸠鸽最为相似。","protection":"IUCN：EN（濒危）","distribution":"仅分布于古巴，曾经在松树岛也有记录，但在佛罗里达南部的记录可能只是迷鸟。目前在古巴的分布较为局限，主要在扎帕塔沼泽附近的森林区域，以及皮纳尔德里奥省的瓜纳哈卡比斯半岛和拉吉拉国家公园。","other":"曾因过度狩猎和栖息地破坏导致数量大幅下降，非法捕猎和飓风造成的森林破坏也是持续威胁。尽管受国家法律保护，但由于执法不严，狩猎行为仍时有发生。"},{"name":"蓝冠鹑鸠","english_name":"Purple Quail-Dove","scientific_name":"Geotrygon purpurata","overview":"蓝冠鹑鸠（英文名：Purple Quail-Dove，学名：Geotrygon purpurata），是鸽形目鸠鸽科鹑鸠属的鸟类。其分布区域自哥伦比亚西北部延伸至厄瓜多尔西北部。这种鸟拥有独特的外观，包括亮紫色的背部和臀部，以及复杂的头部图案，使其在雨林环境中显得格外醒目。","appearance":"蓝冠鹑鸠体型介于22至26厘米，体重约155克。成年雄鸟上半身呈红棕色，带有紫色调，翅膀覆羽为深红色，背部和臀部则为明亮的天蓝色。尾巴为深黑色，外侧三根尾羽尖端带白色。下体灰白。头部有精致的黑白搭配图案，前额为淡白色，与深蓝色的顶冠和颈背形成鲜明对比；颈侧有金色光泽，颊纹为暗紫色，喉部为白色，胸部略显灰色。雌鸟整体色彩较雄鸟暗淡，上半身颜色偏红棕色。幼鸟色彩更暗，面部图案不明显，背部有浅黄色斑点，缺乏成鸟的金属光泽。","call":"蓝冠鹑鸠的鸣声为一系列柔和而空洞的咕咕声，起始音几乎听不见，总体上与蓝冠鹑鸠相似但音调略低。其主要鸣叫声比蓝冠鹑鸠的单音节更短，且蓝冠鹑鸠的最高音频变化比蓝冠鹑鸠更为显著。","habits":"蓝冠鹑鸠栖息于热带雨林的地面层和灌木层，偏好原始和成熟的常绿山地森林，偶尔出现在老的次生林中。它们在哥伦比亚海拔200至1100米的山区和丘陵地带活动，而在厄瓜多尔则主要在200至700米的高度被发现。","breeding":"有关蓝冠鹑鸠的繁殖信息有限，仅知在厄瓜多尔，六月曾捕获到睾丸增大的雄鸟，暗示可能的繁殖季节，但具体繁殖生态尚不清楚。","identification":"蓝冠鹑鸠与青冠鹑鸠容易混淆，尤其是在光线昏暗的森林中。区别在于蓝冠鹑鸠颈部的金色斑块和白色前额与深色顶冠的强烈对比，以及不同的鸣声特征。","protection":"IUCN：EN（濒危）","distribution":"蓝冠鹑鸠分布于南美洲，从哥伦比亚西北部至厄瓜多尔西北部。在哥伦比亚，它们主要分布在阿特拉托河谷以北的丘陵和山脉地带；而在厄瓜多尔，它们主要在200至700米的海拔高度活动。","other":"蓝冠鹑鸠曾经被认为是青冠鹑鸠的一个亚种，但在21世纪初被确认为独立物种。"},{"name":"青冠鹑鸠","english_name":"Sapphire Quail-Dove","scientific_name":"Geotrygon saphirina","overview":"青冠鹑鸠（英文名：Sapphire Quail-Dove，学名：Geotrygon saphirina），是鸽形目鸠鸽科鹑鸠属的鸟类。分布于南美洲，从哥伦比亚南部至秘鲁东南部的鸟类。栖息于低地和山地雨林的地面层，以其独特的头部图案和鲜艳的色彩著称。","appearance":"雄鸟具有白额头、喉咙和眼下的小斑点，以及醒目的紫黑色颊纹。冠羽暗蓝灰色渐变为颈背的铜绿色，颈部有金色、绿色和紫粉色的虹彩。背部和翼内侧覆羽深紫色，翼上有明显的白色斑点。臀部和尾上覆羽虹彩绿或蓝紫色。中央尾羽石板黑，外侧尾羽黑而端蓝灰。胸部淡灰色，腹部白色，两胁和下尾覆羽呈淡黄色。眼睛颜色从浅黄到深棕色不等。雌鸟的羽毛模式相同但色彩较暗淡。幼鸟全身暗红褐色，面部标记较弱，白色部分颜色更暗。","call":"其鸣唱为单调的双音节'hu..huuuuu'或'ca..whooooo'，第一个音节比第二个短，有时听不清楚。每约4秒重复一次。","habits":"通常独居或成对出现在地面，可能偏好靠近溪流和浅沟壑的地带。以种子和小型无脊椎动物为食。生活在低地和山地常绿森林的地面和灌木丛中，高度可达1350米，但主要在1100米以下。","breeding":"关于繁殖信息知之甚少。已知巢由枝条和根须搭建，高1.7至3米，位于灌木丛中，巢内直径14.3厘米，内径8.5厘米，深度2.3厘米。巢中发现过单个蛋、两个蛋或单个雏鸟。孵化中的蛋为全褐色或白色。雌鸟在8月处于繁殖状态或正在照料幼鸟。","identification":"与紫鹑鸠在暗处容易混淆，但青冠鹑鸠的脸部图案更为明显。","protection":"IUCN：LC（无危）。然而，该物种一般被视为不常见且分布非常局部，需更多调查工作以确定其确切分布范围和估计种群规模。主要威胁是亚马逊盆地加速的森林砍伐。","distribution":"分布于南美，具体包括哥伦比亚南部、东部厄瓜多尔、秘鲁东南部和极西巴西亚马逊地区。","other":"直到最近，青冠鹑鸠还与蓝冠鹑鸠被视为同一物种的一部分。"},{"name":"凤头鹑鸠","english_name":"Crested Quail-Dove","scientific_name":"Geotrygon versicolor","overview":"凤头鹑鸠（英文名：Crested Quail-Dove，学名：Geotrygon versicolor），是鸽形目鸠鸽科鹑鸠属的鸟类。拥有独特的冠羽和鲜明的色彩，广泛分布在牙买加的蓝山和约翰克劳山脉等地，偏爱潮湿的森林环境。","appearance":"凤头鹑鸠体型丰满，雄鸟长度约27至31厘米，雌鸟略小，体重约225克。额头有硬质毛发，颜色从暗黑到灰黑色不等；冠部呈暗褐色，侧面和后方逐渐变为灰色；颈部两侧和后部有金属青铜色或青铜绿色光泽；有小型颈后冠；喉部中央和面颊条纹呈红棕色；脸、颈和腹部为灰色；背部和小翼羽具虹彩红紫色，肩部转为蓝紫色，下背部和尾巴呈绿黑色，带有紫虹彩；腹部和两胁为栗色；眼睛红色，眼睑边缘鲜红；眼周皮肤灰色；喙黑色；腿和脚粉色。雌鸟有时与雄鸟难以区分，但在颈和腹部可能较淡和偏褐色。幼鸟比成鸟更暗淡，多数羽毛边缘呈锈色。","call":"其广告鸣声为短暂的两声咕咕音节，首音高亢响亮，第二音较为低沉，有时几乎听不见甚至缺失，如'whuuOh..whuuw'，两音节间隔时间约为1.5秒。","habits":"栖息于海拔100米至1800米的湿润石灰岩森林，偏好深林中的落叶层，偶尔出现在小径和路边。以种子、落果和可能的无脊椎动物为食，在森林地面的阴暗处觅食，也会沿小径甚至道路边缘活动。","breeding":"繁殖季节为3月至6月。巢由枝条构成，靠近地面置于植被中，有时直接建在地上。每次产卵2枚浅黄色蛋。在圈养条件下，孵化期为13天，幼鸟离巢时间为12天。","identification":"凤头鹑鸠可通过其较大的体型、主要为紫色的上部、灰色的下部以及缺乏明显的苍白面部条纹与红鹑鸠区分开来。","protection":"IUCN：NT（近危）。凤头鹑鸠在当地相当常见，尤其是在潮湿年份，但其生存依赖于森林的保护。","distribution":"主要分布在牙买加的蓝山和约翰克劳山脉、迪亚波罗山区域和Cockpit Country，海拔从100米到1800米，避开低地干燥森林和种植园地带。","other":"曾是Geotrygon属的唯一成员，但现在该属包含更多种类。"},{"name":"红鹑鸠","english_name":"Ruddy Quail-Dove","scientific_name":"Geotrygon montana","overview":"红鹑鸠（英文名：Ruddy Quail-Dove，学名：Geotrygon montana），是鸽形目鸠鸽科鹑鸠属的鸟类，广泛分布于中美洲至南美洲，包括西印度群岛。这中等体型的热带森林和种植园低地鸟，其性格害羞，不常被见到。","appearance":"红鹑鸠雄鸟主要呈亮红色，具有独特的面部图案，而雌鸟整体为棕色，带有较淡的面部条纹和胸部的垂直浅色条纹。雌雄两性均有眼下的苍白条纹和红褐色跗蹠。雄鸟的上部主要为红褐色，最显著的特征是头部侧面的红褐色条纹，下部主要为黄褐色。雌鸟上部为橄榄棕色，面部条纹较为暗淡。","habits":"红鹑鸠栖息于湿润和落叶林中，通常单独或成对在地面寻找种子和无脊椎动物，行进时小心翼翼，常在浓密的植被下活动。它对栖息地的碎片化较为敏感，不易在严重破碎的环境中生存。","breeding":"红鹑鸠的繁殖习性包括在灌木丛中建造脆弱的平台，产下两个淡黄色的蛋，有时会在地面上筑巢。","identification":"红鹑鸠与同属的其他物种相比，其全身的红褐色或棕色以及头部侧面的深色条纹在大部分分布范围内都是独特的。它与棕胸鹑鸠最为相似，但后者通常出现在更高的海拔，且颜色更深，头部有灰色冠羽，颊部的深色条纹为黑色而非棕色。","protection":"IUCN状态未提供。","distribution":"红鹑鸠在中美洲和南美洲广泛分布，北至墨西哥，南至阿根廷，同时在加勒比海岛屿也有记录。","other":"红鹑鸠的幼鸟上部呈深橄榄色至灰暗色，翅膀覆羽、飞羽和尾羽边缘有肉桂色，下体白色至肉桂色，幼年雄鸟比幼年雌鸟更亮更鲜明。"},{"name":"紫鹑鸠","english_name":"Violaceous Quail-Dove","scientific_name":"Geotrygon violacea","overview":"紫鹑鸠（英文名：Violaceous Quail-Dove，学名：Geotrygon violacea），是鸽形目鸠鸽科鹑鸠属的鸟类。拥有广泛但零散的分布区，从中美洲的尼加拉瓜延伸到南美洲南部的巴西。其外观相对朴素，头部呈灰白色，颈部和背部带有紫色光泽，翅膀为赤褐色。与红鹑鸠相比，紫鹑鸠的色调更深，尤其是头部和下体。在热带雨林的成熟森林或邻近的次生林中较为常见。","appearance":"雄性紫鹑鸠体长21-23.5厘米，体重93-150克；雌鸟稍大，体长21-24.5厘米。前额和脸部灰白至灰紫色，头顶紫色光泽，上体棕色带紫色光泽，喉部和胸部淡紫色，腹部白色，两翼斑驳的白色、黑色和栗色。虹膜橙棕色或黄棕色，喙和鼻孔鲜红色，脚和腿珊瑚红色。雌鸟颜色较暗淡，仅在颈后和上背有紫色光泽，颈部和胸部棕色带紫色调。幼鸟与雌鸟相似，但更暗，缺乏光泽，羽毛边缘为肉桂色和暗赤褐色。","call":"广告鸣叫声为重复的单个高音咕咕声，持续约1秒，音调约500-600赫兹，与更为常见的灰额棕翅鸠的叫声容易混淆，但其声音具有轻微的频率调制，赋予其更柔和的哀怨特质。","habits":"栖息于热带低地常绿森林的浓荫下层，偶尔出现在次生林和可可种植园，海拔可达1650米。相较于同类，紫鹑鸠更倾向于树栖，经常在下层至中层树冠处歇息。主要以种子、落地果实及可能的小型无脊椎动物为食，地面觅食。","breeding":"在哥伦比亚，3月至6月期间观察到处于繁殖状态的个体，7月发现幼鸟，9月末发现条纹幼鸟；在巴拿马，7月发现带有卵的巢；在巴拉圭，11月观察到生殖器官增大的成鸟。巢通常位于离地2-3米的树枝上，内含两个淡黄色的卵。","identification":"与红鹑鸠相比，紫鹑鸠的色彩更深，尤其是在头部和下体部分。此外，紫鹑鸠的翅膀为赤褐色，而红鹑鸠的翅膀颜色更丰富。亚种G. v. albiventer头部、胸部和肩部的颜色比指名亚种更蓝。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的尼加拉瓜至南美洲的委内瑞拉，南美东部和中部，包括阿根廷、玻利维亚、巴西、哥伦比亚、哥斯达黎加、圭亚那、尼加拉瓜、巴拿马、巴拉圭、秘鲁、苏里南和委内瑞拉。","other":"尽管在许多地区的分布似乎稀少至普通，紫鹑鸠总体上具有庞大的种群数量。"},{"name":"灰头鹑鸠","english_name":"Grey-fronted Quail-Dove","scientific_name":"Geotrygon caniceps","overview":"灰头鹑鸠（英文名：Grey-fronted Quail-Dove，学名：Geotrygon caniceps），是鸽形目鸠鸽科鹑鸠属的鸟类。最显著的外部特征是灰白渐变为灰色的额头和头部，以及独特的紫蓝色光泽体羽。分布于古巴，尤其在Zapata半岛和Sierra del Rosario的森林中较为常见。","appearance":"雄性灰头鹑鸠体长26至30厘米，雌鸟27厘米，体重介于192至210克之间。额头呈灰白至灰色渐变，头部背面略带紫色光泽，喉部中灰，胸部暗色，腹部中央奶油色，臀部及尾下覆羽赤褐色。翅膀基部和初级飞羽边缘浅红棕色，背部和胸部侧面紫蓝色光泽，下背、臀部和尾上覆羽转为蓝紫色，尾巴深灰棕色。雌鸟较雄鸟稍显暗淡，繁殖季节光泽减弱。幼鸟额头棕色，喉咙淡灰色，上体暗棕色，下体栗褐色。","call":"鸣唱为一系列短促低沉的‘haoo’或‘cooo’音节，既可快速连续发出，也可间隔约0.5秒缓慢吟唱，两种形式的鸣唱被称为‘快歌’和‘慢歌’。","habits":"灰头鹑鸠栖息于热带低地森林和旧次生林，偏好湿润环境，包括靠近沼泽地带的非常潮湿的森林，偶尔出现在海拔高达1200米的山地森林。它在地面上觅食，以种子和小型无脊椎动物为食，如昆虫、幼虫和毛虫，通常单独或成对活动。","breeding":"繁殖季节至少从1月持续到8月。巢由树枝和树叶构成，内衬根须和草，置于离地面1至3米高的灌木丛中或折断的棕榈树中央，周围被高草遮掩。每窝产1至2枚淡黄色的蛋。在圈养条件下，孵化期大约13天，雏鸟在12天后离巢，但在十天大时可能已能离开巢穴。","identification":"灰头鹑鸠与其他鹑鸠属物种的区别在于其不带条纹的头部、淡灰色的额头以及大部分具有虹彩的身体。与蓝头鹑鸠相比，它似乎更偏爱湿度较高的区域。","protection":"IUCN：VU（易危）","distribution":"灰头鹑鸠主要分布于古巴，特别是在Zapata半岛和Sierra del Rosario的森林中。它在古巴东部边缘和西部的Sierra del Rosario山区较为集中。","other":"灰头鹑鸠是古巴特有种，目前在古巴的多个保护区中被记录，包括Viñales、Ciénaga de Zapata、Pico Cristal、Pico La Bayamesa、Turquino和Alejandro de Humboldt国家公园。"},{"name":"白额鹑鸠","english_name":"White-fronted Quail-Dove","scientific_name":"Geotrygon leucometopia","overview":"白额鹑鸠（英文名：White-fronted Quail-Dove，学名：Geotrygon leucometopia），是鸽形目鸠鸽科鹑鸠属的鸟类。主要分布在多米尼加共和国的特定山区，可能已从海地消失。拥有独特的深紫色光泽羽毛，头部带有醒目的白色前额斑点。","appearance":"成年白额鹑鸠长约28厘米，重约171克。头顶、颈侧和头两侧为板岩灰色，前额有鲜明的白色斑点。颈侧泛红紫色或紫罗兰色，有时延伸至灰色胸部。上身略暗，带金属蓝紫色光泽，腹部下部呈赤褐色。眼睛红色，喙部由红色渐变为尖端的淡黄色，腿和脚亦呈红色。幼鸟颜色较成鸟更棕，缺乏金属光泽。","call":"其鸣唱为一系列短暂低沉的‘haoo’或‘cooo’音符，以极快的速度连续发出，或每约0.5秒一次较为缓慢持续的版本。","habits":"白额鹑鸠栖息于海拔低至1800米的亚热带森林、高山森林及干燥的仙人掌和灌木丛地带，以种子和小无脊椎动物如昆虫、幼虫和毛虫为食。","breeding":"巢由枝条和叶子构成，内部铺垫细根和草，通常筑于低矮的灌木丛或藤蔓交织处。一窝产卵1-2枚，有时可达三枚，蛋壳呈米黄色。","identification":"与灰头鹑鸠的区别在于额头的白色斑点，整体色调更深，背部和肩部的光泽更丰富。在海地的其他鹑鸠中，它是唯一具有白色前额的种类。","protection":"IUCN：EN（濒危）","distribution":"分布于多米尼加共和国的科迪勒拉中央山脉、巴奥鲁科山脉和内伊巴山脉，历史上可能存在于海地的莫恩拉塞勒山。","other":"该物种曾与视为同种，现认为是独立物种。"},{"name":"绿顶鹑鸠","english_name":"Key West Quail-Dove","scientific_name":"Geotrygon chrysia","overview":"绿顶鹑鸠（英文名：Key West Quail-Dove，学名：Geotrygon chrysia），是鸽形目鸠鸽科鹑鸠属的鸟类。体型较小，结构紧凑，栖息于茂密林地的地面上，偏好干燥环境。其特征为暗锈色背部与翼部，头部顶部、颈背呈现青铜绿或紫罗兰色光泽。","appearance":"雄性绿顶鹑鸠体长27-31厘米，重109-212克；雌鸟略小。上身呈栗褐色，冠、颈背带青铜绿或紫罗兰光泽；肩羽、背部、臀部和内翼覆羽带紫色或紫红色光泽；内侧次级飞羽和初级飞羽尖端橄榄棕色；喉部白色，下颚条纹深棕色，面部宽阔白条纹从喙延伸至眼后；颈侧和胸脯粉紫色或灰粉色，腹部转白，两胁暗棕色；虹膜红、橙或黄色；眼周皮肤红色；喙基部暗红，尖端褐色；腿脚红或粉红色。雌鸟相似，但下颌条纹较暗淡；翼覆羽、肩羽后缘及尾羽边缘灰色棕色；下方颜色更深，尤以胸部为著。幼鸟外观与成鸟差异大：上部红肉桂色；肩羽、间肩羽和翼覆羽有肉桂色斑点；头颈比成鸟暗淡，羽毛尖端浅色；胸脯和前颈灰暗，边缘肉桂色。","call":"绿顶鹑鸠的鸣唱是一系列低沉的咕咕声，音调单一，约1-1.5秒，频率大约300-400赫兹，逐渐增强再减弱，最后音调轻微下降。","habits":"绿顶鹑鸠栖息于半干旱林地、低地灌木丛和湿润山地森林，最高可达海拔500米，多见于未受干扰的下层植被。在皮内斯岛发现于次生灌木丛，巴哈马群岛常接近居民区。飞行无声。","breeding":"繁殖期一般为2月至8月；在巴哈马群岛，从1月至9月初都可听到其鸣唱。巢由轻而干的枝条构成，类似哀鸽的巢，置于灌木丛下的植被中，有时筑于地面；一个地面巢完全由松散排列的叶子构成。每次产卵2枚，蛋壳呈奶油色。","identification":"绿顶鹑鸠与绿颈鹑鸠相似，但后者上背呈哑光棕色而非红或紫色，颈侧有青绿色光泽。与Ruddy Quail-Doves相比，面部标记对比度较低，雄鸟背部全锈色；部分有垂直白色肩纹。蓝头鹑鸠的冠部和领部蓝色。","protection":"IUCN：LC（无危）","distribution":"分布于巴哈马群岛（南至圣萨尔瓦多和北凯科斯岛）、古巴、皮内斯岛、海地、多米尼加共和国和波多黎各。曾经在佛罗里达群岛繁殖，现仅偶尔出现。","other":"绿顶鹑鸠曾在海地的干燥区域被描述为常见，尤其在Tortue Island和Gonâve Island数量众多；当地人曾大量捕获，使用玉米或水为诱饵。"},{"name":"绿颈鹑鸠","english_name":"Bridled Quail-Dove","scientific_name":"Geotrygon mystacea","appearance":"绿颈鹑鸠是一种体形圆胖、腿长的中型地面栖息鸽，整体羽色暗淡；颈部以绿色为主，带有蓝紫光泽；翼羽呈肉桂红色；眼下方有一条独特的水平白色线条。成年鸟具有鲜明的白线横过眼睛下方，从喙基延伸至颈侧。雄鸟的头部和颈背有绿色光泽，向下逐渐变为蓝色和紫色；雌鸟光泽较弱。腹部奶油色，尾羽深褐色灰。","call":"绿颈鹑鸠的鸣叫声被描述为深沉而回荡的\"coo\"声，具体表现为\"haaaaao\"、\"hoo-hoooooo\"或\"who-whooo\"。","habits":"绿颈鹑鸠通常单独或成对活动，有时会形成较大的群体，特别是在非繁殖季节。它们在森林地面翻找落叶层中的种子、落果和无脊椎动物，如蜗牛和昆虫。已知它们也会捕食Sphaerodactylus macrolepis蜥蜴。在受干扰时，它们倾向于向上坡行走而非飞行。","breeding":"绿颈鹑鸠在藤蔓、灌木或树木上搭建由细枝构成的平台巢，每窝产卵一到两枚。","identification":"绿颈鹑鸠与绿顶鹑鸠和红鹑鸠相似，但后者颈部缺乏虹彩蓝绿色，且背部颜色不同。红鹑鸠面部标记对比度较低，雄鸟背部全锈色，部分个体有垂直白色肩纹。","protection":"IUCN：LC（无危）","distribution":"绿颈鹑鸠分布在北美的小安的列斯群岛，包括波多黎各南部和东部至圣卢西亚。在波多黎各，它是最需要保护措施的物种之一。"},{"name":"绿背鹑鸠","english_name":"Olive-backed Quail-Dove","scientific_name":"Leptotrygon veraguensis","overview":"绿背鹑鸠（英文名：Olive-backed Quail-Dove，学名：Leptotrygon veraguensis），是鸽形目鸠鸽科Leptotrygon的鸟类。体型丰满，地面栖居，较同类鹑鸠略小，全身色调偏暗，以深灰为主，脸部与颊部的白色形成鲜明对比。腹部下方白色渐变为淡黄色，两腿呈粉红色，性别特征相似。偏好森林环境，尤其在晨昏时分沿林间小径活动，易于观察。","appearance":"头部前额白色，逐渐过渡到灰色的冠羽，后冠羽及颈项呈紫色。上体橄榄褐色，喉部及面部条纹有时带有淡黄色调，脸颊具显著黑纹。腹部白色或淡黄白色，两侧及臀下覆羽暗红褐色。翼下羽呈栗色，其余羽毛橄榄褐或紫褐色，颈部、胸部及背部具绿色或紫色光泽。虹膜棕色，眼周皮肤紫红色，喙与蜡膜黑色，脚和腿红色。雌雄外观相似，但雌鸟前额有时呈淡黄色，冠羽少有灰色。幼鸟羽毛边缘锈色，无光泽。","call":"其鸣声为低沉的单音'whOuw'，具有类似蛙鸣的特质。","habits":"居住在低地至海拔900米的湿润森林中，偏好潮湿的溪谷地带。通常短距离飞行，面对危险更倾向于步行或奔跑逃离，但在受惊时会拍翅升空。以种子（如Scleria）、浆果和小型无脊椎动物（如甲虫）为食，单独或成对在林下层或地面觅食。","breeding":"繁殖季为1月至7月，哥斯达黎加有记录。巴拿马和哥伦比亚有接近繁殖状态的标本记录，时间介于2月至4月之间。筑巢于植被中，距地面1至1.8米，常位于沟壑或溪流附近。巢由细枝和根须构成，内部铺垫更细的枝条。每次产卵2枚，蛋壳呈浅黄色。","identification":"绿背鹑鸠与其他鹑鸠种类相比，整体色调较暗，头部特征明显，尤其是白色脸部和黑颊纹。与同属其他物种在颜色和大小上有显著区别。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲极端南部尼加拉瓜的加勒比斜坡，贯穿哥斯达黎加和巴拿马，至巴拿马东太平洋斜坡，西哥伦比亚至安蒂奥基亚和卡乌卡河谷下游，北厄瓜多尔埃斯梅拉达斯省。在哥斯达黎加北部至托图格罗的森林中较为常见，而在尼加拉瓜南部干旱森林中缺失，巴拿马加勒比斜坡中罕见至局部常见。","other":"绿背鹑鸠最初归入Geotrygon和Oreopeleia属，后于2013年被重新分类至Leptotrygon属，成为该属唯一成员。"},{"name":"白额棕翅鸠","english_name":"White-tipped Dove","scientific_name":"Leptotila verreauxi","overview":"白额棕翅鸠（英文名：White-tipped Dove，学名：Leptotila verreauxi），是鸽形目鸠鸽科棕翅鸠属的鸟类。科学命名纪念了法国自然学家Jules和Edouard Verreaux。分布广泛，从美国南部的得克萨斯州至南美的阿根廷，其足迹遍布中美洲和南美洲的多个地区。","appearance":"成年白额棕翅鸠长约28厘米，重约155克。头部灰色，前额灰白或白色，喉部白色。眼周环通常是红色的，但在亚马逊和南美北部多数地区呈蓝色。上身和翅膀呈灰褐色，下身白色渐变为胸腹部的粉红、淡灰或浅黄色。翼下覆羽为锈色。尾巴宽端有白色尖端，最佳观察时机是在下方或飞行中。喙黑色，腿红色，虹膜黄色。","call":"其叫声为深沉的空洞音调'ooo-wooooo'，两音节同高，先以一短暂的低沉呼噜声开始，随后是一长而响亮的空洞音。","habits":"通常单独或成对出现，性情警觉，不迁徙。飞行快速直接，翅膀拍打规律并伴有嘎吱声，这是鸽子共有的特征。栖息于多种林地环境，从灌木丛到森林地带均有分布。","breeding":"在树上靠近地面处筑造大枝条巢，每次产两枚白色卵。孵化期约为14天，幼鸟离巢需再过15天左右。它们利用声音执行各种任务：保卫领地、吸引潜在伴侣、指示食物资源、警告捕食者以及维持群体联系。","identification":"与近缘的灰额棕翅鸠相似，但前额和头顶更偏向灰色，与后颈对比不如灰额棕翅鸠明显。在分布重叠区域，白额棕翅鸠的眼周环通常是蓝色而非红色，但在巴西、阿根廷、玻利维亚、巴拉圭和乌拉圭部分地区，两物种的眼周环都可能是红色，因此这不是可靠的区分特征。","protection":"IUCN：LC（无危）","distribution":"白额棕翅鸠广泛分布于中美洲和南美洲，从美国南部的得克萨斯州向南延伸至南美的西部秘鲁和阿根廷中部。它还在南美北部的离岸岛屿，如特立尼达和多巴哥以及荷属安的列斯群岛繁殖。","other":"已知存在12至14个亚种，分布自得克萨斯州南至乌拉圭，尽管它们之间羽毛差异非常微妙。"},{"name":"大尾棕翅鸠","english_name":"Yungas Dove","scientific_name":"Leptotila megalura","overview":"大尾棕翅鸠（英文名：Yungas Dove，学名：Leptotila megalura），是鸽形目鸠鸽科棕翅鸠属的鸟类。又被称为白面鸠或大型尾鸠，主要分布在南美洲的玻利维亚和阿根廷西北部，常见于安第斯山脉东侧的云加斯地区。","appearance":"大尾棕翅鸠体型中等至较大，长度约29至32厘米。成鸟前额呈灰白色，头顶蓝灰色，眼周环绕着白色羽毛，其余面部为浅粉色或肉色。上体和尾巴呈现深红棕色，带有紫色光泽，尤其在颈背和上背处更为明显。胸部和颈部两侧为灰粉色调，腹部转为白色。两性相似，幼鸟较暗淡，翅膀覆羽表面似有鳞片状纹路。","call":"其鸣唱由四到五个忧郁单调的音符组成，音调相同，重音在第一个和最后一个音符上，发出“woooo-o-o-oooooo”的叫声，每3至5秒重复一次。","habits":"栖息于亚热带和热带湿润森林，包括桤木林、灌木丛和次生林，也会出现在半干旱的Prosopis林地。海拔高度范围为900至2800米。通常单独或小群体活动。","breeding":"关于其繁殖生态的细节尚不清楚。已知它在灌木或树上筑巢，一窝产两枚奶油色的蛋。","identification":"与Verreaux's Dove在野外易混淆，但大尾棕翅鸠颜色更深更红棕，眼周白色，虹膜非常暗，后颈和上背有紫色光泽，尾羽末端的白色条带较窄，外侧初级飞羽尖端略膨胀。两物种通过声音和部分地区的眶周皮肤颜色（Verreaux's Dove的虹膜黄色或橙色）可以区分。","protection":"IUCN：LC（无危）","distribution":"分布于玻利维亚北部、东部和南部，以及阿根廷西北部的朱胡伊、萨尔塔、卡塔马卡、图库曼和拉里奥哈等地。","other":"尽管在整个分布范围内通常数量不多，但在云加斯地区，如玻利维亚的Vila-Vila和阿根廷朱胡伊的Calilegua，大尾棕翅鸠较为常见。由于可能与Verreaux's Dove混淆，对其观察受限，需进行广泛研究。"},{"name":"灰额棕翅鸠","english_name":"Grey-fronted Dove","scientific_name":"Leptotila rufaxilla","overview":"灰额棕翅鸠（英文名：Grey-fronted Dove，学名：Leptotila rufaxilla），是鸽形目鸠鸽科棕翅鸠属的大型热带鸟类。其分布广泛，遍及南美洲，从哥伦比亚至阿根廷东北部，包括特立尼达岛，唯独不包括智利。该鸟种嘴和眼之间有一条显著的黑色线条。","appearance":"体长约28厘米，体重在115至183克之间。成年雄鸟头部前额灰色至蓝白色，逐渐变为蓝灰色的头顶，颈背灰紫色带光泽。眼睛周围有红色裸皮，环绕着粉白色羽毛，喉部也是粉白色，脸部余下部分呈淡褐色至粉红褐色。上身橄榄棕色，背部微泛青铜或紫光。中央尾羽橄榄棕色，外侧尾羽黑褐色，具明显白尖。下体灰粉色渐变至腹部白色，翅膀下覆羽栗色。喙黑色，腿脚红色。雌鸟较雄鸟更偏褐色，侧翼更显橄榄色，上身绿色调。幼鸟似雌鸟，但胸部有锈色和暗褐色斑纹，上身羽毛边缘常带锈色。","call":"鸣唱为单一声调的哀怨声 'wooOOOoo'，声音时隐时现，持续约0.8秒，频率大约500至600赫兹，每4至10秒重复一次。","habits":"栖息于各种森林环境，偏好湿润森林，通常不在干旱地带。在哥伦比亚可见于河岸林、高地森林和廊道森林。在委内瑞拉，海拔高度可达550米，巴西东南部局部地区可达2200米。在地面觅食，以种子和小型果实为主食，偶尔食用昆虫和其他无脊椎动物。曾在喂食站观察到其食用香蕉和稻米。","breeding":"在特立尼达岛全年繁殖，仅九月至十月例外。筑巢于1至7.5米高的灌木或树木上的平台，使用树枝搭建，常见于Astrocaryum paramaca棕榈树。产1至2枚乳白色蛋。在厄瓜多尔记录到一月份的孵化行为。","identification":"与白额棕翅鸠相似，但尾羽外缘白色较少，眼周皮肤红色而非蓝色，前额对比更鲜明的灰色。与同属物种的区别在于颜色和大小的细微差异。","protection":"IUCN：LC（无危）","distribution":"南美大陆，从哥伦比亚至阿根廷东北部，包括特立尼达岛。","other":"曾被认为与灰头棕翅鸠、褐背棕翅鸠、苍棕翅鸠和威氏棕翅鸠为同一物种，现已确认为独立种类。"},{"name":"灰头棕翅鸠","english_name":"Grey-headed Dove","scientific_name":"Leptotila plumbeiceps","overview":"灰头棕翅鸠（英文名：Grey-headed Dove，学名：Leptotila plumbeiceps），是鸽形目鸠鸽科棕翅鸠属的鸟类.羽色以暗褐上体、淡灰头顶及锈红翼下为显著特征，分布于墨西哥东部至哥伦比亚安第斯山西坡的低地及山地湿润森林，海拔通常 500 米以下，局部可达 2600 米。其鸣声为单调拖长的一声“呜——”，晨昏活动于林下路缘，受惊时骤然飞至低枝。","appearance":"成鸟体长 25.5–28 厘米，体重约 170 克。头顶前部淡灰白至淡蓝灰，向冠部、后冠及颈侧渐深，呈铅灰色；颈背棕褐，与头部形成明显对比。面颊、喉及胸淡粉褐，上体橄榄褐色带锈色，翼较背稍暗，初级飞羽外缘缺刻。外侧 3 枚尾羽末端白，飞行时尾角白、翼下覆羽及腋羽锈红。下体余部白色。虹膜淡角质色，眼圈红至红紫色，嘴黑，足鲜红。雄鸟头顶及颈背具微弱紫辉，雌鸟较暗；幼鸟整体暗淡，上体羽缘肉桂色，胸羽缘浅棕，无灰冠。","call":"鸣唱为单声长而哀婉的“呜——”(wooOOOoo)，长约 0.6 秒，重音频率约 312 Hz，每 3–5 秒重复一次，无先导音，雌雄以略不同音高对唱。亚种 battyi 鸣声更长(0.9 秒)、音调略高且通常无泛音。","habits":"留鸟，不迁徙，昼夜活动，以黎明及黄昏最活跃。栖息于低地及山地湿润常绿林、林缘、次生林及咖啡、柑橘等人工林，海拔范围海平面至 2600 米，罕见于干燥林。常单独或成对在林下地面行走觅食，偶成小群于水源处；受惊时先竖尾示警，继则骤然低飞至下方枝干。食物以种子、落果为主，兼食少量无脊椎动物。","breeding":"繁殖资料稀少。墨西哥维拉克鲁斯咖啡林一单巢观察：5 月下旬筑巢，巢为 20 厘米直径的浅盘，置于 1 米高咖啡树上，由枝条、叶片及人工杂物构成；窝卵 2 枚，乳白或奶油色，长 3 厘米；双亲轮流孵卵 14 天，雏鸟 12 天离巢，离巢当日即分散。巴拿马科伊瓦岛亚种 battyi 繁殖峰期为 2–3 月与 7 月，巢多位于距地 1–2 米的蕨类或藤蔓中。","identification":"与同域 Leptotila 属成员相比，灰头棕翅鸠具淡蓝灰色头顶与颈背，形成显著对比；尾端白仅外侧 2–3 枚尾羽，翼下锈红。白顶棕翅鸠尾白区更宽，头颈色一致，虹膜橙；灰胸棕翅鸠头颈暗褐，鸣声更长渐弱；加勒比棕翅鸠面部更白，颈侧粉辉，虹膜橙。若仅闻声，其鸣声短促单一，缺乏白顶棕翅鸠的先导音，亦短于灰胸棕翅鸠和红鹑鸠的长音。","protection":"IUCN: LC（无危）。亚种 battyi 与 malae 曾被视为独立种 褐背棕翅鸠，级别 VU（易危）。全球估计 5–50 万成熟个体，趋势下降。","distribution":"繁殖区：墨西哥东南部（塔毛利帕斯至恰帕斯）、伯利兹、危地马拉加勒比坡、洪都拉斯及尼加拉瓜加勒比坡（尼加拉瓜局部太平洋坡）、哥斯达黎加西北及太平洋坡至尼科亚湾、巴拿马加勒比坡（波卡斯-德尔托罗省）及太平洋坡科伊瓦岛与阿苏埃罗半岛。哥伦比亚：中科迪勒拉山西坡及中科迪勒拉山东坡之考卡河谷，海拔 1000–2600 米。非繁殖期未见迁徙记录。","other":"battyi 与 malae 亚种因羽色更深、鸣声差异及基因研究支持，曾被提升为独立种“褐背棕翅鸠”或“阿苏埃罗棕翅鸠”；剩余亚种 plumbeiceps 与 notia 仍属灰头棕翅鸠。notia 亚种与指名亚种差异微小，部分学者视为同种。历史记录中墨西哥联邦区及瓜纳华托州标本疑似误标。"},{"name":"苍棕翅鸠","english_name":"Pallid Dove","scientific_name":"Leptotila pallida","overview":"苍棕翅鸠（英文名：Pallid Dove，学名：Leptotila pallida），是鸽形目鸠鸽科棕翅鸠属的鸟类。中等体型的鸽子，主要分布在南美洲西部的热带低地，包括哥伦比亚西部、厄瓜多尔和秘鲁西北部。其上体呈深暖棕色，与白皙的下体形成鲜明对比，常在地面活动。","appearance":"苍棕翅鸠长约23至26厘米，雄鸟的额头、脸部和喉咙为白色，头冠灰色，颈背紫灰色，颈侧和胸部淡紫红色，腹部白色。上体为栗棕色，具有一些栗红色的外翼覆羽，尾羽中央为暗栗色，末端有黑色亚端斑和白色尖端，虹膜黄色，腿脚粉红至褐红色。雌鸟颜色较雄鸟淡，上体红色调较少。","call":"鸣叫声为单调而哀伤的单音符'wooOOOoo'，持续约0.7秒，频率通常在500至600赫兹之间，间隔4至10秒重复，与灰额棕翅鸠的声音非常相似。","habits":"栖息于热带低地森林、干燥半落叶林和次生林，海拔从海平面到800米。常见于地面觅食，或快速飞过。偶尔访问喂食器。","breeding":"关于繁殖行为的信息很少，仅知在12月观察到处于繁殖状态的雄鸟。","identification":"与白额棕翅鸠的区别在于其上体颜色更深，更暖色调，且与下体的对比更为明显。鸣叫声也有助于辨识。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部、厄瓜多尔和秘鲁西北部的热带低地。","other":"曾被认为与灰额棕翅鸠、灰头棕翅鸠、褐背棕翅鸠和威氏棕翅鸠为同一物种，现在确认为独立物种。"},{"name":"褐背棕翅鸠","english_name":"Azuero Dove","scientific_name":"Leptotila battyi","overview":"褐背棕翅鸠（英文名：Azuero Dove，学名：Leptotila battyi），是鸽形目鸠鸽科棕翅鸠属的鸟类。特有于巴拿马。2010年被纳入《世界自然保护联盟》关注名单。","appearance":"成年褐背棕翅鸠体长约23.5至25.5厘米。雄鸟具有淡灰色前额，石板灰色冠部和颈背，棕色灰后颈。面部余部及喉部呈红灰色，胸部为粉红色调，腹部和臀部白色。上体为栗褐色，中央尾羽同样栗褐色，外侧尾羽棕色黑，尖端带棕色白。眼黄色或黄绿色，周围有裸露的红色皮肤。喙黑色，腿脚暗红或粉红。雌鸟背部和胸部较雄鸟暗淡。幼鸟前额、冠部、颈及上胸为棕色，带有肉桂色斑纹。L. l. malae亚种颜色更深，头部和胸部偏灰。","call":"其广告叫声为连续单一的咕咕声。","habits":"褐背棕翅鸠主要在地面觅食，通常以两到三只为一群，对其饮食习惯和食物了解甚少。生活在高大的森林和木沼泽中。","breeding":"关于褐背棕翅鸠的繁殖生态知之甚少。","identification":"与同属物种相比，褐背棕翅鸠的识别特征在于其独特的颜色模式，尤其是栗褐色的上体和粉红的胸部。","protection":"IUCN：VU（易危）","distribution":"分布在中美洲的巴拿马，包括科伊巴岛和塞巴科岛。在大陆上，主要分布在西中部巴拿马的丘陵地带，包括塞罗霍亚山区。","other":"现为灰头棕翅鸠亚种。"},{"name":"威氏棕翅鸠","english_name":"Grenada Dove","scientific_name":"Leptotila wellsi","overview":"威氏棕翅鸠（英文名：Grenada Dove，学名：Leptotila wellsi），是鸽形目鸠鸽科棕翅鸠属的鸟类。中型热带鸽子，特有于加勒比海小安的列斯群岛中的格林纳达岛。曾被称为豌豆鸽或Well's dove，自1991年起被指定为格林纳达的国鸟，是全球最濒危的鸽子之一。","appearance":"威氏棕翅鸠体长约28至31厘米，体重约200克。其面部和前额呈淡粉色，逐渐变为灰色至冠部和颈背的暗棕色；喉咙白色；颈部和上胸为粉红肉色，向下渐变为胸部、腹部和下尾覆羽的白色；两胁淡棕色；背部橄榄棕色至红棕色；虹膜棕色，眼周有深红色环；喙黑色；腿和脚为红色。雌雄外观相似，但在繁殖季节，雌鸟可能略显暗淡，羽毛光泽减弱。幼鸟更暗淡，翅膀和肩羽边缘有淡黄色，胸羽有肉桂色尖端；眼周皮肤呈暗红紫色，腿和脚为暗红色。","call":"发出单个低沉哀婉的音符，每5至8秒一次，声音类似“hoooo......hoooo”，低沉且似吹过瓶口产生的声音，但结束更为突然。","habits":"威氏棕翅鸠生活在低海拔和山腰的干燥灌木林中，最高可达150米。在Mt Hartman庄园，其栖息地由落叶荆棘灌木丛组成，树冠高达6至8米，主要包括金合欢、Bauhinia ungulata和Randia mitis；也有高大的树木如Bursera simaruba、Glivicidia、Pithecellobium、Tabebuia和Tecona。偏好较为封闭的树冠区域，有大片裸露地面和大量灌木丛，其中Haematoxylum campechianum占据主导。雄鸟可能在距地面1至6米的树枝上鸣唱。它们以种子、小果实、昆虫、幼虫和毛虫为食，仅在地上觅食，通常单独或成对活动。","breeding":"繁殖季为12月至2月，以及7月，但会根据降雨量而有所不同。雄鸟在1989年12月至1990年1月期间被听到鸣唱。筑巢行为未被记录，但已知会在1月在一棵棕榈叶上，距离地面4米处发现巢穴，随后在2月中发现巢中有雏鸟。每次产两枚白色卵，孵化和离巢时间未知。","identification":"威氏棕翅鸠通过其朴素的羽毛颜色、翼上缺乏白色标记以及尾部有限的白色与格拉纳达岛上的其他鸽子区分开来。","protection":"IUCN：CR（极危）","distribution":"威氏棕翅鸠仅分布在格林纳达岛，特别是在Mt Hartman和Perseverance庄园有其主要栖息地。","other":"威氏棕翅鸠的数量受到飓风的影响，总数量在1998年约为100只，到2003-2004年估计增加到182只，但2004年的飓风Ivan导致数量下降。"},{"name":"灰胸棕翅鸠","english_name":"Grey-chested Dove","scientific_name":"Leptotila cassinii","overview":"灰胸棕翅鸠（英文名：Grey-chested Dove，学名：Leptotila cassinii），是鸽形目鸠鸽科棕翅鸠属的鸟类。主要分布于中美洲和南美洲，从危地马拉至哥伦比亚北部的热带低地森林中。较为隐秘、陆栖的鸟类，经常听到其声音却难以一见。","appearance":"灰胸棕翅鸠长约22.5至28厘米，体重介于132至179克之间。头部前额呈粉灰色，冠部和颈背为深棕色，喉部白色，胸部为酒红色并渐变为带有金属光泽的灰紫色，腹部酒红色，尾下覆羽白色。上体橄榄棕色，肩部和翼内侧覆羽有绿色或紫色光泽。初级飞羽和尾羽较其余上体颜色更深，尾羽外缘有白色尖端，翅膀下方覆羽为栗色，部分初级飞羽下方亦有栗色。虹膜灰黄色至绿黄色，眼周皮肤灰色，眼后角和眼睑区域暗红，腿脚红色，喙黑色，鼻甲红色。雌鸟比雄鸟色泽稍暗，不同亚种在色彩上有差异。","call":"灰胸棕翅鸠的鸣唱为单一声调的哀婉音符“woOOOooo”，起始迅速消逝，结尾缓慢淡化，持续时间约1.2秒，频率通常在400至600赫兹之间，重复间隔4至8秒。","habits":"栖息于次生林和Heliconia灌丛中，海拔高度可达1400米。在哥斯达黎加的加勒比海沿岸，其分布从海平面到750米，在南太平洋沿岸仅局部出现，海拔可达1200米。在巴拿马，主要分布在加勒比海沿岸的低地，但在奇里基省西部的太平洋山麓地带，其分布可达1284米高。它以种子和小昆虫为食，通常单独或成对活动，不会形成群体。","breeding":"在哥斯达黎加，繁殖季节为2月至5月和7月至9月；在巴拿马，为2月至9月；在哥伦比亚，记录显示繁殖期可能从1月至4月。巢筑于树的水平枝上，离地面1至5米处，位于灌木丛或藤蔓缠绕的地方，由树枝、叶柄和稻草构成的浅凹平台状巢，每次产2枚白色至淡黄色的蛋。","identification":"灰胸棕翅鸠与白额棕翅鸠和灰头鸽的区别在于其温暖的棕色冠部和颈背，以及更暗淡的灰褐色胸部。飞行时，所有棕翅鸠属的鸽子都有白色的尾尖和翅膀下方的锈色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的危地马拉至南美洲的哥伦比亚北部，包括墨西哥、伯利兹、洪都拉斯、尼加拉瓜、巴拿马等地。","other":"与托利棕翅鸠和赭腹棕翅鸠关系密切，可能形成超物种复合体。"},{"name":"赭腹棕翅鸠","english_name":"Ochre-bellied Dove","scientific_name":"Leptotila ochraceiventris","overview":"赭腹棕翅鸠（英文名：Ochre-bellied Dove，学名：Leptotila ochraceiventris），是鸽形目鸠鸽科棕翅鸠属的鸟类。分布于厄瓜多尔西南部至秘鲁西北部的森林地带。其特征在于红紫色的身体，深紫色背部与翅膀，以及较为淡色的前额和腹部。","appearance":"赭腹棕翅鸠长约23至25厘米，重约146克。头部前方呈粉白色，逐渐变为锈紫色，颈后部闪耀紫罗兰光泽，上体为深橄榄褐色，肩部和翼覆羽带有青铜绿或紫罗兰金属光泽。喉部白色，颈部前面为米黄色，胸部酒红色向下渐变为米黄色的下胸、侧腹和腹部。尾下覆羽带有米黄色调，翼下为栗色；中央尾羽深棕色，外侧尾羽黑色，尖端白色；虹膜黄色。两性相似。","call":"其鸣唱为一个相当独特的单音节、略带下滑的音符 'wOOOooo'，起始音明显，随后逐渐减弱，持续时间约为0.7秒，频率通常在400至600Hz之间，每隔8至10秒重复一次。","habits":"栖息于低地至海拔1800米的森林地带，包括湿润常绿林、半落叶林、干燥落叶林、低山林和云雾林。偏好地面活动，偶尔在4米以上的树果处觅食。通常单独或成对出现，有时会在饮水池与其它种类的鸽子群聚，数量可达5只。","breeding":"关于繁殖习性的信息非常有限，巢、蛋和雏鸟尚未被描述。在厄瓜多尔西南部，歌唱活动主要集中在1月至4月，8月有较小的高峰；8月、9月和4月观察到处于繁殖状态的个体。","identification":"与白尖鸽或苍白鸽相比，赭腹棕翅鸠的背部呈紫色而非棕色，下体更显玫瑰色。在不良观察条件下容易混淆。","protection":"IUCN：VU（易危）","distribution":"分布于南美洲，从厄瓜多尔西南部的马纳比省到秘鲁西北部的通贝斯、皮乌拉和兰巴耶克省。","other":"在20世纪早期，赭腹棕翅鸠在厄瓜多尔西南部的森林中并不罕见，但在1926年至1980年间仅被观测到两次。现今多数种群规模小且高度分散，由于栖息地破坏，全球估计数量在3000至15000只之间。"},{"name":"托利棕翅鸠","english_name":"Tolima Dove","scientific_name":"Leptotila conoveri","overview":"托利棕翅鸠（英文名：Tolima Dove，学名：Leptotila conoveri），是鸽形目鸠鸽科棕翅鸠属的鸟类。仅见于哥伦比亚安第斯山脉云雾森林中，拥有独特的紫红颈胸色彩和灰色头冠，偏好隐蔽栖息，但在清晨会出现在空旷地带或安静的路边。其鸣声低沉而间隔分明。","appearance":"成年托利棕翅鸠体长22.5至25厘米，头冠呈蓝灰色至深灰色，喉部白色，后颈为酒红色并带有紫色光泽。上背为酒红色灰色，覆以紫蓝色光泽，其余背部暗灰色并带有紫色光泽，翅膀颜色较深，尾部石板色，外侧尾羽尖端白色。胸部为酒红色粉红，与下胸及腹部的淡黄色界限明显。","call":"发出低沉且间隔较大的‘wooOOOooo’声，中间有明显的重音，每次鸣叫持续约0.6秒，频率通常在400至600赫兹之间，间隔6至8秒重复一次。","habits":"主要栖息于湿润的森林内部和边缘，海拔1200至2500米的亚热带区域，适应于受扰动的开放地带，如咖啡园和人类住区附近。以Bocconia frutescens种子为主要食物。","breeding":"繁殖季节从3月至9月，巢建于灌木或小树（如咖啡树）中，离地面高度0.3至2米，巢结构类似于白额棕翅鸠，每次产卵两枚。","identification":"与广泛分布的白额棕翅鸠相比，颈部和胸部的暗红紫色、灰色的头冠和苍白的眼睛是其显著特征。","protection":"IUCN：NT（近危）","distribution":"分布于哥伦比亚中部安第斯山脉的东坡，从托利马省的科埃略-康贝伊玛河系统到胡伊拉省的马格达莱纳河上游，2014年在哥伦比亚东部安第斯山脉的昆迪纳马卡省也有发现。","other":"尽管原生栖息地遭受严重破坏，但该物种成功适应了次生林和咖啡种植园等次级栖息地。"},{"name":"卡氏鹑鸠","english_name":"Tuxtla Quail-Dove","scientific_name":"Zentrygon carrikeri","overview":"卡氏鹑鸠（英文名：Tuxtla Quail-Dove，学名：Zentrygon carrikeri），是鸽形目鸠鸽科Zentrygon的鸟类。主要栖息在墨西哥东南部的Sierra de Los Tuxtlas山区的湿润常绿森林中。以蓝灰色的脸部、黑色的髭纹、淡褐色的两胁和轻盈的体型为显著特征。","appearance":"卡氏鹑鸠体长29至31.5厘米，头部、颈部、喉咙和胸部呈现淡蓝灰色，两胁为淡褐色。具有宽大的黑色髭纹，背部和翅膀为橄榄棕色，几乎没有虹彩。幼鸟全身颜色较深，上体羽毛边缘呈肉桂色，胸部有浅黄色的条纹。","call":"其鸣唱为三音节的'whu-hu-whUuuw'，最后一音节尤为强调。远处仅能听到最后一音节，声音略带颤音，音调较高。","habits":"栖息在海拔350至2100米的湿润常绿森林和云雾林中，常见树种包括Bernoullia、Brosimum、Dussia等。通常单独或成对出现，主要在森林地面觅食，可能以果实、种子和无脊椎动物为食。","breeding":"已知唯一的巢穴发现于1962年中期，位于500米处，巢由交错的竹枝支撑，呈松散平台状，内有一枚淡粉色的蛋，这种颜色对于该属来说较为罕见。","identification":"与紫背鹑鸠相比，卡氏鹑鸠体型更大，颜色更浅，翼羽、下背和臀部更亮，背部和肩部颜色更浅，带有更明显的紫色调，两侧颜色更淡，胸部颜色更淡，上体羽毛的紫色光泽在中缺失，黑颊纹更宽，两物种在翼弦、尾巴和露出的喙长上没有重叠。","protection":"IUCN：EN（濒危）","distribution":"仅分布于墨西哥东南部的Veracruz州的Volcán de San Martín和Sierra de Santa Marta两个火山区域。","other":"由于栖息地的广泛破坏，卡氏鹑鸠的数量估计在350至1500只之间，已被列为濒危物种。"},{"name":"黄额鹑鸠","english_name":"Buff-fronted Quail-Dove","scientific_name":"Zentrygon costaricensis","overview":"黄额鹑鸠（英文名：Buff-fronted Quail-Dove，学名：Zentrygon costaricensis），是鸽形目鸠鸽科Zentrygon的鸟类。最显著特征为黄色或淡粉色的前额，头、颈和胸主要呈灰色，腹部逐渐变为棕色，背部与翅膀为深红棕色并带有紫色光泽。该物种主要分布于中美洲的哥斯达黎加高地至巴拿马西部，栖息于海拔1000至3000米的常绿山地森林。","appearance":"黄额鹑鸠拥有厚实的身体，短尾和短腿。头部大部分为灰色，前额为独特的黄色或粉黄色，冠部和颈背带有绿色光泽。上体为暗红棕色，混杂紫色，下体为灰色，腹部转为浅棕色。两性相似，成鸟与幼鸟在颜色上略有差异，幼鸟的颜色较为暗淡，且上体为暗褐色，下体有灰、肉桂色条纹和斑点。","call":"其鸣唱被描述为低沉的‘hoOOOO’声，音量在结尾处增大，略带上升的音调。","habits":"黄额鹑鸠偏好栖息于蒙特内哥罗的常绿森林，常在地面觅食，有时会飞至树的较低层。它们以单独或成对的形式活动，主要在清晨和黄昏沿着小径活动。食物主要包括果实、种子，可能还包括昆虫。","breeding":"关于繁殖行为的资料有限，已知的巢为由粗枝、苔藓和肝叶组成的几乎平坦的平台，位于离地面约4米高的灌木水平枝上，巢中至少有一只雏鸟。","identification":"与紫背鹑鸠的区别在于后者前额为白色而非黄色；与棕胸鹑鸠相比，体型较小，冠部无明显浅色前额，且下体为灰色而非肉桂色。","protection":"IUCN：LC（无危）","distribution":"黄额鹑鸠的分布区域集中在中美洲，包括哥斯达黎加北部的瓜纳卡斯特山脉，向东南延伸至巴拿马西部的维拉瓜斯省。","other":"黄额鹑鸠的系统分类经历多次调整，最初归于Geotrygon属，后移至Oreopeleia属，现置于Zentrygon属内，为单型种。"},{"name":"紫背鹑鸠","english_name":"Purplish-backed Quail-Dove","scientific_name":"Zentrygon lawrencii","appearance":"紫背鹑鸠长约26至27厘米，体重约220克。成鸟头部呈灰白色，冠部至颈后为蓝绿至灰绿色。上体和翅膀橄榄棕色至暗褐色，带微红调。背部有一块不甚显眼的紫色区域。尾羽中央为紫棕色，外侧尾羽黑褐色，尖端灰。脸和喉部白色，颈部和胸部为板岩灰色，腹部中心淡黄色至肉桂色，两侧巧克力色。眼睛棕橙至红色，周围有裸露的洋红色皮肤，腿脚亦为洋红色。幼鸟缺乏成鸟的绿色和紫色，面部图案较不明显，多数羽毛边缘呈淡黄色。","call":"其鸣唱为三音节的'pum-wha-huUUu'，最后一个音节尤为突出。在远处仅能听到最后一音节。","habits":"紫背鹑鸠常以步行或奔跑的方式躲避危险，而非立即飞翔。它们在地面觅食，多单独或成对出现，以果实、种子、昆虫和蠕虫为食。活动范围主要限于潮湿密集的山地森林，海拔高度从400米到800米，部分地区可达2600米。","breeding":"在哥斯达黎加，繁殖季节从6月持续至10月，但在巴拿马可能更早开始。它们会建造一个松散的杯状巢，由细枝构成并衬以柔软材料，置于近地面的密林中，每次仅产一枚卵。","identification":"紫背鹑鸠与卡氏鹑鸠曾被视作同种，但现已明确区分。主要通过颜色模式、分布区域和鸣声特征来辨识。","protection":"IUCN：LC（无危）","distribution":"分布于哥斯达黎加北部的Cordillera de Guanacaste向东南至巴拿马中部，零星分布至Darién省。","other":"紫背鹑鸠的种群在哥斯达黎加西北部曾一度被视为亚种，现已确认为单一物种。"},{"name":"灰头白脸鹑鸠","english_name":"White-faced Quail-Dove","scientific_name":"Zentrygon albifacies","overview":"灰头白脸鹑鸠（英文名：White-faced Quail-Dove，学名：Zentrygon albifacies），是鸽形目鸠鸽科Zentrygon的鸟类。分布广泛，自墨西哥东部至尼加拉瓜北部，常见于海拔1000-2700米的高山区，偏好湿润的常绿森林和松树常绿林。其最显著特征为蓝灰色的冠部和苍白的脸部，整体呈锈褐色。","appearance":"灰头白脸鹑鸠成鸟的头部前额为淡白色或灰白色，逐渐过渡到较深的灰色至后颈。上体主要为暗红褐色，背部带有紫蓝色光泽。颈侧有独特的暗色条纹，下体颜色为浅肉桂色。雌雄相似，幼鸟上体为暗棕色，胸部和两侧为带暗色条纹的赤褐色。全长约28-31.5厘米。","call":"其叫声低沉、空洞而哀婉，通常发出'whoooo'或'whoo'oo'的声音。","habits":"栖息于各种类型的湿润山地森林，包括常绿林和松树常绿林，偶尔也出现在遮阴咖啡种植园。主要在地面觅食，喜欢单独或成对活动，偏好密集的植被覆盖。以种子、掉落的果实为主食，可能也吃昆虫。","breeding":"繁殖季节在不同地区有所变化，尚未充分研究。巢由枝条粗略搭建，位于隐蔽处，距地面可达6米。每窝产卵两枚。","identification":"与白尖鹑鸠相比，缺乏白色的尾羽角，体型更大，头部图案不同。与红鹑鸠相比，体型更大，脸部无暗色颊纹。","protection":"IUCN：LC（无危）。尽管分布范围大，但种群被认为正在减少，墨西哥当局将其视为受威胁物种。","distribution":"分布于中美洲，从墨西哥南部至尼加拉瓜西北部，主要栖息在1000-2700米的高山森林。","other":"其生物学特性了解甚少，饮食和繁殖行为的详细信息仍待研究。"},{"name":"白喉鹑鸠","english_name":"White-throated Quail-Dove","scientific_name":"Zentrygon frenata","overview":"白喉鹑鸠（英文名：White-throated Quail-Dove，学名：Zentrygon frenata），是鸽形目鸠鸽科Zentrygon的鸟类。大型地面栖息的鹑鸠。主要识别特征为脸部淡色、灰色头顶、鳞状颈项和明显的白色喉咙，全身主要呈棕色。白喉鹑鸠在海拔较高的山地森林中活动，高度通常介于1000至3300米之间。","appearance":"白喉鹑鸠体型丰满，长度在30至34厘米之间，体重约311克。面部下方及前额呈淡色，头顶为蓝灰色，肩部深紫色，上体其余部分为红褐色，喉咙白色，胸部灰色，腹部及两侧暗黄色。雌雄外观相似，但雌鸟较灰，幼鸟上体及下体有粗大的暗色条纹。不同亚种头部色彩有所差异。","call":"白喉鹑鸠的鸣叫声为单调的低沉'whoOOo'音节，音量在音节中部达到最高，持续时间约为0.6至0.7秒，频率通常在400赫兹左右，每3至6秒重复一次。","habits":"栖息于安第斯山脉的湿润常绿山地森林，海拔范围为900至3000米，偶尔降至700米。通常在地面觅食，单独或以2至3只为一群。活动范围广泛，但在特定区域较为分散。","breeding":"繁殖季节可能在哥伦比亚西部的1月至7月，秘鲁乌鲁班巴山谷的9月晚期。已知一巢位于距离地面2米的浓密植被中，内含一枚浅色蛋，其余繁殖行为细节未知。","identification":"与非常相似，但前额和眼下的区域为淡色，头顶蓝灰色，整体颜色略深，尤其是肩部呈现深紫色。雌鸟颜色不如雄鸟灰。幼鸟上体和下体有粗大的暗色条纹。不同亚种主要通过头部色彩进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，自哥伦比亚西部至阿根廷西北部，包括玻利维亚、厄瓜多尔和秘鲁。","other":"白喉鹑鸠的系统分类历史复杂，曾被归入Geotrygon和Oreopeleia属，现属于Zentrygon属。"},{"name":"白脸鹑鸠","english_name":"Lined Quail-Dove","scientific_name":"Zentrygon linearis","overview":"白脸鹑鸠（英文名：Lined Quail-Dove，学名：Zentrygon linearis），是鸽形目鸠鸽科Zentrygon的鸟类。体型丰满，地栖性。其面部呈淡褐色至非常浅的棕色，具灰色冠顶和鳞状颈部，喉咙白色，全身大部分呈棕色。性别间外观相似，与白喉鹑鸠相似但分布范围不重叠，常见于较低海拔地区。分布于南美洲的哥伦比亚、委内瑞拉和特立尼达及多巴哥群岛。","appearance":"体长27至29厘米，体重230至284克。额头粉红棕色渐变为紫棕色冠顶，眼后有一条灰色带延伸至颈背，脸部呈淡白色至浅棕色，有两条暗色条纹，一条从喙延伸至眼睛后方，另一条位于耳羽下方。上体呈红棕色，肩部紫红色，背部有金属光泽的紫色或青铜绿色，颈部两侧有独特的褶皱，类似灰头白脸鹑鸠。胸部淡灰色至棕色，两侧紫色，腹部、两胁和下尾覆羽为浅黄褐色，虹膜颜色多样，眼环红色，周围有蓝色裸皮，喙黑色，腿和脚红色。雌鸟与雄鸟相似，但胸部灰色带棕色调。幼鸟整体更红，羽毛上有大量棕色和黑色条纹。","call":"发出单调的低音'whoOOo'，音量在中间最高，长度约0.7至0.8秒，频率通常在400至500赫兹之间，每隔3至6秒重复一次。当两只鸟同时鸣叫时，音调略有差异。","habits":"栖息于热带低地和山地常绿森林，海拔高度可达2500米。通常在地面行走，除非受惊才飞入树的低层。以种子为食，单独或成对在森林地面觅食。","breeding":"在哥伦比亚，繁殖季节至少从4月持续到10月；在特立尼达及多巴哥，筑巢期可能更早。巢为深杯状，由小枝条构成，内衬枯叶，置于离地3.7米高的水平树叉上，每窝产2枚乳白色蛋。","identification":"与白喉鹑鸠区别在于无分布重叠，且通常栖息于稍低海拔。可通过羽毛颜色、眼环颜色和叫声进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚的卡乌卡谷地、圣玛尔塔山脉、安第斯山脉的中部和东部，委内瑞拉西部和北部，包括梅里达、阿维拉山、瓦伦西亚峰、帕里亚半岛，以及特立尼达和多巴哥群岛。","other":"该物种的系统学历史复杂，曾被归入Geotrygon属，与灰头白脸鹑鸠和棕胸鹑鸠曾被视为超种或甚至同种。"},{"name":"棕胸鹑鸠","english_name":"Chiriqui Quail-Dove","scientific_name":"Zentrygon chiriquensis","overview":"棕胸鹑鸠（英文名：Chiriqui Quail-Dove，学名：Zentrygon chiriquensis），是鸽形目鸠鸽科Zentrygon的鸟类。体型丰满的地面栖息型鸽类。全身呈温暖的红褐色调，与红鹑鸠相似，但头部灰冠与黑色颊纹为其独特之处。偏好山林地带，活动范围从中美洲的哥斯达黎加至巴拿马西部。","appearance":"成年雄鸟长27-31厘米，雌鸟26-32厘米，体重约295-308克。头部顶部为浅灰色，逐渐加深至后颈，前额颜色较淡；上体由肩部的栗色渐变为上背部的紫色，再转为带绿光泽的橄榄色；翅膀暗淡，有时带有栗色色调；明显的黑色颊纹；细长的黑色眼后线和眼先纹；下巴和上喉部为米白色，向下逐渐变为红褐色，至腹部转为淡肉桂色；两胁和尾下覆羽为深肉桂棕色；虹膜为棕橙色，眼周皮肤红色；喙和蜡膜黑色；腿脚紫红色。雌鸟与雄鸟相似，但胸部颜色通常更深，头顶灰色更暗淡。幼鸟上体包括头部为棕色，头部和枕部颜色更深，翼覆羽红褐色，翅覆羽和肩羽有暗色亚端斑点或条纹；前颈、胸部和两侧的颜色与成鸟类似，但带有暗黑色条纹。","call":"其鸣唱为单调的一声'wooOoh'，音量逐渐增强，持续时间约为0.75-0.9秒，频率在400-500赫兹之间，声音低沉，每3-5秒重复一次。","habits":"栖息于中海拔的山林下层，偏好干燥森林环境。活动范围从哥斯达黎加的瓜纳卡斯特山脉南端到巴拿马西部，海拔高度在600-1700米之间，局部可达2000米；太平洋侧海拔1000-2500米，偶尔上至3100米。繁殖季节时，从地面1-3米高的树枝上不断发出叫声，有时从空巢发出。以种子、落果和小型无脊椎动物为食，单独或成对在地面觅食，早晨可能沿道路和小径觅食。","breeding":"在巴拿马8月末发现产卵，哥斯达黎加9月筑巢。巢为浅杯状，由树叶和细枝构成，置于树梢悬垂的细枝末端，高度在地面以上2.5米处。产2枚淡黄色或乳白色的蛋。","identification":"与灰头白脸鹑鸠和白脸鹑鸠有相似之处，但通过灰冠、黑色颊纹和特定的鸣唱声可区分开。","protection":"IUCN：LC（无危）","distribution":"分布于哥斯达黎加至巴拿马西部(Chiriquí, Veraguas)。在加勒比海一侧，分布于600-1700米海拔，局部可达2000米；太平洋一侧海拔1000-2500米，偶尔上至3100米。","other":"关于其生态和生物学信息知之甚少，需要进一步研究和调查以确定真实状况。"},{"name":"黄顶鹑鸠","english_name":"Russet-crowned Quail-Dove","scientific_name":"Zentrygon goldmani","overview":"黄顶鹑鸠（英文名：Russet-crowned Quail-Dove，学名：Zentrygon goldmani），是鸽形目鸠鸽科Zentrygon的鸟类。最显著的外部特征是其特有的黄褐色冠羽。分布于巴拿马东部至哥伦比亚西北部的山麓和低海拔高地森林。","appearance":"成年雄鸟长约26.5至28.5厘米，雌鸟约27至28厘米，体重约为258克。雄鸟的头部呈黄褐色，额部颜色较浅，面部有黑色颊纹。后颈为棕色，翅膀和背部带有紫色调的棕色，腹部灰白色，两胁棕色。眼橙色，眼圈红色，腿脚红色。雌鸟胸部略带棕色，翅膀比雄鸟少些红棕色。幼鸟上部暗淡肉桂棕色，下部暗褐色边缘红褐色。","call":"鸣唱为单一略带滑音的音符'wOuu'，有时听起来像双音节，持续时间约0.75秒，频率通常约500Hz，每4至6秒重复一次。","habits":"栖息于中美洲和南美洲的山麓地带，偏好潮湿森林下的灌木丛，主要在海拔750至1600米间活动，偶尔低至90米。通常在地面觅食，以种子为主食，偶尔吞食小石子作为消化辅助。","breeding":"关于繁殖信息几乎一无所知，仅有一例在哥伦比亚Chocó发现的未完全成长的幼鸟记录。","identification":"与紫背鹑鸠的区别在于黄顶鹑鸠的冠羽和颈背为黄褐色，颊纹为肉色而非白色，后颈棕色而非灰绿色，翅膀和背部更偏棕色，腹部灰白色，眼圈灰色，眼周和喙裂红色。","protection":"IUCN：NT（近危）。物种因栖息地丧失导致数量下降，需要更多研究以确定其种群规模和趋势。","distribution":"分布于巴拿马东部至哥伦比亚西北部的山麓和低海拔高地森林。具体而言，从巴拿马的东潘省到迪里安省，进入哥伦比亚极西北部。","other":"有两个亚种，指名亚种为Z. g. goldmani和Z. g. oreas，后者分布于巴拿马东部，但与指名亚种种西部相隔。"},{"name":"旅鸽","english_name":"Passenger Pigeon","scientific_name":"Ectopistes migratorius","overview":"旅鸽（英文名：Passenger Pigeon，学名：Ectopistes migratorius），是鸽形目鸠鸽科旅鸽属的鸟类。又称: 漂泊鸠，又名漂泊鸠，是北美历史上最著名的绝灭鸟类之一。以惊人的数量存在，估计曾有3至5亿只，可能占北美大陆鸟类总数的四分之一。旅鸽体型介于35至41厘米之间，重约250至340克，背部蓝灰色，腹部灰棕色，胸部暗红带大白斑点，颈部羽毛青铜色并带有紫绿光泽。喙黑，虹膜红，腿深红。曾经广泛分布在加拿大中南部、东南部以及美国中部和东部的森林中。","appearance":"旅鸽数量众多，体长约35至41厘米，体重在250至340克之间。雄鸟比雌鸟略大。头部和上半身呈蓝灰色，翅膀和尾巴尖端较暗，尾羽扇形且长。腹部、胸至尾为灰棕色，胸部有暗红色并伴有大白斑点。颈部羽毛呈现青铜色，带有紫色和绿色闪光。喙黑色，虹膜红色，腿脚深红色。幼鸟与成年雌鸟相似，但颜色较为暗淡，缺乏成年雄鸟的鲜明色彩。","call":"旅鸽的叫声被描述为响亮、粗糙且缺乏乐感，有时被形容为咕噜声、啾啾声和呼呼声。在筑巢时会发出类似蛙鸣的声音，在求偶时则会发出钟声般的声响。","habits":"旅鸽是典型的群居鸟类，每群可达数亿只。它们主要生活在东部森林，依赖季节性丰富的坚果和果实生存。旅鸽的迁徙路线广泛，冬季会南迁至美国南部和墨西哥东南部。它们的飞行速度极快，平均时速可达62英里。","breeding":"旅鸽通常每年繁殖一次，每窝产一枚卵，雌雄共同孵化，孵化期约为13天。雏鸟出生后第一周靠双亲分泌的鸽乳喂养。","identification":"旅鸽与哀鸽最为相似，但前者体型更大，缺乏面部条纹，两性异形明显，颈部羽毛有金属光泽，且每窝产卵较少。在形态和行为上，旅鸽与其他鸽子种类有显著区别。","protection":"IUCN：EX（绝灭）","distribution":"旅鸽原生地为北美的东部森林，包括加拿大中南部和东南部，美国中部和东部。它们夏季在北美洲落基山脉东部广泛地区生活，冬季迁徙至美国南部。","other":"旅鸽的快速灭绝是人类过度猎杀和栖息地破坏的直接结果。从19世纪中叶开始，旅鸽数量急剧下降，至1900年，最后一只野生旅鸽被射杀。1914年，最后一只人工饲养的旅鸽‘玛莎’在美国辛辛那提动物园去世，标志着这一物种的彻底消失。"},{"name":"哀鸽","english_name":"Mourning Dove","scientific_name":"Zenaida macroura","overview":"哀鸽（英文名：Mourning Dove，学名：Zenaida macroura），是鸽形目鸠鸽科哀鸠属的鸟类。又名: 泣鸽、哀鸠，又名泣鸽、哀鸠，以其哀伤的鸣叫声闻名。全身为暗哑的浅灰褐色，翼上具有黑色斑点，雌雄外观相似。广泛分布于北美至中美洲，包括加拿大南部至巴拿马，以及加勒比海地区。哀鸽对人类改造的环境有极高的适应性，数量庞大，繁殖力强，全球估计有1.3亿只。栖息于开放和半开放环境，如农田、城市和轻度林地。","appearance":"哀鸽体型中等，长约31厘米，体重介于110-170克之间。头部圆润，长尾巴呈锥形，翅膀宽阔，腿短且为淡红色。全身羽毛为浅灰褐色，翅膀下部颜色较浅，头和胸腹部为粉红色，翅膀上有黑色斑点，外层尾羽为白色，与内层黑色形成鲜明对比。成年雄鸟颈部两侧有亮紫色斑块，雌鸟总体上灰色羽毛较多，幼鸟羽色暗哑。","call":"哀鸽的鸣叫声极具特色，听起来像是“咕——呜－呜－呜——”，其中“咕”为重音，之后声音渐弱。近听时，可在第一声“咕”前听到喉咙中的摩擦声和咯咯声。","habits":"哀鸽的食物主要是种子，占其饮食的99%，偶尔也会吃蜗牛或昆虫。它们会吃足够的食物来填满嗉囊，然后在飞行间隙休息时消化。哀鸽会吞下细砂以帮助消化。哀鸽主要的天敌是昼行性猛禽，如隼和鹰。","breeding":"哀鸽繁殖力旺盛，一季最多可产六窝，每窝两枚蛋。雌雄双方共同参与孵蛋和照顾雏鸟，雏鸟在11-15天后会长出羽毛，但仍依赖父母喂养数周。","identification":"哀鸽与白翅哀鸽、鸣哀鸽、灰斑鸠、环颈斑鸠和珠颈斑鸠的区别在于后者具有黑色颈圈或尾部形状不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布于北美至中美洲，包括加拿大南部至巴拿马，以及加勒比海地区。在北美和中美洲的分布极为广泛。","other":"哀鸽是北美洲最常见和数量最多的陆地鸟类之一，对人类环境的适应能力强，是狩猎运动中的重要猎物。"},{"name":"索岛哀鸽","english_name":"Socorro Dove","scientific_name":"Zenaida graysoni","overview":"索岛哀鸽（英文名：Socorro Dove，学名：Zenaida graysoni），是鸽形目鸠鸽科哀鸠属的鸟类。又名: 索哥罗鸠，已野外灭绝的鸽类，原生于墨西哥西部的雷维利亚希赫多群岛中的索科罗岛。最后一次在自然环境中的记录是在1972年，现在仅存于圈养之中，全球数量不到200只，纯种圈养个体估计不足100只。该物种的命名向Zénaïde Laetitia Julie Bonaparte和美国鸟类学家Andrew Jackson Grayson致敬。索岛哀鸽是陆栖性的，以其长腿著称，体长约26.5至34厘米，体重平均190克。","appearance":"索岛哀鸽具有中等体型，腿长，属于典型的陆栖鸽类，体长介于26.5至34厘米之间，平均重约190克。其头部和下体呈深橙肉桂色或栗棕色，头部侧面有类似于近亲的耳纹。颈后部呈现蓝灰色，颈部有金属光泽的粉红色斑块，这些特征在换羽后更为明显。上体为红褐色，雌鸟和幼鸟的色彩较雄鸟稍显暗淡。最显著的特征是其深色的体羽和强健的双足，这在索科罗岛上黑暗的火山岩和阴凉的森林环境中十分有利。","call":"索岛哀鸽的鸣叫声以两声二音节的咕咕声开始，随后是三声单独的叫声，最后以另一声二音节的咕咕声结束，每部分持续时间大约一秒。","habits":"索岛哀鸽偏好在种子和小果实丰富的地带活动，主要在地面行走而非飞行。它们在海拔500米以上的季节性湿润森林中最为常见，但在猫类引入前，也会季节性地下降至低地。在人类定居者和猫类到达之前，它们似乎会进行规律的垂直迁移，夏季在高海拔区域较为丰富，冬季则移至低海拔地区。","breeding":"索岛哀鸽的繁殖周期约为6.6年。在圈养环境下，雌鸟通常会在距离地面1至2.5米的巢箱中产下两枚白色蛋，孵化期为14到17天，幼鸟大约在14至20天后离巢。","identification":"与哀鸽相比，索岛哀鸽体型更大，重约15-20%更多，具有更长的喙和脚跗骨。它们的下体颜色为赤褐色而非浅黄色，尾羽标记和叫声也有所不同。此外，哀鸽常群居，而索岛哀鸽则倾向于独居。","protection":"IUCN：EW（野外绝灭）","distribution":"索岛哀鸽原产于墨西哥的索科罗岛，位于太平洋上的雷维利亚希赫多群岛中。目前，圈养的个体分布在欧洲和北美的动物园和其他设施中。","other":"由于野猫的捕食，索岛哀鸽在野外灭绝。然而，1925年的采集行动使得一些个体得以保存，从而避免了该物种的彻底消失。目前正在进行的再引入计划旨在清除岛上的野猫和恢复生态平衡，以便将圈养的索岛哀鸽重新引入其原生岛屿。"},{"name":"斑颊哀鸽","english_name":"Eared Dove","scientific_name":"Zenaida auriculata","overview":"斑颊哀鸽（英文名：Eared Dove，学名：Zenaida auriculata），是鸽形目鸠鸽科哀鸠属的鸟类。是南美洲最广泛分布且数量最多的鸽类之一。从哥伦比亚到南阿根廷和智利都有踪迹，甚至出现在格林纳丁斯群岛等离岸岛屿上。与北美的哀鸽有紧密的亲缘关系，形成一个超物种群。该鸟种适应力强，能快速殖民新环境。","appearance":"成年斑颊哀鸽体长约24厘米，体重约112克。雄鸟具有橄榄棕色的背部，翅膀上有黑色斑点，头部呈灰蓝色，眼睛后方有一条黑色线纹，下耳覆羽为蓝黑色。雌鸟色彩较暗淡，幼鸟则呈现灰色至褐色，带淡色边缘。两性均具红褐色的腿脚，喙部为黑色。","call":"发出深沉柔和的‘oo-ah-oo’叫声。","habits":"斑颊哀鸽常见于开阔地带，包括大草原、农田及人类居住区。它们适应性强，常在城市电线、电话杆上休息，在特立尼达和委内瑞拉的城市公共空间及托巴哥海滩附近觅食。以地面种子和谷物为主食，偶尔食用昆虫和软体动物。","breeding":"在树上几米高的位置筑巢，通常每窝产两个白色蛋，孵化期约为12-14天，幼鸟再过9天左右即可离巢。繁殖季节不固定，只要有充足的食物和栖息地，几乎全年都能繁殖。","identification":"斑颊哀鸽与哀鸽有相似的外观，但可通过其较大的体型、翅膀上的黑斑和更细长的体形加以区分。","protection":"IUCN：LC（无危）","distribution":"遍布南美洲，从哥伦比亚至阿根廷南部和智利，以及格林纳丁斯群岛等地。在特立尼达和多巴哥可能为近期的殖民者。","other":"斑颊哀鸽在某些地区被视为严重的农业害鸟，大量群体可一次性摧毁谷物田，因此在阿根廷每年有数百万只被猎杀。"},{"name":"鸣哀鸽","english_name":"Zenaida Dove","scientific_name":"Zenaida aurita","overview":"鸣哀鸽（英文名：Zenaida Dove，学名：Zenaida aurita），是鸽形目鸠鸽科哀鸠属的鸟类。是安圭拉的国鸟，也被当地人亲切地称为“turtle dove”。广泛分布于加勒比海地区及尤卡坦半岛，偶尔在佛罗里达礁岛群繁殖，但在科罗拉多州仅有三次确凿的记录。这种鸽子长约28-30厘米，外观与哀鸽相似，但体型略小，尾巴更短且圆润，双翼有明显的白色边缘。","appearance":"成年鸣哀鸽的头部呈肉桂色，颈侧稍淡，冠部颜色更深。枕部、颈背为褐色灰色，颈部两侧和下方有金属紫色光泽。背部、肩部、二级飞羽和臀部中间部分呈红棕色。胸部和下体为较浅的红棕色。翼端覆羽、羽轴、一级飞羽覆羽和臀部侧面为灰色。二级飞羽近端有黑色斑点，外侧二级飞羽边缘灰暗，逐渐过渡至白色。脚和腿为红色，虹膜为深棕色至棕黑色。雌鸟颜色较淡，背部红色较少。幼鸟似雌鸟，但缺乏颈上的虹彩斑块，背部和翅膀羽毛有淡黄色边缘。","call":"鸣哀鸽的叫声与哀鸽类似，是一种忧伤的咕咕声“whoo’oOO...hu...hu...hu”，但音调略高，节奏更为规律。","habits":"鸣哀鸽主要栖息于低地的开阔林地、森林边缘和空地，以及耕作地带、次生林、灌木丛和红树林。它们在树上筑巢和栖息，以果实和种子为主食，但也在地面觅食。在牙买加，它们最高可达1500米的耕作区域活动。","breeding":"繁殖季节在多米尼加为3月至12月，维京群岛为5月至8月。在波多黎各湿润的低地山区全年筑巢，2月至5月（4月至5月一项研究）达到高峰，但在岛西南部（瓜尼卡和苏苏亚森林）3月至6月和10月至1月达到高峰。巢通常建在树或灌木上，由20种树木构成，最常用的是芒果、王棕榈、仙人掌和高大的阿比齐亚。在多米尼加，最常用的树是血木。在少有或无天敌的岛屿上，巢建在地面。通常产卵两枚（1-3枚），孵化期13-15天，离巢期同样为13-15天。","identification":"鸣哀鸽与哀鸽非常相似，但鸣哀鸽体型较小，尾巴更短更圆，飞行时翼缘有白色边缘，而哀鸽没有这一特征。","protection":"IUCN：LC（无危）","distribution":"鸣哀鸽分布于整个加勒比海地区和尤卡坦半岛（墨西哥东北部）。在北美，常见于西印度群岛和尤卡坦半岛。在佛罗里达礁岛群的记录极为罕见。","other":"鸣哀鸽因其肉质美味，被视作猎鸟，承受着巨大的狩猎压力。"}];
